    }

    private static void TestDclAbilityBindings(AbilityCatalog nativeCatalog)
    {
        DclActionProfile action = BuildDclMagicTargetingTestProfile();
        var authoring = new DclAuthoringRegistry();
        Check(authoring.TryRegister(action).IsValid,
            "the sentinel action must enter the normalized registry before a native carrier can bind it");
        var fireBinding = new DclAbilityBinding(
            AbilityId: 16,
            NativeFormula: 0x08,
            action.ActionId,
            action.ProfileRevision,
            DclNativeCarrierKind.SingleResult,
            DclCarrierRewritePolicy.ReplaceCompleteResult,
            RequiresDataNeutralization: true,
            ForecastBoundary: "forecast-state-0x19",
            AiBoundary: "compute-point-post-0x281F12",
            ExecutionBoundary: "outer-sweep-state-0x2A",
            ApplyBoundary: "native-pre-clamp-and-apply",
            PresentationBoundary: "native-result-selector");
        Check(DclAbilityBindingContract.Validate(fireBinding, nativeCatalog, authoring).IsValid,
            "native Fire 16/formula 0x08 must bind one normalized action revision to explicit forecast/AI/execution/apply/presentation owners");
        string json = DclAbilityBindingJsonLoader.Serialize(new DclAbilityBindingBundle(
            DclAbilityBindingJsonLoader.CurrentSchemaRevision,
            [fireBinding]));
        DclAbilityBindingRegistry registry = DclAbilityBindingJsonLoader.Load(json, nativeCatalog, authoring);
        Check(registry.Bindings.Count == 1 && registry.Bindings[16].ActionId == action.ActionId &&
              registry.Bindings[16].NativeFormula == 0x08,
            "strict ability binding loading must retain the native record/formula and exact normalized action revision without inferring mechanics from animation or name");

        DclAbilityBindingCoverage coverage = registry.Audit(nativeCatalog, new HashSet<int> { 510, 511 });
        Check(!coverage.Complete && coverage.BoundCount == 1 && coverage.ExcludedCount == 2 &&
              coverage.MissingAbilityIds.Count == nativeCatalog.Count - 3 &&
              !coverage.MissingAbilityIds.Contains(16) && !coverage.MissingAbilityIds.Contains(510),
            "ability coverage must expose every still-unbound native record rather than substituting permissive defaults");
        DclAbilityBindingCoverage badExclusion = registry.Audit(nativeCatalog, new HashSet<int> { 999 });
        Check(!badExclusion.Complete && badExclusion.UnknownExcludedIds.SequenceEqual([999]),
            "carrier exclusions must themselves resolve to real native records");

        DclAbilityBindingValidation formulaMismatch = DclAbilityBindingContract.Validate(
            fireBinding with { NativeFormula = 0x09 }, nativeCatalog, authoring);
        DclAbilityBindingValidation revisionMismatch = DclAbilityBindingContract.Validate(
            fireBinding with { ProfileRevision = action.ProfileRevision + 1 }, nativeCatalog, authoring);
        Check(!formulaMismatch.IsValid && formulaMismatch.Findings.Any(f => f.Path == "NativeFormula") &&
              !revisionMismatch.IsValid && revisionMismatch.Findings.Any(f => f.Path == "ProfileRevision"),
            "binding validation must reject stale formula evidence and action revisions before execution");
        CheckThrows<DclAuthoringLoadException>(
            () => DclAbilityBindingJsonLoader.Load(DclAbilityBindingJsonLoader.Serialize(
                new DclAbilityBindingBundle(1, [fireBinding, fireBinding])), nativeCatalog, authoring),
            "one native ability record must never publish two canonical bindings");
        CheckThrows<DclAuthoringLoadException>(
            () => DclAbilityBindingJsonLoader.Load(json.Replace(
                "\"schemaRevision\": 1,",
                "\"schemaRevision\": 1,\n  \"unexpected\": true,",
                StringComparison.Ordinal), nativeCatalog, authoring),
            "ability binding JSON must reject unknown fields rather than silently dropping carrier ownership");
    }

