        DclCanonicalNativeActionApplication SettleSimpleApplication(
            DclCanonicalBattleRuntime owner,
            long actionInstanceId,
            int abilityId,
            string actionId,
            DclUnitKey source,
            DclUnitKey target)
        {
            (DclAbilityBinding actionBinding, _) = runtime.ResolveAbility(abilityId);
            var projection = new DclCanonicalNativeMultiCarrierProjection(
                actionInstanceId,
                abilityId,
                actionId,
                actionBinding.ProfileRevision,
                actionBinding.CarrierKind,
                actionBinding.RewritePolicy,
                [new DclCanonicalNativeStrikeProjection(
                    target,
                    StrikeIndex: 0,
                    DclMagicDeliveryOutcome.Delivered,
                    PhysicalOutcome: null,
                    Delivered: true,
                    new DclCanonicalNativeNumericChannels(0, 0, 0, 0),
                    MagicalRoute: null,
                    InjuryConsequences: null,
                    TargetKoAfterStrike: false,
                    KoShortCircuited: false)],
                ResourcePayment: null,
                ReactionWindowOpened: false,
                ResourceFailed: false);
            DclCanonicalNativeActionApplication application =
                owner.NativeActions.Publish(source, actionBinding, projection);
            application.ApplyNextStrike(target, strikeIndex: 0);
            application.CommitResourcePayment();
            application.Settle();
            return application;
        }

        DclCanonicalNativeActionApplication SettlePeriodicInvocation(DclCanonicalStateTickInvocation invocation)
            => SettleSimpleApplication(
                periodicBattle,
                invocation.ActionInstanceId,
                invocation.AbilityId,
                invocation.EffectActionId,
                invocation.Source,
                invocation.Target);

        DclCanonicalStateTickInvocation immediate = periodicBattle.BeginImmediatePayloadInvocation(periodicInstance);
        Check(ReferenceEquals(immediate, periodicBattle.BeginImmediatePayloadInvocation(periodicInstance)) &&
              immediate is { AbilityId: var immediateAbility, EffectActionId: "periodic.poison.test", ImmediatePayload: true } &&
              immediateAbility == periodicAbilityId && immediate.Source == periodicTarget && immediate.Target == periodicTarget,
            "an immediate periodic payload must reserve one retry-stable outer ActionInstance with an explicit source and native carrier");
        DclCanonicalNativeActionApplication immediateApplication = SettlePeriodicInvocation(immediate);
        periodicBattle.CommitImmediatePayloadInvocation(immediate, immediateApplication);
        CheckThrows<InvalidOperationException>(
            () => periodicBattle.BeginImmediatePayloadInvocation(periodicInstance),
            "a settled immediate payload cannot be manufactured a second time");

        DclCanonicalGlobalScheduleStep scheduled = periodicBattle.BeginNextGlobalScheduleStepThrough(3) ??
            throw new InvalidOperationException("periodic sentinel lost its first scheduled tick");
        Check(ReferenceEquals(scheduled, periodicBattle.BeginNextGlobalScheduleStepThrough(3)) &&
              scheduled.TickInvocation is { ImmediatePayload: false } scheduledTick &&
              scheduledTick.ActionInstanceId != immediate.ActionInstanceId &&
              periodicBattle.States.TryGet(periodicInstance.InstanceId, out DclStateInstance beforeTick) &&
              beforeTick.NextTickGlobalCt == 3,
            "a scheduled tick must be retry-stable and leave the state cursor unchanged until its outer action settles");
        DclCanonicalNativeActionApplication scheduledApplication =
            SettlePeriodicInvocation(scheduled.TickInvocation!);
        DclStateScheduleCommit periodicCommit =
            periodicBattle.CommitGlobalScheduleStep(scheduled, scheduledApplication);
        Check(!periodicCommit.Expired &&
              periodicBattle.States.TryGet(periodicInstance.InstanceId, out DclStateInstance afterTick) &&
              afterTick.NextTickGlobalCt == 6 && periodicBattle.NativeActions.Count == 0,
            "a scheduled tick advances exactly once only after native apply, payment, Reaction policy, and settlement complete");

        var timelineBattle = new DclCanonicalBattleRuntime(runtime, battleGeneration: 18, initialGlobalCt: 0);
        var timelineSource = new DclUnitKey(18, 1, 46);
        var timelineTarget = new DclUnitKey(18, 2, 47);
        timelineBattle.ObserveUnit(timelineSource);
        timelineBattle.ObserveUnit(timelineTarget);
        DclStateInstance timelinePeriodic = timelineBattle.States.Apply(new DclStateApplication(
            periodicState,
            timelineTarget,
            Source: null,
            AppliedAtGlobalCt: 0,
            AppliedBeforeTurnSerial: 0,
            FirstEligibleTargetTurnSerial: null,
            FirstEligibleSourceTurnSerial: null,
            DurationUnits: 6,
            Strength: null,
            WinningMargin: null,
            StackDiscriminator: "timeline-periodic",
            ContributionIdentity: null,
            new DclPropertyStatePayload(periodicState.PayloadSchema, new Dictionary<string, string>()),
            periodicState.PresentationProfile)).Instance;
        DclCanonicalStateTickInvocation timelineImmediate =
            timelineBattle.BeginImmediatePayloadInvocation(timelinePeriodic);
        DclCanonicalNativeActionApplication timelineImmediateApplication = SettleSimpleApplication(
            timelineBattle,
            timelineImmediate.ActionInstanceId,
            timelineImmediate.AbilityId,
            timelineImmediate.EffectActionId,
            timelineImmediate.Source,
            timelineImmediate.Target);
        timelineBattle.CommitImmediatePayloadInvocation(timelineImmediate, timelineImmediateApplication);

        var sourceClock = new DclCtState(initialCt: 70);
        var targetClock = new DclCtState(initialCt: 70);
        var timeline = new DclCanonicalTimelineScheduler(
            timelineBattle,
            [
                new DclCanonicalTimelineUnit(timelineSource, initiativeRank: 0, sourceClock, DclCtRate.Normal),
                new DclCanonicalTimelineUnit(timelineTarget, initiativeRank: 1, targetClock, DclCtRate.Normal),
            ]);
        long chargedActionId = timelineBattle.NextActionInstanceId();
        var chargedDeclaration = new DclActionDeclaration(
            chargedActionId,
            timelineSource,
            action.ActionId,
            action.ProfileRevision,
            DclTargetMode.Unit,
            timelineTarget,
            FixedTile: null,
            DeclarationTile: new DclBattleTile(0, 0, 0),
            PassedRangeCheck: true,
            PassedVerticalCheck: true,
            FinalMpCost: action.ResourceProfile.BaseMpCost,
            ApprovedHpCap: 0,
            CastCt: 3,
            DeclaredAtGlobalCt: 0,
            ResolvesAtGlobalCt: 3);
        timeline.ScheduleChargedAction(binding.AbilityId, chargedDeclaration);

        DclCanonicalTimelineStep chargedStep = timeline.BeginNextStepThrough(3) ??
            throw new InvalidOperationException("timeline lost its charged action");
        Check(ReferenceEquals(chargedStep, timeline.BeginNextStepThrough(3)) &&
              chargedStep is { Kind: DclCanonicalTimelineStepKind.ChargedAction, GlobalCt: 3 } &&
              sourceClock.CurrentCt == DclRational.FromInteger(100) &&
              targetClock.CurrentCt == DclRational.FromInteger(100) &&
              timelineBattle.States.TryGet(timelinePeriodic.InstanceId, out DclStateInstance beforeTimelineTick) &&
              beforeTimelineTick.NextTickGlobalCt == 3,
            "CastCT completion must reserve first at a shared timestamp while turn and state cursors remain pending");
        DclCanonicalNativeActionApplication chargedApplication = SettleSimpleApplication(
            timelineBattle,
            chargedActionId,
            binding.AbilityId,
            action.ActionId,
            timelineSource,
            timelineTarget);
        timeline.CommitChargedAction(chargedStep, chargedApplication);

        DclCanonicalTimelineStep tickStep = timeline.BeginNextStepThrough(3) ??
            throw new InvalidOperationException("timeline lost its same-CT periodic tick");
        Check(tickStep is { Kind: DclCanonicalTimelineStepKind.StateSchedule, GlobalCt: 3,
                           StateSchedule.TickInvocation: not null },
            "periodic ticks must follow charged deliveries and precede same-CT turns");
        DclCanonicalStateTickInvocation timelineTick = tickStep.StateSchedule!.TickInvocation!;
        DclCanonicalNativeActionApplication timelineTickApplication = SettleSimpleApplication(
            timelineBattle,
            timelineTick.ActionInstanceId,
            timelineTick.AbilityId,
            timelineTick.EffectActionId,
            timelineTick.Source,
            timelineTick.Target);
        timeline.CommitStateSchedule(tickStep, timelineTickApplication);

        DclCanonicalTimelineStep sourceTurn = timeline.BeginNextStepThrough(3) ??
            throw new InvalidOperationException("timeline lost its first eligible turn");
        Check(sourceTurn is { Kind: DclCanonicalTimelineStepKind.TurnGrant, TurnUnit: var firstTurn } &&
              firstTurn == timelineSource,
            "equal-CT turn ties must preserve canonical initiative rank after all same-CT actions and state events");
        Check(timeline.CommitTurnGrant(sourceTurn) == 1 && timeline.ActiveTurn == timelineSource &&
              sourceClock.CurrentCt == DclRational.FromInteger(0) &&
              targetClock.CurrentCt == DclRational.FromInteger(100),
            "turn grant must reset only the selected unit CT, preserve every other eligible CT, and open its battle turn resources");
        CheckThrows<InvalidOperationException>(
            () => timeline.BeginNextStepThrough(3),
            "the global timeline cannot overtake an active unit turn");
        timeline.CompleteActiveTurn(timelineSource);
        DclCanonicalTimelineStep targetTurn = timeline.BeginNextStepThrough(3) ??
            throw new InvalidOperationException("timeline lost its second eligible turn");
        Check(targetTurn.TurnUnit == timelineTarget && timeline.CommitTurnGrant(targetTurn) == 1,
            "the next same-CT eligible unit must receive its own distinct active turn");
        timeline.CompleteActiveTurn(timelineTarget);

        var highCtBattle = new DclCanonicalBattleRuntime(runtime, battleGeneration: 19, initialGlobalCt: 0);
        var highCtLaterRank = new DclUnitKey(19, 1, 48);
        var lowerCtEarlierRank = new DclUnitKey(19, 2, 49);
        highCtBattle.ObserveUnit(highCtLaterRank);
        highCtBattle.ObserveUnit(lowerCtEarlierRank);
        var highCtClock = new DclCtState(initialCt: 95);
        var lowerCtClock = new DclCtState(initialCt: 95);
        var highCtTimeline = new DclCanonicalTimelineScheduler(
            highCtBattle,
            [
                new DclCanonicalTimelineUnit(highCtLaterRank, initiativeRank: 1, highCtClock, DclCtRate.Haste),
                new DclCanonicalTimelineUnit(lowerCtEarlierRank, initiativeRank: 0, lowerCtClock, DclCtRate.Normal),
            ]);
        DclCanonicalTimelineStep highCtTurn = highCtTimeline.BeginNextStepThrough(1) ??
            throw new InvalidOperationException("timeline lost a same-boundary higher-CT turn");
        Check(highCtTurn.TurnUnit == highCtLaterRank,
            "current CT must outrank the earlier initial initiative rank when several units are already eligible");
        highCtTimeline.CommitTurnGrant(highCtTurn);
        Check(highCtClock.CurrentCt == DclRational.FromInteger(0) &&
              lowerCtClock.CurrentCt == DclRational.FromInteger(105),
            "a higher-CT turn grant must reset only its selected clock and preserve the waiting eligible clock exactly");
        highCtTimeline.CompleteActiveTurn(highCtLaterRank);

        DclCanonicalTimelineStep finalTick = timeline.BeginNextStepThrough(6) ??
            throw new InvalidOperationException("timeline lost its tick at expiry CT");
        Check(finalTick.StateSchedule?.Pending.Event is
              { Kind: DclStateScheduleEventKind.Tick, GlobalCt: 6 },
            "a tick sharing its timestamp with expiry must reserve before expiry");
        DclCanonicalStateTickInvocation finalTickInvocation = finalTick.StateSchedule!.TickInvocation!;
        timeline.CommitStateSchedule(finalTick, SettleSimpleApplication(
            timelineBattle,
            finalTickInvocation.ActionInstanceId,
            finalTickInvocation.AbilityId,
            finalTickInvocation.EffectActionId,
            finalTickInvocation.Source,
            finalTickInvocation.Target));
        DclCanonicalTimelineStep expiryStep = timeline.BeginNextStepThrough(6) ??
            throw new InvalidOperationException("timeline lost its same-CT expiry");
        DclStateScheduleCommit expiryCommit = timeline.CommitStateSchedule(expiryStep);
        Check(expiryCommit.Expired && timelineBattle.CurrentGlobalCt == 6 &&
              !timelineBattle.States.TryGet(timelinePeriodic.InstanceId, out _),
            "same-CT expiry must occur only after the periodic outer ActionInstance settles");

        var invalidQuickTimelineBattle = new DclCanonicalBattleRuntime(runtime, battleGeneration: 18, initialGlobalCt: 0);
        var invalidQuickTimelineUnit = new DclUnitKey(18, 1, 46);
        invalidQuickTimelineBattle.ObserveUnit(invalidQuickTimelineUnit);
        var invalidQuickTimelineClock = new DclCtState(initialCt: 20);
        var invalidQuickTimelineLocks = new DclQuickLockController();
        invalidQuickTimelineLocks.TryApplyQuick(
            invalidQuickTimelineUnit,
            invalidQuickTimelineClock,
            DclRational.FromInteger(80));
        var invalidQuickTimeline = new DclCanonicalTimelineScheduler(
            invalidQuickTimelineBattle,
            [new DclCanonicalTimelineUnit(
                invalidQuickTimelineUnit,
                initiativeRank: 0,
                invalidQuickTimelineClock,
                DclCtRate.Normal)],
            invalidQuickTimelineLocks,
            quickLockDefinition.Kind);
        DclCanonicalTimelineStep invalidQuickTurn = invalidQuickTimeline.BeginNextStepThrough(0) ??
            throw new InvalidOperationException("invalid QuickLock timeline did not expose its eligible turn");
        invalidQuickTimeline.CommitTurnGrant(invalidQuickTurn);
        CheckThrows<InvalidOperationException>(
            () => invalidQuickTimeline.CompleteActiveTurn(invalidQuickTimelineUnit),
            "timeline turn completion must reject a controller/persistent QuickLock mismatch before mutation");
        Check(invalidQuickTimelineLocks.IsLocked(invalidQuickTimelineUnit) &&
              invalidQuickTimeline.ActiveTurn == invalidQuickTimelineUnit,
            "failed QuickLock completion preflight must preserve the controller and active-turn boundary for diagnosis/retry");

        var quickTimelineBattle = new DclCanonicalBattleRuntime(runtime, battleGeneration: 17, initialGlobalCt: 0);
        var quickTimelineUnit = new DclUnitKey(17, 1, 45);
        quickTimelineBattle.ObserveUnit(quickTimelineUnit);
        var quickTimelineClock = new DclCtState(initialCt: 20);
        var quickTimelineLocks = new DclQuickLockController();
        Check(quickTimelineLocks.TryApplyQuick(
                  quickTimelineUnit,
                  quickTimelineClock,
                  DclRational.FromInteger(80)),
            "Quick timeline sentinel must atomically grant turn-eligible CT and its controller lock");
        DclStateInstance quickTimelineState = quickTimelineBattle.States.Apply(new DclStateApplication(
            quickLockDefinition,
            quickTimelineUnit,
            quickTimelineUnit,
            AppliedAtGlobalCt: 0,
            AppliedBeforeTurnSerial: 0,
            FirstEligibleTargetTurnSerial: null,
            FirstEligibleSourceTurnSerial: null,
            DurationUnits: null,
            Strength: null,
            WinningMargin: null,
            StackDiscriminator: "quick-timeline",
            ContributionIdentity: null,
            new DclPropertyStatePayload(quickLockDefinition.PayloadSchema, new Dictionary<string, string>()),
            quickLockDefinition.PresentationProfile)).Instance;
        var quickTimeline = new DclCanonicalTimelineScheduler(
            quickTimelineBattle,
            [new DclCanonicalTimelineUnit(quickTimelineUnit, initiativeRank: 0, quickTimelineClock, DclCtRate.Normal)],
            quickTimelineLocks,
            quickLockDefinition.Kind);
        DclCanonicalTimelineStep quickTurn = quickTimeline.BeginNextStepThrough(0) ??
            throw new InvalidOperationException("Quick did not expose its immediate eligible turn");
        quickTimeline.CommitTurnGrant(quickTurn);
        DclCanonicalTimelineTurnCompletion quickTurnCompletion =
            quickTimeline.CompleteActiveTurn(quickTimelineUnit);
        Check(quickTurnCompletion.QuickUnlock is
              { LockControllerCleared: true, RemovedStateInstanceIds.Count: 1 } &&
              quickTurnCompletion.QuickUnlock.Value.RemovedStateInstanceIds[0] == quickTimelineState.InstanceId &&
              !quickTimelineLocks.IsLocked(quickTimelineUnit) &&
              !quickTimelineBattle.States.TryGet(quickTimelineState.InstanceId, out _),
            "QuickLock must remain through the granted turn and clear atomically at that turn's completion boundary");

        var interruptionBattle = new DclCanonicalBattleRuntime(runtime, battleGeneration: 16, initialGlobalCt: 0);
        var interruptedCaster = new DclUnitKey(16, 1, 43);
        var interruptionTarget = new DclUnitKey(16, 2, 44);
        interruptionBattle.ObserveUnit(interruptedCaster);
        interruptionBattle.ObserveUnit(interruptionTarget);
        var interruptionTimeline = new DclCanonicalTimelineScheduler(
            interruptionBattle,
            [new DclCanonicalTimelineUnit(
                interruptedCaster,
                initiativeRank: 0,
                new DclCtState(initialCt: 10),
                DclCtRate.Stopped)]);
        long interruptedActionId = interruptionBattle.NextActionInstanceId();
        var interruptedDeclaration = new DclActionDeclaration(
            interruptedActionId,
            interruptedCaster,
            action.ActionId,
            action.ProfileRevision,
            DclTargetMode.Unit,
            interruptionTarget,
            FixedTile: null,
            DeclarationTile: new DclBattleTile(0, 0, 0),
            PassedRangeCheck: true,
            PassedVerticalCheck: true,
            FinalMpCost: action.ResourceProfile.BaseMpCost,
            ApprovedHpCap: 0,
            CastCt: 5,
            DeclaredAtGlobalCt: 0,
            ResolvesAtGlobalCt: 5);
        interruptionTimeline.ScheduleChargedAction(binding.AbilityId, interruptedDeclaration);
        var failedConcentration = new DclInjuryConsequenceResult(
            new DclMajorWoundResult(RemainingHp: 10, RequiresHtRoll: false, AvoidedCollapse: true),
            UnexpiredShockInjury: 1,
            ShockPenaltyMagnitude: 1,
            ApplyStun: false,
            ApplyKnockedDown: false,
            CriticalKnockbackTiles: 0,
            TotalForcedDisplacement: 0,
            new DclConcentrationResult(DclConcentrationOutcome.Interrupted, Score: 7, Rolled: true));
        DclCanonicalChargedCancellation? interruption =
            interruptionTimeline.ResolveInjuryConcentration(interruptedCaster, failedConcentration);
        Check(interruption is
              { ChargedAction.Declaration.ActionInstanceId: var cancelledId,
                Reason: DclChargingCancellationReason.ConcentrationFailure } &&
              cancelledId == interruptedActionId &&
              !interruptionTimeline.TryGetChargedAction(interruptedCaster, out _) &&
              interruptionTimeline.BeginNextStepThrough(5) is null && interruptionTimeline.CurrentGlobalCt == 5,
            "failed concentration must cancel exactly the source's Charging declaration without manufacturing payment, delivery, or a due action");

        long preservedActionId = interruptionBattle.NextActionInstanceId();
        interruptionTimeline.ScheduleChargedAction(binding.AbilityId, interruptedDeclaration with
        {
            ActionInstanceId = preservedActionId,
            DeclaredAtGlobalCt = 5,
            ResolvesAtGlobalCt = 8,
            CastCt = 3,
        });
        var preservedConcentration = failedConcentration with
        {
            Concentration = new DclConcentrationResult(DclConcentrationOutcome.Preserved, Score: 7, Rolled: true),
        };
        Check(interruptionTimeline.ResolveInjuryConcentration(interruptedCaster, preservedConcentration) is null &&
              interruptionTimeline.TryGetChargedAction(interruptedCaster, out DclCanonicalScheduledCast preserved) &&
              preserved.Declaration.ActionInstanceId == preservedActionId,
            "successful concentration must preserve the original scheduled ActionInstance and due CT");
        DclCanonicalChargedCancellation? voluntary = interruptionTimeline.CancelChargedActionForSource(
            interruptedCaster,
            DclChargingCancellationReason.Voluntary);
        Check(voluntary?.Reason == DclChargingCancellationReason.Voluntary &&
              voluntary.ChargedAction.Declaration.ActionInstanceId == preservedActionId,
            "voluntary cancellation must remove the exact pending declaration through the same explicit cancellation boundary");

        var checkpointBattle = new DclCanonicalBattleRuntime(runtime, battleGeneration: 15, initialGlobalCt: 0);
        var checkpointCaster = new DclUnitKey(15, 1, 41);
        var checkpointQuickTarget = new DclUnitKey(15, 2, 42);
        checkpointBattle.ObserveUnit(checkpointCaster);
        checkpointBattle.ObserveUnit(checkpointQuickTarget);
        checkpointBattle.BeginTurn(checkpointCaster);
        checkpointBattle.CompleteTurn(checkpointCaster);
        DclDefenseResourceSnapshot checkpointDefenseBefore = checkpointBattle.CaptureDefenseResources(
            checkpointCaster,
            ["checkpoint-main-hand"]);
        checkpointBattle.CommitDefenseResourcesBatch(
        [
            new DclCanonicalDefenseResourceCommit(
                checkpointCaster,
                checkpointDefenseBefore,
                new DclDefenseResourceSnapshot(
                    new Dictionary<string, int> { ["checkpoint-main-hand"] = 2 },
                    BlockAvailable: false,
                    checkpointDefenseBefore.Revision)),
        ]);
        DclWeaponActionState checkpointWeapon = checkpointBattle.WeaponState(
            checkpointCaster,
            "checkpoint-main-hand",
            DclWeaponBalance.Unbalanced,
            DclWeaponReadinessProperty.UnreadyAfterAttack);
        checkpointWeapon.CommitAttack();
        var checkpointCasterClock = DclCtState.Restore(new DclRational(155, 2));
        var checkpointQuickClock = new DclCtState(initialCt: 20);
        var checkpointQuickLocks = new DclQuickLockController();
        checkpointQuickLocks.TryApplyQuick(
            checkpointQuickTarget,
            checkpointQuickClock,
            DclRational.FromInteger(80));
        DclStateInstance checkpointQuickState = checkpointBattle.States.Apply(new DclStateApplication(
            quickLockDefinition,
            checkpointQuickTarget,
            checkpointCaster,
            AppliedAtGlobalCt: 0,
            AppliedBeforeTurnSerial: 0,
            FirstEligibleTargetTurnSerial: null,
            FirstEligibleSourceTurnSerial: null,
            DurationUnits: null,
            Strength: null,
            WinningMargin: null,
            StackDiscriminator: "checkpoint-quick",
            ContributionIdentity: null,
            new DclPropertyStatePayload(quickLockDefinition.PayloadSchema, new Dictionary<string, string>()),
            quickLockDefinition.PresentationProfile)).Instance;
        var checkpointTimeline = new DclCanonicalTimelineScheduler(
            checkpointBattle,
            [
                new DclCanonicalTimelineUnit(checkpointCaster, 0, checkpointCasterClock, DclCtRate.Slow),
                new DclCanonicalTimelineUnit(checkpointQuickTarget, 1, checkpointQuickClock, DclCtRate.Haste),
            ],
            checkpointQuickLocks,
            quickLockDefinition.Kind);
        long checkpointChargeId = checkpointBattle.NextActionInstanceId();
        checkpointTimeline.ScheduleChargedAction(binding.AbilityId, chargedDeclaration with
        {
            ActionInstanceId = checkpointChargeId,
            Source = checkpointCaster,
            TrackedTarget = checkpointQuickTarget,
            DeclaredAtGlobalCt = 0,
            ResolvesAtGlobalCt = 5,
            CastCt = 5,
        });
        string timelineCheckpointJson = DclCanonicalTimelineCheckpointCodec.Serialize(checkpointTimeline);
        Check(timelineCheckpointJson == DclCanonicalTimelineCheckpointCodec.Serialize(checkpointTimeline),
            "timeline checkpoint serialization must be deterministic at one settled boundary");
        DclCanonicalTimelineRestoreResult restoredTimeline = DclCanonicalTimelineCheckpointCodec.Restore(
            timelineCheckpointJson,
            runtime,
            battleGeneration: 25);
        DclCanonicalTimelineUnit[] restoredUnits = restoredTimeline.Timeline.TimelineUnits.ToArray();
        DclCanonicalScheduledCast restoredCharge = restoredTimeline.Timeline.ChargedActions.Single();
        DclStateInstance restoredQuickState = restoredTimeline.Battle.States.Instances.Single(instance =>
            instance.Kind == quickLockDefinition.Kind);
        DclWeaponActionState restoredWeapon = restoredTimeline.Battle.WeaponState(
            restoredUnits[0].Unit,
            "checkpoint-main-hand",
            DclWeaponBalance.Unbalanced,
            DclWeaponReadinessProperty.UnreadyAfterAttack);
        DclDefenseResourceSnapshot restoredDefense = restoredTimeline.Battle.CaptureDefenseResources(
            restoredUnits[0].Unit,
            ["checkpoint-main-hand"]);
        Check(restoredUnits.Length == 2 &&
              restoredUnits[0].Unit == new DclUnitKey(25, checkpointCaster.UnitSlot, checkpointCaster.CharacterId) &&
              restoredUnits[0].Clock.CurrentCt == new DclRational(155, 2) &&
              restoredUnits[0].Rate == DclCtRate.Slow &&
              restoredUnits[1].Clock.CurrentCt == DclRational.FromInteger(100) &&
              restoredUnits[1].Rate == DclCtRate.Haste &&
              restoredTimeline.Battle.CurrentTurnSerial(restoredUnits[0].Unit) == 1 &&
              restoredCharge.Declaration.ActionInstanceId == checkpointChargeId &&
              restoredCharge.Declaration.Source == restoredUnits[0].Unit &&
              restoredCharge.Declaration.TrackedTarget == restoredUnits[1].Unit &&
              restoredQuickState.InstanceId == checkpointQuickState.InstanceId &&
              restoredQuickState.Target == restoredUnits[1].Unit &&
              restoredTimeline.QuickLocks?.IsLocked(restoredUnits[1].Unit) == true &&
              !restoredWeapon.Ready && restoredWeapon.ParrySuppressedAfterAttack &&
              !restoredDefense.BlockAvailable && restoredDefense.Revision == 2 &&
              restoredDefense.ParryAttemptCounts["checkpoint-main-hand"] == 2 &&
              restoredTimeline.Battle.NextActionInstanceId() == checkpointChargeId + 1,
            "timeline restore must rebase identities while preserving exact CT, rates, turn serials, weapon and defense cadence, QuickLock, state ids, charged declaration, and ActionInstance cursor");
        CheckThrows<InvalidOperationException>(
            () => DclCanonicalTimelineCheckpointCodec.Restore(
                timelineCheckpointJson.Replace(
                    $"\"nextActionInstanceId\":{checkpointChargeId + 1}",
                    $"\"nextActionInstanceId\":{checkpointChargeId}",
                    StringComparison.Ordinal),
                runtime,
                battleGeneration: 26),
            "timeline restore must reject an ActionInstance cursor that collides with a pending charged declaration");
        DclCanonicalTimelineStep checkpointPendingTurn = checkpointTimeline.BeginNextStepThrough(0) ??
            throw new InvalidOperationException("checkpoint sentinel lost its Quick-eligible turn");
        CheckThrows<InvalidOperationException>(
            () => DclCanonicalTimelineCheckpointCodec.Serialize(checkpointTimeline),
            "timeline checkpoint must reject a pending event rather than serialize an ambiguous half-commit");
        checkpointTimeline.CommitTurnGrant(checkpointPendingTurn);
        CheckThrows<InvalidOperationException>(
            () => DclCanonicalTimelineCheckpointCodec.Serialize(checkpointTimeline),
            "timeline checkpoint must reject an active unit turn");
        checkpointTimeline.CompleteActiveTurn(checkpointQuickTarget);
        var injuryRandomSource = new SequenceRandomSource([6, 6, 6, 1, 1, 1]);
        var injuryRandomBattle = new DclCanonicalBattleRuntime(
            runtime,
            battleGeneration: 20,
            initialGlobalCt: 0,
            executionRandomSource: injuryRandomSource);
        var injurySource = new DclUnitKey(20, 1, 50);
        var injuryTarget = new DclUnitKey(20, 2, 51);
        injuryRandomBattle.ObserveUnit(injurySource);
        injuryRandomBattle.ObserveUnit(injuryTarget);
        var injuryContext = new DclCanonicalInjuryTargetContext(
            MaxHp: 10,
            TargetSt: 10,
            EffectiveHt: 10,
            UnexpiredShockInjury: 0,
            Charging: true,
            Will: 10,
            ConcentrationModifier: 0,
            ConcentrationStatePenaltyMagnitude: 0);
        DclInjuryResult majorInjury = DclInjury.Resolve(
            rawRolledDamage: 7,
            DclDamageType.Crushing,
            applicableDr: 0,
            armorDivisor: DclRational.FromInteger(1));
        DclCanonicalInjuryConsequenceRolls majorRolls = DclCanonicalInjuryRandomPlanner.PlanRolls(
            injuryRandomBattle,
            actionInstanceId: 1,
            injurySource,
            injuryTarget,
            strikeIndex: 0,
            hpBeforeInjury: 10,
            majorInjury,
            DclDamageType.Crushing,
            criticalSuccess: false,
            injuryContext,
            directConcentrationCancellation: false,
            authoredForcedDisplacement: 0);
        Check(majorRolls is { MajorWoundHtRoll: 18, ConcentrationRoll: null } &&
              DclInjury.ResolveConsequences(
                  10,
                  majorInjury,
                  DclDamageType.Crushing,
                  criticalSuccess: false,
                  DclCanonicalInjuryRandomPlanner.BuildInput(injuryContext, majorRolls)) is
              {
                  ApplyStun: true,
                  ApplyKnockedDown: true,
                  Concentration: { Outcome: DclConcentrationOutcome.DirectCancellation, Rolled: false },
              },
            "a failed surviving Major-Wound roll must collapse posture and cancel concentration without consuming a second roll");
        DclInjuryResult displacedInjury = DclInjury.Resolve(
            rawRolledDamage: 1,
            DclDamageType.Crushing,
            applicableDr: 0,
            armorDivisor: DclRational.FromInteger(1));
        DclCanonicalInjuryConsequenceRolls concentrationRolls = DclCanonicalInjuryRandomPlanner.PlanRolls(
            injuryRandomBattle,
            actionInstanceId: 2,
            injurySource,
            injuryTarget,
            strikeIndex: 0,
            hpBeforeInjury: 10,
            displacedInjury,
            DclDamageType.Crushing,
            criticalSuccess: false,
            injuryContext,
            directConcentrationCancellation: false,
            authoredForcedDisplacement: 1);
        DclCanonicalInjuryConsequenceRolls repeatedConcentrationRolls = DclCanonicalInjuryRandomPlanner.PlanRolls(
            injuryRandomBattle,
            2,
            injurySource,
            injuryTarget,
            0,
            10,
            displacedInjury,
            DclDamageType.Crushing,
            false,
            injuryContext,
            false,
            1);
        Check(concentrationRolls is { MajorWoundHtRoll: null, ConcentrationRoll: 3 } &&
              repeatedConcentrationRolls == concentrationRolls && injuryRandomSource.DrawCount == 6 &&
              injuryRandomBattle.ExecutionRandom.Count == 2,
            "a non-cancelling charging incident must roll concentration exactly once and reuse it on execution re-entry");
        var battleRuntime = new DclCanonicalBattleRuntime(runtime, battleGeneration: 16, initialGlobalCt: 100);
        var battleUnit = new DclUnitKey(16, 10, 60);
        battleRuntime.ObserveUnit(battleUnit);
        DclTurnResources battleTurn = battleRuntime.TurnResources(battleUnit);
        DclWeaponActionState battleWeapon = battleRuntime.WeaponState(
            battleUnit,
            "main-hand",
            DclWeaponBalance.Unbalanced,
            DclWeaponReadinessProperty.AlwaysReady);
        battleTurn.RemoveAction();
        battleTurn.RemoveMovement();
        battleWeapon.CommitAttack();
        long battleTurnSerial = battleRuntime.BeginTurn(battleUnit);
        Check(battleRuntime.NextActionInstanceId() == 1 && battleRuntime.NextActionInstanceId() == 2 &&
              battleTurnSerial == 1 && battleTurn.ActionAvailable && battleTurn.MovementAvailable &&
              battleWeapon.CanParry,
            "one canonical battle runtime must own generation-local ActionInstance identity, turn resources, and weapon balance reset");
        var battleTargetUnit = new DclUnitKey(16, 11, 62);
        battleRuntime.ObserveUnit(battleTargetUnit);
        DclRollIdentity battleRollIdentity = battleRuntime.RollIdentity(
            actionInstanceId: 2,
            battleUnit,
            battleTargetUnit,
            strikeIndex: 3,
            DclRollSite.Resistance,
            drawIndex: 1);
        Check(battleRollIdentity == new DclRollIdentity(16, 2, 10, 60, 11, 62, 3, DclRollSite.Resistance, 1),
            "the battle owner must construct random identities only from its currently observed stable UnitKeys");
        CheckThrows<InvalidOperationException>(
            () => battleRuntime.RollIdentity(2, battleUnit, new DclUnitKey(16, 12, 63), 0, DclRollSite.Attack, 0),
            "an unobserved target cannot fabricate a confirmed-execution random identity");
        CheckThrows<InvalidOperationException>(
            () => battleRuntime.WeaponState(
                battleUnit,
                "main-hand",
                DclWeaponBalance.Balanced,
                DclWeaponReadinessProperty.AlwaysReady),
            "a live weapon resource identity cannot silently change normalized balance metadata");
        DclStateDefinition battleAimDefinition = BuildDclStateDefinition(
            "aim", DclStateStackPolicy.Replace, DclStateDurationClock.UsesOrTriggers);
        DclStateApplicationResult battleAim = battleRuntime.States.Apply(new DclStateApplication(
            battleAimDefinition,
            battleUnit,
            Source: null,
            AppliedAtGlobalCt: battleRuntime.CurrentGlobalCt,
            AppliedBeforeTurnSerial: battleTurnSerial,
            FirstEligibleTargetTurnSerial: null,
            FirstEligibleSourceTurnSerial: null,
            DurationUnits: 1,
            Strength: null,
            WinningMargin: null,
            StackDiscriminator: "",
            ContributionIdentity: null,
            new DclAimStatePayload(battleAimDefinition.PayloadSchema, battleTargetUnit, 1),
            battleAimDefinition.PresentationProfile));
        var replacementBattleTarget = battleTargetUnit with { CharacterId = battleTargetUnit.CharacterId + 1 };
        Check(battleRuntime.ObserveUnit(replacementBattleTarget).Contains(battleAim.Instance.InstanceId) &&
              !battleRuntime.States.TryGet(battleAim.Instance.InstanceId, out _),
            "native slot replacement must cancel Aim instances that track the lost stable UnitKey, even when the Aim owner remains valid");
        var replacementBattleUnit = battleUnit with { CharacterId = 61 };
        battleRuntime.ObserveUnit(replacementBattleUnit);
        CheckThrows<InvalidOperationException>(
            () => battleRuntime.TurnResources(battleUnit),
            "a native unit-slot identity replacement must invalidate every mutable resource owned by the previous UnitKey");
        Check(!ReferenceEquals(battleTurn, battleRuntime.TurnResources(replacementBattleUnit)),
            "a replacement UnitKey must receive fresh turn resources rather than inherit the previous slot occupant's state");
        var nativeTargetRaw = new byte[0x200];
        nativeTargetRaw[0x4F] = 7;
        nativeTargetRaw[0x50] = 8;
        nativeTargetRaw[0x51] = 0x82;
        nativeTargetRaw[0x61] = 0x10;
        nativeTargetRaw[0x38] = 9;
        nativeTargetRaw[0x39] = 11;
        nativeTargetRaw[0x3A] = 12;
        var nativeTargetSnapshot = new UnitSnapshot(
            Ptr: (nint)0x1234,
            CharId: 61,
            Level: 1,
            Hp: 0,
            MaxHp: 20,
            Team: 1,
            IsFoe: true,
            Pa: 10,
            Ma: 10,
            Speed: 10,
            Move: 4,
            Jump: 3,
            Brave: 50,
            Faith: 50,
            Raw: nativeTargetRaw);
        DclTargetCandidate projectedNativeTarget = DclCanonicalNativeSnapshotAdapter.ProjectTarget(
            nativeTargetSnapshot,
            battleGeneration: 16,
            unitSlot: 10,
