            sourceTeam: 0,
            tileHeight: 6,
            combatStateRevision: 4,
            new DclDefenseResourceSnapshot(new Dictionary<string, int> { ["main-hand"] = 2 }, BlockAvailable: false));
        Check(projectedNativeTarget is
              {
                  Tile: { X: 7, Y: 8, Layer: 1 },
                  Height: 6,
                  Relation: DclAllegianceRelation.Enemy,
                  States: DclEligibleTargetStates.Ko | DclEligibleTargetStates.Undead,
                  CurrentHp: 0,
                  CombatStateRevision: 4,
              } && projectedNativeTarget.DefenseResources.ParryAttemptCounts["main-hand"] == 2,
            "the native snapshot adapter must project proven coordinates/layer, allegiance, KO+Undead state, revision, and finite defenses without inventing job data");
        nativeTargetRaw[0x61] = 0;
        nativeTargetRaw[0x1EF] = 0x10;
        DclTargetCandidate masterOnlyNativeTarget = DclCanonicalNativeSnapshotAdapter.ProjectTarget(
            nativeTargetSnapshot,
            battleGeneration: 16,
            unitSlot: 10,
            source: new DclUnitKey(16, 1, 10),
            sourceTeam: 0,
            tileHeight: 6,
            combatStateRevision: 4,
            new DclDefenseResourceSnapshot(new Dictionary<string, int>(), BlockAvailable: false));
        Check(masterOnlyNativeTarget.States == DclEligibleTargetStates.Ko,
