        DclPrimaryCharacteristics projectedNativePrimary = DclCanonicalNativeSnapshotAdapter.ProjectPrimary(
            nativeTargetSnapshot,
            new DclCanonicalAttributeAdjustments(JobSt: 1, JobDx: 2, JobIq: 3));
        Check(projectedNativePrimary == new DclPrimaryCharacteristics(St: 10, Dx: 14, Iq: 14, Ht: 10),
