        var synchronizedRaw = new byte[0x200];
        synchronizedRaw[0x38] = 10;
        synchronizedRaw[0x39] = 10;
        synchronizedRaw[0x3A] = 10;
        synchronizedRaw[0x4F] = 2;
        synchronizedRaw[0x50] = 3;
        synchronizedRaw[0x51] = 1;
        var synchronizedKey = new DclUnitKey(16, 12, 70);
        var synchronizedNative = new UnitSnapshot(
            Ptr: (nint)0x5678,
