            "one synchronized native projection must expose canonical characteristics, pools, identity, target state, MP, and Faith without draft-job inference");
        var snapshotBatchBattle = new DclCanonicalBattleRuntime(runtime, battleGeneration: 16);
        snapshotBatchBattle.ObserveUnit(synchronizedKey);
        var synchronizedBatchRequest = new DclCanonicalNativeUnitSnapshotRequest(
            UnitSlot: synchronizedKey.UnitSlot,
            synchronizedNative,
            new DclCanonicalAttributeAdjustments(),
            new DclSecondaryInputs(),
            TileHeight: 4);
        DclCanonicalNativeSnapshotBatch synchronizedBatch =
            DclCanonicalNativeSnapshotBatchProjector.Project(
                snapshotBatchBattle,
                synchronizedKey,
                [synchronizedBatchRequest]);
        DclCanonicalNativeUnitSnapshotResult synchronizedBatchUnit =
            synchronizedBatch.Units[synchronizedKey];
        Check(synchronizedBatch.Source == synchronizedKey && synchronizedBatch.Units.Count == 1 &&
              synchronizedBatchUnit.Unit.Primary == synchronizedProjection.Primary &&
              synchronizedBatchUnit.Unit.Secondary == synchronizedProjection.Secondary &&
