            "snapshot batching must reject duplicate unit slots before projection");

        var admittedTargetA = new DclUnitKey(16, 13, 72);
        var admittedTargetB = new DclUnitKey(16, 14, 73);
        snapshotBatchBattle.ObserveUnit(admittedTargetA);
        snapshotBatchBattle.ObserveUnit(admittedTargetB);
        DclCanonicalNativeOuterSweepAdmission singleAdmission = snapshotBatchBattle.NativeAdmissions.Admit(
            snapshotBatchBattle,
            new DclCanonicalNativeOuterSweepRequest(
                SweepSerial: 1,
                synchronizedKey,
                ActionType: 0x0B,
                AbilityId: statusBinding.AbilityId,
                BattleState: DclCalcProvenance.ConfirmedExecutionBattleState,
                NativeRepeatCount: 1,
                NativeRepeatIndex: 0,
                Targets: [admittedTargetA, admittedTargetB],
                SelectedTile: new DclBattleTile(3, 3, 0)));
        Check(singleAdmission is
              {
                  ActionInstanceId: 1,
                  StrikeIndex: 0,
                  StartsAction: true,
                  CompletesNativeSweepSequence: true,
              } && singleAdmission.Targets.SequenceEqual([admittedTargetA, admittedTargetB]),
            "one proven nonrepeat outer sweep must reserve exactly one canonical ActionInstance for its complete target batch");

        var admissionDuplicateSuppressor = new DclCanonicalAdmissionDuplicateSuppressor();
        Check(!admissionDuplicateSuppressor.ShouldSuppress("fire:one-target", nowTick: 10_000, duplicateWindowTicks: 250) &&
              admissionDuplicateSuppressor.ShouldSuppress("fire:one-target", nowTick: 10_125, duplicateWindowTicks: 250) &&
              !admissionDuplicateSuppressor.ShouldSuppress("fire:one-target", nowTick: 10_251, duplicateWindowTicks: 250),
            "canonical admission duplicate suppression must skip only identical same-loop keys inside the short duplicate window");
        admissionDuplicateSuppressor.Clear();
        Check(!admissionDuplicateSuppressor.ShouldSuppress("fire:one-target", nowTick: 10_126, duplicateWindowTicks: 250) &&
              !admissionDuplicateSuppressor.ShouldSuppress("fire:other-target", nowTick: 10_127, duplicateWindowTicks: 250),
            "canonical admission duplicate suppression must reset on battle boundaries and never suppress distinct keys");

        DclCanonicalNativeOuterSweepAdmission[] repeatedAdmissions = Enumerable.Range(0, physicalAction.TransactionProfile.StrikeCount)
            .Select(index => snapshotBatchBattle.NativeAdmissions.Admit(
                snapshotBatchBattle,
                new DclCanonicalNativeOuterSweepRequest(
                    SweepSerial: index + 2,
                    synchronizedKey,
                    ActionType: 1,
                    AbilityId: physicalBinding.AbilityId,
                    BattleState: index == 0
                        ? DclCalcProvenance.ConfirmedExecutionBattleState
                        : DclCalcProvenance.NativeRepeatExecutionBattleState,
                    NativeRepeatCount: physicalAction.TransactionProfile.StrikeCount,
                    NativeRepeatIndex: index,
                    Targets: [admittedTargetA],
                    SelectedTile: new DclBattleTile(3, 3, 0),
                    ActiveWeaponItemId: 19,
                    ActiveWeaponHand: DclNativeWeaponHand.Primary)))
            .ToArray();
        Check(repeatedAdmissions.Select(admission => admission.ActionInstanceId).Distinct().Single() == 2 &&
              repeatedAdmissions.Select(admission => admission.StrikeIndex)
                  .SequenceEqual(Enumerable.Range(0, physicalAction.TransactionProfile.StrikeCount)) &&
              repeatedAdmissions[0].StartsAction &&
              repeatedAdmissions.Skip(1).All(admission => !admission.StartsAction) &&
              repeatedAdmissions[^1].CompletesNativeSweepSequence &&
              !snapshotBatchBattle.NativeAdmissions.HasActiveRepeat,
            "state-0x2A plus ordered state-0x2F native repeats must retain one outer ActionInstance and expose exact Strike indexes");

        var capturedAdmissionBattle = new DclCanonicalBattleRuntime(runtime, battleGeneration: 16);
        capturedAdmissionBattle.ObserveUnit(synchronizedKey);
        capturedAdmissionBattle.ObserveUnit(admittedTargetA);
        var outerCapture = new DclCanonicalNativeOuterActionCapture();
        UnitSnapshot capturedSourceNative = synchronizedNative with
        {
            Raw = (byte[])synchronizedNative.Raw.Clone(),
        };
        UnitSnapshot capturedTargetNative = synchronizedNative with
        {
            Ptr = (nint)0x6789,
            CharId = admittedTargetA.CharacterId,
            Team = 1,
            IsFoe = true,
            Raw = (byte[])synchronizedNative.Raw.Clone(),
        };
        DclCanonicalNativeAdmittedAction? capturedAction = null;
        for (int index = 0; index < physicalAction.TransactionProfile.StrikeCount; index++)
        {
            capturedAction = outerCapture.Capture(
                capturedAdmissionBattle,
                new DclCanonicalNativeOuterSweepRequest(
                    SweepSerial: index + 1,
                    synchronizedKey,
                    ActionType: 1,
                    AbilityId: physicalBinding.AbilityId,
                    BattleState: index == 0
                        ? DclCalcProvenance.ConfirmedExecutionBattleState
                        : DclCalcProvenance.NativeRepeatExecutionBattleState,
                    NativeRepeatCount: physicalAction.TransactionProfile.StrikeCount,
                    NativeRepeatIndex: index,
                    Targets: [admittedTargetA],
                    SelectedTile: new DclBattleTile(3, 3, 0),
                    ActiveWeaponItemId: 19,
                    ActiveWeaponHand: DclNativeWeaponHand.Primary),
                new Dictionary<DclUnitKey, UnitSnapshot>
                {
                    [synchronizedKey] = capturedSourceNative,
                    [admittedTargetA] = capturedTargetNative with { Hp = 8 - index },
                });
            if (index == 0)
                capturedSourceNative.Raw[0x38] = 99;
            if (index < physicalAction.TransactionProfile.StrikeCount - 1)
                Check(capturedAction is null && outerCapture.HasPendingAction,
                    "native outer capture must withhold an incomplete NativeRepeat sequence from request composition");
        }
        Check(capturedAction is
              {
                  ActionInstanceId: 1,
                  Source: var capturedSource,
                  AbilityId: var capturedAbility,
              } && capturedSource == synchronizedKey && capturedAbility == physicalBinding.AbilityId &&
              capturedAction.Admissions.Select(admission => admission.StrikeIndex)
                  .SequenceEqual(Enumerable.Range(0, physicalAction.TransactionProfile.StrikeCount)) &&
              capturedAction.Targets.SequenceEqual([admittedTargetA]) &&
              capturedAction.NativeRows[admittedTargetA].Hp == 8 &&
              capturedAction.NativeRows[synchronizedKey].Raw[0x38] == 10 &&
              !outerCapture.HasPendingAction,
            "the pre-calculation capture boundary must publish one complete Strike-major action with the deeply frozen index-zero native batch");
        DclCanonicalNativeSnapshotBatch capturedBatch =
            DclCanonicalNativeSnapshotBatchProjector.ProjectCaptured(
                capturedAdmissionBattle,
                capturedAction!,
                [
                    new DclCanonicalNativeUnitPolicyInput(
