                        new DclCanonicalAttributeAdjustments(),
                        new DclSecondaryInputs(),
                        TileHeight: 4),
                    new DclCanonicalNativeUnitPolicyInput(
                        admittedTargetA,
                        new DclCanonicalAttributeAdjustments(),
                        new DclSecondaryInputs(),
                        TileHeight: 5),
                ]);
        Check(capturedBatch.Units[synchronizedKey].Unit.Primary.St == 10 &&
              capturedBatch.Units[admittedTargetA].Unit.Target.CurrentHp == 8 &&
              capturedBatch.Units[admittedTargetA].Unit.Target.Height == 5,
            "explicit unit policy inputs must project only the frozen first-sweep rows, never post-Strike live pools");
        CheckThrows<ArgumentException>(
