                        new DclCanonicalAttributeAdjustments(),
                        new DclSecondaryInputs(),
                        TileHeight: 4),
                ]),
            "captured snapshot projection must fail when any target lacks explicit characteristic and tile policy");
        var lateObservationBattle = new DclCanonicalBattleRuntime(runtime, battleGeneration: 16);
        DclUnitKey lateObserved = Mod.ObserveDclCanonicalAdmissionUnit(
