        CheckThrows<InvalidOperationException>(
            () => Mod.ObserveDclCanonicalAdmissionUnit(
                lateObservationBattle,
                synchronizedKey.UnitSlot,
                synchronizedNative with { CharId = synchronizedKey.CharacterId + 1 }),
            "the admission boundary must reject a live character replacement in an already-owned slot");

        var divergentAdmissionBattle = new DclCanonicalBattleRuntime(runtime, battleGeneration: 16);
        divergentAdmissionBattle.ObserveUnit(synchronizedKey);
        divergentAdmissionBattle.ObserveUnit(admittedTargetA);
        divergentAdmissionBattle.NativeAdmissions.Admit(
