                synchronizedKey,
                ActionType: 1,
                AbilityId: physicalBinding.AbilityId,
                BattleState: DclCalcProvenance.ConfirmedExecutionBattleState,
                NativeRepeatCount: physicalAction.TransactionProfile.StrikeCount,
