            "native repeat admission must reject a skipped index before allocating or reusing another ActionInstance");

        var divergentTileBattle = new DclCanonicalBattleRuntime(runtime, battleGeneration: 16);
        divergentTileBattle.ObserveUnit(synchronizedKey);
        divergentTileBattle.ObserveUnit(admittedTargetA);
        divergentTileBattle.NativeAdmissions.Admit(
            divergentTileBattle,
            new DclCanonicalNativeOuterSweepRequest(
                SweepSerial: 1,
                synchronizedKey,
                ActionType: 1,
                AbilityId: physicalBinding.AbilityId,
                BattleState: DclCalcProvenance.ConfirmedExecutionBattleState,
                NativeRepeatCount: physicalAction.TransactionProfile.StrikeCount,
                NativeRepeatIndex: 0,
                Targets: [admittedTargetA],
                SelectedTile: new DclBattleTile(3, 3, 0),
                ActiveWeaponItemId: 19,
                ActiveWeaponHand: DclNativeWeaponHand.Primary));
        CheckThrows<InvalidOperationException>(
            () => divergentTileBattle.NativeAdmissions.Admit(
                divergentTileBattle,
                new DclCanonicalNativeOuterSweepRequest(
                    SweepSerial: 2,
                    synchronizedKey,
                    ActionType: 1,
                    AbilityId: physicalBinding.AbilityId,
                    BattleState: DclCalcProvenance.NativeRepeatExecutionBattleState,
                    NativeRepeatCount: physicalAction.TransactionProfile.StrikeCount,
                    NativeRepeatIndex: 1,
                    Targets: [admittedTargetA],
