        byte[] directTargetRaw = (byte[])synchronizedRaw.Clone();
        directTargetRaw[0x4F] = 3;
        directTargetRaw[0x50] = 3;
        var directTargetKey = new DclUnitKey(16, 13, 72);
        UnitSnapshot directTargetNative = synchronizedNative with
        {
            Ptr = (nint)0x5680,
            CharId = directTargetKey.CharacterId,
            Team = 1,
            IsFoe = true,
            Hp = 10,
            Faith = 50,
            Raw = directTargetRaw,
        };
        var directCompositionRandom = new SequenceRandomSource([3, 3, 4, 3, 3, 4, 2, 3, 4, 4, 4]);
        var directCompositionBattle = new DclCanonicalBattleRuntime(
            runtime,
            battleGeneration: 16,
            executionRandomSource: directCompositionRandom);
        directCompositionBattle.ObserveUnit(synchronizedKey);
        directCompositionBattle.ObserveUnit(directTargetKey);
        DclCanonicalNativeSnapshotBatch directCompositionBatch =
            DclCanonicalNativeSnapshotBatchProjector.Project(
                directCompositionBattle,
                synchronizedKey,
