                new DclCanonicalNativeOuterSweepRequest(
                    SweepSerial: 1,
                    synchronizedKey,
                    ActionType: 0x0B,
                    AbilityId: binding.AbilityId,
                    BattleState: DclCalcProvenance.ConfirmedExecutionBattleState,
                    NativeRepeatCount: 1,
