        DclCanonicalNativeOuterSweepAdmission directCompositionAdmission =
            directCapturedAction.Admissions.Single();
        var directCompositionMovementBranches = new DclCanonicalInjuryMovementBranchSet(
            DclForcedMovementDirection.AwayFromSource,
            new Dictionary<int, DclCanonicalNativeMovementVerdict>
            {
                [1] = new(
                    directTargetKey,
                    new DclBattleTile(3, 3, 0),
                    new DclBattleTile(4, 3, 0),
                    RequestedTiles: 1,
                    MovedTiles: 1,
                    DclForcedMovementDirection.AwayFromSource,
                    Fell: false,
                    NativePathResolved: true),
            });
        var directPolicySource = new DclCanonicalNativeDirectActionPolicySource(
            new DclCanonicalNativeSingleTargetMagicPolicySource(
                Tradition: "sentinel-magic",
                TraditionSkill: 12,
                DclZodiacCompatibility.Neutral,
                TargetRelativePenaltyMagnitude: 0,
                Learned: true,
                SourceUsable: true,
                PrerequisitesMet: true,
                OvercastConfirmed: true),
            new DclDefenseOption(DclDefenseKind.Dodge, 9, Depletes: false),
            InjuryMovementBranches: directCompositionMovementBranches);
        DclCanonicalNativeDirectActionInputs composedDirectPolicy =
            DclCanonicalNativeDirectActionPolicyProvider.BuildForCapturedUnitAction(
                directCapturedAction,
                directPolicySource);
        Check(composedDirectPolicy.DeclaredTarget == directTargetKey &&
              composedDirectPolicy.Tradition == "sentinel-magic" &&
              composedDirectPolicy.TraditionSkill == 12 &&
              composedDirectPolicy.Defense == new DclDefenseOption(DclDefenseKind.Dodge, 9, Depletes: false) &&
              ReferenceEquals(composedDirectPolicy.InjuryMovementBranches, directCompositionMovementBranches),
            "native Direct policy provider must materialize the exact declared unit, casting policy, defense, and explicit movement branches without row inference");
        string policyTemplateJson = DclCanonicalNativePolicyTicketTemplateJsonLoader.Serialize(
            new DclCanonicalNativePolicyTicketTemplateBundle(
                DclCanonicalNativePolicyTicketTemplateJsonLoader.CurrentSchemaRevision,
                [
                    new DclCanonicalNativePolicyTicketTemplate(
                        binding.AbilityId,
                        new DclCanonicalNativeUnitPolicyTemplate(SourceTileHeight: 4, TargetTileHeight: 4),
                        new DclCanonicalNativeFamilyPolicyTicketTemplate(
                            DclCanonicalActionFamily.DirectNumeric,
                            new DclCanonicalNativeDirectActionPolicyTemplate(
                                directPolicySource.Magic,
                                directPolicySource.Defense,
                                ResistanceScore: directPolicySource.ResistanceScore,
                                Immune: directPolicySource.Immune))),
