            throw new InvalidOperationException("Dual Wield dispatch did not publish its native application.");
        int ExpectedWeaponDamage(int itemId) {
            DclWeaponMetadata weapon = runtime.Items.Items[itemId].Weapon!;
            DclDiceExpression expression = DclCanonicalMagnitude.BuildDiceExpression(
                dualRequest.SourceSt,
                weapon.DamageBasis,
                weapon.FixedDamageExpression,
                weapon.DamageModifier + ((DclDamageMagnitude)dualPhysicalAction.MagnitudeProfile!).IntegerModifier,
                weapon.WholeDiceModifier + ((DclDamageMagnitude)dualPhysicalAction.MagnitudeProfile!).WholeDiceModifier);
            return DclInjury.RollDamage(expression, Enumerable.Repeat(1, expression.Dice).ToArray());
        }
        Check(dualResult.Strikes.Select(strike => strike.Injury?.RolledDamage)
                  .SequenceEqual([ExpectedWeaponDamage(19), ExpectedWeaponDamage(20)]) &&
              rightState.Ready && !leftState.Ready &&
              dualRandom.DrawCount == 8 &&
              dualApplication.Plan.Strikes.Count == 2,
            "Dual Wield execution must use each hand's damage expression and commit each hand's independent readiness once under one outer ActionInstance");
        DclCanonicalPhysicalPlanningResult dualUnreadyPlanning =
            DclCanonicalPhysicalPlanningCoordinator.Evaluate(
                dualBattle,
                synchronizedKey,
                "right-weapon",
                dualEvaluationInput,
                isUniversalNormalAttack: true,
                selectedTarget: directTargetKey);
        Check(dualUnreadyPlanning is
              {
                  StatePlan: { Legal: false, Reason: "weapon-unready:left-weapon" },
                  Evaluation: null,
                  PlayerForecast.Count: 0,
                  AiProjection.Count: 0,
