                    new DclCanonicalNativeUnitPolicyInput(
                        synchronizedKey,
                        new DclCanonicalAttributeAdjustments(),
                        new DclSecondaryInputs(),
                        TileHeight: 4),
                    new DclCanonicalNativeUnitPolicyInput(
                        directTargetKey,
                        new DclCanonicalAttributeAdjustments(),
                        new DclSecondaryInputs(CharacterHpModifier: 90),
