                    PassedRangeCheck: true,
                    PassedVerticalCheck: true,
                    Targets: [new DclCanonicalNativePhysicalTargetInputs(directTargetKey)],
                    Strikes:
                    [
                        new DclCanonicalNativePhysicalStrikeInputs(directTargetKey, 0, 18, []),
                        new DclCanonicalNativePhysicalStrikeInputs(directTargetKey, 1, 14, []),
