        byte[] promotedLeftRaw = (byte[])dualSourceRaw.Clone();
        promotedLeftRaw[0x20] = 0;
        promotedLeftRaw[0x21] = 0;
        DclCanonicalEquipmentSnapshot promotedLeftEquipment = DclCanonicalEquipmentProjector.Project(
