        byte[] unarmedRaw = (byte[])promotedLeftRaw.Clone();
        unarmedRaw[0x24] = 0;
        unarmedRaw[0x25] = 0;
        DclCanonicalEquipmentSnapshot unarmedEquipment = DclCanonicalEquipmentProjector.Project(
            dualSourceNative with { Raw = unarmedRaw },
            runtime.Items);
        DclCanonicalPhysicalStrikeWeapon[] unarmedStrikeWeapons =
        [
            new DclCanonicalPhysicalStrikeWeapon(
                0,
