                    [directTargetKey] = dualTargetNative,
                }) ?? throw new InvalidOperationException("single-hand native Attack did not complete at its first sweep");
        DclCanonicalNativeComposedExecution singleAttackComposed =
            DclCanonicalNativeConfirmedRequestComposer.ComposeCaptured(
