                ]));
        DclCanonicalNativePolicyTicketTemplateRegistry areaPolicyTemplateRegistry =
            DclCanonicalNativePolicyTicketTemplateJsonLoader.Load(areaPolicyTemplateJson);
        var areaTemplateBattle = new DclCanonicalBattleRuntime(
            runtime,
            battleGeneration: 16,
            executionRandomSource: new SequenceRandomSource([]));
        areaTemplateBattle.ObserveUnit(synchronizedKey);
        areaTemplateBattle.ObserveUnit(directTargetKey);
        var areaTemplateCapture = new DclCanonicalNativeOuterActionCapture();
        DclCanonicalNativeAdmittedAction? areaTemplateAction = null;
        for (int index = 0; index < areaAction.TransactionProfile.StrikeCount; index++)
        {
            areaTemplateAction = areaTemplateCapture.Capture(
                areaTemplateBattle,
                new DclCanonicalNativeOuterSweepRequest(
                    SweepSerial: index + 1,
                    synchronizedKey,
                    ActionType: 0x0B,
                    AbilityId: areaBinding.AbilityId,
                    BattleState: index == 0
                        ? DclCalcProvenance.ConfirmedExecutionBattleState
                        : DclCalcProvenance.NativeRepeatExecutionBattleState,
                    NativeRepeatCount: areaAction.TransactionProfile.StrikeCount,
                    NativeRepeatIndex: index,
                    Targets: [directTargetKey],
                    SelectedUnit: directTargetKey,
                    SelectedTile: new DclBattleTile(3, 3, 0)),
                new Dictionary<DclUnitKey, UnitSnapshot>
                {
                    [synchronizedKey] = synchronizedNative,
                    [directTargetKey] = directTargetNative,
                });
        }
        Check(areaTemplateAction is not null &&
              areaTemplateAction.Admissions.Count == areaAction.TransactionProfile.StrikeCount,
