        areaTemplateBattle.NativeAdmittedActions.Publish(areaTemplateBattle, areaTemplateAction!);
        DclCanonicalNativePolicyTicketTemplateBuildResult areaTemplateTicket =
            areaPolicyTemplateRegistry.TryBuildTicket(areaTemplateBattle, areaTemplateAction!);
        DclCanonicalNativePolicyTicketPublishResult areaTemplatePublish =
            areaTemplateBattle.NativePolicySources.TryPublishForRetainedAdmission(
                areaTemplateBattle,
                areaTemplateTicket.Ticket!);
        Check(areaTemplateTicket.Status == DclCanonicalNativePolicyTicketTemplateBuildStatus.Built &&
              areaTemplateTicket.Ticket?.FamilyPolicySource is DclCanonicalNativeAreaActionPolicySource
              {
                  Targets.Count: 1,
                  TraditionSkill: 12,
              } &&
              areaTemplatePublish.Status == DclCanonicalNativePolicyTicketPublishStatus.Published &&
              areaTemplateBattle.NativePolicySources.Count == 1 &&
