                    Tradition: "sentinel-magic",
                    TraditionSkill: 12,
                    Learned: true,
                    SourceUsable: true,
                    PrerequisitesMet: true,
                    OvercastConfirmed: true,
                    ExplicitCasterStatePenaltyMagnitude: 0,
