                new DclCanonicalNativeAreaActionPolicySource(
                    "sentinel-magic",
                    12,
                    true,
                    true,
                    true,
                    true,
                    0,
                    Targets: [])),
            "native Area policy provider must reject unit-target Area admissions that lack the selected unit");

        var statusCompositionRandom = new SequenceRandomSource([3, 3, 4, 3, 4, 4]);
        var statusCompositionBattle = new DclCanonicalBattleRuntime(
            runtime,
            battleGeneration: 16,
            executionRandomSource: statusCompositionRandom);
        statusCompositionBattle.ObserveUnit(synchronizedKey);
        statusCompositionBattle.ObserveUnit(directTargetKey);
        DclCanonicalNativeSnapshotBatch statusCompositionBatch =
            DclCanonicalNativeSnapshotBatchProjector.Project(
                statusCompositionBattle,
                synchronizedKey,
                [
                    synchronizedBatchRequest,
                    new DclCanonicalNativeUnitSnapshotRequest(
                        directTargetKey.UnitSlot,
                        directTargetNative,
                        new DclCanonicalAttributeAdjustments(),
                        new DclSecondaryInputs(),
                        TileHeight: 4),
