            () => DclCanonicalNativeExecutionPublisher.PublishMagic(battleRuntime, 16, caster, hit),
            "one canonical ActionInstance cannot be published twice by native re-entry");
        DclCanonicalNativeStrikeProjection appliedHit = hitApplication.ApplyNextStrike(targetKey, 0);
        Check(DclCanonicalNativeApplyRouter.TryPreparePayment(
                  battleRuntime,
                  hitProjection.ActionInstanceId,
                  out DclCanonicalNativePaymentReservation hitPaymentReservation),
            "native application must expose its distinct source payment after target apply");
        DclCanonicalNativePaymentApplyPlan hitPaymentPlan = DclCanonicalNativeApplyRouter.PlanPayment(
            battleRuntime,
            hitPaymentReservation,
            caster,
            new DclCanonicalNativePoolSnapshot(currentHp: 20, maxHp: 30, currentMp: 8, maxMp: 20));
        int writtenPayerHp = 20;
        int writtenPayerMp = 8;
        var payerWriteOrder = new List<string>();
        DclCanonicalNativePaymentWriter.Apply(
            hitPaymentPlan,
            () => new DclCanonicalNativePoolSnapshot(writtenPayerHp, 30, writtenPayerMp, 20),
            value =>
            {
                payerWriteOrder.Add("mp");
                writtenPayerMp = value;
            },
            value =>
            {
                payerWriteOrder.Add("hp");
                writtenPayerHp = value;
            });
        Check(writtenPayerMp == 0 && writtenPayerHp == 18 && payerWriteOrder.SequenceEqual(["mp", "hp"]),
            "native source-payment writer must validate and confirm the exact snapshot while writing MP before HP");
        int rollbackPayerHp = 20;
        int rollbackPayerMp = 8;
        var rollbackWriteOrder = new List<string>();
        CheckThrows<InvalidOperationException>(
            () => DclCanonicalNativePaymentWriter.Apply(
                hitPaymentPlan,
                () => new DclCanonicalNativePoolSnapshot(rollbackPayerHp, 30, rollbackPayerMp, 20),
                value =>
                {
                    rollbackWriteOrder.Add("mp");
                    rollbackPayerMp = value;
                },
                _ =>
                {
                    rollbackWriteOrder.Add("hp");
                    throw new InvalidOperationException("synthetic HP write failure");
                }),
            "native source-payment writer must surface a failed HP write");
        Check(rollbackPayerHp == 20 && rollbackPayerMp == 8 &&
              rollbackWriteOrder.SequenceEqual(["mp", "hp", "mp"]),
            "failed native source payment must roll its earlier MP write back to the exact before snapshot");
        DclCanonicalNativePaymentApplyPlan zeroMpNoPayment = DclCanonicalNativePaymentApplyPlanner.Build(
            caster,
            new DclCanonicalNativePoolSnapshot(currentHp: 5, maxHp: 5, currentMp: 0, maxMp: 0),
            payment: null);
        int zeroMpWrites = 0;
        DclCanonicalNativePaymentWriter.Apply(
            zeroMpNoPayment,
            () => new DclCanonicalNativePoolSnapshot(5, 5, 0, 0),
            _ => zeroMpWrites++,
            _ => zeroMpWrites++);
        Check(zeroMpWrites == 0,
            "a zero-MaxMP unit with no source payment must remain a valid no-op native payer snapshot");
        Check(hitPaymentPlan is
              {
                  MpDebit: 8,
                  HpDebit: 2,
                  ApplyMpFirst: true,
                  PayerKo: false,
                  After: { CurrentHp: 18, CurrentMp: 0 },
              } &&
              hitApplication.ReadAppliedForPresentation(targetKey, 0) == appliedHit &&
              DclCanonicalNativeApplyRouter.CommitPayment(hitPaymentReservation, hitPaymentPlan) is
              {
                  Payer: var hitPayer,
                  Channels: { HpDebit: 2, MpDebit: 8 },
              } && hitPayer == caster,
            "native application must expose presentation after target apply and atomically plan MP-first then HP source payment");
        DclCanonicalNativeApplyRouter.AcknowledgeReactionWindow(hitPaymentReservation);
        DclCanonicalNativeApplyRouter.SettleAndRetire(battleRuntime, hitPaymentReservation);
        Check(hitApplication.Stage == DclCanonicalNativeActionStage.Settled && battleRuntime.NativeActions.Count == 0,
            "one canonical native action must retire only after its single Reaction and settlement boundaries");
        CheckThrows<InvalidOperationException>(
            () => DclCanonicalNativeExecutionPublisher.PublishMagic(battleRuntime, 16, caster, hit),
            "a retired canonical ActionInstance must remain tombstoned and cannot be republished by late native replay");
        var paymentCleanupRegistry = new DclStateRegistry(16, initialGlobalCt: 0);
        DclStateDefinition payerTargetCleanup = BuildDclStateDefinition(
            "payer-target-cleanup",
            DclStateStackPolicy.Refresh,
            DclStateDurationClock.GlobalCt,
            removeOnTargetKo: true);
        DclStateDefinition payerSourceCleanup = BuildDclStateDefinition(
            "payer-source-cleanup",
            DclStateStackPolicy.Refresh,
            DclStateDurationClock.GlobalCt,
            sourceRequired: true,
            removeOnSourceKo: true);
        DclStateApplication PaymentCleanupApplication(
            DclStateDefinition definition,
            DclUnitKey stateTarget,
            DclUnitKey? stateSource)
            => new(
                definition,
                stateTarget,
                stateSource,
                AppliedAtGlobalCt: 0,
                AppliedBeforeTurnSerial: 0,
                FirstEligibleTargetTurnSerial: null,
                FirstEligibleSourceTurnSerial: null,
                DurationUnits: 5,
                Strength: null,
                WinningMargin: null,
                StackDiscriminator: "",
                ContributionIdentity: null,
                new DclPropertyStatePayload(definition.PayloadSchema, new Dictionary<string, string>()),
                definition.PresentationProfile);
        paymentCleanupRegistry.Apply(PaymentCleanupApplication(payerTargetCleanup, caster, null));
        paymentCleanupRegistry.Apply(PaymentCleanupApplication(payerSourceCleanup, targetKey, caster));
        DclCanonicalNativePaymentApplyPlan lethalPayment =
            DclCanonicalNativePaymentApplyPlanner.Build(
                caster,
                new DclCanonicalNativePoolSnapshot(currentHp: 5, maxHp: 30, currentMp: 3, maxMp: 20),
                new DclCanonicalNativePaymentProjection(
                    caster,
                    new DclCanonicalNativeNumericChannels(hpDebit: 5, hpCredit: 0, mpDebit: 3, mpCredit: 0),
                    PayerKo: true,
                    IsResourcePayment: true,
                    OpensDamageReaction: false),
                paymentCleanupRegistry);
        Check(lethalPayment is
              {
                  ApplyMpFirst: true,
                  PayerKo: true,
                  After: { CurrentHp: 0, CurrentMp: 0 },
                  RemovedOnPayerKo.Count: 2,
              } && DclCanonicalNativePaymentApplyPlanner.CommitPayerKoCleanup(
                  lethalPayment,
                  paymentCleanupRegistry).Count == 2 &&
              paymentCleanupRegistry.Instances.Count == 0,
            "authorized lethal overcast payment must preserve MP-first ordering, exact payer KO, and target/source KO cleanup");
        CheckThrows<ArgumentException>(
            () => DclCanonicalNativePaymentApplyPlanner.Build(
                caster,
                new DclCanonicalNativePoolSnapshot(5, 30, 3, 20),
                new DclCanonicalNativePaymentProjection(
                    caster,
                    new DclCanonicalNativeNumericChannels(hpDebit: 0, hpCredit: 1, mpDebit: 0, mpCredit: 0),
                    PayerKo: false,
                    IsResourcePayment: true,
                    OpensDamageReaction: false)),
            "resource-payment apply must reject a target-style credit channel");

        var managedPaymentBattle = new DclCanonicalBattleRuntime(runtime, battleGeneration: 16);
        managedPaymentBattle.ObserveUnit(caster);
        managedPaymentBattle.ObserveUnit(targetKey);
        managedPaymentBattle.States.Apply(PaymentCleanupApplication(payerTargetCleanup, caster, null));
        managedPaymentBattle.States.Apply(PaymentCleanupApplication(payerSourceCleanup, targetKey, caster));
        DclCanonicalNativeCarrierProjection managedPaymentProjection = hitProjection with
        {
            ActionInstanceId = 502,
            Reactions = hitProjection.Reactions! with { ActionInstanceId = 502 },
            ResourcePayment = new DclCanonicalNativePaymentProjection(
                caster,
                new DclCanonicalNativeNumericChannels(hpDebit: 5, hpCredit: 0, mpDebit: 3, mpCredit: 0),
                PayerKo: true,
                IsResourcePayment: true,
                OpensDamageReaction: false),
        };
        DclCanonicalNativeActionApplication managedPaymentApplication =
            managedPaymentBattle.NativeActions.Publish(caster, binding, managedPaymentProjection);
        managedPaymentApplication.ApplyNextStrike(targetKey, 0);
        Check(DclCanonicalNativeApplyRouter.TryPreparePayment(
                  managedPaymentBattle,
                  managedPaymentProjection.ActionInstanceId,
                  out DclCanonicalNativePaymentReservation managedPaymentReservation),
            "managed lethal payment must expose one source reservation after target apply");
        DclCanonicalNativePaymentApplyPlan managedPaymentPlan = DclCanonicalNativeApplyRouter.PlanPayment(
            managedPaymentBattle,
            managedPaymentReservation,
            caster,
            new DclCanonicalNativePoolSnapshot(currentHp: 5, maxHp: 30, currentMp: 3, maxMp: 20));
        DclCanonicalNativePaymentCommitResult managedPaymentCommit =
            DclCanonicalNativeApplyRouter.CommitPayment(
                managedPaymentBattle,
                managedPaymentReservation,
                managedPaymentPlan);
        Check(managedPaymentCommit is
              {
                  Payment: { PayerKo: true, Channels: { HpDebit: 5, MpDebit: 3 } },
                  RemovedOnPayerKo.Count: 2,
              } && managedPaymentBattle.States.Instances.Count == 0 &&
              managedPaymentApplication.Stage == DclCanonicalNativeActionStage.PaymentCommitted,
            "managed payment commit must advance the action ledger and exact payer KO cleanup together");

        var stalePaymentBattle = new DclCanonicalBattleRuntime(runtime, battleGeneration: 16);
        stalePaymentBattle.ObserveUnit(caster);
        stalePaymentBattle.ObserveUnit(targetKey);
        DclStateApplicationResult staleCleanup =
            stalePaymentBattle.States.Apply(PaymentCleanupApplication(payerTargetCleanup, caster, null));
        DclCanonicalNativeCarrierProjection stalePaymentProjection = managedPaymentProjection with
        {
            ActionInstanceId = 503,
            Reactions = managedPaymentProjection.Reactions! with { ActionInstanceId = 503 },
        };
        DclCanonicalNativeActionApplication stalePaymentApplication =
            stalePaymentBattle.NativeActions.Publish(caster, binding, stalePaymentProjection);
        stalePaymentApplication.ApplyNextStrike(targetKey, 0);
        Check(DclCanonicalNativeApplyRouter.TryPreparePayment(
                  stalePaymentBattle,
                  stalePaymentProjection.ActionInstanceId,
                  out DclCanonicalNativePaymentReservation stalePaymentReservation),
            "stale-payment sentinel must expose its source reservation");
        DclCanonicalNativePaymentApplyPlan stalePaymentPlan = DclCanonicalNativeApplyRouter.PlanPayment(
            stalePaymentBattle,
            stalePaymentReservation,
            caster,
            new DclCanonicalNativePoolSnapshot(currentHp: 5, maxHp: 30, currentMp: 3, maxMp: 20));
        stalePaymentBattle.States.RemoveInstances([staleCleanup.Instance.InstanceId]);
        CheckThrows<InvalidOperationException>(
            () => DclCanonicalNativeApplyRouter.CommitPayment(
                stalePaymentBattle,
                stalePaymentReservation,
                stalePaymentPlan),
            "managed lethal payment must fail closed if its exact KO cleanup set changed before commit");
        Check(stalePaymentApplication.Stage == DclCanonicalNativeActionStage.StrikesApplied,
            "a stale payment cleanup plan must not advance the native action ledger");

        var turnLifecycleBattle = new DclCanonicalBattleRuntime(runtime, battleGeneration: 16);
        turnLifecycleBattle.ObserveUnit(caster);
        turnLifecycleBattle.ObserveUnit(targetKey);
        long targetTurnSerial = turnLifecycleBattle.BeginTurn(targetKey);
        DclStateDefinition targetTurnState = BuildDclStateDefinition(
            "target-turn-lifecycle",
            DclStateStackPolicy.Refresh,
            DclStateDurationClock.TargetTurn) with
        {
            NativeStatusBit = new DclNativeStatusBit(2, 0x04),
        };
        DclStateDefinition sourceTurnState = BuildDclStateDefinition(
            "source-turn-lifecycle",
            DclStateStackPolicy.Refresh,
            DclStateDurationClock.SourceTurn,
            sourceRequired: true);
        DclStateApplication TurnLifecycleApplication(
            DclStateDefinition definition,
            DclUnitKey stateTarget,
            DclUnitKey? stateSource)
            => new(
                definition,
                stateTarget,
                stateSource,
                AppliedAtGlobalCt: 0,
                AppliedBeforeTurnSerial: targetTurnSerial,
                FirstEligibleTargetTurnSerial:
                    definition.Duration.Clock == DclStateDurationClock.TargetTurn ? targetTurnSerial : null,
                FirstEligibleSourceTurnSerial:
                    definition.Duration.Clock == DclStateDurationClock.SourceTurn ? targetTurnSerial : null,
                DurationUnits: 1,
                Strength: null,
                WinningMargin: null,
                StackDiscriminator: "",
                ContributionIdentity: null,
                new DclPropertyStatePayload(definition.PayloadSchema, new Dictionary<string, string>()),
                definition.PresentationProfile);
        DclStateApplicationResult expiringTarget =
            turnLifecycleBattle.States.Apply(TurnLifecycleApplication(targetTurnState, targetKey, null));
        DclStateApplicationResult expiringSource =
            turnLifecycleBattle.States.Apply(TurnLifecycleApplication(sourceTurnState, caster, targetKey));
        DclCanonicalTurnCompletion turnCompletion = turnLifecycleBattle.CompleteTurn(targetKey);
        DclCanonicalNativeAuxiliaryEffects? turnRemovalProjection =
            DclCanonicalNativeAuxiliaryProjector.ProjectRemovedStates(turnCompletion.RemovedStates);
        Check(turnCompletion.TurnSerial == targetTurnSerial &&
              turnCompletion.RemovedStateInstanceIds.SequenceEqual(
                  new[] { expiringTarget.Instance.InstanceId, expiringSource.Instance.InstanceId }.Order()) &&
              turnCompletion.RemovedStates.Select(instance => instance.Kind).Order().SequenceEqual(
                  new[] { sourceTurnState.Kind, targetTurnState.Kind }.Order()) &&
              turnRemovalProjection?.RemovedStates.Select(mutation => mutation.StateKind).Order().SequenceEqual(
                  new[] { sourceTurnState.Kind, targetTurnState.Kind }.Order()) == true,
            "turn completion must retain and project the exact target/source states removed at the same proven boundary");

        var coordinatorRandomSource = new SequenceRandomSource([3, 3, 4, 3, 3, 4, 2, 3]);
        var coordinatorBattle = new DclCanonicalBattleRuntime(
            runtime,
            battleGeneration: 16,
            executionRandomSource: coordinatorRandomSource);
        coordinatorBattle.ObserveUnit(caster);
        coordinatorBattle.ObserveUnit(targetKey);
        var coordinatorRequest = new DclCanonicalMagicExecutionRequest(
            AbilityId: 16,
            request,
            ActionInstanceId: 900,
            target with
            {
                CombatStateRevision = coordinatorBattle.States.CaptureTarget(targetKey).Revision,
            },
            BaseSpellScore: 12,
            TargetSpellScore: 12,
            new DclDefenseOption(DclDefenseKind.Dodge, 9, Depletes: false),
            MagnitudeAttribute: 10,
            neutralAffinity,
            FaithMagnitude: DclRational.FromInteger(1),
            TargetHasShell: false,
            TargetMaxHp: 30,
            FireEffect: true,
            OilContributed: false,
            CurrentMpAtResolution: 8,
            CurrentHpAtResolution: 20,
            InjuryTargetContext: new DclCanonicalInjuryTargetContext(
                MaxHp: 30,
                TargetSt: 10,
                EffectiveHt: 10,
                UnexpiredShockInjury: 0,
                Charging: false,
                Will: 10,
                ConcentrationModifier: 0,
                ConcentrationStatePenaltyMagnitude: 0));
        CheckThrows<ArgumentException>(
            () => DclCanonicalMagicExecutionCoordinator.ResolveAndPublish(
                coordinatorBattle,
                coordinatorRequest with { Defense = new DclDefenseOption(DclDefenseKind.Parry, 9, Depletes: false) }),
            "invalid direct-magic defense metadata must fail before any confirmed-execution random site");
        Check(coordinatorRandomSource.DrawCount == 0 && coordinatorBattle.ExecutionRandom.Count == 0,
            "fail-closed direct-magic request validation must not perturb the execution RNG stream");
        CheckThrows<ArgumentException>(
            () => DclCanonicalMagicExecutionCoordinator.ResolveAndPublish(
                coordinatorBattle,
                coordinatorRequest with
                {
                    Target = coordinatorRequest.Target with
                    {
                        CombatStateRevision = coordinatorRequest.Target.CombatStateRevision + 1,
                    },
                }),
            "confirmed direct magic must reject a stale target custom-state revision before RNG");
        Check(coordinatorRandomSource.DrawCount == 0 && coordinatorBattle.ExecutionRandom.Count == 0 &&
              coordinatorBattle.NativeActions.Count == 0,
            "stale direct-magic state metadata must leave execution and native-action ledgers unchanged");
        CheckThrows<ArgumentException>(
            () => DclCanonicalConfirmedExecutionDispatcher.ResolveAndPublish(
                coordinatorBattle,
                coordinatorRequest.AbilityId,
                new object()),
            "the confirmed dispatcher must reject an execution input object from another family");
        CheckThrows<ArgumentException>(
            () => DclCanonicalConfirmedExecutionDispatcher.ResolveAndPublish(
                coordinatorBattle,
                coordinatorRequest.AbilityId,
                coordinatorRequest with { AbilityId = 1 }),
            "the confirmed dispatcher must reject an execution input carrying another ability identity");
        CheckThrows<ArgumentException>(
            () => DclCanonicalConfirmedExecutionDispatcher.ResolveAndPublish(
                coordinatorBattle,
                coordinatorRequest.AbilityId,
                coordinatorRequest,
                auxiliaryReactionCandidates: []),
            "an embedded-Reaction family must reject a second dispatcher-owned candidate list");
        Check(coordinatorRandomSource.DrawCount == 0 && coordinatorBattle.ExecutionRandom.Count == 0 &&
              coordinatorBattle.NativeActions.Count == 0,
            "confirmed dispatcher preflight failures must precede every random, state, and publication site");
        DclCanonicalConfirmedExecutionDispatchResult coordinatedDispatch =
            DclCanonicalConfirmedExecutionDispatcher.ResolveAndPublish(
                coordinatorBattle,
                coordinatorRequest.AbilityId,
                coordinatorRequest);
        Check(coordinatedDispatch is
              {
                  Family: DclCanonicalActionFamily.DirectNumeric,
                  Resolution: DclCanonicalMagicExecutionResult,
                  Application: not null,
                  NativePassthrough: false,
              },
            "the confirmed dispatcher must select the bound direct-numeric coordinator and publish exactly once");
        DclCanonicalMagicExecutionResult coordinatedResult =
            (DclCanonicalMagicExecutionResult)coordinatedDispatch.Resolution!;
        DclCanonicalNativeActionApplication coordinatedApplication = coordinatedDispatch.Application!;
        Check(coordinatedResult.Delivery is { Delivered: true } &&
              coordinatedResult.Effect is { FinalInjury: 5 } &&
              coordinatedResult.InjuryStates?.Shock?.Instance is { Kind: "shock" } &&
              coordinatorBattle.States.Instances.Count(instance => instance.Kind == "shock") == 1 &&
              coordinatedResult.Payment is { MpPaid: 8, HpPaid: 2 } &&
              coordinatedResult.Reactions is { Candidates.Count: 0, Accepted.Count: 0 } &&
              ReferenceEquals(coordinatedApplication.Plan.Reactions, coordinatedResult.Reactions) &&
              coordinatorRandomSource.DrawCount == 8 && coordinatorBattle.ExecutionRandom.Count == 4 &&
              coordinatedApplication.Stage == DclCanonicalNativeActionStage.Published,
            "the direct-magic execution coordinator must own casting/defense/magnitude, resolve even an empty Reaction window, and publish once");

        var directConcentrationRandom = new SequenceRandomSource(
        [
            3, 3, 4,
            3, 3, 4,
            2, 3,
            6, 6, 6,
        ]);
        var directConcentrationBattle = new DclCanonicalBattleRuntime(
            runtime,
            battleGeneration: 16,
            initialGlobalCt: 0,
            directConcentrationRandom);
        directConcentrationBattle.ObserveUnit(caster);
        directConcentrationBattle.ObserveUnit(targetKey);
        var reverseTarget = new DclTargetCandidate(
            caster,
            request.CasterTile,
            Height: request.CasterHeight,
            DclAllegianceRelation.Enemy,
            DclEligibleTargetStates.Alive,
            CurrentHp: 20,
            CombatStateRevision: directConcentrationBattle.States.CaptureTarget(caster).Revision,
            new DclDefenseResourceSnapshot(new Dictionary<string, int>(), BlockAvailable: true));
        DclCastDeclarationAttempt directPendingAttempt = DclMagicTargeting.Declare(
            request with
            {
                Caster = targetKey,
                CasterTile = target.Tile,
                UnitTarget = reverseTarget,
                CurrentGlobalCt = directConcentrationBattle.CurrentGlobalCt,
            },
            directConcentrationBattle.NextActionInstanceId());
        Check(directPendingAttempt is { Legal: true, Declaration: not null },
            "direct Injury concentration sentinel requires one legal pending target cast");
        var directConcentrationTimeline = new DclCanonicalTimelineScheduler(
            directConcentrationBattle,
            [new DclCanonicalTimelineUnit(targetKey, initiativeRank: 0, new DclCtState(0), DclCtRate.Normal)]);
        directConcentrationTimeline.ScheduleChargedAction(16, directPendingAttempt.Declaration!);
        DclCanonicalPublishedMagicExecution directConcentrationExecution =
            DclCanonicalMagicExecutionCoordinator.ResolveAndPublish(
                directConcentrationBattle,
                coordinatorRequest with
                {
                    ActionInstanceId = 903,
                    Target = coordinatorRequest.Target with
                    {
                        CombatStateRevision = directConcentrationBattle.States.CaptureTarget(targetKey).Revision,
                    },
                    InjuryTargetContext = coordinatorRequest.InjuryTargetContext!.Value with { Charging = true },
                });
        Check(directConcentrationExecution.Result is
              {
                  Effect.FinalInjury: 5,
                  InjuryConsequences.Concentration:
                  {
                      Outcome: DclConcentrationOutcome.Interrupted,
                      Rolled: true,
                  },
                  ChargingCancellation:
                  {
                      Reason: DclChargingCancellationReason.ConcentrationFailure,
                      ChargedAction.Declaration.ActionInstanceId: var cancelledDirectActionId,
                  },
                  Reactions: { Accepted.Count: 0 },
              } &&
              cancelledDirectActionId == directPendingAttempt.Declaration!.ActionInstanceId &&
              !directConcentrationTimeline.TryGetChargedAction(targetKey, out _) &&
              directConcentrationRandom.DrawCount == 11 &&
              directConcentrationBattle.ExecutionRandom.Count == 5,
            "direct magical Injury must cancel the exact pending target action before its terminal Reaction window");
        CheckThrows<ArgumentException>(
            () => DclCanonicalMagicExecutionCoordinator.ResolveAndPublish(coordinatorBattle, coordinatorRequest),
            "confirmed-execution callback re-entry must reject the now-stale target state revision before reusing or publishing the ActionInstance");
        Check(coordinatorRandomSource.DrawCount == 8 && coordinatorBattle.ExecutionRandom.Count == 4,
            "duplicate execution entry must not consume casting, defense, or magnitude RNG again");
        Check(DclCanonicalNativeApplyRouter.TryPrepare(
                  coordinatorBattle,
                  caster,
                  16,
                  targetKey,
                  0,
                  naturalHpDebit: 99,
                  naturalHpCredit: 0,
                  naturalMpDebit: 0,
                  naturalMpCredit: 0,
                  naturalResultFlags: 0x80,
                  controlResultFlags: true,
                  preserveResultFlagsMask: DclResultFlags.DefaultPreserveMask,
                  out DclCanonicalNativeApplyReservation coordinatedApply) &&
              coordinatedApply.NumericPlan.HpDebit == 5 &&
              coordinatedApply.AuxiliaryPlan.CustomAddedStates.Single().StateKind == "shock" &&
              DclCanonicalNativeApplyRouter.Commit(coordinatedApply).Channels.HpDebit == 5 &&
              DclCanonicalNativeApplyRouter.ReadPresentation(coordinatedApply).Channels.HpDebit == 5,
            "one coordinated direct-magic result must flow unchanged through compute reservation, apply, and presentation acknowledgement");
        Check(DclCanonicalNativeApplyRouter.TryPreparePayment(
                  coordinatorBattle,
                  900,
                  out DclCanonicalNativePaymentReservation coordinatedPayment) &&
              DclCanonicalNativeApplyRouter.CommitPayment(coordinatedPayment) is
              { Channels: { HpDebit: 2, MpDebit: 8 } },
            "the coordinated direct-magic target result must retain its distinct source payment");
        DclCanonicalNativeApplyRouter.AcknowledgeReactionWindow(coordinatedPayment);
        DclCanonicalNativeApplyRouter.SettleAndRetire(coordinatorBattle, coordinatedPayment);
        var failedCoordinatorSource = new SequenceRandomSource([]);
        var failedCoordinatorBattle = new DclCanonicalBattleRuntime(
            runtime,
            battleGeneration: 16,
            executionRandomSource: failedCoordinatorSource);
        failedCoordinatorBattle.ObserveUnit(caster);
        failedCoordinatorBattle.ObserveUnit(targetKey);
        DclCanonicalPublishedMagicExecution coordinatedFailure =
            DclCanonicalMagicExecutionCoordinator.ResolveAndPublish(
                failedCoordinatorBattle,
                coordinatorRequest with
                {
                    ActionInstanceId = 901,
                    CurrentMpAtResolution = 0,
                    CurrentHpAtResolution = 5,
                });
        Check(coordinatedFailure.Result.Outcome == DclCastingOutcome.ResourceFailure &&
              coordinatedFailure.Application.Plan.ResourceFailed &&
              coordinatedFailure.Application.Plan.Strikes.Count == 0 &&
              failedCoordinatorSource.DrawCount == 0 && failedCoordinatorBattle.ExecutionRandom.Count == 0,
            "resolution-time ResourceFailure must publish an empty Action without touching casting, defense, magnitude, or consequence RNG");
        DclCanonicalNativeApplyRouter.SettleResourceFailure(failedCoordinatorBattle, 901);

        var magicAimRandom = new SequenceRandomSource([3, 3, 4, 2, 3, 3, 4, 4]);
        var magicAimBattle = new DclCanonicalBattleRuntime(
            runtime,
            battleGeneration: 16,
            initialGlobalCt: 100,
            magicAimRandom);
        magicAimBattle.ObserveUnit(caster);
        magicAimBattle.ObserveUnit(targetKey);
        DclStateDefinition magicAimDefinition = BuildDclStateDefinition(
            "aim", DclStateStackPolicy.Replace, DclStateDurationClock.UsesOrTriggers);
        DclStateApplicationResult magicTargetAim = magicAimBattle.States.Apply(new DclStateApplication(
            magicAimDefinition,
            targetKey,
            Source: null,
            AppliedAtGlobalCt: 100,
            AppliedBeforeTurnSerial: 0,
            FirstEligibleTargetTurnSerial: null,
            FirstEligibleSourceTurnSerial: null,
            DurationUnits: 1,
            Strength: null,
            WinningMargin: null,
            StackDiscriminator: "",
            ContributionIdentity: null,
            new DclAimStatePayload(magicAimDefinition.PayloadSchema, caster, 1),
            magicAimDefinition.PresentationProfile));
        DclCanonicalPublishedMagicExecution coordinatedMagicAim =
            DclCanonicalMagicExecutionCoordinator.ResolveAndPublish(
                magicAimBattle,
                coordinatorRequest with
                {
                    ActionInstanceId = 902,
                    Defense = new DclDefenseOption(DclDefenseKind.None, 0, Depletes: false),
                    Target = coordinatorRequest.Target with
                    {
                        CombatStateRevision = magicAimBattle.States.CaptureTarget(targetKey).Revision,
                    },
                });
        Check(coordinatedMagicAim.Result.Effect is { FinalInjury: 5 } &&
              coordinatedMagicAim.AimRetention is
              { HadAim: true, Retained: false, Reason: "retention-roll-failed" } &&
              coordinatedMagicAim.Result.AimRetention == coordinatedMagicAim.AimRetention &&
              coordinatedMagicAim.Application.Plan.Strikes.Single().AuxiliaryEffects?.RemovedStates.Single() is
              { InstanceId: var removedMagicAimId, StateKind: "aim" } &&
              removedMagicAimId == magicTargetAim.Instance.InstanceId &&
              !magicAimBattle.States.TryGet(magicTargetAim.Instance.InstanceId, out _) &&
              magicAimRandom.DrawCount == 8 && magicAimBattle.ExecutionRandom.Count == 4,
            "positive magical Injury must add exactly one reachable AimRetention site after casting and magnitude, then remove the failed target Aim before native publication");

        DclActionProfile magicBlockAction = action with
        {
            ActionId = "spell.blockable.test",
            DeliveryProfile = action.DeliveryProfile with
            {
                Blockable = true,
                UsesDefenseBonus = true,
            },
        };
        var magicBlockAuthoring = new DclAuthoringRegistry();
        Check(magicBlockAuthoring.TryRegister(magicBlockAction).IsValid &&
              magicBlockAuthoring.TryRegister(universalShockDefinition).IsValid &&
              magicBlockAuthoring.TryRegister(universalStunDefinition).IsValid &&
              magicBlockAuthoring.TryRegister(universalKnockedDownDefinition).IsValid,
            "the magic Block cadence sentinel must register its action and universal Injury states");
        var magicBlockBindings = new DclAbilityBindingRegistry();
        Check(magicBlockBindings.TryRegister(
                  binding with { ActionId = magicBlockAction.ActionId },
                  nativeCatalog,
                  magicBlockAuthoring).IsValid,
            "the magic Block cadence sentinel must bind its direct native carrier");
        var magicBlockRuntime = new DclCanonicalRuntimeCatalog(
            magicBlockAuthoring,
            runtime.Items,
            magicBlockBindings,
            new DclNativeReactionBindingRegistry());
        DclCastDeclarationRequest magicBlockDeclaration = request with { Profile = magicBlockAction };
        var magicBlockRandom = new SequenceRandomSource([3, 3, 4, 3, 3, 4, 2, 3]);
        var magicBlockBattle = new DclCanonicalBattleRuntime(
            magicBlockRuntime,
            battleGeneration: 16,
            initialGlobalCt: 100,
            magicBlockRandom);
        magicBlockBattle.ObserveUnit(caster);
        magicBlockBattle.ObserveUnit(targetKey);
        DclDefenseResourceSnapshot magicBlockBefore = magicBlockBattle.CaptureDefenseResources(targetKey);
        DclCanonicalPublishedMagicExecution coordinatedMagicBlock =
            DclCanonicalMagicExecutionCoordinator.ResolveAndPublish(
                magicBlockBattle,
                coordinatorRequest with
                {
                    ActionInstanceId = 903,
                    DeclarationRequest = magicBlockDeclaration,
                    Defense = new DclDefenseOption(DclDefenseKind.Block, 9, Depletes: true),
                    Target = coordinatorRequest.Target with
                    {
                        CombatStateRevision = magicBlockBattle.States.CaptureTarget(targetKey).Revision,
                        DefenseResources = magicBlockBefore,
                    },
                });
        DclDefenseResourceSnapshot magicBlockAfter = magicBlockBattle.CaptureDefenseResources(targetKey);
        Check(coordinatedMagicBlock.Result.Delivery is { DefenseKind: DclDefenseKind.Block } &&
              coordinatedMagicBlock.Result.FinalDefenseResources?.BlockAvailable == false &&
              coordinatedMagicBlock.Result.Transaction is { } magicBlockTransaction &&
              !magicBlockTransaction.DefenseResourcesFor(targetKey).CaptureSnapshot().BlockAvailable &&
              magicBlockBefore.BlockAvailable && !magicBlockAfter.BlockAvailable &&
              magicBlockAfter.Revision == magicBlockBefore.Revision + 1,
            "a reachable External Projectile Block attempt must spend the battle-owned one-per-turn Block resource even when the defense roll fails");
        int drawsBeforeSpentBlockRetry = magicBlockRandom.DrawCount;
        int applicationsBeforeSpentBlockRetry = magicBlockBattle.NativeActions.Count;
        CheckThrows<ArgumentException>(
            () => DclCanonicalMagicExecutionCoordinator.ResolveAndPublish(
                magicBlockBattle,
                coordinatorRequest with
                {
                    ActionInstanceId = 904,
                    DeclarationRequest = magicBlockDeclaration,
                    Defense = new DclDefenseOption(DclDefenseKind.Block, 9, Depletes: true),
                    Target = coordinatorRequest.Target with
                    {
                        CombatStateRevision = magicBlockBattle.States.CaptureTarget(targetKey).Revision,
                        DefenseResources = magicBlockAfter,
                    },
                }),
            "direct magic must reject a spent Block before casting or defense RNG");
        Check(magicBlockRandom.DrawCount == drawsBeforeSpentBlockRetry &&
              magicBlockBattle.NativeActions.Count == applicationsBeforeSpentBlockRetry,
            "a spent magic Block retry must leave execution RNG and native publication unchanged");

        if (_stopCanonicalRuntimeAfterInjuryMovement)
            Console.WriteLine("injury-movement: direct forecast");
        var directForecastMovementBranches = new DclCanonicalInjuryMovementBranchSet(
            DclForcedMovementDirection.AwayFromSource,
            new Dictionary<int, DclCanonicalNativeMovementVerdict>
            {
                [1] = new(
                    targetKey,
                    target.Tile,
                    target.Tile with { X = target.Tile.X + 1 },
                    RequestedTiles: 1,
                    MovedTiles: 1,
                    DclForcedMovementDirection.AwayFromSource,
                    Fell: true,
                    NativePathResolved: true),
            });
        var blockedDirectMovementBranches = new DclCanonicalInjuryMovementBranchSet(
            DclForcedMovementDirection.AwayFromSource,
            new Dictionary<int, DclCanonicalNativeMovementVerdict>
            {
                [1] = new(
                    targetKey,
                    target.Tile,
                    target.Tile,
                    RequestedTiles: 1,
                    MovedTiles: 0,
                    DclForcedMovementDirection.AwayFromSource,
                    Fell: false,
                    NativePathResolved: true),
            });
        DclCanonicalForcedMovementResult blockedDirectMovement =
            blockedDirectMovementBranches.Resolve(targetKey, targetKo: false, requestedTiles: 1)!;
        DclCanonicalForcedMovementResult koSuppressedDirectMovement =
            directForecastMovementBranches.Resolve(targetKey, targetKo: true, requestedTiles: 1)!;
        DclInjuryConsequenceResult blockedZeroInjuryConsequence = DclInjury.ResolveConsequences(
            hpBeforeInjury: 20,
            new DclInjuryResult(
                RolledDamage: 5,
                ApplicableDr: 5,
                EffectiveDr: 5,
                PenetratingDamage: 0,
                Injury: 0),
            DclDamageType.Cutting,
            criticalSuccess: true,
            new DclInjuryConsequenceInput(
                MaxHp: 30,
                TargetSt: 5,
                EffectiveHt: 10,
                UnexpiredShockInjury: 0,
                StillCharging: true,
                Will: 10,
                ConcentrationModifier: 0,
                ConcentrationStatePenaltyMagnitude: 0,
                MajorWoundHtRoll: null,
                DirectConcentrationCancellation: false,
                AuthoredForcedDisplacement: 0,
                ConcentrationRoll: null,
                SettledForcedDisplacement: blockedDirectMovement.MovedTiles));
        Check(blockedDirectMovement is
              {
                  RequestedTiles: 1,
                  MovedTiles: 0,
                  CancelAim: false,
                  CreatesConcentrationIncident: false,
                  SuppressedByTargetKo: false,
              } && koSuppressedDirectMovement is
              {
                  RequestedTiles: 1,
                  MovedTiles: 0,
                  CancelAim: false,
                  CreatesConcentrationIncident: false,
                  SuppressedByTargetKo: true,
              } && blockedZeroInjuryConsequence is
              {
                  RequestedForcedDisplacement: 1,
                  TotalForcedDisplacement: 0,
                  Concentration: { Outcome: DclConcentrationOutcome.NoIncident, Rolled: false },
              },
            "blocked and KO-suppressed Injury displacement must preserve Aim and consume no concentration RNG");
        CheckThrows<InvalidOperationException>(
            () => directForecastMovementBranches.Resolve(targetKey, targetKo: false, requestedTiles: 2),
            "Injury displacement must fail closed when the selected distance has no frozen map branch");
        var hitEvaluationInput = new DclCanonicalMagicEvaluationInput(
            AbilityId: 16,
            request,
            target,
            BaseSpellScore: 12,
            TargetSpellScore: 12,
            new DclDefenseOption(DclDefenseKind.Dodge, 9, Depletes: false),
            MagnitudeAttribute: 10,
            neutralAffinity,
            FaithMagnitude: DclRational.FromInteger(1),
            TargetHasShell: false,
            TargetMaxHp: 30,
            FireEffect: true,
            OilContributed: false,
            CurrentMpAtResolution: 8,
            CurrentHpAtResolution: 20,
            InjuryTargetContext: new DclCanonicalInjuryTargetContext(
                MaxHp: 30,
                TargetSt: 5,
                EffectiveHt: 10,
                UnexpiredShockInjury: 0,
                Charging: false,
                Will: 10,
                ConcentrationModifier: 0,
                ConcentrationStatePenaltyMagnitude: 0),
            InjuryMovementBranches: directForecastMovementBranches);
        DclCanonicalMagicEvaluationResult hitEvaluation =
            DclCanonicalMagicEvaluationExecutor.Evaluate(runtime, hitEvaluationInput);
        var composedHitEvaluation = new DclCanonicalComposedEvaluation(
            hitEvaluationInput.AbilityId,
            DclCanonicalActionFamily.DirectNumeric,
            hitEvaluationInput);
        DclCanonicalEvaluationDispatchResult dispatchedHitEvaluation =
            DclCanonicalEvaluationDispatcher.Evaluate(runtime, composedHitEvaluation);
        Check(dispatchedHitEvaluation is
              {
                  Family: DclCanonicalActionFamily.DirectNumeric,
                  NativePassthrough: false,
                  Evaluation: DclCanonicalMagicEvaluationResult,
                  PlayerProjection: DclCanonicalMagicForecastProjection,
                  AiProjection: DclCanonicalMagicAiProjection,
              } &&
              ((DclCanonicalMagicEvaluationResult)dispatchedHitEvaluation.Evaluation).DeliveryProbability ==
                  hitEvaluation.DeliveryProbability,
            "the single evaluation dispatcher must consume the retained composed evaluation, select the bound family, and preserve exact player/AI outputs without native-formula inference");
        CheckThrows<ArgumentException>(
            () => DclCanonicalEvaluationDispatcher.Evaluate(
                runtime,
                composedHitEvaluation with { Family = DclCanonicalActionFamily.PhysicalDamage }),
            "a composed canonical evaluation must fail when its retained family diverges from the runtime ability classification");
        CheckThrows<ArgumentException>(
            () => DclCanonicalEvaluationDispatcher.Evaluate(runtime, hitEvaluationInput.AbilityId, new object()),
            "the evaluation dispatcher must reject an input object from a different family");
        CheckThrows<ArgumentException>(
            () => DclCanonicalEvaluationDispatcher.Evaluate(
                runtime,
                hitEvaluationInput.AbilityId,
                hitEvaluationInput with { AbilityId = 1 }),
            "the evaluation dispatcher must reject a family input carrying another ability identity");
        DclRational exactHitProbability = DclSpellResolution.ExternalSuccessProbability(
            12,
            12,
            new DclDefenseOption(DclDefenseKind.Dodge, 9, Depletes: false)).Fraction;
        DclRational ordinaryFailureProbability =
            hitEvaluation.Resources.BaseOutcomeProbability[DclCastingOutcome.OrdinaryFailure];
        Check(hitEvaluation.Legal && !hitEvaluation.ResourceFailed &&
              hitEvaluation.DeliveryProbability == exactHitProbability &&
              hitEvaluation.NormalMagnitudeExpression == new DclDiceExpression(2, 0) &&
              hitEvaluation.CriticalMagnitudeExpression == new DclDiceExpression(2, 0) &&
              hitEvaluation.TargetHpDebit.Minimum == 0 && hitEvaluation.TargetHpDebit.Maximum == 12 &&
              hitEvaluation.TargetHpDebit.ExpectedValue == exactHitProbability * new DclRational(7, 1) &&
              hitEvaluation.TargetHpCredit.ExpectedValue == DclRational.FromInteger(0) &&
              hitEvaluation.ExpectedMovedTiles ==
                  hitEvaluation.CriticalDeliveryProbability * new DclRational(35, 36) &&
              hitEvaluation.FallProbability == hitEvaluation.ExpectedMovedTiles &&
              hitEvaluation.Resources.ExpectedMpDebit ==
                  (DclRational.FromInteger(1) - ordinaryFailureProbability) * DclRational.FromInteger(8) +
                  ordinaryFailureProbability &&
              hitEvaluation.Resources.ExpectedHpDebit ==
                  (DclRational.FromInteger(1) - ordinaryFailureProbability) * DclRational.FromInteger(2),
            "player forecast must enumerate the exact shared casting/defense space, full 2d6 Injury distribution, and outcome-dependent MP/HP settlement without sampling");
        if (_stopCanonicalRuntimeAfterInjuryMovement)
            Console.WriteLine("injury-movement: direct execution");
        var directMovementRandom = new SequenceRandomSource([1, 1, 2, 2, 3]);
        var directMovementBattle = new DclCanonicalBattleRuntime(
            runtime,
            battleGeneration: 16,
            initialGlobalCt: 0,
            directMovementRandom);
        directMovementBattle.ObserveUnit(caster);
        directMovementBattle.ObserveUnit(targetKey);
        DclCanonicalPublishedMagicExecution directMovementExecution =
            DclCanonicalMagicExecutionCoordinator.ResolveAndPublish(
                directMovementBattle,
                coordinatorRequest with
                {
                    ActionInstanceId = 905,
                    Target = coordinatorRequest.Target with
                    {
                        CombatStateRevision = directMovementBattle.States.CaptureTarget(targetKey).Revision,
                    },
                    InjuryTargetContext = coordinatorRequest.InjuryTargetContext!.Value with { TargetSt = 5 },
                    InjuryMovementBranches = directForecastMovementBranches,
                });
        Check(directMovementExecution.Result is
              {
                  Delivery.Outcome: DclMagicDeliveryOutcome.CriticalDelivered,
                  InjuryConsequences:
                  {
                      CriticalKnockbackTiles: 1,
                      TotalForcedDisplacement: 1,
                  },
                  ForcedMovement:
                  {
                      RequestedTiles: 1,
                      MovedTiles: 1,
                      Fell: true,
                      CancelAim: true,
                      SuppressedByTargetKo: false,
                  },
                  Reactions: { Candidates.Count: 0, Accepted.Count: 0 },
              } && directMovementExecution.Application.Plan.Strikes.Single().AuxiliaryEffects?.ForcedMovement ==
                  directMovementExecution.Result.ForcedMovement,
            "critical direct Injury must select and publish the same frozen settled movement with only its outer Reaction window");
        DclCanonicalMagicEvaluationResult magicBlockEvaluation =
            DclCanonicalMagicEvaluationExecutor.Evaluate(
                magicBlockRuntime,
                hitEvaluationInput with
                {
                    DeclarationRequest = magicBlockDeclaration,
                    Target = hitEvaluationInput.Target with { DefenseResources = magicBlockBefore },
                    Defense = new DclDefenseOption(DclDefenseKind.Block, 9, Depletes: true),
                });
        DclCanonicalMagicForecastProjection magicBlockForecast =
            DclCanonicalMagicForecastProjection.From(magicBlockEvaluation);
        Check(magicBlockEvaluation.DefenseAttemptProbability > DclRational.FromInteger(0) &&
              magicBlockEvaluation.BlockSpendProbability == magicBlockEvaluation.DefenseAttemptProbability &&
              magicBlockForecast.BlockSpendPercent == magicBlockForecast.DefenseAttemptPercent,
            "direct-magic forecast and AI must expose the exact correlated probability that a reachable noncritical cast spends Block");
        CheckThrows<ArgumentException>(
            () => DclCanonicalMagicEvaluationExecutor.Evaluate(
                magicBlockRuntime,
                hitEvaluationInput with
                {
                    DeclarationRequest = magicBlockDeclaration,
                    Target = hitEvaluationInput.Target with { DefenseResources = magicBlockAfter },
                    Defense = new DclDefenseOption(DclDefenseKind.Block, 9, Depletes: true),
                }),
            "direct-magic evaluation must reject a spent Block just like confirmed execution");
        DclCanonicalMagicEvaluationResult focusedHitEvaluation =
            DclCanonicalMagicEvaluationExecutor.Evaluate(
                runtime,
                hitEvaluationInput with { AdditionalMagnitudeIntegerModifier = 1 });
        DclCanonicalMagicExecutionResult focusedHitExecution = DclCanonicalMagicExecutor.Resolve(
            runtime,
            hitInput with
            {
                ActionInstanceId = 604,
                AdditionalMagnitudeIntegerModifier = 1,
            });
        Check(focusedHitEvaluation.NormalMagnitudeExpression == new DclDiceExpression(2, 1) &&
              focusedHitEvaluation.TargetHpDebit.Maximum == 13 &&
              focusedHitExecution.Effect is { FinalInjury: 6 },
            "focus magnitude modifiers must enter the identical normalized dice expression in forecast/AI and confirmed execution");
        DclCanonicalMagicAiProjection hitAi = DclCanonicalMagicAiProjection.From(hitEvaluation);
        DclCanonicalMagicForecastProjection hitForecast =
            DclCanonicalMagicForecastProjection.From(hitEvaluation);
        DclCanonicalMagicEvaluationResult repeatedHitEvaluation =
            DclCanonicalMagicEvaluationExecutor.Evaluate(runtime, hitEvaluationInput);
        Check(hitAi.ExpectedTargetHpDebit == hitEvaluation.TargetHpDebit.ExpectedValue &&
              hitAi.ExpectedCasterMpDebit == hitEvaluation.Resources.ExpectedMpDebit &&
              hitAi.AiBoundary == binding.AiBoundary &&
              hitAi.NativeExpectedHpDebit == checked((int)hitEvaluation.TargetHpDebit.ExpectedValue.RoundNearest()) &&
              hitForecast.ForecastBoundary == binding.ForecastBoundary &&
              hitForecast.DeliveryPercent == checked((int)(exactHitProbability * DclRational.FromInteger(100)).RoundNearest()) &&
              hitForecast.NormalMagnitude == "2d6" && hitForecast.MinimumHpDebit == 0 && hitForecast.MaximumHpDebit == 12 &&
              repeatedHitEvaluation.DeliveryOutcomeProbability.OrderBy(pair => pair.Key)
                  .SequenceEqual(hitEvaluation.DeliveryOutcomeProbability.OrderBy(pair => pair.Key)) &&
              repeatedHitEvaluation.TargetHpDebit.ProbabilityByValue.OrderBy(pair => pair.Key)
                  .SequenceEqual(hitEvaluation.TargetHpDebit.ProbabilityByValue.OrderBy(pair => pair.Key)) &&
              repeatedHitEvaluation.Resources.ExpectedHpDebit == hitEvaluation.Resources.ExpectedHpDebit,
            "AI and repeated menu evaluation must consume the same immutable exact plan and cannot perturb a future execution result");
        DclComputePointNumericPlan hitNativePlan = DclCanonicalNativeCarrierProjector.BuildTargetNumericPlan(
            hitProjection,
            naturalHpDebit: 99,
            naturalHpCredit: 7,
            naturalMpDebit: 6,
            naturalMpCredit: 5,
            naturalResultFlags: 0x80,
            controlResultFlags: true,
            preserveResultFlagsMask: DclResultFlags.DefaultPreserveMask);
        Check(hitNativePlan is
              {
                  HpDebit: 5,
                  HpCredit: 0,
                  MpDebit: 0,
                  MpCredit: 0,
                  WriteHpDebit: true,
                  WriteHpCredit: true,
                  WriteMpDebit: true,
                  WriteMpCredit: true,
                  WriteResultFlags: true,
              },
            "a canonical target projection must replace every staged numeric channel rather than leave unrelated vanilla credit/debit behind");
        DclCanonicalMagicExecutionResult armoredHit = DclCanonicalMagicExecutor.Resolve(
            runtime,
            hitInput with { ActionInstanceId = 602, ApplicableDr = 3 });
        Check(armoredHit.BaseInjury is
              {
                  RolledDamage: 5,
                  ApplicableDr: 3,
                  EffectiveDr: 3,
                  PenetratingDamage: 2,
                  Injury: 2,
              } && armoredHit.Effect is { BaseInjury: 2, FinalInjury: 2 },
            "Manifestation magic must resolve location DR and wound behavior before affinity, Faith, Shell, Oil, and final magical rounding");

        DclCanonicalMagicExecutionResult defended = DclCanonicalMagicExecutor.Resolve(
            runtime,
            hitInput with { ActionInstanceId = 502, DefenseRoll = 9, MagnitudeDice = null, InjuryConsequenceInput = null });
        Check(defended.Delivery is { Outcome: DclMagicDeliveryOutcome.Defended } && defended.Effect is null &&
              defended.Transaction?.VisibleEffects.Count == 0 && defended.Payment.CostDue == 10,
            "a defended canonical cast must retain successful-cast settlement while planning no damage/status effect");
        DclCanonicalNativeCarrierProjection defendedProjection =
            DclCanonicalNativeCarrierProjector.ProjectMagic(runtime, 16, caster, defended);
        DclComputePointNumericPlan defendedNativePlan = DclCanonicalNativeCarrierProjector.BuildTargetNumericPlan(
            defendedProjection,
            naturalHpDebit: 99,
            naturalHpCredit: 7,
            naturalMpDebit: 6,
            naturalMpCredit: 5,
            naturalResultFlags: 0x80,
            controlResultFlags: true,
            preserveResultFlagsMask: DclResultFlags.DefaultPreserveMask);
        Check(defendedNativePlan is
              {
                  HpDebit: 0,
                  HpCredit: 0,
                  MpDebit: 0,
                  MpCredit: 0,
                  WriteResultFlags: false,
              },
            "a defended canonical delivery must zero all native numeric channels while leaving miss presentation to the proven downstream selector");
        DclCanonicalMagicExecutionResult failed = DclCanonicalMagicExecutor.Resolve(
            runtime,
            hitInput with { ActionInstanceId = 503, SharedCasterRoll = 13, DefenseRoll = null, MagnitudeDice = null, InjuryConsequenceInput = null });
        Check(failed.Delivery is { Outcome: DclMagicDeliveryOutcome.BaseFailure } && failed.Effect is null &&
              failed.Payment.CostDue == 1 && failed.Transaction?.VisibleEffects.Count == 0,
            "ordinary BaseSpellScore failure must spend one point, consume no defense RNG, and commit no target effect");
        DclCanonicalMagicExecutionResult critical = DclCanonicalMagicExecutor.Resolve(
            runtime,
            hitInput with { ActionInstanceId = 504, SharedCasterRoll = 4, DefenseRoll = null, MagnitudeDice = new[] { 2, 3 } });
        Check(critical.Delivery is { Outcome: DclMagicDeliveryOutcome.CriticalDelivered } &&
              critical.Effect is { FinalInjury: 5 } && critical.Payment.CostDue == 10,
            "critical External delivery must bypass defense while retaining ordinary full settlement and magnitude pipeline");
        var reflectedCasterTarget = target with
        {
            Unit = caster,
            Tile = new DclBattleTile(0, 0, 0),
            Relation = DclAllegianceRelation.Self,
            CurrentHp = 20,
            CombatStateRevision = 18,
        };
        DclCanonicalMagicExecutionResult reflected = DclCanonicalMagicExecutor.Resolve(
            runtime,
            hitInput with
            {
                ActionInstanceId = 600,
                Defense = new DclDefenseOption(DclDefenseKind.None, 0, Depletes: false),
                DefenseRoll = null,
                TargetMaxHp = 20,
                InjuryConsequenceInput = hitInput.InjuryConsequenceInput!.Value with { MaxHp = 20 },
                DeclaredTargetHasReflect = true,
                ReflectedTarget = reflectedCasterTarget,
            });
        Check(reflected.ReflectRoute is { Reflected: true, ReflectionConsumed: true } &&
              reflected.ReflectRoute.FinalTarget == caster && reflected.Delivery is { Delivered: true } &&
              reflected.Effect is { FinalInjury: 5 } &&
              reflected.Transaction?.TargetBatch?.Targets.Single().Target == caster &&
              reflected.Payment.CostDue == hit.Payment.CostDue,
            "Reflect must rebind the recipient to the original caster before target-relative delivery while retaining the same caster draw, cost, and magnitude profile");
        DclCanonicalNativeCarrierProjection reflectedProjection =
            DclCanonicalNativeCarrierProjector.ProjectMagic(runtime, 16, caster, reflected);
        Check(reflectedProjection.TargetResult?.Target == caster &&
              reflectedProjection.ResourcePayment?.Payer == caster &&
              reflectedProjection.TargetResult.Channels.HpDebit == 5 &&
              reflectedProjection.ResourcePayment.Channels.HpDebit == 2 &&
              !reflectedProjection.ResourcePayment.OpensDamageReaction,
            "a reflected self-hit must retain separate Injury and resource-payment semantics even when both native records name the caster");
        DclCanonicalMagicExecutionResult reflectLoopGuard = DclCanonicalMagicExecutor.Resolve(
            runtime,
            hitInput with
            {
                ActionInstanceId = 601,
                ReflectionAlreadyConsumed = true,
                DeclaredTargetHasReflect = true,
            });
        Check(!reflectLoopGuard.ReflectRoute.Reflected &&
              reflectLoopGuard.ReflectRoute.FinalTarget == target.Unit &&
              reflectLoopGuard.Transaction?.TargetBatch?.Targets.Single().Target == target.Unit,
            "an already-consumed reflection guard must prevent a second route without changing the original delivery");
        DclCanonicalMagicExecutionResult resourceFailure = DclCanonicalMagicExecutor.Resolve(
            runtime,
            hitInput with
            {
                ActionInstanceId = 505,
                SharedCasterRoll = null,
                CurrentMpAtResolution = 0,
                CurrentHpAtResolution = 5,
                DefenseRoll = null,
                MagnitudeDice = null,
                InjuryConsequenceInput = null,
            });
        Check(resourceFailure.Outcome == DclCastingOutcome.ResourceFailure &&
              resourceFailure.CastingGate is null && resourceFailure.Delivery is null &&
              resourceFailure.Effect is null &&
              resourceFailure.Transaction is { Stage: DclActionTransactionStage.ResourceFailed, ReactionWindowOpened: false } &&
              resourceFailure.Payment is { Legal: true, CostDue: 0, MpPaid: 0, HpPaid: 0, RemainingMp: 0, RemainingHp: 5 },
            "ResourceFailure must terminate its declared transaction before target snapshot and casting RNG with no debit, effect, or Reaction window");
        DclCanonicalNativeCarrierProjection resourceFailureProjection =
            DclCanonicalNativeCarrierProjector.ProjectMagic(runtime, 16, caster, resourceFailure);
        Check(resourceFailureProjection is
              {
                  ResourceFailed: true,
                  TargetResult: null,
                  ResourcePayment: null,
                  ReactionWindowOpened: false,
              },
            "ResourceFailure must project no native target, payment, or Reaction record");
        var resourceFailureLedger = new DclCanonicalNativeActionLedger(caster.BattleGeneration);
        DclCanonicalNativeActionApplication resourceFailureApplication =
            resourceFailureLedger.Publish(caster, binding, resourceFailureProjection);
        var resourceFailureBattle = new DclCanonicalBattleRuntime(runtime, caster.BattleGeneration);
        resourceFailureBattle.ObserveUnit(caster);
        resourceFailureBattle.ObserveUnit(target.Unit);
        DclCanonicalNativeActionApplication bridgedResourceFailure =
            DclCanonicalNativeExecutionPublisher.PublishMagic(resourceFailureBattle, 16, caster, resourceFailure);
        Check(!DclCanonicalNativeApplyRouter.TryPrepare(
                  resourceFailureBattle,
                  caster,
                  16,
                  target.Unit,
                  0,
                  99, 8, 7, 6, 0x80, true, DclResultFlags.DefaultPreserveMask,
                  out _),
            "ResourceFailure must expose no native target/Strike reservation at compute point");
        resourceFailureApplication.Settle();
        resourceFailureLedger.Retire(resourceFailureProjection.ActionInstanceId);
        DclCanonicalNativeApplyRouter.SettleResourceFailure(
            resourceFailureBattle,
            resourceFailureProjection.ActionInstanceId);
        DclCanonicalMagicEvaluationResult resourceFailureEvaluation =
            DclCanonicalMagicEvaluationExecutor.Evaluate(
                runtime,
                hitEvaluationInput with { CurrentMpAtResolution = 0, CurrentHpAtResolution = 5 });
        Check(!resourceFailureEvaluation.Legal && resourceFailureEvaluation.ResourceFailed &&
              resourceFailureEvaluation.DeliveryOutcomeProbability.Count == 0 &&
              resourceFailureEvaluation.TargetHpDebit.ExpectedValue == DclRational.FromInteger(0) &&
              resourceFailureEvaluation.Resources.ExpectedHpDebit == DclRational.FromInteger(0),
            "resolution-time ResourceFailure forecast must terminate before target probability/magnitude and project no resource debit");
        CheckThrows<ArgumentException>(
            () => DclCanonicalMagicExecutor.Resolve(
                runtime,
                hitInput with
                {
                    ActionInstanceId = 506,
                    CurrentMpAtResolution = 0,
                    CurrentHpAtResolution = 5,
                    DefenseRoll = null,
                    MagnitudeDice = null,
                }),
            "ResourceFailure must reject a pre-supplied caster draw as unreachable RNG");

        DclTargetCandidate healingTarget = target with
        {
            Relation = DclAllegianceRelation.Ally,
            CurrentHp = 10,
            CombatStateRevision = 8,
        };
        DclCastDeclarationRequest healingRequest = request with
        {
            Profile = healingAction,
            UnitTarget = healingTarget,
        };
        DclCanonicalMagicExecutionInput healingInput = hitInput with
        {
            AbilityId = 1,
            DeclarationRequest = healingRequest,
            ActionInstanceId = 507,
            Target = healingTarget,
            SharedCasterRoll = 4,
            Defense = new DclDefenseOption(DclDefenseKind.None, 0, Depletes: false),
            DefenseRoll = null,
            MagnitudeDice = new[] { 1, 2 },
            InjuryConsequenceInput = null,
            FireEffect = false,
            OilContributed = false,
        };
        DclCanonicalMagicExecutionResult criticalHealing = DclCanonicalMagicExecutor.Resolve(runtime, healingInput);
        Check(criticalHealing.Delivery is { Outcome: DclMagicDeliveryOutcome.CriticalDelivered } &&
              criticalHealing.Effect is null &&
              criticalHealing.Healing is { RawHealing: 11, FinalHealing: 11, AppliedHealing: 11 } &&
              criticalHealing.Transaction?.VisibleEffects.Single().Effect.Kind == DclEffectKind.Healing,
            "critical direct healing must replace exactly one of 3d6+2 with +6, then apply Faith and the missing-HP cap outside Injury");
        DclCanonicalMagicEvaluationResult healingEvaluation =
            DclCanonicalMagicEvaluationExecutor.Evaluate(
                runtime,
                new DclCanonicalMagicEvaluationInput(
                    AbilityId: 1,
                    healingRequest,
                    healingTarget,
                    BaseSpellScore: 12,
                    TargetSpellScore: 12,
                    new DclDefenseOption(DclDefenseKind.None, 0, Depletes: false),
                    MagnitudeAttribute: 10,
                    neutralAffinity,
                    FaithMagnitude: DclRational.FromInteger(1),
                    TargetHasShell: false,
                    TargetMaxHp: 30,
                    FireEffect: false,
                    OilContributed: false,
                    CurrentMpAtResolution: 8,
                    CurrentHpAtResolution: 20));
        Check(healingEvaluation.NormalMagnitudeExpression == new DclDiceExpression(3, 2) &&
              healingEvaluation.CriticalMagnitudeExpression == new DclDiceExpression(2, 8) &&
              healingEvaluation.TargetHpCredit.Minimum == 0 && healingEvaluation.TargetHpCredit.Maximum == 20 &&
              healingEvaluation.TargetHpDebit.ExpectedValue == DclRational.FromInteger(0),
            "healing forecast must enumerate ordinary and maximize-one-die critical expressions separately, then apply the missing-HP cap to every outcome");
        DclCanonicalNativeCarrierProjection healingProjection =
            DclCanonicalNativeCarrierProjector.ProjectMagic(runtime, 1, caster, criticalHealing);
        Check(healingProjection.TargetResult is
              {
                  DeliveryOutcome: DclMagicDeliveryOutcome.CriticalDelivered,
                  Channels: { HpDebit: 0, HpCredit: 11, MpDebit: 0, MpCredit: 0 },
                  MagicalRoute: null,
              },
            "direct canonical healing must project only target HP credit while retaining its critical delivery presentation");
        DclCanonicalMagicExecutionResult ordinaryHealing = DclCanonicalMagicExecutor.Resolve(
            runtime,
            healingInput with { ActionInstanceId = 508, SharedCasterRoll = 10, MagnitudeDice = new[] { 1, 2, 3 } });
        Check(ordinaryHealing.Healing is { RawHealing: 8, FinalHealing: 8, AppliedHealing: 8 } &&
              ordinaryHealing.Payment.CostDue == 10,
            "ordinary direct healing must roll every normal die and retain the successful-cast resource settlement");

        DclCastDeclarationRequest statusRequest = request with { Profile = statusAction };
        var stateRegistry = new DclStateRegistry(16, initialGlobalCt: 100);
        var statusMaterialization = new DclCanonicalStateMaterialization(
            BindSource: true,
            AppliedBeforeTurnSerial: 40,
            FirstEligibleTargetTurnSerial: null,
            FirstEligibleSourceTurnSerial: null,
            DurationUnits: 6,
            Strength: null,
            StackDiscriminator: "default",
            ContributionIdentity: null,
            new DclPropertyStatePayload(statusDefinition.PayloadSchema, new Dictionary<string, string>()));
        var statusInput = new DclCanonicalStatusExecutionInput(
            AbilityId: 28,
            statusRequest,
            ActionInstanceId: 509,
            target,
            BaseSpellScore: 12,
            TargetSpellScore: 12,
            SharedCasterRoll: 10,
            ResistanceScore: 9,
            ResistanceRoll: 11,
            Immune: false,
            CurrentMpAtResolution: 8,
            CurrentHpAtResolution: 20,
            stateRegistry,
            statusMaterialization);
        DclCanonicalStatusEvaluationResult statusEvaluation = DclCanonicalStatusEvaluation.Evaluate(
            runtime,
            new DclCanonicalStatusEvaluationInput(
                AbilityId: 28,
                statusRequest,
                target,
                BaseSpellScore: 12,
                TargetSpellScore: 12,
                ResistanceScore: 9,
                Immune: false,
                CurrentMpAtResolution: 8,
                CurrentHpAtResolution: 20,
                MaterializedDurationUnits: 6));
        DclExactProbability expectedStatusProbability =
            DclSpellResolution.InternalSuccessProbability(12, 12, 9);
        DclCanonicalStatusForecastProjection statusForecast =
            DclCanonicalStatusEvaluation.ProjectPlayer(statusEvaluation);
        DclCanonicalStatusAiProjection statusAi =
            DclCanonicalStatusEvaluation.ProjectAi(statusEvaluation);
        Check(statusEvaluation.ApplicationProbability == expectedStatusProbability.Fraction &&
              statusEvaluation.DeliveryOutcomeProbability.Values.Aggregate(
                  DclRational.FromInteger(0), (sum, probability) => sum + probability) == DclRational.FromInteger(1) &&
              statusEvaluation.WinningMarginProbability.Values.Aggregate(
                  DclRational.FromInteger(0), (sum, probability) => sum + probability) ==
                  statusEvaluation.ApplicationProbability &&
              statusEvaluation.DurationProbability.Single().Key == 6 &&
              statusEvaluation.DurationProbability.Single().Value == statusEvaluation.ApplicationProbability &&
              statusEvaluation.ExpectedDurationUnits ==
                  DclRational.FromInteger(6) * statusEvaluation.ApplicationProbability &&
              statusForecast.ApplicationPercent == expectedStatusProbability.RoundWholePercent() &&
              statusForecast.DurationProbability == statusEvaluation.DurationProbability &&
              statusAi.ApplicationProbability == statusEvaluation.ApplicationProbability &&
              statusAi.DurationProbability == statusEvaluation.DurationProbability &&
              statusAi.ExpectedDurationUnits == statusEvaluation.ExpectedDurationUnits &&
              statusAi.ExpectedCasterMpDebit == statusEvaluation.Resources.ExpectedMpDebit &&
              statusAi.ExpectedCasterHpDebit == statusEvaluation.Resources.ExpectedHpDebit,
            "status player forecast and AI must enumerate the same shared casting and conditional target-resistance space without execution RNG");
        DclCanonicalStatusEvaluationResult immuneStatusEvaluation =
            DclCanonicalStatusEvaluation.Evaluate(
                runtime,
                new DclCanonicalStatusEvaluationInput(
                    AbilityId: 28,
                    statusRequest,
                    target,
                    BaseSpellScore: 12,
                    TargetSpellScore: 12,
                    ResistanceScore: 9,
                    Immune: true,
                    CurrentMpAtResolution: 8,
                    CurrentHpAtResolution: 20,
                    MaterializedDurationUnits: 6));
        Check(immuneStatusEvaluation.ApplicationProbability == DclRational.FromInteger(0) &&
              immuneStatusEvaluation.WinningMarginProbability.Count == 0 &&
              immuneStatusEvaluation.DeliveryOutcomeProbability.Values.Aggregate(
                  DclRational.FromInteger(0), (sum, probability) => sum + probability) == DclRational.FromInteger(1),
            "status immunity forecast must stop before inventing a resistance branch or winning margin");
        DclCanonicalStatusEvaluationResult failedStatusEvaluation =
            DclCanonicalStatusEvaluation.Evaluate(
                runtime,
                new DclCanonicalStatusEvaluationInput(
                    AbilityId: 28,
                    statusRequest,
                    target,
                    BaseSpellScore: 12,
                    TargetSpellScore: 12,
                    ResistanceScore: 9,
                    Immune: false,
                    CurrentMpAtResolution: 0,
                    CurrentHpAtResolution: 5,
                    MaterializedDurationUnits: 6));
        Check(!failedStatusEvaluation.Legal && failedStatusEvaluation.ResourceFailed &&
              failedStatusEvaluation.DeliveryOutcomeProbability.Count == 0 &&
              failedStatusEvaluation.Resources.ExpectedMpDebit == DclRational.FromInteger(0) &&
              failedStatusEvaluation.Resources.ExpectedHpDebit == DclRational.FromInteger(0),
            "status ResourceFailure evaluation must terminate before all casting/resistance outcomes and payment");
        DclCanonicalStatusExecutionResult appliedStatus = DclCanonicalStatusExecutor.Resolve(runtime, statusInput);
        Check(appliedStatus.Delivery is { Delivered: true, WinningMargin: 4 } &&
              appliedStatus.StateApplication?.Instance is { Kind: "canonical-status-test", ExpiresAtGlobalCt: 106 } &&
              appliedStatus.Transaction is { Stage: DclActionTransactionStage.Settled, ReactionWindowOpened: true } &&
              appliedStatus.Transaction.VisibleEffects.Count == 1,
            "Internal Direct status must gate casting first, win one target Quick Contest, commit its normalized state before the single Reaction window, and retain duration/source identity");
        int stateCount = stateRegistry.Instances.Count;
        DclCanonicalStatusExecutionResult resistedStatus = DclCanonicalStatusExecutor.Resolve(
            runtime,
            statusInput with { ActionInstanceId = 510, ResistanceScore = 10, ResistanceRoll = 8 });
        Check(resistedStatus.Delivery is { Outcome: DclMagicDeliveryOutcome.Resisted } &&
              resistedStatus.StateApplication is null && resistedStatus.Transaction.VisibleEffects.Count == 0 &&
              stateRegistry.Instances.Count == stateCount,
            "a tied Internal Direct contest must belong to resistance and commit no status effect");
        DclCanonicalStatusExecutionResult immuneStatus = DclCanonicalStatusExecutor.Resolve(
            runtime,
            statusInput with { ActionInstanceId = 511, Immune = true, ResistanceRoll = null });
        Check(immuneStatus.Delivery is { Outcome: DclMagicDeliveryOutcome.Resisted, ResistanceRoll: null } &&
              immuneStatus.StateApplication is null && stateRegistry.Instances.Count == stateCount,
            "status immunity must short-circuit before the target resistance random site");
        DclCanonicalStatusExecutionResult failedStatus = DclCanonicalStatusExecutor.Resolve(
            runtime,
            statusInput with { ActionInstanceId = 512, SharedCasterRoll = 13, ResistanceRoll = null });
        Check(failedStatus.Delivery is { Outcome: DclMagicDeliveryOutcome.BaseFailure } &&
              failedStatus.Payment.CostDue == 1 && failedStatus.StateApplication is null,
            "a failed status casting gate must consume no resistance RNG, apply no state, and use ordinary-failure settlement");

        DclCanonicalStatusExecutionResult resourceFailedStatus = DclCanonicalStatusExecutor.Resolve(
            runtime,
            statusInput with
            {
                ActionInstanceId = 513,
                SharedCasterRoll = null,
                ResistanceRoll = null,
                CurrentMpAtResolution = 0,
                CurrentHpAtResolution = 5,
            });
        Check(resourceFailedStatus.Outcome == DclCastingOutcome.ResourceFailure &&
              resourceFailedStatus.Delivery is null && resourceFailedStatus.StateApplication is null &&
              resourceFailedStatus.Transaction.Stage == DclActionTransactionStage.ResourceFailed,
            "status ResourceFailure must terminate before both casting and resistance RNG");

        var coordinatedStatusRandom = new SequenceRandomSource([3, 3, 4, 3, 4, 4]);
        var coordinatedStatusBattle = new DclCanonicalBattleRuntime(
            runtime,
            battleGeneration: 16,
            initialGlobalCt: 100,
            coordinatedStatusRandom);
        coordinatedStatusBattle.ObserveUnit(caster);
        coordinatedStatusBattle.ObserveUnit(targetKey);
        var coordinatedStatusInput = statusInput with
        {
            Target = statusInput.Target with
            {
                CombatStateRevision = coordinatedStatusBattle.States.CaptureTarget(targetKey).Revision,
            },
        };
        CheckThrows<ArgumentException>(
            () => DclCanonicalAuxiliaryExecutionCoordinator.ResolveStatus(
                coordinatedStatusBattle,
                statusInput with
                {
                    ActionInstanceId = 704,
                    SharedCasterRoll = null,
                    ResistanceRoll = null,
                    StateRegistry = coordinatedStatusBattle.States,
                }),
            "confirmed auxiliary execution must reject a stale target custom-state revision before RNG, state mutation, or publication");
        Check(coordinatedStatusRandom.DrawCount == 0 && coordinatedStatusBattle.ExecutionRandom.Count == 0 &&
              coordinatedStatusBattle.States.Instances.Count == 0 &&
              coordinatedStatusBattle.NativeActions.Count == 0,
            "stale auxiliary target state must leave random, state, and native-application ledgers unchanged");
        DclCanonicalPublishedAuxiliaryExecution<DclCanonicalStatusExecutionResult> coordinatedStatus =
            DclCanonicalAuxiliaryExecutionCoordinator.ResolveStatus(
            coordinatedStatusBattle,
            coordinatedStatusInput with
            {
                ActionInstanceId = 705,
                SharedCasterRoll = null,
                ResistanceRoll = null,
                StateRegistry = coordinatedStatusBattle.States,
            },
            [new DclCanonicalReactionCandidate(
                0,
                targetKey,
                automaticReaction.ReactionId,
                TriggerSatisfied: false,
                Eligible: true,
                Aware: true,
                CostsAndUsesAvailable: true,
                ActivationReferenceScore: null,
                ActivationRoll: null,
                NativeCardinalityAllows: true)]);
        Check(coordinatedStatus.Result.Delivery is { Delivered: true, WinningMargin: 4 } &&
              coordinatedStatus.Result.StateApplication?.Instance.Kind == statusDefinition.Kind &&
              coordinatedStatus.Result.Reactions is { Candidates.Count: 1, Accepted.Count: 0 } &&
              ReferenceEquals(coordinatedStatus.Result.Reactions, coordinatedStatus.Application.Plan.Reactions) &&
              coordinatedStatusRandom.DrawCount == 6 && coordinatedStatusBattle.ExecutionRandom.Count == 2 &&
              coordinatedStatus.Application.Stage == DclCanonicalNativeActionStage.Published,
            "confirmed Internal Direct status must own casting/resistance, state commit, semantic projection, and publication in one coordinated operation");
        coordinatedStatus.Application.ApplyNextStrike(targetKey, 0);
        Check(DclCanonicalNativeApplyRouter.TryPreparePayment(
                  coordinatedStatusBattle,
                  705,
                  out DclCanonicalNativePaymentReservation coordinatedStatusPayment),
            "coordinated status must expose payment after its target carrier");
        DclCanonicalNativeApplyRouter.CommitPayment(coordinatedStatusPayment);
        DclCanonicalNativeApplyRouter.AcknowledgeReactionWindow(coordinatedStatusPayment);
        DclCanonicalNativeApplyRouter.SettleAndRetire(coordinatedStatusBattle, coordinatedStatusPayment);
        int stateCountBeforeInvalidReaction = coordinatedStatusBattle.States.Instances.Count;
        CheckThrows<KeyNotFoundException>(
            () => DclCanonicalAuxiliaryExecutionCoordinator.ResolveStatus(
                coordinatedStatusBattle,
                coordinatedStatusInput with
                {
                    ActionInstanceId = 706,
                    SharedCasterRoll = null,
                    ResistanceRoll = null,
                    StateRegistry = coordinatedStatusBattle.States,
                    Target = coordinatedStatusInput.Target with
                    {
                        CombatStateRevision = coordinatedStatusBattle.States.CaptureTarget(targetKey).Revision,
                    },
                },
                [new DclCanonicalReactionCandidate(
                    0,
                    targetKey,
                    "missing-reaction",
                    TriggerSatisfied: true,
                    Eligible: true,
                    Aware: true,
                    CostsAndUsesAvailable: true,
                    ActivationReferenceScore: null,
                    ActivationRoll: null,
                    NativeCardinalityAllows: true)]),
            "confirmed execution must reject an unresolved Reaction identity before RNG, state mutation, or publication");
        Check(coordinatedStatusRandom.DrawCount == 6 && coordinatedStatusBattle.ExecutionRandom.Count == 2 &&
              coordinatedStatusBattle.States.Instances.Count == stateCountBeforeInvalidReaction &&
              coordinatedStatusBattle.NativeActions.Count == 0,
            "Reaction preflight failure must leave random, state, and native-application ledgers unchanged");
        CheckThrows<ArgumentException>(
            () => DclCanonicalAuxiliaryExecutionCoordinator.ResolveStatus(
                coordinatedStatusBattle,
                coordinatedStatusInput with
                {
                    ActionInstanceId = 707,
                    StateRegistry = coordinatedStatusBattle.States,
                    Target = coordinatedStatusInput.Target with
                    {
                        CombatStateRevision = coordinatedStatusBattle.States.CaptureTarget(targetKey).Revision,
                    },
                }),
            "confirmed status execution must reject pre-supplied casting/resistance rolls before touching a new ActionInstance stream");
        Check(coordinatedStatusRandom.DrawCount == 6 && coordinatedStatusBattle.ExecutionRandom.Count == 2,
            "invalid confirmed status metadata must leave the execution ledger unchanged");

        var immuneStatusRandom = new SequenceRandomSource([3, 3, 4]);
        var immuneStatusBattle = new DclCanonicalBattleRuntime(
            runtime,
            battleGeneration: 16,
            initialGlobalCt: 100,
            immuneStatusRandom);
        immuneStatusBattle.ObserveUnit(caster);
        immuneStatusBattle.ObserveUnit(targetKey);
        DclCanonicalStatusExecutionResult coordinatedImmuneStatus = DclCanonicalStatusExecutor.Resolve(
            runtime,
            statusInput with
            {
                ActionInstanceId = 707,
                SharedCasterRoll = null,
                ResistanceRoll = null,
                Immune = true,
                StateRegistry = immuneStatusBattle.States,
                ExecutionBattle = immuneStatusBattle,
                ReactionWindow = DclCanonicalReactionWindow.ConfirmedRequest(immuneStatusBattle, null),
                Target = statusInput.Target with
                {
                    CombatStateRevision = immuneStatusBattle.States.CaptureTarget(targetKey).Revision,
                },
            });
        Check(coordinatedImmuneStatus.Delivery is
              { Outcome: DclMagicDeliveryOutcome.Resisted, ResistanceRoll: null } &&
              immuneStatusRandom.DrawCount == 3 && immuneStatusBattle.ExecutionRandom.Count == 1,
            "confirmed status immunity must consume the shared casting site but short-circuit before target resistance RNG");

        var riderRegistry = new DclStateRegistry(16, initialGlobalCt: 100);
        DclCastDeclarationRequest riderRequest = request with { Profile = riderAction };
        var riderMaterialization = statusMaterialization with
        {
            AppliedBeforeTurnSerial = 41,
            DurationUnits = 7,
        };
        var riderInput = hitInput with
        {
            AbilityId = 17,
            DeclarationRequest = riderRequest,
            ActionInstanceId = 514,
            StatusRiders =
            [
                new DclCanonicalStatusRiderInput(
                    EffectIndex: 1,
                    ResistanceScore: 9,
                    ResistanceRoll: 11,
                    Immune: false,
                    riderRegistry,
                    riderMaterialization),
            ],
        };
        DclCanonicalMagicExecutionResult appliedRider = DclCanonicalMagicExecutor.Resolve(runtime, riderInput);
        Check(appliedRider.Effect is { FinalInjury: 5 } &&
              appliedRider.StatusRiders.Single() is
              {
                  Gate: { Attempted: true, Applied: true, CasterMargin: 2 },
                  StateApplication.Instance.ExpiresAtGlobalCt: 107,
              } &&
              appliedRider.Transaction is { ReactionWindowOpened: true } &&
              appliedRider.Transaction.VisibleEffects.Count == 2,
            "a landed damage Carrier must resolve its status Rider with the reused caster roll, materialize the state before one Reaction window, and expose both ordered effects");
        DclCanonicalNativeCarrierProjection appliedRiderProjection =
            DclCanonicalNativeCarrierProjector.ProjectMagic(runtime, 17, caster, appliedRider);
        DclCanonicalNativeActionApplication appliedRiderCarrier =
            DclCanonicalNativeExecutionPublisher.PublishMagic(battleRuntime, 17, caster, appliedRider);
        DclCanonicalNativeStrikeProjection appliedRiderStrike = appliedRiderCarrier.PeekNextStrike();
        DclCanonicalNativeAuxiliaryApplyPlan appliedRiderNative =
            DclCanonicalNativeAuxiliaryApplyPlanner.Build(runtime, appliedRiderStrike);
        DclCanonicalNativeAuxiliaryEffects projectedRiderAuxiliary =
            appliedRiderProjection.TargetResult?.AuxiliaryEffects ??
            throw new InvalidOperationException("applied Rider projection lost its auxiliary effects");
        Check(projectedRiderAuxiliary.AddedStates.Single() is
              { StateKind: "canonical-status-test" },
            "a direct-magic status Rider must retain its exact state instance in native projection");
        Check(appliedRiderStrike.AuxiliaryEffects?.AddedStates.Single() ==
              projectedRiderAuxiliary.AddedStates.Single(),
            "a direct-magic status Rider must retain its auxiliary projection through ledger publication");
        Check(appliedRiderNative.StatusPacketMutations.Single() is
              { Add: true, Bit.ByteIndex: 1, Bit.Mask: 0x02 },
            "a native direct-magic status Rider must reach its exact owned packet bit");
        appliedRiderCarrier.ApplyNextStrike(targetKey, 0);
        Check(DclCanonicalNativeApplyRouter.TryPreparePayment(
                  battleRuntime,
                  appliedRider.Declaration.ActionInstanceId,
                  out DclCanonicalNativePaymentReservation appliedRiderPayment),
            "a direct-magic Rider carrier must reach payment only after its combined numeric/status target apply");
        DclCanonicalNativeApplyRouter.CommitPayment(appliedRiderPayment);
        DclCanonicalNativeApplyRouter.AcknowledgeReactionWindow(appliedRiderPayment);
        DclCanonicalNativeApplyRouter.SettleAndRetire(battleRuntime, appliedRiderPayment);
        int riderStateCount = riderRegistry.Instances.Count;
        DclCanonicalMagicExecutionResult resistedRider = DclCanonicalMagicExecutor.Resolve(
            runtime,
            riderInput with
            {
                ActionInstanceId = 515,
                StatusRiders =
                [
                    riderInput.StatusRiders!.Single() with { ResistanceScore = 10, ResistanceRoll = 8 },
                ],
            });
        Check(resistedRider.Effect is { FinalInjury: 5 } &&
              resistedRider.StatusRiders.Single().Gate is { Attempted: true, Applied: false } &&
              resistedRider.Transaction?.VisibleEffects.Count == 1 && riderRegistry.Instances.Count == riderStateCount,
            "a tied Rider contest must preserve Carrier damage but commit no Rider state");
        DclCanonicalMagicExecutionResult defendedRider = DclCanonicalMagicExecutor.Resolve(
            runtime,
            riderInput with
            {
                ActionInstanceId = 516,
                DefenseRoll = 9,
                MagnitudeDice = null,
                InjuryConsequenceInput = null,
                StatusRiders =
                [
                    riderInput.StatusRiders!.Single() with { ResistanceRoll = null },
                ],
            });
        Check(defendedRider.Delivery?.Outcome == DclMagicDeliveryOutcome.Defended &&
              defendedRider.StatusRiders.Single().Gate is { Attempted: false, Applied: false } &&
              defendedRider.Transaction?.VisibleEffects.Count == 0,
            "a defended Carrier must stop its Rider before resistance RNG");
        DclCanonicalMagicEvaluationResult directRiderEvaluation =
            DclCanonicalMagicEvaluationExecutor.Evaluate(
                runtime,
                hitEvaluationInput with
                {
                    AbilityId = 17,
                    DeclarationRequest = riderRequest,
                    StatusRiders = [new DclMagicStatusRiderForecast(1, 9, Immune: false)],
                });
        DclRational expectedDirectRider = DclRational.FromInteger(0);
        for (int casterRoll = DclSuccessRoll.MinRoll; casterRoll <= DclSuccessRoll.MaxRoll; casterRoll++)
        {
            DclSpellGateResult gate = DclSpellResolution.ClassifySharedRoll(casterRoll, 12, 12);
            if (!gate.TargetSucceeded) continue;
            DclRational landed = gate.TargetCritical
                ? DclRational.FromInteger(1)
                : DclRational.FromInteger(1) - new DclRational(
                    DclSuccessRoll.SuccessOutcomeCount(9), 216);
            int riderWins = 0;
            for (int resistanceRoll = DclSuccessRoll.MinRoll;
                 resistanceRoll <= DclSuccessRoll.MaxRoll;
                 resistanceRoll++)
            {
                if (DclQuickContest.Resolve(12, casterRoll, 9, resistanceRoll).ActingSideWon)
                    riderWins += DclSuccessRoll.OutcomeMultiplicity(resistanceRoll);
            }
            expectedDirectRider += new DclRational(
                    DclSuccessRoll.OutcomeMultiplicity(casterRoll), 216) *
                landed * new DclRational(riderWins, 216);
        }
        DclCanonicalMagicForecastProjection directRiderForecast =
            DclCanonicalMagicForecastProjection.From(directRiderEvaluation);
        DclCanonicalMagicAiProjection directRiderAi =
            DclCanonicalMagicAiProjection.From(directRiderEvaluation);
        Check(directRiderEvaluation.RiderApplicationProbability.Single() is
              { Key: 1, Value: var directRiderProbability } &&
              directRiderProbability == expectedDirectRider &&
              directRiderProbability < directRiderEvaluation.DeliveryProbability &&
              directRiderAi.RiderApplicationProbability[1] == directRiderProbability &&
              directRiderForecast.RiderApplicationPercent[1] ==
                  checked((int)(directRiderProbability * DclRational.FromInteger(100)).RoundNearest()),
            "direct numeric Rider forecast and AI must enumerate the shared Carrier draw, conditional defense, and authored resistance gate exactly without execution RNG");

        DclActionDeclaration physicalDeclaration = new(
            ActionInstanceId: 517,
            caster,
            physicalAction.ActionId,
            physicalAction.ProfileRevision,
            DclTargetMode.Unit,
            targetKey,
            FixedTile: null,
            new DclBattleTile(0, 0, 0),
            PassedRangeCheck: true,
            PassedVerticalCheck: true,
            FinalMpCost: 0,
            ApprovedHpCap: 0,
            CastCt: 0,
            DeclaredAtGlobalCt: 100,
            ResolvesAtGlobalCt: 100);
        var physicalTarget = new DclTargetResolutionSnapshot(
            targetKey,
            CurrentHp: 20,
            CombatStateRevision: 9,
            new DclDefenseResourceSnapshot(
                new Dictionary<string, int> { ["main-hand"] = 0 },
                BlockAvailable: true));
        var physicalTargetContext = new DclCanonicalPhysicalTargetContext(
            targetKey,
            MaxHp: 20,
            TargetSt: 10,
            EffectiveHt: 10,
            UnexpiredShockInjury: 0,
            Charging: false,
            Will: 10,
            ConcentrationModifier: 0,
            ConcentrationStatePenaltyMagnitude: 0);
        DclDefenseCandidate[] PhysicalDefenses() =>
        [
            new DclDefenseCandidate(DclDefenseKind.Dodge, 8, Legal: true, "available"),
            new DclDefenseCandidate(DclDefenseKind.Parry, 10, Legal: true, "available", "main-hand"),
            new DclDefenseCandidate(DclDefenseKind.Block, 7, Legal: true, "available"),
        ];
        var physicalTurnResources = new DclTurnResources();
        var physicalWeaponState = new DclWeaponActionState(
            "main-hand",
            sentinelWeapon.Weapon!.Balance,
            sentinelWeapon.Weapon.Readiness);
        var physicalInput = new DclCanonicalPhysicalExecutionInput(
            AbilityId: 358,
            physicalDeclaration,
            WeaponItemId: 19,
            SourceSt: 10,
            Targets: [physicalTarget],
            TargetContexts: [physicalTargetContext],
            Strikes:
            [
                new DclCanonicalPhysicalStrikeInput(targetKey, 0, 12, AttackRoll: 10, PhysicalDefenses(), DefenseRoll: 11, DamageDice: [5], ApplicableDr: 3),
                new DclCanonicalPhysicalStrikeInput(targetKey, 1, 12, AttackRoll: 10, PhysicalDefenses(), DefenseRoll: 9, DamageDice: [5], ApplicableDr: 3),
                new DclCanonicalPhysicalStrikeInput(targetKey, 2, 12, AttackRoll: 10, PhysicalDefenses(), DefenseRoll: 8, DamageDice: null, ApplicableDr: 3),
                new DclCanonicalPhysicalStrikeInput(targetKey, 3, 12, AttackRoll: 4, PhysicalDefenses(), DefenseRoll: null, DamageDice: [5], ApplicableDr: 3),
            ],
            physicalTurnResources,
            physicalWeaponState,
            ReactionWindow: new DclCanonicalReactionWindowRequest(runtime, []));
        DclCanonicalPhysicalExecutionResult physical = DclCanonicalPhysicalExecutor.Resolve(runtime, physicalInput);
        Check(physical.Strikes[0].Contest is { DefenseKind: DclDefenseKind.Parry, Outcome: DclPhysicalOutcome.Hit } &&
              physical.Strikes[1].Contest is { DefenseKind: DclDefenseKind.Dodge, Outcome: DclPhysicalOutcome.Hit } &&
              physical.Strikes[2].Contest is { DefenseKind: DclDefenseKind.Dodge, Outcome: DclPhysicalOutcome.Defended } &&
              physical.Strikes[3].Contest is { DefenseKind: DclDefenseKind.None, Outcome: DclPhysicalOutcome.CriticalHit } &&
              physical.Strikes.Where(strike => strike.Injury is not null).All(strike => strike.Injury!.Value.Injury == 4) &&
              physical.Strikes[0].Consequences is { UnexpiredShockInjury: 4, ShockPenaltyMagnitude: 2 } &&
              physical.Strikes[1].Consequences is { UnexpiredShockInjury: 8, ShockPenaltyMagnitude: 3 } &&
              physical.Strikes[3].Consequences is { UnexpiredShockInjury: 12, ShockPenaltyMagnitude: 3 } &&
              physical.Commit.Transaction is { Stage: DclActionTransactionStage.Settled, ReactionWindowOpened: true } &&
              physical.Commit.Transaction.VisibleEffects.Count == 3 &&
              !physicalTurnResources.ActionAvailable && physicalTurnResources.MovementAvailable && physicalWeaponState.Ready,
            "canonical Barrage must use weapon ST dice and DR/Injury, spend the first Parry attempt, prefer Dodge after the cumulative -4, bypass defense on critical, and open one Reaction window");
        DclCanonicalPhysicalEvaluationResult physicalEvaluation =
            DclCanonicalPhysicalEvaluation.Evaluate(
                runtime,
                new DclCanonicalPhysicalEvaluationInput(
                    AbilityId: 358,
                    WeaponItemId: 19,
                    SourceSt: 10,
                    Targets: [physicalTarget],
                    Strikes: physicalInput.Strikes.Select(strike => strike with
                    {
                        AttackRoll = null,
                        DefenseRoll = null,
                        DamageDice = null,
                        MajorWoundHtRoll = null,
                        ConcentrationRoll = null,
                        AimRetentionRoll = null,
                    }).ToArray()));
        DclCanonicalPhysicalTargetEvaluation physicalTargetEvaluation = physicalEvaluation.Targets.Single();
        DclRational PhysicalOutcomeProbability(int strikeIndex, DclPhysicalOutcome outcome)
            => physicalTargetEvaluation.OutcomeProbabilityByStrike[strikeIndex]
                .TryGetValue(outcome, out DclRational probability)
                    ? probability
                    : DclRational.FromInteger(0);
        DclRational DefenseSelectionProbability(int strikeIndex, DclDefenseKind defense)
            => physicalTargetEvaluation.DefenseSelectionProbabilityByStrike[strikeIndex]
                .TryGetValue(defense, out DclRational probability)
                    ? probability
                    : DclRational.FromInteger(0);
        DclRational firstHitProbability =
            PhysicalOutcomeProbability(0, DclPhysicalOutcome.Hit) +
            PhysicalOutcomeProbability(0, DclPhysicalOutcome.CriticalHit);
        DclExactProbability expectedFirstHit = DclPhysicalContest.HitProbability(
            attackSkill: 12,
            new DclDefenseOption(DclDefenseKind.Parry, 10, Depletes: true));
        IReadOnlyList<DclCanonicalPhysicalPlayerForecast> physicalPlayer =
            DclCanonicalPhysicalEvaluation.ProjectPlayer(physicalEvaluation);
        IReadOnlyList<DclCanonicalPhysicalAiProjection> physicalAi =
            DclCanonicalPhysicalEvaluation.ProjectAi(physicalEvaluation);
        Check(firstHitProbability == expectedFirstHit.Fraction &&
              physicalTargetEvaluation.DefenseSelectionProbabilityByStrike[0].Keys.SequenceEqual([DclDefenseKind.Parry]) &&
              DefenseSelectionProbability(1, DclDefenseKind.Parry) > DclRational.FromInteger(0) &&
