            new DclWeaponBoundStatePayload(
                projectionBound.PayloadSchema,
                "main-hand",
                SuppressAttack: false,
                SuppressParry: false,
                SuppressWeaponReactions: true,
                WeaponSkillPenalty: -2),
            duration: 1,
            strength: 2,
            discriminator: "main-hand"));
        stateProjectionBattle.States.Apply(ProjectionState(
            projectionGuard,
            targetKey,
            new DclGuardBrokenStatePayload(projectionGuard.PayloadSchema, SuppressBlock: true, ParryPenalty: 3),
            duration: 1,
            strength: 1_000_003));
        stateProjectionBattle.States.Apply(ProjectionState(
            projectionBulwark,
            targetKey,
            new DclBulwarkStatePayload(
                projectionBulwark.PayloadSchema,
                new DclBulwarkPayload(2, 3, 4, "native-passability")),
            duration: null));
        DclCanonicalPhysicalStrikeInput projectedStateStrike =
            DclCanonicalActionStateProjection.ProjectPhysicalStrikes(
                stateProjectionBattle,
                caster,
                "main-hand",
                [new DclCanonicalPhysicalStrikeInput(
                    targetKey,
                    StrikeIndex: 0,
                    EffectiveAttackSkill: 12,
                    AttackRoll: null,
                    DefenseCandidates:
                    [
                        new DclDefenseCandidate(DclDefenseKind.Dodge, 8, Legal: true, "available"),
                        new DclDefenseCandidate(DclDefenseKind.Parry, 10, Legal: true, "available", "main-hand"),
                        new DclDefenseCandidate(DclDefenseKind.Block, 7, Legal: true, "available"),
                    ],
                    DefenseRoll: null,
                    DamageDice: null,
                    ApplicableDr: 3)])[0];
        Check(projectedStateStrike.EffectiveAttackSkill == 10 && projectedStateStrike.ApplicableDr == 6 &&
              projectedStateStrike.DefenseCandidates.Single(candidate => candidate.Kind == DclDefenseKind.Dodge)
                  is { Legal: true, Score: 8 } &&
              projectedStateStrike.DefenseCandidates.Single(candidate => candidate.Kind == DclDefenseKind.Parry)
                  is { Legal: true, Score: 7 } &&
              projectedStateStrike.DefenseCandidates.Single(candidate => candidate.Kind == DclDefenseKind.Block)
                  is { Legal: false, Score: 9, Reason: "guard-broken-suppresses-block" },
