        Check(physicalCoordinatorRandom.DrawCount == 0 && physicalCoordinatorBattle.ExecutionRandom.Count == 0,
            "invalid physical execution metadata must not perturb any future random site");
        CheckThrows<ArgumentException>(
            () => DclCanonicalPhysicalExecutionCoordinator.ResolveAndPublish(
                physicalCoordinatorBattle,
