        Check(physicalCoordinatorRandom.DrawCount == 0 && physicalCoordinatorBattle.ExecutionRandom.Count == 0 &&
              physicalCoordinatorBattle.NativeActions.Count == 0,
            "stale physical state metadata must leave execution and native-action ledgers unchanged");
        var protectionPhysicalRandom = new SequenceRandomSource(
        [
            3, 3, 4,
            3, 4, 4,
            5,
            3, 3, 4,
            3, 3, 3,
            5,
            3, 3, 4,
            2, 3, 3,
            1, 1, 2,
            5,
