        DclUnitKey physicalProtector = new(16, 7, 107);
        protectionPhysicalBattle.ObserveUnit(caster);
        protectionPhysicalBattle.ObserveUnit(targetKey);
        protectionPhysicalBattle.ObserveUnit(physicalProtector);
        DclStateApplicationResult physicalProtectionState = protectionPhysicalBattle.ApplyState(new DclStateApplication(
            protectionDefinition,
            physicalProtector,
            physicalProtector,
            AppliedAtGlobalCt: 100,
            AppliedBeforeTurnSerial: 43,
            FirstEligibleTargetTurnSerial: null,
            FirstEligibleSourceTurnSerial: null,
            DurationUnits: 1,
            Strength: null,
            WinningMargin: null,
            StackDiscriminator: targetKey.ToString(),
            ContributionIdentity: null,
            new DclProtectionStatePayload(
                protectionDefinition.PayloadSchema,
                new DclProtectionPayload(
                    targetKey,
                    new HashSet<DclDelivery> { DclDelivery.PhysicalAttack },
                    AdjacencyOrRangeRule: "adjacent",
                    RemainingIntercepts: 1,
                    ExpiresAfterSourceTurnSerial: 50)),
            protectionDefinition.PresentationProfile));
        var physicalProtectionPlan = protectionPhysicalBattle.PlanProtectionRedirect(
            new DclCanonicalProtectionRedirectCandidate(
                physicalProtectionState.Instance.InstanceId,
