                DclDelivery.PhysicalAttack,
                RangeOrAdjacencyLegal: true,
                ProtectorCanReceiveHit: true));
        DclCanonicalPhysicalStrikeInput[] protectedPhysicalStrikes = coordinatedStrikeRequests
            .Select(strike => strike with { Target = physicalProtector })
