        var protectedPhysicalTarget = physicalTarget with
        {
            Target = physicalProtector,
            CombatStateRevision = protectionPhysicalBattle.States.CaptureTarget(physicalProtector).Revision,
            DefenseResources = protectionPhysicalBattle.CaptureDefenseResources(physicalProtector, protectedParryKeys),
        };
        var protectedPhysicalRequest = physicalCoordinatorRequest with
        {
            Declaration = physicalCoordinatorRequest.Declaration with { ActionInstanceId = 621 },
            Targets = [protectedPhysicalTarget],
            TargetContexts = [physicalTargetContext with { Target = physicalProtector }],
            Strikes = protectedPhysicalStrikes,
            ReactionCandidates = [],
            ProtectionRedirect = physicalProtectionPlan,
        };
        CheckThrows<ArgumentException>(
            () => DclCanonicalPhysicalExecutionCoordinator.ResolveAndPublish(
                protectionPhysicalBattle,
