                {
                    Targets =
                    [
                        physicalCoordinatorRequest.Targets.Single() with
                        {
                            CombatStateRevision =
                                protectionPhysicalBattle.States.CaptureTarget(targetKey).Revision,
                            DefenseResources = protectionPhysicalBattle.CaptureDefenseResources(targetKey, protectedParryKeys),
                        },
                    ],
                }),
            "confirmed physical Cover routing must reject a request whose final target does not match the planned protector before mutation");
        Check(protectionPhysicalBattle.States.TryGet(physicalProtectionState.Instance.InstanceId, out _) &&
              protectionPhysicalRandom.DrawCount == 0 && protectionPhysicalBattle.ExecutionRandom.Count == 0 &&
              protectionPhysicalBattle.NativeActions.Count == 0,
            "rejected physical Cover routing must preserve the intercept state and every RNG/native ledger");
        DclCanonicalPhysicalPlanningResult protectedPhysicalPlanning =
            DclCanonicalPhysicalPlanningCoordinator.Evaluate(
                protectionPhysicalBattle,
                caster,
                "main-hand",
                new DclCanonicalPhysicalEvaluationInput(
                    protectedPhysicalRequest.AbilityId,
                    protectedPhysicalRequest.WeaponItemId,
                    protectedPhysicalRequest.SourceSt,
                    protectedPhysicalRequest.Targets,
                    protectedPhysicalRequest.Strikes,
                    protectedPhysicalRequest.TargetContexts,
                    StrikeWeapons: protectedPhysicalRequest.StrikeWeapons),
                selectedTarget: targetKey,
                protectionRedirect: physicalProtectionPlan);
        Check(protectedPhysicalPlanning is
              {
                  StatePlan.Legal: true,
                  ProtectionRedirect.Resolution.FinalTarget: var plannedProtectedTarget,
                  Evaluation.Targets.Count: 1,
                  PlayerForecast.Count: 1,
                  AiProjection.Count: 1,
              } &&
              plannedProtectedTarget == physicalProtector &&
              protectedPhysicalPlanning.PlayerForecast.Single().Target == physicalProtector &&
              protectedPhysicalPlanning.AiProjection.Single().Target == physicalProtector &&
              protectionPhysicalBattle.States.TryGet(physicalProtectionState.Instance.InstanceId, out _) &&
              protectionPhysicalRandom.DrawCount == 0 && protectionPhysicalBattle.ExecutionRandom.Count == 0 &&
              protectionPhysicalBattle.NativeActions.Count == 0,
            "physical Cover forecast and AI planning must route to the protector without consuming the declared protection state or RNG");
        DclCanonicalPublishedPhysicalExecution protectedPhysical =
            DclCanonicalPhysicalExecutionCoordinator.ResolveAndPublish(
                protectionPhysicalBattle,
                protectedPhysicalRequest);
        Check(protectedPhysical.Result.ProtectionRedirect is
              {
                  Trigger.Trigger.Triggered: true,
                  FinalTarget: var finalProtectedPhysicalTarget,
              } &&
              finalProtectedPhysicalTarget == physicalProtector &&
              protectedPhysical.Result.Commit.Transaction.Declaration.TrackedTarget == targetKey &&
              protectedPhysical.Result.Strikes.All(strike => strike.Target == physicalProtector) &&
              protectedPhysical.Application.Plan.Strikes.All(strike => strike.Target == physicalProtector) &&
              protectedPhysical.Application.Plan.Strikes[0].AuxiliaryEffects?.RemovedStates.Single()
                  is { InstanceId: var removedPhysicalProtection, StateKind: "canonical-protection-test" } &&
              removedPhysicalProtection == physicalProtectionState.Instance.InstanceId &&
              !protectionPhysicalBattle.States.TryGet(physicalProtectionState.Instance.InstanceId, out _) &&
              protectionPhysicalRandom.DrawCount > 0 && protectionPhysicalBattle.NativeActions.Count == 1,
            "confirmed physical Cover routing must keep the declared target for transaction identity while resolving and publishing every Strike against the protector");
        DclCanonicalPublishedPhysicalExecution coordinatedPhysical =
            DclCanonicalPhysicalExecutionCoordinator.ResolveAndPublish(
                physicalCoordinatorBattle,
                physicalCoordinatorRequest);
        Check(coordinatedPhysical.Result.Strikes.Select(strike => strike.Contest?.Outcome).SequenceEqual(
              [DclPhysicalOutcome.Hit, DclPhysicalOutcome.Hit, DclPhysicalOutcome.Defended, DclPhysicalOutcome.CriticalHit]) &&
              coordinatedPhysical.Result.Strikes.Where(strike => strike.Injury is not null)
                  .All(strike => strike.Injury!.Value.Injury == 4 &&
                      strike.InjuryStates?.Shock?.Instance.Kind == "shock") &&
              physicalCoordinatorBattle.States.Instances.Count(instance => instance.Kind == "shock") == 1 &&
              coordinatedPhysical.Application.Plan.Strikes.Where(strike => strike.Channels.HpDebit > 0)
                  .All(strike => strike.AuxiliaryEffects?.AddedStates.Any(state =>
                      state.StateKind == "shock") == true) &&
              coordinatedPhysical.Result.Commit.Reactions is
              {
                  Accepted: [{ Definition.ReactionId: "canonical.reaction.automatic" }],
              } coordinatedPhysicalReactions &&
              ReferenceEquals(coordinatedPhysical.Application.Plan.Reactions, coordinatedPhysicalReactions) &&
              physicalCoordinatorRandom.DrawCount == 24 && physicalCoordinatorBattle.ExecutionRandom.Count == 10 &&
              coordinatedPhysical.Application.Stage == DclCanonicalNativeActionStage.Published,
            "the physical execution coordinator must own its attack/defense/damage sites, resolve the same outer ActionInstance's Reaction window, and publish the immutable Barrage action");

        if (_stopCanonicalRuntimeAfterInjuryMovement)
            Console.WriteLine("injury-movement: physical execution");
        string unarmedResource = DclCanonicalPhysicalStrikeWeapons.PrimaryUnarmedResourceKey;
        var knockbackWeaponState = new DclWeaponActionState(
            unarmedResource,
            sentinelUnarmed.Weapon!.Balance,
            sentinelUnarmed.Weapon.Readiness);
        var knockbackBranches = new DclCanonicalInjuryMovementBranchSet(
            DclForcedMovementDirection.AwayFromSource,
            new Dictionary<int, DclCanonicalNativeMovementVerdict>
            {
                [1] = new(
                    targetKey,
                    target.Tile,
                    target.Tile with { X = target.Tile.X + 1 },
                    RequestedTiles: 1,
                    MovedTiles: 1,
                    DclForcedMovementDirection.AwayFromSource,
                    Fell: false,
                    NativePathResolved: true),
            });
        DclBattleTile firstKnockbackDestination = target.Tile with { X = target.Tile.X + 1 };
        DclBattleTile secondKnockbackDestination = firstKnockbackDestination with
        {
            X = firstKnockbackDestination.X + 1,
        };
        DclBattleTile thirdKnockbackDestination = secondKnockbackDestination with
        {
            X = secondKnockbackDestination.X + 1,
        };
        DclBattleTile fourthKnockbackDestination = thirdKnockbackDestination with
        {
            X = thirdKnockbackDestination.X + 1,
        };
        var chainedKnockbackBranches = new DclCanonicalInjuryMovementBranchSet(
            DclForcedMovementDirection.AwayFromSource,
            new Dictionary<int, DclCanonicalNativeMovementVerdict>
            {
                [1] = new(
                    targetKey,
                    firstKnockbackDestination,
                    secondKnockbackDestination,
                    RequestedTiles: 1,
                    MovedTiles: 1,
                    DclForcedMovementDirection.AwayFromSource,
                    Fell: false,
                    NativePathResolved: true),
            });
        var secondStrikeKnockbackForest = new DclCanonicalInjuryMovementBranchForest(
