                [firstKnockbackDestination] = chainedKnockbackBranches,
            });
        DclCanonicalInjuryMovementBranchSet thirdKnockbackBranches = new(
            DclForcedMovementDirection.AwayFromSource,
            new Dictionary<int, DclCanonicalNativeMovementVerdict>
            {
                [1] = new(
                    targetKey,
                    secondKnockbackDestination,
                    thirdKnockbackDestination,
                    RequestedTiles: 1,
                    MovedTiles: 1,
                    DclForcedMovementDirection.AwayFromSource,
                    Fell: false,
                    NativePathResolved: true),
            });
        DclCanonicalInjuryMovementBranchSet fourthKnockbackBranches = new(
            DclForcedMovementDirection.AwayFromSource,
            new Dictionary<int, DclCanonicalNativeMovementVerdict>
            {
                [1] = new(
                    targetKey,
                    thirdKnockbackDestination,
                    fourthKnockbackDestination,
                    RequestedTiles: 1,
                    MovedTiles: 1,
                    DclForcedMovementDirection.AwayFromSource,
                    Fell: false,
                    NativePathResolved: true),
            });
        var thirdStrikeKnockbackForest = new DclCanonicalInjuryMovementBranchForest(
            new Dictionary<DclBattleTile, DclCanonicalInjuryMovementBranchSet>
            {
                [target.Tile] = knockbackBranches,
                [firstKnockbackDestination] = chainedKnockbackBranches,
                [secondKnockbackDestination] = thirdKnockbackBranches,
            });
        var fourthStrikeKnockbackForest = new DclCanonicalInjuryMovementBranchForest(
            new Dictionary<DclBattleTile, DclCanonicalInjuryMovementBranchSet>
            {
                [target.Tile] = knockbackBranches,
                [firstKnockbackDestination] = chainedKnockbackBranches,
                [secondKnockbackDestination] = thirdKnockbackBranches,
                [thirdKnockbackDestination] = fourthKnockbackBranches,
            });
        DclCanonicalPhysicalStrikeInput[] knockbackStrikes = Enumerable.Range(0, 4)
            .Select(index => new DclCanonicalPhysicalStrikeInput(
                targetKey,
                index,
                EffectiveAttackSkill: 12,
                AttackRoll: index <= 1 ? 4 : 18,
                DefenseCandidates: [],
                DefenseRoll: null,
                DamageDice: index <= 1 ? [5] : null,
                ApplicableDr: 0,
                InjuryMovementBranches: index == 0 ? knockbackBranches : null,
                InjuryMovementBranchForest: index switch
                {
                    1 => secondStrikeKnockbackForest,
                    2 => thirdStrikeKnockbackForest,
                    3 => fourthStrikeKnockbackForest,
                    _ => null,
                }))
            .ToArray();
        DclCanonicalPhysicalExecutionResult criticalKnockback = DclCanonicalPhysicalExecutor.Resolve(
            runtime,
            physicalInput with
            {
                Declaration = physicalDeclaration with { ActionInstanceId = 621 },
                WeaponItemId = 0,
                TargetContexts =
                [
                    physicalTargetContext with
                    {
                        TargetSt = 5,
                        MovementOrigin = target.Tile,
                    },
                ],
                Strikes = knockbackStrikes,
                TurnResources = new DclTurnResources(),
                WeaponActionState = knockbackWeaponState,
                StrikeWeapons = Enumerable.Range(0, 4)
                    .Select(index => new DclCanonicalPhysicalStrikeWeapon(index, 0, unarmedResource))
                    .ToArray(),
            });
        DclCanonicalNativeMultiCarrierProjection criticalKnockbackProjection =
            DclCanonicalNativeCarrierProjector.ProjectPhysical(runtime, 358, criticalKnockback);
        if (_stopCanonicalRuntimeAfterInjuryMovement)
        {
            DclCanonicalPhysicalStrikeResult firstKnockback = criticalKnockback.Strikes[0];
            Console.WriteLine(
                $"injury-movement: physical actual outcome={firstKnockback.Contest?.Outcome} " +
                $"injury={firstKnockback.Injury?.Injury} criticalTiles={firstKnockback.Consequences?.CriticalKnockbackTiles} " +
                $"moved={firstKnockback.ForcedMovement?.MovedTiles} cancelAim={firstKnockback.ForcedMovement?.CancelAim} " +
                $"projected={criticalKnockbackProjection.Strikes[0].AuxiliaryEffects?.ForcedMovement?.MovedTiles} " +
                $"laterMovement={criticalKnockback.Strikes.Skip(1).Count(strike => strike.ForcedMovement is not null)} " +
                $"reactionsNull={criticalKnockback.Commit.Reactions is null}");
        }
        Check(criticalKnockback.Strikes[0] is
              {
                  Contest.Outcome: DclPhysicalOutcome.CriticalHit,
                  Injury.Injury: 3,
                  Consequences: { CriticalKnockbackTiles: 1, TotalForcedDisplacement: 1 },
                  ForcedMovement:
                  {
                      RequestedTiles: 1,
                      MovedTiles: 1,
                      CancelAim: true,
                      SuppressedByTargetKo: false,
                  },
              } && criticalKnockback.Strikes[1] is
              {
                  Contest.Outcome: DclPhysicalOutcome.CriticalHit,
                  Injury.Injury: 3,
                  Consequences: { CriticalKnockbackTiles: 1, TotalForcedDisplacement: 1 },
                  ForcedMovement:
                  {
                      Origin: var secondMovementOrigin,
                      Destination: var secondMovementDestination,
                      RequestedTiles: 1,
                      MovedTiles: 1,
                      CancelAim: true,
                      SuppressedByTargetKo: false,
                  },
              } && secondMovementOrigin == firstKnockbackDestination &&
              secondMovementDestination == secondKnockbackDestination &&
              criticalKnockback.Strikes.Skip(2).All(strike => strike.ForcedMovement is null) &&
              criticalKnockbackProjection.Strikes[0].AuxiliaryEffects?.ForcedMovement ==
                  criticalKnockback.Strikes[0].ForcedMovement &&
              criticalKnockbackProjection.Strikes[1].AuxiliaryEffects?.ForcedMovement ==
                  criticalKnockback.Strikes[1].ForcedMovement &&
              criticalKnockback.Commit.Reactions is { Candidates.Count: 0, Accepted.Count: 0 } &&
              criticalKnockback.Commit.Transaction.ReactionWindowOpened,
            "successive critical crushing Strikes must select one contiguous conditional movement timeline with only the empty outer Reaction window");
        DclCanonicalNativeActionApplication chainedKnockbackApplication =
            new DclCanonicalNativeActionLedger(caster.BattleGeneration).Publish(
                caster,
                physicalBinding,
                criticalKnockbackProjection);
        Check(chainedKnockbackApplication.Stage == DclCanonicalNativeActionStage.Published,
            "native publication must accept a contiguous multi-Strike movement origin timeline");
        DclBattleTile appliedPhysicalMovementTile = target.Tile;
        foreach (DclCanonicalNativeStrikeProjection projectedStrike in criticalKnockbackProjection.Strikes)
        {
            DclCanonicalNativeStrikeProjection appliedStrike = chainedKnockbackApplication.ApplyNextStrike(
                projectedStrike.Target,
                projectedStrike.StrikeIndex);
            DclCanonicalNativeAuxiliaryApplyPlan auxiliaryPlan =
                DclCanonicalNativeAuxiliaryApplyPlanner.Build(runtime, appliedStrike);
            DclCanonicalNativeForcedMovementWriter.Apply(
                auxiliaryPlan,
                () => appliedPhysicalMovementTile,
                movement => appliedPhysicalMovementTile = movement.Destination);
        }
        Check(appliedPhysicalMovementTile == secondKnockbackDestination &&
              chainedKnockbackApplication.Stage == DclCanonicalNativeActionStage.StrikesApplied,
            "physical native apply/readback must consume the complete contiguous movement timeline in Strike order");
        DclCanonicalPhysicalEvaluationResult chainedKnockbackEvaluation =
            DclCanonicalPhysicalEvaluation.Evaluate(
                runtime,
                new DclCanonicalPhysicalEvaluationInput(
                    AbilityId: 358,
                    WeaponItemId: 0,
                    SourceSt: 10,
                    Targets: [physicalTarget],
                    Strikes: knockbackStrikes.Select(strike => strike with
                    {
                        AttackRoll = null,
                        DefenseRoll = null,
                        DamageDice = null,
                    }).ToArray(),
                    TargetContexts:
                    [
                        physicalTargetContext with
                        {
                            TargetSt = 5,
                            MovementOrigin = target.Tile,
                        },
                    ],
                    StrikeWeapons: Enumerable.Range(0, 4)
                        .Select(index => new DclCanonicalPhysicalStrikeWeapon(index, 0, unarmedResource))
                        .ToArray()));
        Check(chainedKnockbackEvaluation.Targets.Single() is
              { ExpectedMovedTiles: var chainedExpectedMovement, FallProbability: var chainedFallProbability } &&
              chainedExpectedMovement > DclRational.FromInteger(0) &&
              chainedFallProbability == DclRational.FromInteger(0),
            "physical forecast/AI must enumerate the same conditional multi-Strike movement origins without execution RNG");
        DclCanonicalNativeStrikeProjection[] repeatedMovementStrikes =
            criticalKnockbackProjection.Strikes.ToArray();
        repeatedMovementStrikes[1] = repeatedMovementStrikes[1] with
        {
            AuxiliaryEffects = repeatedMovementStrikes[0].AuxiliaryEffects,
        };
        CheckThrows<InvalidOperationException>(
            () => new DclCanonicalNativeActionLedger(caster.BattleGeneration).Publish(
                caster,
                physicalBinding,
                criticalKnockbackProjection with
                {
                    ActionInstanceId = 622,
                    Strikes = repeatedMovementStrikes,
                    ReactionWindowOpened = false,
                    Reactions = null,
                }),
            "native publication must fail before apply when one target has multiple movements but no conditional origin timeline");
        DclDefenseResourceSnapshot persistedPhysicalDefense = physicalCoordinatorBattle.CaptureDefenseResources(
            targetKey,
            ["main-hand"]);
        Check(persistedPhysicalDefense.ParryAttemptCounts["main-hand"] == 1 &&
              persistedPhysicalDefense.BlockAvailable && persistedPhysicalDefense.Revision == 1 &&
              coordinatedPhysical.Result.FinalDefenseResources[targetKey].ParryAttemptCounts["main-hand"] == 1 &&
              coordinatedPhysical.Result.Commit.Transaction.DefenseResourcesFor(targetKey)
                  .CaptureSnapshot().ParryAttemptCounts["main-hand"] == 1,
            "a selected Parry must leave the executor, transaction, and battle cadence on the same cumulative resource state");
        var spentBlock = persistedPhysicalDefense with { BlockAvailable = false };
        physicalCoordinatorBattle.CommitDefenseResourcesBatch(
        [
            new DclCanonicalDefenseResourceCommit(targetKey, persistedPhysicalDefense, spentBlock),
        ]);
        CheckThrows<InvalidOperationException>(
            () => physicalCoordinatorBattle.CommitDefenseResourcesBatch(
            [
                new DclCanonicalDefenseResourceCommit(targetKey, persistedPhysicalDefense, spentBlock),
            ]),
            "a stale outer action must not spend Block or Parry cadence a second time");
        physicalCoordinatorBattle.BeginTurn(targetKey);
        DclDefenseResourceSnapshot resetPhysicalDefense = physicalCoordinatorBattle.CaptureDefenseResources(
            targetKey,
            ["main-hand"]);
        Check(resetPhysicalDefense.ParryAttemptCounts["main-hand"] == 0 &&
              resetPhysicalDefense.BlockAvailable && resetPhysicalDefense.Revision == 3,
            "the defender's granted-turn boundary must reset cumulative Parry attempts and restore its one Block");
        foreach (DclCanonicalNativeStrikeProjection strike in coordinatedPhysical.Application.Plan.Strikes)
            coordinatedPhysical.Application.ApplyNextStrike(strike.Target, strike.StrikeIndex);
        var coordinatedPhysicalReactionQueue = new DclCanonicalNativeReactionCompletionQueue();
        DclCanonicalNativeReactionCompletionTicket coordinatedPhysicalReactionTicket =
            coordinatedPhysicalReactionQueue.ReservePrepared(
                physicalCoordinatorBattle.BattleGeneration,
                coordinatedPhysical.Application);
        Check(DclCanonicalNativeApplyRouter.TryPreparePayment(
                  physicalCoordinatorBattle,
                  coordinatedPhysical.Application.Plan.ActionInstanceId,
                  out DclCanonicalNativePaymentReservation coordinatedPhysicalPayment) &&
              DclCanonicalNativeApplyRouter.CommitPayment(coordinatedPhysicalPayment) is null,
            "a coordinated physical action must reach its Reaction window only after every published Strike and empty HP/MP payment commit");
        CheckThrows<InvalidOperationException>(
            () => DclCanonicalNativeReactionCompletionCoordinator.Commit(
                physicalCoordinatorBattle,
                coordinatedPhysicalReactionTicket),
            "the terminal native Reaction boundary must reject settlement while an accepted canonical effect is still unacknowledged");
        DclCanonicalReactionResult expectedPhysicalReaction =
            coordinatedPhysical.Application.Plan.Reactions!.Accepted.Single();
        CheckThrows<InvalidOperationException>(
            () => DclCanonicalNativeReactionCompletionCoordinator.AcknowledgeEffect(
                physicalCoordinatorBattle,
                coordinatedPhysicalReactionTicket,
                targetKey,
                expectedPhysicalReaction.NativeBinding.NativeReactionAbilityId,
                expectedPhysicalReaction.NativeBinding.NativeEffectAbilityId + 1),
            "native Reaction effect completion must reject an actor whose executable effect id differs from the exact binding");
        DclCanonicalNativeReactionEffectAcknowledgement firstPhysicalReactionDelivery =
            DclCanonicalNativeReactionCompletionCoordinator.AcknowledgeEffect(
                physicalCoordinatorBattle,
                coordinatedPhysicalReactionTicket,
                targetKey,
