            InjuryTargetContext: new DclCanonicalInjuryTargetContext(8, 10, 10, 0, false, 10, 0, 0),
            InjuryConsequenceRollsByStrike:
            [
                new DclCanonicalInjuryConsequenceRolls(18, false, 0, null),
                new DclCanonicalInjuryConsequenceRolls(null, false, 0, null),
            ]);
        DclCanonicalAreaMagicExecutionResult immediateArea = DclCanonicalAreaMagicExecutor.Resolve(
            immediateAreaRuntime,
            new DclCanonicalAreaMagicExecutionInput(
                342,
                immediateAreaRequest,
                ActionInstanceId: 518,
                immediateAreaUnits,
                NativeGeometricMembers: [immediateAreaTarget],
                BaseSpellScore: 12,
                SharedCasterRoll: 10,
                Targets: [immediateAreaTargetInput],
                CurrentMpAtResolution: 10,
                CurrentHpAtResolution: 20));
        DclCanonicalAreaMagicStrikeResult[] immediateAreaStrikes = immediateArea.Strikes.ToArray();
        Check(immediateAreaStrikes[0].InjuryConsequences is
              { ApplyStun: true, ApplyKnockedDown: true } &&
              immediateAreaStrikes[1].DeliveryOutcome == DclMagicDeliveryOutcome.Delivered,
            "Immediate Area Injury must reproject Stun -4 and Knocked Down Dodge -3 before the next per-Strike Dodge gate");
        DclCanonicalAreaTargetEvaluationInput immediateAreaEvaluationTarget =
            new(
                immediateAreaTarget,
                TargetSpellScore: 12,
                TargetGateScore: 12,
                MagnitudeAttribute: 10,
                neutralAffinity,
                FaithMagnitude: DclRational.FromInteger(1),
                TargetHasShell: false,
                TargetMaxHp: 8,
                FireEffect: false,
                OilContributed: false,
                EffectiveHt: 10,
                InjuryTargetContext: new DclCanonicalInjuryTargetContext(
                    MaxHp: 8,
                    TargetSt: 100,
                    EffectiveHt: 10,
                    UnexpiredShockInjury: 0,
                    Charging: false,
                    Will: 10,
                    ConcentrationModifier: 0,
                    ConcentrationStatePenaltyMagnitude: 0));
        DclCanonicalAreaTargetEvaluationResult immediateAreaEvaluation =
            DclCanonicalAreaMagicEvaluationExecutor.Evaluate(
                immediateAreaRuntime,
                new DclCanonicalAreaMagicEvaluationInput(
                    342,
                    immediateAreaRequest,
                    immediateAreaUnits,
                    [immediateAreaTarget],
                    BaseSpellScore: 12,
                    Targets: [immediateAreaEvaluationTarget],
                    CurrentMpAtResolution: 10,
                    CurrentHpAtResolution: 20)).Targets.Single();
        DclCanonicalAreaTargetEvaluationResult deferredAreaEvaluation =
            DclCanonicalAreaMagicEvaluationExecutor.Evaluate(
                deferredAreaRuntime,
                new DclCanonicalAreaMagicEvaluationInput(
                    342,
                    immediateAreaRequest with { Profile = deferredAreaAction },
                    immediateAreaUnits,
                    [immediateAreaTarget],
                    BaseSpellScore: 12,
                    Targets: [immediateAreaEvaluationTarget],
                    CurrentMpAtResolution: 10,
                    CurrentHpAtResolution: 20)).Targets.Single();
        Check(immediateAreaEvaluation.ExpectedLandedStrikes > deferredAreaEvaluation.ExpectedLandedStrikes &&
              immediateAreaEvaluation.TotalHpDebit.ExpectedValue > deferredAreaEvaluation.TotalHpDebit.ExpectedValue,
            "Immediate Area forecast/AI magnitude enumeration must branch Major-Wound HT and lower only later Dodge odds after collapse");
        DclCanonicalAreaMagicEvaluationResult lowHpAreaEvaluation =
            DclCanonicalAreaMagicEvaluationExecutor.Evaluate(
                runtime,
                new DclCanonicalAreaMagicEvaluationInput(
                    AbilityId: 342,
                    areaRequest,
                    currentUnits,
                    NativeGeometricMembers: [areaTargetA],
                    BaseSpellScore: 12,
                    Targets:
                    [
                        new DclCanonicalAreaTargetEvaluationInput(
                            areaTargetA,
                            TargetSpellScore: 12,
                            TargetGateScore: areaDodge.Target,
                            MagnitudeAttribute: 10,
                            neutralAffinity,
                            FaithMagnitude: DclRational.FromInteger(1),
                            TargetHasShell: false,
                            TargetMaxHp: 20,
                            FireEffect: false,
                            OilContributed: false,
                            InjuryTargetContext: new DclCanonicalInjuryTargetContext(
                                MaxHp: 20,
                                TargetSt: 100,
                                EffectiveHt: 10,
                                UnexpiredShockInjury: 0,
                                Charging: false,
                                Will: 10,
                                ConcentrationModifier: 0,
                                ConcentrationStatePenaltyMagnitude: 0)),
                    ],
                    CurrentMpAtResolution: 10,
                    CurrentHpAtResolution: 20));
        DclExactValueForecast lowHpAreaDebit = lowHpAreaEvaluation.Targets.Single().TotalHpDebit;
        Check(lowHpAreaDebit.Minimum == 0 && lowHpAreaDebit.Maximum < 18 &&
              lowHpAreaDebit.ProbabilityOf(4) > DclRational.FromInteger(0) &&
              lowHpAreaEvaluation.Targets.Single().ExpectedLandedStrikes <
                  lowHpAreaEvaluation.CorrelatedDelivery.PerTargetExpectedLandedStrikes[areaTargetA.Unit],
            "Area magnitude forecast must carry HP across Strikes and stop later magnitude branches after target-local KO");
        Check(areaResult.Outcome == DclCastingOutcome.Success && areaResult.Center is { Available: true } &&
              areaAResults[0].Effect is { FinalInjury: 4 } &&
              areaAResults[0].InjuryConsequences is { UnexpiredShockInjury: 4, ShockPenaltyMagnitude: 2 } &&
              areaAResults[1].KoShortCircuited && areaAResults[2].KoShortCircuited &&
              areaBResults[0].DeliveryOutcome == DclMagicDeliveryOutcome.Defended &&
              areaBResults[1].Effect is { FinalInjury: 3 } &&
              areaBResults[1].InjuryConsequences is { UnexpiredShockInjury: 3, ShockPenaltyMagnitude: 1 } &&
              areaBResults[2].Effect is { FinalInjury: 2 } &&
              areaBResults[2].InjuryConsequences is { UnexpiredShockInjury: 5, ShockPenaltyMagnitude: 2 } &&
              areaResult.Transaction is { Stage: DclActionTransactionStage.Settled, ReactionWindowOpened: true } &&
              areaResult.Transaction.VisibleEffects.Count == 3,
            "canonical multi-Strike Area must share one caster roll, snapshot stable native geometry, Dodge per target/Strike, stop target-local RNG after KO, and open one Reaction window");
        DclCanonicalNativeMultiCarrierProjection areaProjection =
            DclCanonicalNativeCarrierProjector.ProjectAreaMagic(runtime, 342, caster, areaResult);
        Check(areaProjection.Strikes.Select(strike => (strike.Target, strike.StrikeIndex)).SequenceEqual(
              [
                  (areaTargetA.Unit, 0), (areaTargetB.Unit, 0),
                  (areaTargetA.Unit, 1), (areaTargetB.Unit, 1),
                  (areaTargetA.Unit, 2), (areaTargetB.Unit, 2),
              ]),
            "a native repeated Area carrier must publish Strike-major then native-target order, matching one target sweep per repeat");
        DclCanonicalNativeStrikeProjection[] projectedAreaA = areaProjection.Strikes
            .Where(strike => strike.Target == areaTargetA.Unit)
            .ToArray();
        Check(areaProjection is
              {
                  AbilityId: 342,
                  CarrierKind: DclNativeCarrierKind.NativeRepeat,
                  ReactionWindowOpened: true,
                  ResourceFailed: false,
                  ResourcePayment: { Channels: { HpDebit: 0, MpDebit: 10 } },
              } && areaProjection.Strikes.Count == 6 &&
              projectedAreaA[0] is
              {
                  Delivered: true,
                  Channels: { HpDebit: 4 },
                  InjuryConsequences: { UnexpiredShockInjury: 4, ShockPenaltyMagnitude: 2 },
                  TargetKoAfterStrike: true,
                  KoShortCircuited: false,
              } && projectedAreaA[1] is
              {
                  MagicDeliveryOutcome: null,
                  Delivered: false,
                  TargetKoAfterStrike: true,
                  KoShortCircuited: true,
            },
            "the native Area projection must preserve every target/Strike identity, target-local KO continuation, one payment, and one Reaction window");
        var areaBattle = new DclCanonicalBattleRuntime(runtime, caster.BattleGeneration);
        areaBattle.ObserveUnit(caster);
        areaBattle.ObserveUnit(areaTargetA.Unit);
        areaBattle.ObserveUnit(areaTargetB.Unit);
        DclCanonicalNativeActionApplication areaApplication =
            DclCanonicalNativeExecutionPublisher.PublishAreaMagic(areaBattle, 342, caster, areaResult);
        foreach (DclCanonicalNativeStrikeProjection strike in areaProjection.Strikes)
            Check(areaApplication.ApplyNextStrike(strike.Target, strike.StrikeIndex) == strike,
                "the Area execution publisher must retain the exact stable target/Strike order");
        Check(DclCanonicalNativeApplyRouter.TryPreparePayment(
                  areaBattle,
                  areaProjection.ActionInstanceId,
                  out DclCanonicalNativePaymentReservation areaPayment) &&
              DclCanonicalNativeApplyRouter.CommitPayment(areaPayment) is { Channels: { MpDebit: 10 } },
            "the Area execution publisher must retain one source-owned payment after every target/Strike");
        DclCanonicalNativeApplyRouter.AcknowledgeReactionWindow(areaPayment);
        DclCanonicalNativeApplyRouter.SettleAndRetire(areaBattle, areaPayment);

        var coordinatedAreaRandom = new SequenceRandomSource(
        [
            3, 3, 4,
            3, 3, 3, 4,
            2, 3, 3,
            3, 3, 3, 3, 3, 4, 4,
            3, 3, 3, 2,
        ]);
        var coordinatedAreaBattle = new DclCanonicalBattleRuntime(
            runtime,
            battleGeneration: 16,
            initialGlobalCt: 100,
            coordinatedAreaRandom);
        coordinatedAreaBattle.ObserveUnit(caster);
        coordinatedAreaBattle.ObserveUnit(areaTargetA.Unit);
        coordinatedAreaBattle.ObserveUnit(areaTargetB.Unit);
        DclCastDeclarationAttempt areaInjuryPendingAttempt = DclMagicTargeting.Declare(
            request with
            {
                Caster = areaTargetA.Unit,
                CasterTile = areaTargetA.Tile,
                UnitTarget = reverseTarget,
                CurrentGlobalCt = coordinatedAreaBattle.CurrentGlobalCt,
            },
            coordinatedAreaBattle.NextActionInstanceId());
        Check(areaInjuryPendingAttempt is { Legal: true, Declaration: not null },
            "Area Injury concentration sentinel requires one legal pending target cast");
        var areaInjuryTimeline = new DclCanonicalTimelineScheduler(
            coordinatedAreaBattle,
            [new DclCanonicalTimelineUnit(areaTargetA.Unit, initiativeRank: 0, new DclCtState(0), DclCtRate.Normal)]);
        areaInjuryTimeline.ScheduleChargedAction(16, areaInjuryPendingAttempt.Declaration!);
        DclStateDefinition areaAimDefinition = BuildDclStateDefinition(
            "aim", DclStateStackPolicy.Replace, DclStateDurationClock.UsesOrTriggers);
        DclStateApplicationResult areaTargetAim = coordinatedAreaBattle.States.Apply(new DclStateApplication(
            areaAimDefinition,
            areaTargetB.Unit,
            Source: null,
            AppliedAtGlobalCt: 100,
            AppliedBeforeTurnSerial: 0,
            FirstEligibleTargetTurnSerial: null,
            FirstEligibleSourceTurnSerial: null,
            DurationUnits: 1,
            Strength: null,
            WinningMargin: null,
            StackDiscriminator: "",
            ContributionIdentity: null,
            new DclAimStatePayload(areaAimDefinition.PayloadSchema, caster, 1),
            areaAimDefinition.PresentationProfile));
        DclCanonicalAreaMagicExecutionRequest CurrentAreaRequest(
            DclCanonicalBattleRuntime battle,
            DclCanonicalAreaMagicExecutionRequest sourceRequest)
        {
            DclTargetCandidate CurrentCandidate(DclTargetCandidate candidate) => candidate with
            {
                CombatStateRevision = battle.States.CaptureTarget(candidate.Unit).Revision,
            };

            DclCastDeclarationRequest declaration = sourceRequest.DeclarationRequest with
            {
                UnitTarget = sourceRequest.DeclarationRequest.UnitTarget is { } unitTarget
                    ? CurrentCandidate(unitTarget)
                    : null,
            };
            return sourceRequest with
            {
                DeclarationRequest = declaration,
                CurrentUnits = sourceRequest.CurrentUnits.ToDictionary(
                    pair => pair.Key,
                    pair => CurrentCandidate(pair.Value)),
                NativeGeometricMembers = sourceRequest.NativeGeometricMembers.Select(CurrentCandidate).ToArray(),
                Targets = sourceRequest.Targets.Select(targetRequest => targetRequest with
                {
                    Target = CurrentCandidate(targetRequest.Target),
                }).ToArray(),
            };
        }
        DclCanonicalAreaTargetExecutionRequest[] coordinatedAreaTargets = areaInput.Targets.Select(areaTarget =>
            new DclCanonicalAreaTargetExecutionRequest(
                areaTarget.Target,
                areaTarget.TargetSpellScore,
                areaTarget.Dodge,
                areaTarget.ResistanceScore,
                areaTarget.MagnitudeAttribute,
                areaTarget.Affinity,
                areaTarget.FaithMagnitude,
                areaTarget.TargetHasShell,
                areaTarget.TargetMaxHp,
                areaTarget.FireEffect,
                areaTarget.OilContributed,
                areaTarget.ApplicableDr,
                areaTarget.InjuryTargetContext is { } areaInjuryContext && areaTarget.Target.Unit == areaTargetA.Unit
                    ? areaInjuryContext with { Charging = true }
                    : areaTarget.InjuryTargetContext,
                areaTarget.AdditionalMagnitudeIntegerModifier,
                areaTarget.DirectConcentrationCancellation,
                areaTarget.AuthoredForcedDisplacement,
                areaTarget.AimRetentionModifier,
                areaTarget.AimRetentionStatePenaltyMagnitude)).ToArray();
        var coordinatedAreaRequest = new DclCanonicalAreaMagicExecutionRequest(
            AbilityId: 342,
            areaRequest,
            ActionInstanceId: 523,
            currentUnits,
            NativeGeometricMembers: [areaTargetB, areaTargetA],
            BaseSpellScore: 12,
            coordinatedAreaTargets,
            CurrentMpAtResolution: 10,
            CurrentHpAtResolution: 20);
        DclCanonicalAreaMagicExecutionRequest currentCoordinatedAreaRequest =
            CurrentAreaRequest(coordinatedAreaBattle, coordinatedAreaRequest);
        CheckThrows<ArgumentException>(
            () => DclCanonicalAreaMagicExecutionCoordinator.ResolveAndPublish(
                coordinatedAreaBattle,
                currentCoordinatedAreaRequest with
                {
                    Targets = [currentCoordinatedAreaRequest.Targets[0], currentCoordinatedAreaRequest.Targets[0]],
                }),
            "invalid deterministic Area target metadata must fail before the shared casting site");
        CheckThrows<ArgumentException>(
            () => DclCanonicalAreaMagicExecutionCoordinator.ResolveAndPublish(
                coordinatedAreaBattle,
                currentCoordinatedAreaRequest with
                {
                    ActionInstanceId = 522,
                    Targets =
                    [
                        currentCoordinatedAreaRequest.Targets[0] with
                        {
                            Target = currentCoordinatedAreaRequest.Targets[0].Target with
                            {
                                CombatStateRevision = 999,
                            },
                        },
                        currentCoordinatedAreaRequest.Targets[1],
                    ],
                }),
            "confirmed Area execution must reject a stale member snapshot before the shared casting site");
        Check(coordinatedAreaRandom.DrawCount == 0 && coordinatedAreaBattle.ExecutionRandom.Count == 0,
            "invalid or stale Area coordination must not perturb any future execution random site");
        DclCanonicalPublishedAreaMagicExecution coordinatedArea =
            DclCanonicalAreaMagicExecutionCoordinator.ResolveAndPublish(
                coordinatedAreaBattle,
                currentCoordinatedAreaRequest);
        DclCanonicalAreaMagicStrikeResult[] coordinatedAreaA = coordinatedArea.Result.Strikes
            .Where(strike => strike.Target == areaTargetA.Unit).ToArray();
        DclCanonicalAreaMagicStrikeResult[] coordinatedAreaB = coordinatedArea.Result.Strikes
            .Where(strike => strike.Target == areaTargetB.Unit).ToArray();
        Check(coordinatedAreaA[0] is
              {
                  Effect.FinalInjury: 4,
                  InjuryConsequences.Concentration.Outcome: DclConcentrationOutcome.DirectCancellation,
                  ChargingCancellation:
                  {
                      Reason: DclChargingCancellationReason.Ko,
                      ChargedAction.Declaration.ActionInstanceId: var cancelledAreaInjuryActionId,
                  },
              } &&
              cancelledAreaInjuryActionId == areaInjuryPendingAttempt.Declaration!.ActionInstanceId &&
              !areaInjuryTimeline.TryGetChargedAction(areaTargetA.Unit, out _) &&
              coordinatedAreaA[1].KoShortCircuited && coordinatedAreaA[2].KoShortCircuited &&
              coordinatedAreaB[0].DeliveryOutcome == DclMagicDeliveryOutcome.Defended &&
              coordinatedAreaB[1] is
              {
                  Effect.FinalInjury: 3,
                  AimRetention: { HadAim: true, Retained: false, Reason: "retention-roll-failed" },
              } && coordinatedAreaB[2] is { Effect.FinalInjury: 2, AimRetention: null } &&
              !coordinatedAreaBattle.States.TryGet(areaTargetAim.Instance.InstanceId, out _) &&
              coordinatedAreaRandom.DrawCount == 21 && coordinatedAreaBattle.ExecutionRandom.Count == 9 &&
              coordinatedArea.Application.Stage == DclCanonicalNativeActionStage.Published,
            "the Area coordinator must own only the reachable shared casting, per-Strike Dodge/magnitude, and target Aim-retention sites before one immutable publication");

        var areaRiderTarget = target with
        {
            CurrentHp = 100,
            CombatStateRevision = 15,
        };
        DclCastDeclarationRequest areaRiderRequest = request with
        {
            Profile = areaRiderAction,
            UnitTarget = areaRiderTarget,
        };
        var areaRiderUnits = new Dictionary<DclUnitKey, DclTargetCandidate>
        {
            [caster] = currentCaster,
            [areaRiderTarget.Unit] = areaRiderTarget,
        };
        var areaRiderMovementBranches = new DclCanonicalInjuryMovementBranchSet(
            DclForcedMovementDirection.AwayFromSource,
            new Dictionary<int, DclCanonicalNativeMovementVerdict>
            {
                [1] = new(
                    areaRiderTarget.Unit,
                    areaRiderTarget.Tile,
                    areaRiderTarget.Tile with { X = areaRiderTarget.Tile.X + 1 },
                    RequestedTiles: 1,
                    MovedTiles: 1,
                    DclForcedMovementDirection.AwayFromSource,
                    Fell: false,
                    NativePathResolved: true),
            });
        DclBattleTile areaMovementTile1 = areaRiderTarget.Tile with { X = areaRiderTarget.Tile.X + 1 };
        DclBattleTile areaMovementTile2 = areaMovementTile1 with { X = areaMovementTile1.X + 1 };
        DclBattleTile areaMovementTile3 = areaMovementTile2 with { X = areaMovementTile2.X + 1 };
        DclCanonicalInjuryMovementBranchSet AreaMovementBranches(
            DclBattleTile origin,
            DclBattleTile destination) => new(
                DclForcedMovementDirection.AwayFromSource,
                new Dictionary<int, DclCanonicalNativeMovementVerdict>
                {
                    [1] = new(
                        areaRiderTarget.Unit,
                        origin,
                        destination,
                        RequestedTiles: 1,
                        MovedTiles: 1,
                        DclForcedMovementDirection.AwayFromSource,
                        Fell: false,
                        NativePathResolved: true),
                });
        DclCanonicalInjuryMovementBranchSet areaMovementBranches1 =
            AreaMovementBranches(areaMovementTile1, areaMovementTile2);
        DclCanonicalInjuryMovementBranchSet areaMovementBranches2 =
            AreaMovementBranches(areaMovementTile2, areaMovementTile3);
        var areaMovementForest0 = DclCanonicalInjuryMovementBranchForest.FromSingle(
            areaRiderMovementBranches);
        var areaMovementForest1 = new DclCanonicalInjuryMovementBranchForest(
            new Dictionary<DclBattleTile, DclCanonicalInjuryMovementBranchSet>
            {
                [areaRiderTarget.Tile] = areaRiderMovementBranches,
                [areaMovementTile1] = areaMovementBranches1,
            });
        var areaMovementForest2 = new DclCanonicalInjuryMovementBranchForest(
            new Dictionary<DclBattleTile, DclCanonicalInjuryMovementBranchSet>
            {
                [areaRiderTarget.Tile] = areaRiderMovementBranches,
                [areaMovementTile1] = areaMovementBranches1,
                [areaMovementTile2] = areaMovementBranches2,
            });
        if (_stopCanonicalRuntimeAfterInjuryMovement)
            Console.WriteLine("injury-movement: Area forecast");
        DclCanonicalAreaMagicEvaluationResult areaRiderEvaluation =
            DclCanonicalAreaMagicEvaluationExecutor.Evaluate(
                runtime,
                new DclCanonicalAreaMagicEvaluationInput(
                    AbilityId: 343,
                    areaRiderRequest,
                    areaRiderUnits,
                    NativeGeometricMembers: [areaRiderTarget],
                    BaseSpellScore: 12,
                    Targets:
                    [
                        new DclCanonicalAreaTargetEvaluationInput(
                            areaRiderTarget,
                            TargetSpellScore: 12,
                            TargetGateScore: areaDodge.Target,
                            MagnitudeAttribute: 10,
                            neutralAffinity,
                            FaithMagnitude: DclRational.FromInteger(1),
                            TargetHasShell: false,
                            TargetMaxHp: 100,
                            FireEffect: false,
                            OilContributed: false,
                            InjuryTargetContext: new DclCanonicalInjuryTargetContext(
                                MaxHp: 100,
                                TargetSt: 5,
                                EffectiveHt: 10,
                                UnexpiredShockInjury: 0,
                                Charging: false,
                                Will: 10,
                                ConcentrationModifier: 0,
                                ConcentrationStatePenaltyMagnitude: 0),
                            InjuryMovementBranchForestsByStrike:
                            [
                                areaMovementForest0,
                                areaMovementForest1,
                                areaMovementForest2,
                            ],
                            StatusRiders:
                            [
                                new DclMagicStatusRiderForecast(1, 9, Immune: false),
                            ]),
                    ],
                    CurrentMpAtResolution: 10,
                    CurrentHpAtResolution: 20));
        DclCanonicalAreaTargetEvaluationResult areaRiderTargetEvaluation =
            areaRiderEvaluation.Targets.Single();
        Check(areaRiderEvaluation is
              {
                  Legal: true,
                  ResourceFailed: false,
                  Center.Available: true,
                  TargetBatch.Targets.Count: 1,
              } &&
              areaRiderTargetEvaluation.NormalMagnitudeExpression == new DclDiceExpression(1, 0) &&
              areaRiderTargetEvaluation.TotalHpDebit.Minimum == 0 &&
              areaRiderTargetEvaluation.TotalHpDebit.Maximum == 18 &&
              areaRiderTargetEvaluation.TotalHpDebit.ExpectedValue ==
                  areaRiderTargetEvaluation.ExpectedLandedStrikes * new DclRational(7, 2) &&
              areaRiderTargetEvaluation.ExpectedMovedTiles > DclRational.FromInteger(0) &&
              areaRiderTargetEvaluation.FallProbability == DclRational.FromInteger(0) &&
              areaRiderTargetEvaluation.RiderApplicationProbability[1] ==
                  areaRiderEvaluation.CorrelatedDelivery.PerTargetRiderApplicationProbability[areaRiderTarget.Unit][1],
            "canonical Area evaluation must derive target membership, per-Strike magnitude, KO-aware total channels, and Rider probability from the same normalized profile without execution RNG");
        DclCanonicalAreaMagicAiProjection areaRiderAi =
            DclCanonicalAreaMagicAiProjection.From(areaRiderEvaluation);
        DclCanonicalAreaMagicForecastProjection areaRiderForecast =
            DclCanonicalAreaMagicForecastProjection.From(areaRiderEvaluation);
        Check(areaRiderAi.ExpectedTargetHpDebit == areaRiderTargetEvaluation.TotalHpDebit.ExpectedValue &&
              areaRiderAi.ExpectedLandedStrikes == areaRiderTargetEvaluation.ExpectedLandedStrikes &&
              areaRiderAi.ExpectedMovedTiles == areaRiderTargetEvaluation.ExpectedMovedTiles &&
              areaRiderAi.FallProbability == areaRiderTargetEvaluation.FallProbability &&
              areaRiderAi.ExpectedStatusApplications == areaRiderTargetEvaluation.RiderApplicationProbability[1] &&
              areaRiderForecast.Targets.Single() is
              {
                  NormalMagnitude: "1d6",
                  MinimumTotalHpDebit: 0,
                  MaximumTotalHpDebit: 18,
                  FallChancePercent: 0,
              } && areaRiderForecast.Targets.Single().ExpectedMovedTiles ==
                  areaRiderTargetEvaluation.ExpectedMovedTiles,
            "player Area forecast and AI must be lossless projections of one exact evaluation result");
        if (_stopCanonicalRuntimeAfterInjuryMovement)
            Console.WriteLine("injury-movement: multi-Strike Area execution");
        var multiStrikeAreaMovementRandom = new SequenceRandomSource([1, 1, 1, 3, 3, 3]);
        var multiStrikeAreaMovementBattle = new DclCanonicalBattleRuntime(
            runtime,
            battleGeneration: 16,
            initialGlobalCt: 100,
            multiStrikeAreaMovementRandom);
        multiStrikeAreaMovementBattle.ObserveUnit(caster);
        multiStrikeAreaMovementBattle.ObserveUnit(areaRiderTarget.Unit);
        var multiStrikeAreaMovementTarget = new DclCanonicalAreaTargetExecutionRequest(
            areaRiderTarget,
            TargetSpellScore: 12,
            Dodge: areaDodge,
            ResistanceScore: null,
            MagnitudeAttribute: 10,
            neutralAffinity,
            FaithMagnitude: DclRational.FromInteger(1),
            TargetHasShell: false,
            TargetMaxHp: 100,
            FireEffect: false,
            OilContributed: false,
            InjuryTargetContext: new DclCanonicalInjuryTargetContext(100, 5, 10, 0, false, 10, 0, 0),
            InjuryMovementBranchForestsByStrike:
            [
                areaMovementForest0,
                areaMovementForest1,
                areaMovementForest2,
            ]);
        var multiStrikeAreaMovementRequest = new DclCanonicalAreaMagicExecutionRequest(
            AbilityId: 342,
            areaRequest with { UnitTarget = areaRiderTarget },
            ActionInstanceId: 907,
            areaRiderUnits,
            NativeGeometricMembers: [areaRiderTarget],
            BaseSpellScore: 12,
            Targets: [multiStrikeAreaMovementTarget],
            CurrentMpAtResolution: 10,
            CurrentHpAtResolution: 20);
        DclCanonicalPublishedAreaMagicExecution multiStrikeAreaMovementExecution =
            DclCanonicalAreaMagicExecutionCoordinator.ResolveAndPublish(
                multiStrikeAreaMovementBattle,
                CurrentAreaRequest(multiStrikeAreaMovementBattle, multiStrikeAreaMovementRequest));
        DclCanonicalForcedMovementResult[] multiStrikeAreaMovements =
            multiStrikeAreaMovementExecution.Result.Strikes
                .Select(strike => strike.ForcedMovement)
                .OfType<DclCanonicalForcedMovementResult>()
                .ToArray();
        Check(multiStrikeAreaMovements.Length == 3 &&
              multiStrikeAreaMovements.Select(movement => movement.Origin).SequenceEqual(
                  [areaRiderTarget.Tile, areaMovementTile1, areaMovementTile2]) &&
              multiStrikeAreaMovements.Select(movement => movement.Destination).SequenceEqual(
                  [areaMovementTile1, areaMovementTile2, areaMovementTile3]) &&
              multiStrikeAreaMovementExecution.Application.Plan.Strikes.Select(strike =>
                  strike.AuxiliaryEffects?.ForcedMovement).OfType<DclCanonicalForcedMovementResult>()
                  .SequenceEqual(multiStrikeAreaMovements) &&
              multiStrikeAreaMovementExecution.Result.Reactions is
                  { Candidates.Count: 0, Accepted.Count: 0 },
            "multi-Strike Area Injury execution and publication must select one contiguous conditional movement path");
        DclBattleTile appliedAreaMovementTile = areaRiderTarget.Tile;
        foreach (DclCanonicalNativeStrikeProjection projectedStrike in
            multiStrikeAreaMovementExecution.Application.Plan.Strikes)
        {
            DclCanonicalNativeStrikeProjection appliedStrike =
                multiStrikeAreaMovementExecution.Application.ApplyNextStrike(
                    projectedStrike.Target,
                    projectedStrike.StrikeIndex);
            DclCanonicalNativeAuxiliaryApplyPlan auxiliaryPlan =
                DclCanonicalNativeAuxiliaryApplyPlanner.Build(runtime, appliedStrike);
            DclCanonicalNativeForcedMovementWriter.Apply(
                auxiliaryPlan,
                () => appliedAreaMovementTile,
                movement => appliedAreaMovementTile = movement.Destination);
        }
        Check(appliedAreaMovementTile == areaMovementTile3 &&
              multiStrikeAreaMovementExecution.Application.Stage ==
                  DclCanonicalNativeActionStage.StrikesApplied,
            "Area native apply/readback must consume the complete contiguous movement timeline in Strike order");
        if (_stopCanonicalRuntimeAfterInjuryMovement)
            Console.WriteLine("injury-movement: single-Strike Area execution");
        DclActionProfile singleStrikeAreaMovementAction = areaAction with
        {
            ActionId = "canonical.area.single-strike-injury-movement-test",
            TransactionProfile = areaAction.TransactionProfile with { StrikeCount = 1 },
        };
        var singleStrikeAreaMovementAuthoring = new DclAuthoringRegistry();
        Check(singleStrikeAreaMovementAuthoring.TryRegister(singleStrikeAreaMovementAction).IsValid &&
              singleStrikeAreaMovementAuthoring.TryRegister(universalShockDefinition).IsValid &&
              singleStrikeAreaMovementAuthoring.TryRegister(universalStunDefinition).IsValid &&
              singleStrikeAreaMovementAuthoring.TryRegister(universalKnockedDownDefinition).IsValid,
            "single-Strike Area movement sentinel must normalize with all universal Injury states");
        var singleStrikeAreaMovementBindings = new DclAbilityBindingRegistry();
        Check(singleStrikeAreaMovementBindings.TryRegister(areaHealingBinding with
        {
            ActionId = singleStrikeAreaMovementAction.ActionId,
            ProfileRevision = singleStrikeAreaMovementAction.ProfileRevision,
        }, nativeCatalog, singleStrikeAreaMovementAuthoring).IsValid,
            "single-Strike Area movement sentinel must retain a verified single-result Area carrier");
        var singleStrikeAreaMovementRuntime = new DclCanonicalRuntimeCatalog(
            singleStrikeAreaMovementAuthoring,
            runtimeItems,
            singleStrikeAreaMovementBindings,
            BuildNativeReactionBindings(
                singleStrikeAreaMovementAuthoring,
                singleStrikeAreaMovementBindings,
                nativeCatalog));
        var singleStrikeAreaMovementRandom = new SequenceRandomSource([1, 1, 1, 3]);
        var singleStrikeAreaMovementBattle = new DclCanonicalBattleRuntime(
            singleStrikeAreaMovementRuntime,
            battleGeneration: 16,
            initialGlobalCt: 100,
            singleStrikeAreaMovementRandom);
        singleStrikeAreaMovementBattle.ObserveUnit(caster);
        singleStrikeAreaMovementBattle.ObserveUnit(areaRiderTarget.Unit);
        var singleStrikeAreaMovementTarget = new DclCanonicalAreaTargetExecutionRequest(
            areaRiderTarget,
            TargetSpellScore: 12,
            Dodge: areaDodge,
            ResistanceScore: null,
            MagnitudeAttribute: 10,
            neutralAffinity,
            FaithMagnitude: DclRational.FromInteger(1),
            TargetHasShell: false,
            TargetMaxHp: 100,
            FireEffect: false,
            OilContributed: false,
            InjuryTargetContext: new DclCanonicalInjuryTargetContext(100, 5, 10, 0, false, 10, 0, 0),
            InjuryMovementBranchesByStrike: [areaRiderMovementBranches]);
        var singleStrikeAreaMovementRequest = new DclCanonicalAreaMagicExecutionRequest(
            AbilityId: 2,
            areaRequest with
            {
                Profile = singleStrikeAreaMovementAction,
                UnitTarget = areaRiderTarget,
            },
            ActionInstanceId: 906,
            areaRiderUnits,
            NativeGeometricMembers: [areaRiderTarget],
            BaseSpellScore: 12,
            Targets: [singleStrikeAreaMovementTarget],
            CurrentMpAtResolution: 10,
            CurrentHpAtResolution: 20);
        DclCanonicalPublishedAreaMagicExecution singleStrikeAreaMovementExecution =
            DclCanonicalAreaMagicExecutionCoordinator.ResolveAndPublish(
                singleStrikeAreaMovementBattle,
                CurrentAreaRequest(singleStrikeAreaMovementBattle, singleStrikeAreaMovementRequest));
        DclCanonicalAreaMagicStrikeResult singleStrikeAreaMovementResult =
            singleStrikeAreaMovementExecution.Result.Strikes.Single();
        Check(singleStrikeAreaMovementResult is
              {
                  DeliveryOutcome: DclMagicDeliveryOutcome.CriticalDelivered,
                  InjuryConsequences:
                  {
                      CriticalKnockbackTiles: 1,
                      TotalForcedDisplacement: 1,
                  },
                  ForcedMovement:
                  {
                      RequestedTiles: 1,
                      MovedTiles: 1,
                      CancelAim: true,
                      SuppressedByTargetKo: false,
                  },
              } && singleStrikeAreaMovementExecution.Application.Plan.Strikes.Single()
                  .AuxiliaryEffects?.ForcedMovement == singleStrikeAreaMovementResult.ForcedMovement &&
              singleStrikeAreaMovementExecution.Result.Reactions is
                  { Candidates.Count: 0, Accepted.Count: 0 },
            "single-Strike Area Injury must select and publish the same frozen settled movement with only its outer Reaction window");
        if (_stopCanonicalRuntimeAfterInjuryMovement)
        {
            Console.WriteLine("injury-movement: forecast/execution sentinels complete");
            return;
        }
        DclCanonicalAreaMagicEvaluationResult areaRiderResourceFailure =
            DclCanonicalAreaMagicEvaluationExecutor.Evaluate(
                runtime,
                new DclCanonicalAreaMagicEvaluationInput(
                    343,
                    areaRiderRequest,
                    areaRiderUnits,
                    NativeGeometricMembers: [areaRiderTarget],
                    BaseSpellScore: 12,
                    Targets: [],
                    CurrentMpAtResolution: 0,
                    CurrentHpAtResolution: 5));
        Check(areaRiderResourceFailure is
              { Legal: false, ResourceFailed: true, Center: null, TargetBatch: null, Targets.Count: 0 },
            "Area evaluation ResourceFailure must terminate before center and TargetBatch construction exactly like confirmed execution");
        var areaRiderRandom = new SequenceRandomSource([1, 1, 1, 1, 6, 6, 6, 1, 1]);
        var areaRiderBattle = new DclCanonicalBattleRuntime(
            runtime,
            battleGeneration: 16,
            initialGlobalCt: 100,
            areaRiderRandom);
        areaRiderBattle.ObserveUnit(caster);
        areaRiderBattle.ObserveUnit(areaRiderTarget.Unit);
        var areaRiderMaterialization = statusMaterialization with
        {
            AppliedBeforeTurnSerial = 43,
            DurationUnits = 8,
        };
        var areaRiderTargetRequest = new DclCanonicalAreaTargetExecutionRequest(
            areaRiderTarget,
            TargetSpellScore: 12,
            Dodge: areaDodge,
            ResistanceScore: null,
            MagnitudeAttribute: 10,
            neutralAffinity,
            FaithMagnitude: DclRational.FromInteger(1),
            TargetHasShell: false,
            TargetMaxHp: 100,
            FireEffect: false,
            OilContributed: false,
            InjuryTargetContext: new DclCanonicalInjuryTargetContext(100, 10, 10, 0, false, 10, 0, 0),
            StatusRiders:
            [
                new DclCanonicalStatusRiderExecutionRequest(
                    EffectIndex: 1,
                    ResistanceScore: 9,
                    Immune: false,
                    areaRiderBattle.States,
                    areaRiderMaterialization),
            ]);
        var coordinatedAreaRiderRequest = new DclCanonicalAreaMagicExecutionRequest(
            AbilityId: 343,
            areaRiderRequest,
            ActionInstanceId: 525,
            areaRiderUnits,
            NativeGeometricMembers: [areaRiderTarget],
            BaseSpellScore: 12,
            Targets: [areaRiderTargetRequest],
            CurrentMpAtResolution: 10,
            CurrentHpAtResolution: 20);
        DclCanonicalPublishedAreaMagicExecution coordinatedAreaRider =
            DclCanonicalAreaMagicExecutionCoordinator.ResolveAndPublish(
                areaRiderBattle,
                CurrentAreaRequest(areaRiderBattle, coordinatedAreaRiderRequest));
        DclCanonicalAreaMagicStrikeResult[] areaRiderStrikes = coordinatedAreaRider.Result.Strikes.ToArray();
        Check(areaRiderStrikes.Length == 3 &&
              areaRiderStrikes[0].StatusRiders?.Single() is
              {
                  Gate: { Attempted: true, Applied: true, CasterMargin: 9, Reason: "rider-applied" },
                  StateApplication.Instance: { Kind: "canonical-status-test", ExpiresAtGlobalCt: 108 },
              } &&
              (areaRiderStrikes[1].StatusRiders?.Count ?? 0) == 0 &&
              (areaRiderStrikes[2].StatusRiders?.Count ?? 0) == 0 &&
              areaRiderStrikes.All(strike => strike.InjuryStates?.Shock?.Instance.Kind == "shock") &&
              areaRiderBattle.States.Instances.Count(instance =>
                  instance.Kind == "canonical-status-test") == 1 &&
              areaRiderBattle.States.Instances.Count(instance => instance.Kind == "shock") == 1 &&
              coordinatedAreaRider.Result.Reactions is { Candidates.Count: 0, Accepted.Count: 0 } &&
              ReferenceEquals(
                  coordinatedAreaRider.Application.Plan.Reactions,
                  coordinatedAreaRider.Result.Reactions) &&
              areaRiderRandom.DrawCount == 9 && areaRiderBattle.ExecutionRandom.Count == 5,
            "a deferred multi-Strike Area status Rider must reuse casting, materialize once, retain Injury state, and resolve one empty outer Reaction window");
        DclCanonicalNativeMultiCarrierProjection areaRiderProjection =
            DclCanonicalNativeCarrierProjector.ProjectAreaMagic(
                runtime,
                343,
                caster,
                coordinatedAreaRider.Result);
        DclCanonicalNativeStrikeProjection[] areaRiderNativeStrikes = areaRiderProjection.Strikes.ToArray();
        Check(areaRiderNativeStrikes[0].AuxiliaryEffects?.AddedStates.Count(state =>
                  state.StateKind == "canonical-status-test") == 1 &&
              areaRiderNativeStrikes.Skip(1).All(strike =>
                  (strike.AuxiliaryEffects?.AddedStates.Count(state =>
                      state.StateKind == "canonical-status-test") ?? 0) == 0),
            "Area native projection must attach a status Rider only to the first landed Carrier Strike");
        DclCanonicalNativeAuxiliaryApplyPlan areaRiderNativePlan =
            DclCanonicalNativeAuxiliaryApplyPlanner.Build(runtime, areaRiderNativeStrikes[0]);
        Check(areaRiderNativePlan.StatusPacketMutations.Single() is
              { Add: true, Bit.ByteIndex: 1, Bit.Mask: 0x02 },
            "an Area native status Rider must reach its exact owned status-packet bit");
        foreach (DclCanonicalNativeStrikeProjection strike in areaRiderProjection.Strikes)
        {
            DclCanonicalNativeStrikeProjection appliedStrike =
                coordinatedAreaRider.Application.ApplyNextStrike(strike.Target, strike.StrikeIndex);
            Check(appliedStrike.Target == strike.Target &&
                  appliedStrike.StrikeIndex == strike.StrikeIndex &&
                  appliedStrike.Channels == strike.Channels &&
                  (appliedStrike.AuxiliaryEffects?.AddedStates.Count ?? 0) ==
                  (strike.AuxiliaryEffects?.AddedStates.Count ?? 0) &&
                  (appliedStrike.AuxiliaryEffects?.AddedStates.FirstOrDefault()?.StateKind) ==
                  (strike.AuxiliaryEffects?.AddedStates.FirstOrDefault()?.StateKind),
                "the Area Rider publication must preserve every numeric and auxiliary Strike projection");
        }
        Check(DclCanonicalNativeApplyRouter.TryPreparePayment(
                  areaRiderBattle,
                  525,
                  out DclCanonicalNativePaymentReservation areaRiderPayment) &&
              DclCanonicalNativeApplyRouter.CommitPayment(areaRiderPayment) is { Channels.MpDebit: 10 },
            "the Area Rider Action must expose one source-owned payment after all target carriers");
        DclCanonicalNativeApplyRouter.AcknowledgeReactionWindow(areaRiderPayment);
        DclCanonicalNativeApplyRouter.SettleAndRetire(areaRiderBattle, areaRiderPayment);

        var immuneAreaRiderRandom = new SequenceRandomSource([1, 1, 1, 1, 1, 1]);
        var immuneAreaRiderBattle = new DclCanonicalBattleRuntime(
            runtime,
            battleGeneration: 16,
            initialGlobalCt: 100,
            immuneAreaRiderRandom);
        immuneAreaRiderBattle.ObserveUnit(caster);
        immuneAreaRiderBattle.ObserveUnit(areaRiderTarget.Unit);
        DclCanonicalPublishedAreaMagicExecution immuneAreaRider =
            DclCanonicalAreaMagicExecutionCoordinator.ResolveAndPublish(
                immuneAreaRiderBattle,
                CurrentAreaRequest(immuneAreaRiderBattle, coordinatedAreaRiderRequest with
                {
                    ActionInstanceId = 526,
                    Targets =
                    [
                        areaRiderTargetRequest with
                        {
                            StatusRiders =
                            [
                                areaRiderTargetRequest.StatusRiders!.Single() with
                                {
                                    Immune = true,
                                    StateRegistry = immuneAreaRiderBattle.States,
                                },
                            ],
                        },
                    ],
                }));
        Check(immuneAreaRider.Result.Strikes[0].StatusRiders?.Single().Gate is
              { Attempted: false, Applied: false, Reason: "immune" } &&
              immuneAreaRiderBattle.States.Instances.All(instance =>
                  instance.Kind != "canonical-status-test") &&
              immuneAreaRiderRandom.DrawCount == 6 && immuneAreaRiderBattle.ExecutionRandom.Count == 4,
            "Area Rider immunity must short-circuit before resistance RNG while preserving every landed Carrier Strike");

        var defendedAreaRiderRandom = new SequenceRandomSource(
            [3, 3, 4, 1, 1, 1, 1, 1, 1, 1, 1, 1]);
        var defendedAreaRiderBattle = new DclCanonicalBattleRuntime(
            runtime,
            battleGeneration: 16,
            initialGlobalCt: 100,
            defendedAreaRiderRandom);
        defendedAreaRiderBattle.ObserveUnit(caster);
        defendedAreaRiderBattle.ObserveUnit(areaRiderTarget.Unit);
        DclCanonicalPublishedAreaMagicExecution defendedAreaRider =
            DclCanonicalAreaMagicExecutionCoordinator.ResolveAndPublish(
                defendedAreaRiderBattle,
                CurrentAreaRequest(defendedAreaRiderBattle, coordinatedAreaRiderRequest with
                {
                    ActionInstanceId = 527,
                    Targets =
                    [
                        areaRiderTargetRequest with
                        {
                            Dodge = areaDodge,
                            StatusRiders =
                            [
                                areaRiderTargetRequest.StatusRiders!.Single() with
                                {
                                    StateRegistry = defendedAreaRiderBattle.States,
                                },
                            ],
                        },
                    ],
                }));
        Check(defendedAreaRider.Result.Strikes.All(strike =>
                  strike.DeliveryOutcome == DclMagicDeliveryOutcome.Defended &&
                  (strike.StatusRiders?.Count ?? 0) == 0) &&
              defendedAreaRiderBattle.States.Instances.Count == 0 &&
              defendedAreaRiderRandom.DrawCount == 12 && defendedAreaRiderBattle.ExecutionRandom.Count == 4,
            "an Area target whose Carrier never lands must never reach magnitude or Rider resistance RNG");

        var failedAreaCoordinatorRandom = new SequenceRandomSource([]);
        var failedAreaCoordinatorBattle = new DclCanonicalBattleRuntime(
            runtime,
            battleGeneration: 16,
            executionRandomSource: failedAreaCoordinatorRandom);
        failedAreaCoordinatorBattle.ObserveUnit(caster);
        DclCanonicalPublishedAreaMagicExecution coordinatedAreaFailure =
            DclCanonicalAreaMagicExecutionCoordinator.ResolveAndPublish(
                failedAreaCoordinatorBattle,
                CurrentAreaRequest(failedAreaCoordinatorBattle, coordinatedAreaRequest with
                {
                    ActionInstanceId = 524,
                    CurrentUnits = new Dictionary<DclUnitKey, DclTargetCandidate> { [caster] = currentCaster },
                    NativeGeometricMembers = [],
                    Targets = [],
                    CurrentMpAtResolution = 0,
                    CurrentHpAtResolution = 5,
                }));
        Check(coordinatedAreaFailure.Result.Outcome == DclCastingOutcome.ResourceFailure &&
              coordinatedAreaFailure.Application.Plan.ResourceFailed &&
              failedAreaCoordinatorRandom.DrawCount == 0 && failedAreaCoordinatorBattle.ExecutionRandom.Count == 0,
            "Area ResourceFailure coordination must publish an empty Action without sampling casting or any target-owned site");
        DclCanonicalNativeApplyRouter.SettleResourceFailure(failedAreaCoordinatorBattle, 524);
        CheckThrows<ArgumentException>(
            () => DclCanonicalAreaMagicExecutor.Resolve(runtime, areaInput with
            {
                ActionInstanceId = 520,
                Targets = areaInput.Targets.Select(areaTargetInput => areaTargetInput.Target.Unit == areaTargetA.Unit
                    ? areaTargetInput with { DodgeRolls = [9, 10] }
                    : areaTargetInput).ToArray(),
            }),
            "a KO-short-circuited Area Strike must not consume unreachable Dodge RNG");
        DclCanonicalAreaMagicExecutionResult resourceFailedArea = DclCanonicalAreaMagicExecutor.Resolve(
            runtime,
            areaInput with
            {
                ActionInstanceId = 521,
                SharedCasterRoll = null,
                Targets = [],
                CurrentMpAtResolution = 0,
                CurrentHpAtResolution = 5,
            });
        Check(resourceFailedArea.Outcome == DclCastingOutcome.ResourceFailure &&
              resourceFailedArea.Center is null && resourceFailedArea.Strikes.Count == 0 &&
              resourceFailedArea.Transaction.Stage == DclActionTransactionStage.ResourceFailed,
            "Area ResourceFailure must terminate before center resolution, TargetBatch snapshot, and every random site");
        DclCanonicalNativeMultiCarrierProjection resourceFailedAreaProjection =
            DclCanonicalNativeCarrierProjector.ProjectAreaMagic(runtime, 342, caster, resourceFailedArea);
        Check(resourceFailedAreaProjection is
              {
                  ResourceFailed: true,
                  ReactionWindowOpened: false,
                  ResourcePayment: null,
              } && resourceFailedAreaProjection.Strikes.Count == 0,
            "Area ResourceFailure must project no repeat, payment, or Reaction carrier");

        var areaHealingTargetA = areaTargetA with
        {
            Relation = DclAllegianceRelation.Ally,
            CurrentHp = 10,
            CombatStateRevision = 13,
        };
        var areaHealingTargetB = areaTargetB with
        {
            Relation = DclAllegianceRelation.Ally,
            CurrentHp = 15,
            CombatStateRevision = 14,
        };
        DclCastDeclarationRequest areaHealingRequest = request with
        {
            Profile = areaHealingAction,
            UnitTarget = areaHealingTargetA,
        };
        var areaHealingUnits = new Dictionary<DclUnitKey, DclTargetCandidate>
        {
            [caster] = currentCaster,
            [areaHealingTargetA.Unit] = areaHealingTargetA,
            [areaHealingTargetB.Unit] = areaHealingTargetB,
        };
        var areaHealingInput = new DclCanonicalAreaMagicExecutionInput(
            AbilityId: 2,
            areaHealingRequest,
            ActionInstanceId: 522,
            areaHealingUnits,
            NativeGeometricMembers: [areaHealingTargetB, areaHealingTargetA],
            BaseSpellScore: 12,
            SharedCasterRoll: 10,
            Targets:
            [
                new DclCanonicalAreaTargetInput(
                    areaHealingTargetB,
                    TargetSpellScore: 12,
                    Dodge: null,
                    DodgeRolls: [],
                    ResistanceScore: null,
                    ResistanceRoll: null,
                    MagnitudeAttribute: 10,
                    MagnitudeDiceByStrike: [new[] { 1, 2, 3 }],
                    neutralAffinity,
                    FaithMagnitude: DclRational.FromInteger(1),
                    TargetHasShell: false,
                    TargetMaxHp: 20,
                    FireEffect: false,
                    OilContributed: false),
                new DclCanonicalAreaTargetInput(
                    areaHealingTargetA,
                    TargetSpellScore: 12,
                    Dodge: null,
                    DodgeRolls: [],
                    ResistanceScore: null,
                    ResistanceRoll: null,
                    MagnitudeAttribute: 10,
                    MagnitudeDiceByStrike: [new[] { 1, 2, 3 }],
                    neutralAffinity,
                    FaithMagnitude: DclRational.FromInteger(1),
                    TargetHasShell: false,
                    TargetMaxHp: 20,
                    FireEffect: false,
                    OilContributed: false),
            ],
            CurrentMpAtResolution: 10,
            CurrentHpAtResolution: 20);
        DclCanonicalAreaMagicEvaluationResult areaHealingEvaluation =
            DclCanonicalAreaMagicEvaluationExecutor.Evaluate(
                runtime,
                new DclCanonicalAreaMagicEvaluationInput(
                    AbilityId: 2,
                    areaHealingRequest,
                    areaHealingUnits,
                    NativeGeometricMembers: [areaHealingTargetB, areaHealingTargetA],
                    BaseSpellScore: 12,
                    Targets:
                    [
                        new DclCanonicalAreaTargetEvaluationInput(
                            areaHealingTargetB,
                            TargetSpellScore: 12,
                            TargetGateScore: null,
                            MagnitudeAttribute: 10,
                            neutralAffinity,
                            FaithMagnitude: DclRational.FromInteger(1),
                            TargetHasShell: false,
                            TargetMaxHp: 20,
                            FireEffect: false,
                            OilContributed: false),
                        new DclCanonicalAreaTargetEvaluationInput(
                            areaHealingTargetA,
                            TargetSpellScore: 12,
                            TargetGateScore: null,
                            MagnitudeAttribute: 10,
                            neutralAffinity,
                            FaithMagnitude: DclRational.FromInteger(1),
                            TargetHasShell: false,
                            TargetMaxHp: 20,
                            FireEffect: false,
                            OilContributed: false),
                    ],
                    CurrentMpAtResolution: 10,
                    CurrentHpAtResolution: 20));
        Check(areaHealingEvaluation.Targets.All(targetEvaluation =>
                  targetEvaluation.NormalMagnitudeExpression == new DclDiceExpression(3, 2) &&
                  targetEvaluation.CriticalMagnitudeExpression == new DclDiceExpression(2, 8)) &&
              areaHealingEvaluation.Targets.Single(targetEvaluation =>
                  targetEvaluation.Target == areaHealingTargetA.Unit).TotalHpCredit.Maximum == 10 &&
              areaHealingEvaluation.Targets.Single(targetEvaluation =>
                  targetEvaluation.Target == areaHealingTargetB.Unit).TotalHpCredit.Maximum == 5,
            "Area healing evaluation must use the same maximize-one-die critical expression and per-target missing-HP cap as execution");
        DclCanonicalAreaMagicExecutionResult areaHealingResult =
            DclCanonicalAreaMagicExecutor.Resolve(runtime, areaHealingInput);
        DclCanonicalAreaMagicStrikeResult areaHealingA = areaHealingResult.Strikes.Single(
            strike => strike.Target == areaHealingTargetA.Unit);
        DclCanonicalAreaMagicStrikeResult areaHealingB = areaHealingResult.Strikes.Single(
            strike => strike.Target == areaHealingTargetB.Unit);
        Check(areaHealingResult.Outcome == DclCastingOutcome.Success &&
              areaHealingA is { Effect: null, BaseInjury: null, Healing: { RawHealing: 8, AppliedHealing: 8 } } &&
              areaHealingB is { Effect: null, BaseInjury: null, Healing: { RawHealing: 8, AppliedHealing: 5 } } &&
              areaHealingResult.Transaction is { Stage: DclActionTransactionStage.Settled, ReactionWindowOpened: true } &&
              areaHealingResult.Transaction.VisibleEffects.Count == 2,
            "canonical Area healing must share one casting draw, roll magnitude per target, cap each target independently, and open one Reaction window");
        DclCanonicalNativeMultiCarrierProjection areaHealingProjection =
            DclCanonicalNativeCarrierProjector.ProjectAreaMagic(runtime, 2, caster, areaHealingResult);
        Check(areaHealingProjection.Strikes.Single(strike => strike.Target == areaHealingTargetA.Unit)
                  .Channels.HpCredit == 8 &&
              areaHealingProjection.Strikes.Single(strike => strike.Target == areaHealingTargetB.Unit)
                  .Channels.HpCredit == 5 &&
              areaHealingProjection.Strikes.All(strike => strike.Channels.HpDebit == 0),
            "the native Area projection must retain independent capped HP-credit channels for every healed target");
        DclCanonicalAreaMagicExecutionResult criticalAreaHealing =
            DclCanonicalAreaMagicExecutor.Resolve(
                runtime,
                areaHealingInput with
                {
                    ActionInstanceId = 528,
                    SharedCasterRoll = 3,
                    Targets = areaHealingInput.Targets.Select(targetInput => targetInput with
                    {
                        MagnitudeDiceByStrike = [new[] { 1, 2 }],
                    }).ToArray(),
                });
        Check(criticalAreaHealing.Strikes.Single(strike => strike.Target == areaHealingTargetA.Unit).Healing is
              { RawHealing: 11, AppliedHealing: 10 } &&
              criticalAreaHealing.Strikes.Single(strike => strike.Target == areaHealingTargetB.Unit).Healing is
              { RawHealing: 11, AppliedHealing: 5 },
            "critical Area healing must roll one fewer die, add the maximized six, and cap each target exactly as forecast");

        var undeadRules = Enum.GetValues<DclUndeadEffectFamily>().ToDictionary(
            family => family,
            _ => new DclUndeadFamilyRule(
                DclUndeadInteraction.Normal,
                DclUndeadInteraction.EffectOwned,
                DclUndeadInteraction.Normal));
        undeadRules[DclUndeadEffectFamily.RaiseOrArise] = new DclUndeadFamilyRule(
            DclUndeadInteraction.Normal,
            DclUndeadInteraction.Reject,
            DclUndeadInteraction.Normal);
        undeadRules[DclUndeadEffectFamily.Reraise] = new DclUndeadFamilyRule(
            DclUndeadInteraction.Normal,
            DclUndeadInteraction.Reject,
            DclUndeadInteraction.Normal);
        var undeadInteractions = new DclUndeadInteractionTable(undeadRules);
        var koTarget = target with
        {
            Relation = DclAllegianceRelation.Ally,
            States = DclEligibleTargetStates.Ko,
            CurrentHp = 0,
            CombatStateRevision = 13,
        };
        DclCastDeclarationRequest raiseRequest = request with
        {
            Profile = raiseAction,
            UnitTarget = koTarget,
            CurrentMp = 20,
        };
        var raiseInput = new DclCanonicalReviveExecutionInput(
            AbilityId: 5,
            raiseRequest,
            ActionInstanceId: 522,
            koTarget,
            BaseSpellScore: 12,
            TargetSpellScore: 12,
            SharedCasterRoll: 10,
            ResistanceScore: null,
            ResistanceRoll: null,
            Immune: false,
            RestoredHpDice: [3, 4],
            FaithMultiplier: new DclRational(3, 2),
            TargetUndead: false,
            TargetMaxHp: 50,
            CurrentMpAtResolution: 20,
            CurrentHpAtResolution: 20,
            undeadInteractions);
        DclCanonicalReviveEvaluationResult raiseEvaluation = DclCanonicalReviveEvaluation.Evaluate(
            runtime,
            new DclCanonicalReviveEvaluationInput(
                AbilityId: 5,
                raiseRequest,
                koTarget,
                BaseSpellScore: 12,
                TargetSpellScore: 12,
                ResistanceScore: null,
                Immune: false,
                FaithMultiplier: new DclRational(3, 2),
                TargetUndead: false,
                TargetMaxHp: 50,
                CurrentMpAtResolution: 20,
                CurrentHpAtResolution: 20,
                undeadInteractions));
        DclCanonicalReviveForecastProjection raiseForecast =
            DclCanonicalReviveEvaluation.ProjectPlayer(raiseEvaluation);
        DclCanonicalReviveAiProjection raiseAi = DclCanonicalReviveEvaluation.ProjectAi(raiseEvaluation);
        Check(raiseEvaluation is { Legal: true, ResourceFailed: false, Mode: DclReviveMode.Immediate } &&
              raiseEvaluation.EffectApplicationProbability ==
                  DclSpellResolution.BeneficialSuccessProbability(12, 12).Fraction &&
              raiseEvaluation.ClearKoProbability == raiseEvaluation.EffectApplicationProbability &&
              raiseEvaluation.StoreReraiseProbability == DclRational.FromInteger(0) &&
              raiseEvaluation.RawRestoredHp is { Minimum: 0, Maximum: 14 } &&
              raiseEvaluation.FinalRestoredHp is { Minimum: 0, Maximum: 21 } &&
              raiseEvaluation.AppliedHpCredit is { Minimum: 0, Maximum: 21 } &&
              raiseForecast.AppliedHpCredit == raiseEvaluation.AppliedHpCredit &&
              raiseAi.AppliedHpCredit == raiseEvaluation.AppliedHpCredit &&
              raiseAi.ExpectedAppliedHpCredit == raiseEvaluation.AppliedHpCredit.ExpectedValue,
            "canonical Revive forecast/AI must share exact delivery, restored-HP dice, Faith floor, missing-HP cap, KO-clear, and source-payment distributions");
        DclCanonicalReviveEvaluationResult rejectedUndeadReviveEvaluation =
            DclCanonicalReviveEvaluation.Evaluate(
                runtime,
                new DclCanonicalReviveEvaluationInput(
                    AbilityId: 5,
                    raiseRequest with
                    {
                        UnitTarget = koTarget with
                        {
                            States = DclEligibleTargetStates.Ko | DclEligibleTargetStates.Undead,
                        },
                    },
                    koTarget with { States = DclEligibleTargetStates.Ko | DclEligibleTargetStates.Undead },
                    BaseSpellScore: 12,
                    TargetSpellScore: 12,
                    ResistanceScore: null,
                    Immune: false,
                    FaithMultiplier: new DclRational(3, 2),
                    TargetUndead: true,
                    TargetMaxHp: 50,
                    CurrentMpAtResolution: 20,
                    CurrentHpAtResolution: 20,
                    undeadInteractions));
        Check(rejectedUndeadReviveEvaluation.EffectApplicationProbability == DclRational.FromInteger(0) &&
              rejectedUndeadReviveEvaluation.AppliedHpCredit is { Minimum: 0, Maximum: 0 } &&
              rejectedUndeadReviveEvaluation.RouteProbability.GetValueOrDefault(
                  DclReviveRoute.RejectedByUndeadRule,
                  DclRational.FromInteger(0)) == rejectedUndeadReviveEvaluation.DeliveryOutcomeProbability
                  .Where(pair => pair.Key is DclMagicDeliveryOutcome.Delivered or
                      DclMagicDeliveryOutcome.CriticalDelivered)
                  .Select(pair => pair.Value)
                  .Aggregate(DclRational.FromInteger(0), (total, probability) => total + probability),
            "explicit Undead rejection must preserve delivery probability but create no restored-HP distribution");
        DclCanonicalReviveEvaluationResult failedRaiseEvaluation = DclCanonicalReviveEvaluation.Evaluate(
            runtime,
            new DclCanonicalReviveEvaluationInput(
                AbilityId: 5,
                raiseRequest,
                koTarget,
