                new DclCanonicalStatusRemovalEvaluationInput(
                    AbilityId: 14,
                    removalRequest,
                    removalTarget,
                    BaseSpellScore: 12,
                    TargetSpellScore: 12,
                    CurrentMpAtResolution: 20,
                    CurrentHpAtResolution: 20,
                    removalRegistry));
        Check(absentRemovalEvaluation.MatchingInstanceIds.Count == 0 &&
              absentRemovalEvaluation.RemovalProbability == DclRational.FromInteger(0) &&
              absentRemovalEvaluation.RemovalOutcomes.Single().RemovedInstanceIds.Count == 0 &&
              absentRemovalEvaluation.RemovalOutcomes.Single().Probability == DclRational.FromInteger(1),
            "named StatusRemoval against an absent state must retain a normalized no-removal outcome");
        DclCanonicalStatusRemovalExecutionResult absentStatusRemoval = DclCanonicalStatusRemovalExecutor.Resolve(
            runtime,
            removalInput with { ActionInstanceId = 528 });
        Check(absentStatusRemoval.RemovedInstanceIds.Count == 0 &&
              absentStatusRemoval.Transaction.VisibleEffects.Count == 0 &&
              absentStatusRemoval.Transaction.ReactionWindowOpened,
            "successful StatusRemoval against an absent named state must commit no false visible effect while retaining the outer Reaction window");

        var coordinatedRemovalRandom = new SequenceRandomSource([3, 3, 4]);
        var coordinatedRemovalBattle = new DclCanonicalBattleRuntime(
            runtime,
            battleGeneration: 16,
            initialGlobalCt: 100,
            coordinatedRemovalRandom);
        coordinatedRemovalBattle.ObserveUnit(caster);
        coordinatedRemovalBattle.ObserveUnit(removalTarget.Unit);
        DclStateApplicationResult coordinatedRemovableState = coordinatedRemovalBattle.States.Apply(
            new DclStateApplication(
                statusDefinition,
                removalTarget.Unit,
                caster,
                AppliedAtGlobalCt: 100,
                AppliedBeforeTurnSerial: 44,
                FirstEligibleTargetTurnSerial: null,
                FirstEligibleSourceTurnSerial: null,
                DurationUnits: 6,
                Strength: null,
                WinningMargin: null,
                StackDiscriminator: "coordinated-removal",
                ContributionIdentity: null,
                new DclPropertyStatePayload(statusDefinition.PayloadSchema, new Dictionary<string, string>()),
                statusDefinition.PresentationProfile));
        DclTargetCandidate coordinatedRemovalTarget = removalInput.Target with
        {
            CombatStateRevision = coordinatedRemovalBattle.States.CaptureTarget(removalTarget.Unit).Revision,
        };
        DclCanonicalStatusRemovalExecutionResult coordinatedRemoval =
            DclCanonicalStatusRemovalExecutor.Resolve(
                runtime,
                removalInput with
                {
                    ActionInstanceId = 709,
                    SharedCasterRoll = null,
                    StateRegistry = coordinatedRemovalBattle.States,
                    ExecutionBattle = coordinatedRemovalBattle,
                    ReactionWindow = DclCanonicalReactionWindow.ConfirmedRequest(coordinatedRemovalBattle, null),
                    Target = coordinatedRemovalTarget,
                    DeclarationRequest = removalInput.DeclarationRequest with { UnitTarget = coordinatedRemovalTarget },
                });
        Check(coordinatedRemoval.RemovedInstanceIds.SequenceEqual([coordinatedRemovableState.Instance.InstanceId]) &&
              coordinatedRemovalRandom.DrawCount == 3 && coordinatedRemovalBattle.ExecutionRandom.Count == 1 &&
              coordinatedRemoval.Reactions is { Accepted.Count: 0 },
            "confirmed named StatusRemoval must own one shared casting identity and remove the exact matching state before Reaction");

        var quickTarget = removalTarget with { CombatStateRevision = 16 };
        DclCastDeclarationRequest quickRequest = request with
        {
            Profile = quickAction,
            UnitTarget = quickTarget,
        };
        var quickCt = new DclCtState(initialCt: 20);
        var quickLocks = new DclQuickLockController();
        var quickRegistry = new DclStateRegistry(16, initialGlobalCt: 100);
        var quickMaterialization = new DclCanonicalStateMaterialization(
            BindSource: true,
            AppliedBeforeTurnSerial: 45,
            FirstEligibleTargetTurnSerial: null,
            FirstEligibleSourceTurnSerial: null,
            DurationUnits: null,
            Strength: null,
            StackDiscriminator: "default",
            ContributionIdentity: null,
            new DclPropertyStatePayload(quickLockDefinition.PayloadSchema, new Dictionary<string, string>()));
        var quickInput = new DclCanonicalQuickExecutionInput(
            AbilityId: 41,
            quickRequest,
            ActionInstanceId: 529,
            quickTarget,
            BaseSpellScore: 12,
            TargetSpellScore: 12,
            SharedCasterRoll: 10,
            CurrentMpAtResolution: 20,
            CurrentHpAtResolution: 20,
            quickCt,
            quickLocks,
            quickRegistry,
            quickMaterialization);
        DclCanonicalQuickEvaluationResult quickEvaluation = DclCanonicalQuickEvaluation.Evaluate(
            runtime,
            new DclCanonicalQuickEvaluationInput(
                AbilityId: 41,
                quickRequest,
                quickTarget,
                BaseSpellScore: 12,
                TargetSpellScore: 12,
                CurrentMpAtResolution: 20,
                CurrentHpAtResolution: 20,
                quickCt,
                quickLocks,
                quickRegistry));
        DclCanonicalQuickForecastProjection quickForecast =
            DclCanonicalQuickEvaluation.ProjectPlayer(quickEvaluation);
        DclCanonicalQuickAiProjection quickAi = DclCanonicalQuickEvaluation.ProjectAi(quickEvaluation);
        Check(quickEvaluation is { Legal: true, ResourceFailed: false } &&
              quickEvaluation.GrantProbability ==
                  DclSpellResolution.BeneficialSuccessProbability(12, 12).Fraction &&
              quickEvaluation.CtCreditProbability.Values.Aggregate(
                  DclRational.FromInteger(0),
                  (total, probability) => total + probability) == DclRational.FromInteger(1) &&
              quickEvaluation.ExpectedCtCredit ==
                  quickEvaluation.GrantProbability * DclRational.FromInteger(100) &&
              quickForecast.CtCreditProbability == quickEvaluation.CtCreditProbability &&
              quickAi.CtCreditProbability == quickEvaluation.CtCreditProbability &&
              quickAi.ExpectedCtCredit == quickEvaluation.ExpectedCtCredit,
            "canonical Quick forecast/AI must share the exact Beneficial gate, CT-credit distribution, source payment, and QuickLock legality boundary");
        DclCanonicalQuickEvaluationResult failedQuickEvaluation = DclCanonicalQuickEvaluation.Evaluate(
            runtime,
            new DclCanonicalQuickEvaluationInput(
                AbilityId: 41,
                quickRequest,
                quickTarget,
                BaseSpellScore: 12,
                TargetSpellScore: 12,
                CurrentMpAtResolution: 0,
                CurrentHpAtResolution: 0,
                quickCt,
                quickLocks,
                quickRegistry));
        Check(failedQuickEvaluation is { Legal: false, ResourceFailed: true } &&
              failedQuickEvaluation.GrantProbability == DclRational.FromInteger(0) &&
              failedQuickEvaluation.CtCreditProbability.Count == 0,
            "resource failure must stop Quick evaluation before its caster-roll and CT-credit spaces");
        DclCanonicalQuickExecutionResult quick = DclCanonicalQuickExecutor.Resolve(runtime, quickInput);
        Check(quick.Delivery is { Delivered: true } && quick.CtGrant == DclRational.FromInteger(100) &&
              quickCt.CurrentCt == DclRational.FromInteger(120) && quickCt.IsTurnEligible &&
              quickLocks.IsLocked(quickTarget.Unit) && quick.QuickLock?.Instance.Kind == quickLockDefinition.Kind &&
              quick.Transaction is { ReactionWindowOpened: true } && quick.Transaction.VisibleEffects.Count == 2,
            "canonical Quick must atomically grant enough exact CT, create one visible QuickLock, and expose both effects before one Reaction window");
        DclCanonicalQuickEvaluationResult lockedQuickEvaluation = DclCanonicalQuickEvaluation.Evaluate(
            runtime,
            new DclCanonicalQuickEvaluationInput(
                AbilityId: 41,
                quickRequest,
                quickTarget,
                BaseSpellScore: 12,
                TargetSpellScore: 12,
                CurrentMpAtResolution: 20,
                CurrentHpAtResolution: 20,
                quickCt,
                quickLocks,
                quickRegistry));
        Check(!lockedQuickEvaluation.Legal && lockedQuickEvaluation.Failures.SequenceEqual(["quicklock-active"]) &&
              lockedQuickEvaluation.GrantProbability == DclRational.FromInteger(0),
            "Quick evaluation must reject an existing controller/state QuickLock pair without inventing a cast chance");
        CheckThrows<InvalidOperationException>(
            () => DclCanonicalQuickExecutor.Resolve(runtime, quickInput with { ActionInstanceId = 530 }),
            "Quick must be illegal while the target already owns QuickLock");
        quickCt.GrantTurnAndReset();
        DclCanonicalQuickUnlockResult quickUnlocked = DclCanonicalQuickExecutor.CompleteGrantedTurn(
            quickTarget.Unit,
            quickLockDefinition.Kind,
            quickLocks,
            quickRegistry);
        Check(quickUnlocked.LockControllerCleared && quickUnlocked.RemovedStateInstanceIds.Count == 1 &&
              !quickLocks.IsLocked(quickTarget.Unit) && quickRegistry.Instances.Count == 0,
            "QuickLock must clear from both controller and persistent registry only after the granted turn resolves");
        DclCanonicalQuickExecutionResult failedQuick = DclCanonicalQuickExecutor.Resolve(
            runtime,
            quickInput with { ActionInstanceId = 531, SharedCasterRoll = 13 });
        Check(failedQuick.Delivery is { Delivered: false } &&
              quickCt.CurrentCt == DclRational.FromInteger(0) && !quickLocks.IsLocked(quickTarget.Unit) &&
              quickRegistry.Instances.Count == 0 && failedQuick.Transaction.VisibleEffects.Count == 0,
            "failed Quick casting must change neither CT nor QuickLock state");

        var invalidQuickRandom = new SequenceRandomSource([3, 3, 4]);
        var invalidQuickBattle = new DclCanonicalBattleRuntime(
            runtime,
            battleGeneration: 16,
            initialGlobalCt: 100,
            invalidQuickRandom);
        invalidQuickBattle.ObserveUnit(caster);
        invalidQuickBattle.ObserveUnit(quickTarget.Unit);
        var invalidQuickCt = new DclCtState(initialCt: 20);
        var invalidQuickLocks = new DclQuickLockController();
        DclTargetCandidate invalidQuickTarget = quickInput.Target with
        {
            CombatStateRevision = invalidQuickBattle.States.CaptureTarget(quickTarget.Unit).Revision,
        };
        CheckThrows<ArgumentException>(
            () => DclCanonicalQuickExecutor.Resolve(
                runtime,
                quickInput with
                {
                    ActionInstanceId = 709,
                    SharedCasterRoll = null,
                    TargetCt = invalidQuickCt,
                    QuickLocks = invalidQuickLocks,
                    StateRegistry = invalidQuickBattle.States,
                    ExecutionBattle = invalidQuickBattle,
                    ReactionWindow = DclCanonicalReactionWindow.ConfirmedRequest(invalidQuickBattle, null),
                    Target = invalidQuickTarget,
                    DeclarationRequest = quickInput.DeclarationRequest with { UnitTarget = invalidQuickTarget },
                    LockMaterialization = quickMaterialization with { DurationUnits = 1 },
                }),
            "Quick must reject an invalid persistent QuickLock materialization before execution RNG or CT/controller mutation");
        Check(invalidQuickCt.CurrentCt == DclRational.FromInteger(20) &&
              !invalidQuickLocks.IsLocked(quickTarget.Unit) && invalidQuickBattle.States.Instances.Count == 0 &&
              invalidQuickRandom.DrawCount == 0 && invalidQuickBattle.ExecutionRandom.Count == 0,
            "invalid QuickLock materialization must leave CT, controller, registry, and battle RNG unchanged");

        var coordinatedQuickRandom = new SequenceRandomSource([3, 3, 4]);
        var coordinatedQuickBattle = new DclCanonicalBattleRuntime(
            runtime,
            battleGeneration: 16,
            initialGlobalCt: 100,
            coordinatedQuickRandom);
        coordinatedQuickBattle.ObserveUnit(caster);
        coordinatedQuickBattle.ObserveUnit(quickTarget.Unit);
        var coordinatedQuickCt = new DclCtState(initialCt: 20);
        var coordinatedQuickLocks = new DclQuickLockController();
        DclTargetCandidate coordinatedQuickTarget = quickInput.Target with
        {
            CombatStateRevision = coordinatedQuickBattle.States.CaptureTarget(quickTarget.Unit).Revision,
        };
        DclCanonicalQuickExecutionResult coordinatedQuick = DclCanonicalQuickExecutor.Resolve(
            runtime,
            quickInput with
            {
                ActionInstanceId = 710,
                SharedCasterRoll = null,
                TargetCt = coordinatedQuickCt,
                QuickLocks = coordinatedQuickLocks,
                StateRegistry = coordinatedQuickBattle.States,
                ExecutionBattle = coordinatedQuickBattle,
                ReactionWindow = DclCanonicalReactionWindow.ConfirmedRequest(coordinatedQuickBattle, null),
                Target = coordinatedQuickTarget,
                DeclarationRequest = quickInput.DeclarationRequest with { UnitTarget = coordinatedQuickTarget },
            });
        Check(coordinatedQuick.Delivery is { Delivered: true } &&
              coordinatedQuickCt.CurrentCt == DclRational.FromInteger(120) &&
              coordinatedQuickLocks.IsLocked(quickTarget.Unit) &&
              coordinatedQuick.QuickLock?.Instance.Kind == quickLockDefinition.Kind &&
              coordinatedQuickRandom.DrawCount == 3 && coordinatedQuickBattle.ExecutionRandom.Count == 1 &&
              coordinatedQuick.Reactions is { Accepted.Count: 0 },
            "confirmed Quick must own one shared casting identity before atomically granting CT and materializing QuickLock");

        var auxiliaryCarrierBattle = new DclCanonicalBattleRuntime(runtime, battleGeneration: 16);
        auxiliaryCarrierBattle.ObserveUnit(caster);
        auxiliaryCarrierBattle.ObserveUnit(targetKey);
        DclCanonicalReactionWindowResult EmptyReactions(DclActionTransaction transaction) =>
            DclCanonicalReactionWindow.Resolve(
                transaction.Declaration,
                new DclCanonicalReactionWindowRequest(runtime, []));
        DclCanonicalNativeStrikeProjection ConsumeAuxiliary(
            DclCanonicalNativeActionApplication application)
        {
            DclCanonicalNativeStrikeProjection pending = application.PeekNextStrike();
            DclCanonicalNativeStrikeProjection applied = application.ApplyNextStrike(
                pending.Target,
                pending.StrikeIndex);
            Check(DclCanonicalNativeApplyRouter.TryPreparePayment(
                      auxiliaryCarrierBattle,
                      application.Plan.ActionInstanceId,
                      out DclCanonicalNativePaymentReservation payment),
                "an auxiliary action must expose its source payment only after the target carrier");
            DclCanonicalNativeApplyRouter.CommitPayment(payment);
            if (payment.ReactionWindowOpened)
                DclCanonicalNativeApplyRouter.AcknowledgeReactionWindow(payment);
            DclCanonicalNativeApplyRouter.SettleAndRetire(auxiliaryCarrierBattle, payment);
            return applied;
        }
        DclCanonicalNativeStrikeProjection projectedStatus = ConsumeAuxiliary(
            DclCanonicalNativeExecutionPublisher.PublishStatus(
                auxiliaryCarrierBattle,
                28,
                appliedStatus with { Reactions = EmptyReactions(appliedStatus.Transaction) }));
        DclCanonicalNativeStrikeProjection projectedRemoval = ConsumeAuxiliary(
            DclCanonicalNativeExecutionPublisher.PublishStatusRemoval(
                auxiliaryCarrierBattle,
                14,
                removedStatus with { Reactions = EmptyReactions(removedStatus.Transaction) }));
        DclCanonicalNativeStrikeProjection projectedDispel = ConsumeAuxiliary(
            DclCanonicalNativeExecutionPublisher.PublishDispel(
                auxiliaryCarrierBattle,
                244,
                dispelled with { Reactions = EmptyReactions(dispelled.Transaction) }));
        DclCanonicalNativeStrikeProjection projectedQuick = ConsumeAuxiliary(
            DclCanonicalNativeExecutionPublisher.PublishQuick(
                auxiliaryCarrierBattle,
                41,
                quick with { Reactions = EmptyReactions(quick.Transaction) }));
        DclCanonicalNativeStrikeProjection projectedRaise = ConsumeAuxiliary(
            DclCanonicalNativeExecutionPublisher.PublishRevive(
                auxiliaryCarrierBattle,
                5,
                raised with { Reactions = EmptyReactions(raised.Transaction) }));
        DclCanonicalNativeStrikeProjection projectedReraise = ConsumeAuxiliary(
            DclCanonicalNativeExecutionPublisher.PublishRevive(
                auxiliaryCarrierBattle,
                7,
                storedReraise with { Reactions = EmptyReactions(storedReraise.Transaction) }));
        Check(projectedStatus.AuxiliaryEffects?.AddedStates.Single() is
              { StateKind: "canonical-status-test" } &&
              projectedRemoval.AuxiliaryEffects?.RemovedStates.Single() is
              { StateKind: "canonical-status-test" } &&
              projectedDispel.AuxiliaryEffects?.RemovedStates.Single() is
              { StateKind: "canonical-dispel-strong-test" } &&
              projectedQuick.AuxiliaryEffects is
              {
                  AddedStates: [{ StateKind: "canonical-quick-lock-test" }],
                  CtCredit: var projectedQuickCt,
              } && projectedQuickCt == DclRational.FromInteger(100) &&
              projectedRaise is
              {
                  Channels: { HpCredit: 13 },
                  AuxiliaryEffects.ClearKoAfterPositiveHpCredit: true,
              } && projectedReraise is
              {
                  Channels: { IsEmpty: true },
                  AuxiliaryEffects.AddedStates: [{ StateKind: "canonical-reraise-test" }],
              } && auxiliaryCarrierBattle.NativeActions.Count == 0,
            "status, removal, per-instance Dispel, Quick CT/lock, immediate Revive, and Stored Reraise must retain explicit auxiliary semantics through apply, payment, Reaction, settlement, and retirement");

        DclCanonicalNativeAuxiliaryApplyPlan nativeStatusApply =
            DclCanonicalNativeAuxiliaryApplyPlanner.Build(runtime, projectedStatus);
        DclCanonicalNativeAuxiliaryApplyPlan nativeRemovalApply =
            DclCanonicalNativeAuxiliaryApplyPlanner.Build(runtime, projectedRemoval);
        DclCanonicalNativeAuxiliaryApplyPlan customQuickApply =
            DclCanonicalNativeAuxiliaryApplyPlanner.Build(runtime, projectedQuick);
        DclStatusPacketPlan nativeStatusPacket = DclCanonicalNativeAuxiliaryApplyPlanner.ComposeStatusPacket(
            nativeStatusApply,
            oldAdd: [0x80, 0x00, 0x00, 0x00, 0x00],
            oldRemove: [0x00, 0x02, 0x00, 0x00, 0x00],
            oldResultFlags: 0x80);
        DclStatusPacketPlan nativeRemovalPacket = DclCanonicalNativeAuxiliaryApplyPlanner.ComposeStatusPacket(
            nativeRemovalApply,
            oldAdd: [0x00, 0x02, 0x00, 0x00, 0x00],
            oldRemove: [0x00, 0x00, 0x00, 0x00, 0x00],
            oldResultFlags: 0x80);
        Check(nativeStatusApply.StatusPacketMutations.Single() is
              { Bit.ByteIndex: 1, Bit.Mask: 0x02, Add: true, StateKind: "canonical-status-test" } &&
              nativeStatusApply.CustomAddedStates.Count == 0 &&
              nativeStatusPacket.Add.SequenceEqual(new byte[] { 0x80, 0x02, 0x00, 0x00, 0x00 }) &&
              nativeStatusPacket.Remove.All(value => value == 0) &&
              nativeStatusPacket.ResultFlags == 0x88 &&
              nativeRemovalApply.StatusPacketMutations.Single() is
              { Bit.ByteIndex: 1, Bit.Mask: 0x02, Add: false } &&
              nativeRemovalPacket.Add.All(value => value == 0) &&
              nativeRemovalPacket.Remove.SequenceEqual(new byte[] { 0x00, 0x02, 0x00, 0x00, 0x00 }) &&
              customQuickApply.StatusPacketMutations.Count == 0 &&
              customQuickApply.CustomAddedStates.Single().StateKind == "canonical-quick-lock-test" &&
              customQuickApply.CtCredit == DclRational.FromInteger(100) &&
              DclCanonicalNativeAuxiliaryApplyPlanner.EncodePositiveCtDelta(customQuickApply.CtCredit.Value) == 0xE4,
            "native overlays must own one packet bit while custom states remain registry-only and exact CT credit stays outside the byte packet");
        CheckThrows<InvalidOperationException>(
            () => DclCanonicalNativeAuxiliaryApplyPlanner.EncodePositiveCtDelta(new DclRational(1, 4)),
            "native CT staging must reject fractional credit until a named DCL-to-byte rounding boundary exists");
        CheckThrows<InvalidOperationException>(
            () => DclCanonicalNativeAuxiliaryApplyPlanner.EncodePositiveCtDelta(DclRational.FromInteger(128)),
            "native CT staging must reject credit wider than its one-byte sign-magnitude carrier");

        var nativeReplacementStrike = projectedStatus with
        {
            AuxiliaryEffects = new DclCanonicalNativeAuxiliaryEffects(
                AddedStates: [new DclCanonicalNativeStateMutationProjection(9002, statusDefinition.Kind)],
                RemovedStates: [new DclCanonicalNativeStateMutationProjection(9001, statusDefinition.Kind)],
                CtCredit: null,
                ClearKoAfterPositiveHpCredit: false),
        };
        DclCanonicalNativeAuxiliaryApplyPlan nativeReplacement =
            DclCanonicalNativeAuxiliaryApplyPlanner.Build(runtime, nativeReplacementStrike);
        Check(nativeReplacement.StatusPacketMutations.Single() is { Add: true, Bit.ByteIndex: 1, Bit.Mask: 0x02 },
            "replacing one native overlay inside one outer action must finish with the owned bit present rather than staging contradictory add/remove lanes");

        DclActionDeclaration CommandDeclaration(DclActionProfile profile, long actionInstanceId) => new(
            actionInstanceId,
            caster,
            profile.ActionId,
            profile.ProfileRevision,
            DclTargetMode.Caster,
            TrackedTarget: null,
            FixedTile: null,
            new DclBattleTile(0, 0, 0),
            PassedRangeCheck: true,
            PassedVerticalCheck: true,
            FinalMpCost: 0,
            ApprovedHpCap: 0,
            CastCt: 0,
            DeclaredAtGlobalCt: 100,
            ResolvesAtGlobalCt: 100);
        var commandSource = new DclTargetResolutionSnapshot(
            caster,
            CurrentHp: 20,
            CombatStateRevision: 17,
            new DclDefenseResourceSnapshot(
                new Dictionary<string, int> { ["main-hand"] = 2 },
                BlockAvailable: false));
        var readyResources = new DclTurnResources();
        var unreadyWeapon = new DclWeaponActionState(
            "main-hand",
            DclWeaponBalance.Balanced,
            DclWeaponReadinessProperty.UnreadyAfterAttack,
            initiallyReady: false);
        DclCanonicalCommandExecutionResult readied = DclCanonicalCommandExecutor.Ready(
            runtime,
            CommandDeclaration(readyAction, 532),
            commandSource,
            readyResources,
            unreadyWeapon);
        Check(unreadyWeapon.Ready && !readyResources.ActionAvailable && readyResources.MovementAvailable &&
              readied.Transaction is { ReactionWindowOpened: true } && readied.Transaction.VisibleEffects.Count == 1,
            "canonical Ready must spend Action only, ready the selected Unready weapon during commit, and open one Reaction window");

        var reequipResources = new DclTurnResources();
        var defenseBeforeReequip = new DclReequipDefenseSnapshot(
            new Dictionary<string, int> { ["main-hand"] = 2 },
            BlockAvailable: false,
            new Dictionary<string, bool> { ["main-hand"] = false },
            new Dictionary<string, bool> { ["main-hand"] = true });
        DclCanonicalCommandExecutionResult reequipped = DclCanonicalCommandExecutor.Reequip(
            runtime,
            CommandDeclaration(reequipAction, 533),
            commandSource,
            reequipResources,
            defenseBeforeReequip);
        DclReequipDefenseSnapshot preservedReequip = reequipped.ReequipSnapshot ??
            throw new InvalidOperationException("canonical Reequip returned no defense snapshot");
        Check(!reequipResources.ActionAvailable && reequipResources.MovementAvailable &&
              preservedReequip.ParryAttemptCounts["main-hand"] == 2 &&
              preservedReequip.BlockAvailable == false &&
              preservedReequip.WeaponReady["main-hand"] == false &&
              preservedReequip.ParrySuppressedAfterAttack["main-hand"] &&
              reequipped.Transaction is { ReactionWindowOpened: true },
            "canonical Reequip must spend Action while preserving every existing Parry, Block, readiness, and balance resource");

        var standUpResources = new DclTurnResources();
        var standUpRegistry = new DclStateRegistry(16, initialGlobalCt: 100);
        DclStateApplicationResult knockedDownState = standUpRegistry.Apply(new DclStateApplication(
            knockedDownDefinition,
            caster,
            Source: null,
            AppliedAtGlobalCt: 100,
            AppliedBeforeTurnSerial: 46,
            FirstEligibleTargetTurnSerial: null,
            FirstEligibleSourceTurnSerial: null,
            DurationUnits: null,
            Strength: null,
            WinningMargin: null,
            StackDiscriminator: "default",
            ContributionIdentity: null,
            new DclPropertyStatePayload(knockedDownDefinition.PayloadSchema, new Dictionary<string, string>()),
            knockedDownDefinition.PresentationProfile));
        DclCanonicalCommandExecutionResult stoodUp = DclCanonicalCommandExecutor.StandUp(
            runtime,
            CommandDeclaration(standUpAction, 534),
            commandSource with
            {
                CombatStateRevision = standUpRegistry.CaptureTarget(caster).Revision,
            },
            standUpResources,
            standUpRegistry,
            knockedDownDefinition.Kind);
        Check(!standUpResources.ActionAvailable && !standUpResources.MovementAvailable &&
              stoodUp.RemovedStateInstanceIds.SequenceEqual([knockedDownState.Instance.InstanceId]) &&
              standUpRegistry.Instances.Count == 0 && stoodUp.Transaction is { ReactionWindowOpened: true },
            "canonical Stand Up must spend both Action and Movement, remove Knocked Down atomically, and open one Reaction window");

        DclTargetResolutionSnapshot CurrentCommandSource(DclCanonicalBattleRuntime battle)
        {
            DclStateRegistryTargetSnapshot state = battle.States.CaptureTarget(caster);
            DclDefenseResourceSnapshot defense = battle.CaptureDefenseResources(caster);
            return new DclTargetResolutionSnapshot(caster, CurrentHp: 20, state.Revision, defense);
        }

        var confirmedCommandRandom = new SequenceRandomSource([]);
        var confirmedCommandBattle = new DclCanonicalBattleRuntime(
            runtime,
            battleGeneration: 16,
            initialGlobalCt: 100,
            confirmedCommandRandom);
        confirmedCommandBattle.ObserveUnit(caster);
        confirmedCommandBattle.ObserveUnit(targetKey);
        DclWeaponActionState confirmedUnreadyWeapon = confirmedCommandBattle.WeaponState(
            caster,
            "main-hand",
            DclWeaponBalance.Balanced,
            DclWeaponReadinessProperty.UnreadyAfterAttack,
            initiallyReady: false);
        DclTargetResolutionSnapshot confirmedCommandSource = CurrentCommandSource(confirmedCommandBattle);
        CheckThrows<ArgumentException>(
            () => DclCanonicalCommandExecutionCoordinator.Ready(
                confirmedCommandBattle,
                CommandDeclaration(readyAction, 541),
                confirmedCommandSource with { CombatStateRevision = 7 },
                "main-hand"),
            "confirmed Ready must reject a stale source state snapshot before changing turn or weapon state");
        Check(confirmedUnreadyWeapon.RequiresReadyAction &&
              confirmedCommandBattle.TurnResources(caster) is { ActionAvailable: true, MovementAvailable: true } &&
              confirmedCommandRandom.DrawCount == 0,
            "stale confirmed Ready must leave weapon, turn-resource, and random state unchanged");
        CheckThrows<KeyNotFoundException>(
            () => DclCanonicalCommandExecutionCoordinator.Ready(
                confirmedCommandBattle,
                CommandDeclaration(readyAction, 542),
                confirmedCommandSource,
                "main-hand",
                [new DclCanonicalReactionCandidate(
                    0,
                    targetKey,
                    "missing-reaction",
                    TriggerSatisfied: true,
                    Eligible: true,
                    Aware: true,
                    CostsAndUsesAvailable: true,
                    ActivationReferenceScore: null,
                    ActivationRoll: null,
                    NativeCardinalityAllows: true)]),
            "confirmed Ready must preflight its exact Reaction window before spending Action or changing readiness");
        Check(confirmedUnreadyWeapon.RequiresReadyAction &&
              confirmedCommandBattle.TurnResources(caster).ActionAvailable &&
              confirmedCommandRandom.DrawCount == 0,
            "invalid confirmed Ready Reaction metadata must leave all deterministic state unchanged");
        DclCanonicalCommandExecutionResult confirmedReady =
            DclCanonicalCommandExecutionCoordinator.Ready(
                confirmedCommandBattle,
                CommandDeclaration(readyAction, 543),
                confirmedCommandSource,
                "main-hand",
                []);
        Check(confirmedUnreadyWeapon.Ready &&
              confirmedCommandBattle.TurnResources(caster) is { ActionAvailable: false, MovementAvailable: true } &&
              confirmedReady.Reactions is { Candidates.Count: 0, Accepted.Count: 0 } &&
              confirmedReady.Transaction is { Stage: DclActionTransactionStage.Settled, ReactionWindowOpened: true },
            "confirmed Ready must use battle-owned weapon/resources and resolve one explicit empty Reaction window");

        var tauntedCommandBattle = new DclCanonicalBattleRuntime(runtime, 16, initialGlobalCt: 100);
        tauntedCommandBattle.ObserveUnit(caster);
        tauntedCommandBattle.ObserveUnit(targetKey);
        DclWeaponActionState tauntedUnreadyWeapon = tauntedCommandBattle.WeaponState(
            caster,
            "main-hand",
            DclWeaponBalance.Balanced,
            DclWeaponReadinessProperty.UnreadyAfterAttack,
            initiallyReady: false);
        DclStateDefinition commandTauntDefinition = BuildDclStateDefinition(
            "taunt", DclStateStackPolicy.Replace, DclStateDurationClock.TargetTurn, sourceRequired: true);
        tauntedCommandBattle.States.Apply(new DclStateApplication(
            commandTauntDefinition,
            caster,
            Source: targetKey,
            AppliedAtGlobalCt: 100,
            AppliedBeforeTurnSerial: 0,
            FirstEligibleTargetTurnSerial: 1,
            FirstEligibleSourceTurnSerial: null,
