                        WeaponSlot: "main-hand",
                        TriggerArcOrTiles: "front-arc",
                        TriggerCondition: "enemy-finishes-movement",
                        RemainingTriggers: payloadUses,
                        ExpiresAfterSourceTurnSerial: 50),
                    physicalAction.ActionId,
                    physicalBinding.AbilityId),
                overwatchDefinition.PresentationProfile);
        CheckThrows<InvalidOperationException>(
            () => preparedBattle.ApplyState(OverwatchApplication(2, 1, "invalid-count")),
            "battle-owned prepared application must reject a payload/use mismatch before registry mutation");
        Check(preparedRegistry.Instances.Count == 0,
            "rejected prepared application must leave the battle state registry unchanged");
        DclStateApplication invalidOverwatchBinding = OverwatchApplication(1, 1, "invalid-binding");
        invalidOverwatchBinding = invalidOverwatchBinding with
        {
            Payload = ((DclOverwatchStatePayload)invalidOverwatchBinding.Payload) with
            {
                EffectAbilityId = quickBinding.AbilityId,
            },
        };
        CheckThrows<InvalidOperationException>(
            () => preparedBattle.ApplyState(invalidOverwatchBinding),
            "Overwatch must reject a native effect ability bound to a different Action before registry mutation");
        Check(preparedRegistry.Instances.Count == 0,
            "rejected Overwatch effect binding must leave the battle state registry unchanged");
        DclStateApplicationResult overwatchInstance = preparedBattle.ApplyState(
            OverwatchApplication(2, 2, "main-hand"));
        DclOverwatchStatePayload declaredOverwatchPayload =
            (DclOverwatchStatePayload)overwatchInstance.Instance.Payload;
        Check(declaredOverwatchPayload.ReservedActionInstanceIds?.Count == 2 &&
              declaredOverwatchPayload.ReservedActionInstanceIds.SequenceEqual([1L, 2L]) &&
              preparedBattle.ActionInstances.NextId == 3,
            "Overwatch declaration must reserve one stable outer ActionInstance per authored trigger before movement occurs");
        DclCanonicalOverwatchTriggerResult midMovement = preparedRuntime.TryOverwatch(
            overwatchInstance.Instance.InstanceId,
            new DclOverwatchTriggerContext(
                MovementEvent: true,
                MovementSettled: false,
                WeaponStillValid: false,
                SourceStillValid: false,
                TargetStillValid: false,
                RangeLegal: false,
                TrajectoryLegal: false,
                TriggerConditionSatisfied: true));
        Check(!midMovement.Trigger.Triggered && midMovement.Trigger.StateRemains &&
              midMovement.Trigger.RemainingUses == 2 && midMovement.EffectAction is null,
            "canonical Overwatch must ignore every tile-by-tile movement event before revalidation and never pause movement");
        DclCanonicalOverwatchTriggerResult settledMovement = preparedRuntime.TryOverwatch(
            overwatchInstance.Instance.InstanceId,
            new DclOverwatchTriggerContext(
                MovementEvent: true,
                MovementSettled: true,
                WeaponStillValid: true,
                SourceStillValid: true,
                TargetStillValid: true,
                RangeLegal: true,
                TrajectoryLegal: true,
                TriggerConditionSatisfied: true));
        Check(settledMovement.Trigger is { Triggered: true, StateRemains: true, RemainingUses: 1 } &&
              settledMovement.EffectAction?.ActionId == physicalAction.ActionId &&
              settledMovement.ReservedActionInstanceId == declaredOverwatchPayload.ReservedActionInstanceIds![0] &&
              preparedRegistry.TryGet(overwatchInstance.Instance.InstanceId, out DclStateInstance oneUseOverwatch) &&
              oneUseOverwatch.RemainingUses == 1,
            "settled-movement Overwatch must revalidate every dependency, reserve its normalized effect action, and consume exactly one persistent trigger");
        var restoredPreparedRuntime = new DclCanonicalPreparedStateRuntime(runtime, preparedRegistry);
        DclCanonicalOverwatchTriggerResult invalidatedOverwatch = restoredPreparedRuntime.TryOverwatch(
            overwatchInstance.Instance.InstanceId,
            new DclOverwatchTriggerContext(
                MovementEvent: true,
                MovementSettled: true,
                WeaponStillValid: false,
                SourceStillValid: true,
                TargetStillValid: true,
                RangeLegal: true,
                TrajectoryLegal: true,
                TriggerConditionSatisfied: true));
        Check(!invalidatedOverwatch.Trigger.Triggered && !invalidatedOverwatch.Trigger.StateRemains &&
              invalidatedOverwatch.RemovedStateInstanceIds.SequenceEqual([overwatchInstance.Instance.InstanceId]) &&
              !preparedRegistry.TryGet(overwatchInstance.Instance.InstanceId, out _),
            "a reconstructed battle-owned prepared runtime must resume from the registry's exact remaining use, while failed settled-movement revalidation cancels the persistent state without firing");

        DclStateApplicationResult finalTileFiringState = preparedBattle.ApplyState(
            OverwatchApplication(1, 1, "final-tile-fire"));
        DclStateApplicationResult finalTileIdleState = preparedBattle.ApplyState(
            OverwatchApplication(1, 1, "final-tile-idle"));
        var completedMovement = new DclFinalTileSnapshot(
            BattleGeneration: 16,
            Sequence: 1,
            ActorPtr: (nint)0x1000,
            UnitPtr: (nint)0x2000,
            MoverTableIndex: target.Unit.UnitSlot,
            MoverCharId: target.Unit.CharacterId,
            RouteLength: 0,
            RouteCursor: 1,
            ActorState: 0,
            ActorTile: new DclFinalTilePosition(5, 6, 0),
            TargetTile: new DclFinalTilePosition(5, 6, 0),
            UnitTile: new DclFinalTilePosition(5, 6, 0),
            BattleState: DclFinalTileEvent.MovementBattleState,
            RouteSignature: 0x1234UL);
        DclCanonicalOverwatchFinalTileCandidate FinalTileCandidate(
            long stateInstanceId,
            bool triggerCondition) => new(
                stateInstanceId,
                caster,
                new DclBattleTile(3, 4, 0),
                WeaponSlot: "main-hand",
                WeaponStillValid: true,
                SourceCanExecute: true,
                TargetEligible: true,
                RangeLegal: true,
                VerticalLegal: true,
                TrajectoryLegal: true,
                TriggerConditionSatisfied: triggerCondition);
        CheckThrows<ArgumentException>(
            () => preparedBattle.ResolveOverwatchFinalTile(
                completedMovement with { MoverCharId = target.Unit.CharacterId + 1 },
                [FinalTileCandidate(finalTileFiringState.Instance.InstanceId, triggerCondition: true)]),
            "final-tile Overwatch must reject a mover identity that does not match the observed battle unit");
        Check(preparedRegistry.TryGet(finalTileFiringState.Instance.InstanceId, out _) &&
              preparedRegistry.TryGet(finalTileIdleState.Instance.InstanceId, out _),
            "rejected final-tile identity must not consume or cancel any prepared state");
        DclCanonicalOverwatchFinalTileBatch finalTileBatch = preparedBattle.ResolveOverwatchFinalTile(
            completedMovement,
            [
                FinalTileCandidate(finalTileIdleState.Instance.InstanceId, triggerCondition: false),
                FinalTileCandidate(finalTileFiringState.Instance.InstanceId, triggerCondition: true),
            ]);
        DclCanonicalOverwatchFinalTileResolution firedFinalTile = finalTileBatch.Resolutions.Single(
            resolution => resolution.Candidate.StateInstanceId == finalTileFiringState.Instance.InstanceId);
        DclCanonicalOverwatchFinalTileResolution idleFinalTile = finalTileBatch.Resolutions.Single(
            resolution => resolution.Candidate.StateInstanceId == finalTileIdleState.Instance.InstanceId);
        Check(finalTileBatch.Mover == target.Unit && finalTileBatch.FinalTile == new DclBattleTile(5, 6, 0) &&
              finalTileBatch.Resolutions.Select(result => result.Candidate.StateInstanceId)
                  .SequenceEqual(finalTileBatch.Resolutions.Select(result => result.Candidate.StateInstanceId).Order()) &&
              firedFinalTile.Trigger.Trigger.Triggered &&
              firedFinalTile.Trigger.EffectBinding?.AbilityId == physicalBinding.AbilityId &&
              firedFinalTile.ReservedAction is
              {
                  Source: var reservedSource,
                  TrackedTarget: var reservedTarget,
                  DeclarationTile: var reservedSourceTile,
                  CastCt: 0,
                  FinalMpCost: 0,
              } && reservedSource == caster && reservedTarget == target.Unit &&
              reservedSourceTile == new DclBattleTile(3, 4, 0) &&
              firedFinalTile.ReservedAction.ActionInstanceId ==
                  ((DclOverwatchStatePayload)finalTileFiringState.Instance.Payload).ReservedActionInstanceIds!.Single() &&
              !preparedRegistry.TryGet(finalTileFiringState.Instance.InstanceId, out _) &&
              !idleFinalTile.Trigger.Trigger.Triggered && idleFinalTile.ReservedAction is null &&
              preparedRegistry.TryGet(finalTileIdleState.Instance.InstanceId, out DclStateInstance idlePersistent) &&
              idlePersistent.RemainingUses == 1,
            "one accepted final-tile batch must bind the exact mover/tile/weapon state, sort candidates, reserve one immediate zero-cost Action per firing state, and preserve nonmatching triggers");
        DclCanonicalPreparedActionTicket pendingPrepared = preparedBattle.PeekNextPreparedAction();
        Check(preparedBattle.PendingPreparedActionCount == 1 &&
              pendingPrepared is
              {
                  MovementSequence: 1,
                  NativeOrder: 0,
                  StateInstanceId: var pendingPreparedState,
                  Stage: DclCanonicalPreparedActionStage.Reserved,
                  Application: null,
              } && pendingPreparedState == finalTileFiringState.Instance.InstanceId &&
              pendingPrepared.Declaration == firedFinalTile.ReservedAction,
            "a firing final-tile trigger must enter the battle-owned prepared Action queue with its declaration-time identity");
        var preparedTimeline = new DclCanonicalTimelineScheduler(
            preparedBattle,
            [
                new DclCanonicalTimelineUnit(caster, initiativeRank: 0, new DclCtState(0), DclCtRate.Normal),
                new DclCanonicalTimelineUnit(target.Unit, initiativeRank: 1, new DclCtState(0), DclCtRate.Normal),
            ]);
        CheckThrows<InvalidOperationException>(
            () => DclCanonicalTimelineCheckpointCodec.Serialize(preparedTimeline),
            "timeline checkpoint must reject a reserved prepared Action even before native publication");
        CheckThrows<InvalidOperationException>(
            () => preparedBattle.ResolveOverwatchFinalTile(
                completedMovement,
                [FinalTileCandidate(finalTileIdleState.Instance.InstanceId, triggerCondition: true)]),
            "the battle-owned final-tile ledger must reject duplicate delivery or any event that overtakes its queued Action");
        Check(preparedRegistry.TryGet(finalTileIdleState.Instance.InstanceId, out idlePersistent) &&
              idlePersistent.RemainingUses == 1,
            "duplicate final-tile delivery must not consume the surviving prepared state");

        CheckThrows<ArgumentException>(
            () => preparedBattle.ResolveAndPublishNextPreparedAction(physicalCoordinatorRequest),
            "prepared execution must reject a deterministic family input that changes its reserved declaration before publication");
        Check(preparedBattle.NativeActions.Count == 0 &&
              preparedBattle.PeekNextPreparedAction().Stage == DclCanonicalPreparedActionStage.Reserved,
            "rejected prepared execution identity must leave both queue and native ledger untouched");
        string[] preparedParryKeys = coordinatedStrikeRequests
            .SelectMany(strike => strike.DefenseCandidates)
            .Where(candidate => candidate.Kind == DclDefenseKind.Parry &&
                !string.IsNullOrWhiteSpace(candidate.ResourceKey))
            .Select(candidate => candidate.ResourceKey!)
            .Distinct(StringComparer.Ordinal)
            .ToArray();
        DclTargetResolutionSnapshot preparedPhysicalTarget = physicalCoordinatorRequest.Targets.Single() with
        {
            CombatStateRevision = preparedBattle.States.CaptureTarget(target.Unit).Revision,
            DefenseResources = preparedBattle.CaptureDefenseResources(target.Unit, preparedParryKeys),
        };
        DclCanonicalPhysicalExecutionRequest preparedPhysicalRequest = physicalCoordinatorRequest with
        {
            AbilityId = physicalBinding.AbilityId,
            Declaration = pendingPrepared.Declaration,
            Targets = [preparedPhysicalTarget],
            ReactionCandidates = [],
        };
        DclCanonicalConfirmedExecutionDispatchResult preparedDispatch =
            preparedBattle.ResolveAndPublishNextPreparedAction(preparedPhysicalRequest);
        DclCanonicalNativeActionApplication preparedApplication = preparedDispatch.Application!;
        Check(preparedBattle.PeekNextPreparedAction() is
              {
                  Stage: DclCanonicalPreparedActionStage.Published,
                  Application: not null,
              } && ReferenceEquals(preparedBattle.PeekNextPreparedAction().Application, preparedApplication) &&
              ReferenceEquals(preparedBattle.NativeActions.Get(pendingPrepared.Declaration.ActionInstanceId), preparedApplication),
            "prepared execution must publish only the queue head and retain the exact native application until settlement");
        foreach (DclCanonicalNativeStrikeProjection strike in preparedApplication.Plan.Strikes)
            preparedApplication.ApplyNextStrike(strike.Target, strike.StrikeIndex);
        if (preparedApplication.Plan.SourceEffect is not null)
            preparedApplication.CommitSourceEffect();
        preparedApplication.CommitResourcePayment();
        if (preparedApplication.Plan.ReactionWindowOpened)
            preparedApplication.AcknowledgeReactionWindow();
        preparedApplication.Settle();
        DclCanonicalPreparedActionTicket completedPrepared =
            preparedBattle.CompleteNextPreparedAction(preparedApplication);
        Check(completedPrepared.Declaration == pendingPrepared.Declaration &&
              preparedBattle.PendingPreparedActionCount == 0 && preparedBattle.NativeActions.Count == 0,
            "only the exact settled prepared application may retire the queue head and expose the next event boundary");
        string preparedCheckpoint = DclCanonicalTimelineCheckpointCodec.Serialize(preparedTimeline);
        DclCanonicalTimelineRestoreResult restoredPrepared = DclCanonicalTimelineCheckpointCodec.Restore(
            preparedCheckpoint,
            runtime,
            battleGeneration: 17);
        DclOverwatchStatePayload restoredIdlePayload = (DclOverwatchStatePayload)restoredPrepared.Battle.States
            .Instances.Single(instance => instance.Kind == overwatchDefinition.Kind).Payload;
        Check(restoredIdlePayload.ReservedActionInstanceIds?.SequenceEqual(
                  ((DclOverwatchStatePayload)idlePersistent.Payload).ReservedActionInstanceIds!) == true &&
              restoredPrepared.Battle.ActionInstances.NextId == preparedBattle.ActionInstances.NextId,
            "settled checkpoint restore must preserve every unused declared Overwatch reservation and the later Action cursor");

        var cancellationBattle = new DclCanonicalBattleRuntime(runtime, battleGeneration: 18, initialGlobalCt: 100);
        DclUnitKey cancellationSource = caster with { BattleGeneration = 18 };
        DclUnitKey cancellationTarget = target.Unit with { BattleGeneration = 18 };
        cancellationBattle.ObserveUnit(cancellationSource);
        cancellationBattle.ObserveUnit(cancellationTarget);
        DclStateApplication cancellationApplication = OverwatchApplication(1, 1, "identity-loss") with
        {
            Target = cancellationSource,
            Source = cancellationSource,
        };
        DclStateApplicationResult cancellationState = cancellationBattle.ApplyState(cancellationApplication);
        var cancellationMovement = completedMovement with
        {
            BattleGeneration = 18,
            Sequence = 1,
            MoverTableIndex = cancellationTarget.UnitSlot,
            MoverCharId = cancellationTarget.CharacterId,
        };
        DclCanonicalOverwatchFinalTileCandidate cancellationCandidate =
            FinalTileCandidate(cancellationState.Instance.InstanceId, triggerCondition: true) with
            {
                Source = cancellationSource,
            };
        DclCanonicalOverwatchFinalTileBatch cancellationBatch = cancellationBattle.ResolveOverwatchFinalTile(
            cancellationMovement,
            [cancellationCandidate]);
        long cancelledReservation = cancellationBatch.Resolutions.Single().ReservedAction!.ActionInstanceId;
        Check(cancellationBattle.PendingPreparedActionCount == 1,
            "identity-loss sentinel requires one reserved but unpublished prepared Action");
        cancellationBattle.RemoveUnit(cancellationTarget);
        Check(cancellationBattle.PendingPreparedActionCount == 0 &&
              cancellationBattle.NextActionInstanceId() > cancelledReservation,
            "removing an unpublished prepared source or tracked target must cancel its queue ticket without reusing the burned identity");
        preparedRegistry.RemoveInstances([finalTileIdleState.Instance.InstanceId]);

        var protector = new DclUnitKey(16, 6, 106);
        preparedBattle.ObserveUnit(protector);
        DclStateApplicationResult protectionInstance = preparedBattle.ApplyState(new DclStateApplication(
            protectionDefinition,
            protector,
            protector,
            AppliedAtGlobalCt: 100,
            AppliedBeforeTurnSerial: 48,
            FirstEligibleTargetTurnSerial: null,
            FirstEligibleSourceTurnSerial: null,
            DurationUnits: 1,
            Strength: null,
            WinningMargin: null,
            StackDiscriminator: target.Unit.ToString(),
            ContributionIdentity: null,
            new DclProtectionStatePayload(
                protectionDefinition.PayloadSchema,
                new DclProtectionPayload(
                    target.Unit,
                    new HashSet<DclDelivery> { DclDelivery.PhysicalAttack },
                    AdjacencyOrRangeRule: "adjacent",
                    RemainingIntercepts: 1,
                    ExpiresAfterSourceTurnSerial: 50)),
            protectionDefinition.PresentationProfile));
        var protectionCandidate = new DclCanonicalProtectionRedirectCandidate(
            protectionInstance.Instance.InstanceId,
            Attacker: caster,
            DeclaredTarget: target.Unit,
            protector,
            DclDelivery.PhysicalAttack,
            RangeOrAdjacencyLegal: true,
            ProtectorCanReceiveHit: true);
        CheckThrows<ArgumentException>(
            () => preparedBattle.ResolveProtectionRedirect(protectionCandidate with { DeclaredTarget = caster }),
            "protection redirect must reject a declared target outside the persistent source-owned link before mutation");
        Check(preparedRegistry.TryGet(protectionInstance.Instance.InstanceId, out _),
            "rejected protection identity must preserve the exact intercept state");
        DclCanonicalProtectionRedirectResolution protectedHit =
            preparedBattle.ResolveProtectionRedirect(protectionCandidate);
        Check(protectedHit.Trigger.Trigger is { Triggered: true, StateRemains: false, RemainingUses: 0 } &&
              protectedHit.Trigger.RedirectTarget == protector && protectedHit.FinalTarget == protector &&
              protectedHit.Trigger.RemovedStateInstanceIds.SequenceEqual([protectionInstance.Instance.InstanceId]),
            "canonical Cover/Bodyguard must redirect only an eligible revalidated delivery to the protector and consume its exact intercept state");
        CheckThrows<ArgumentException>(
            () => new DclProtectionState(new DclProtectionPayload(
                target.Unit,
                new HashSet<DclDelivery> { DclDelivery.ExternalProjectile },
                AdjacencyOrRangeRule: "adjacent",
                RemainingIntercepts: 1,
                ExpiresAfterSourceTurnSerial: 50)),
            "Cover/Bodyguard must reject ExternalProjectile because tracked spells ignore physical cover");

        DclStateApplicationResult invalidRangeProtection = preparedBattle.ApplyState(new DclStateApplication(
            protectionDefinition,
            protector,
            protector,
            AppliedAtGlobalCt: 100,
            AppliedBeforeTurnSerial: 49,
            FirstEligibleTargetTurnSerial: null,
            FirstEligibleSourceTurnSerial: null,
            DurationUnits: 1,
            Strength: null,
            WinningMargin: null,
            StackDiscriminator: target.Unit.ToString(),
            ContributionIdentity: null,
            new DclProtectionStatePayload(
                protectionDefinition.PayloadSchema,
                new DclProtectionPayload(
                    target.Unit,
                    new HashSet<DclDelivery> { DclDelivery.PhysicalAttack },
                    AdjacencyOrRangeRule: "adjacent",
                    RemainingIntercepts: 1,
                    ExpiresAfterSourceTurnSerial: 50)),
            protectionDefinition.PresentationProfile));
        DclCanonicalProtectionRedirectResolution invalidRangeRedirect = preparedBattle.ResolveProtectionRedirect(
            protectionCandidate with
            {
                StateInstanceId = invalidRangeProtection.Instance.InstanceId,
                RangeOrAdjacencyLegal = false,
            });
        Check(!invalidRangeRedirect.Trigger.Trigger.Triggered &&
              invalidRangeRedirect.FinalTarget == target.Unit &&
              invalidRangeRedirect.Trigger.RemovedStateInstanceIds.SequenceEqual(
                  [invalidRangeProtection.Instance.InstanceId]) &&
              !preparedRegistry.TryGet(invalidRangeProtection.Instance.InstanceId, out _),
            "an invalid protection link must end atomically without redirecting the declared target");

        DclStateApplicationResult bulwarkInstance = preparedRegistry.Apply(new DclStateApplication(
            bulwarkDefinition,
            caster,
            caster,
            AppliedAtGlobalCt: 100,
            AppliedBeforeTurnSerial: 49,
            FirstEligibleTargetTurnSerial: null,
            FirstEligibleSourceTurnSerial: null,
            DurationUnits: null,
            Strength: null,
            WinningMargin: null,
            StackDiscriminator: "default",
            ContributionIdentity: null,
            new DclBulwarkStatePayload(
                bulwarkDefinition.PayloadSchema,
                new DclBulwarkPayload(2, 3, 4, "native-passability")),
            bulwarkDefinition.PresentationProfile));
        preparedRuntime.Attach(bulwarkInstance.Instance.InstanceId);
        Check(preparedRuntime.ApplyBulwarkCancellation(
                  bulwarkInstance.Instance.InstanceId,
                  movedVoluntarily: false,
                  knockedDown: false,
                  stanceCancellingStun: false,
                  ko: false).Count == 0 &&
              preparedRegistry.TryGet(bulwarkInstance.Instance.InstanceId, out _),
            "Bulwark must persist while no authored cancellation condition occurs");
        Check(preparedRuntime.ApplyBulwarkCancellation(
                  bulwarkInstance.Instance.InstanceId,
                  movedVoluntarily: true,
                  knockedDown: false,
                  stanceCancellingStun: false,
                  ko: false).SequenceEqual([bulwarkInstance.Instance.InstanceId]) &&
              !preparedRegistry.TryGet(bulwarkInstance.Instance.InstanceId, out _),
            "voluntary movement must cancel Bulwark atomically through the persistent-state owner");
    }

    private static void TestDclNumericContract()
    {
        Check(new DclRational(5, 2).RoundNearest() == 3 &&
              new DclRational(-5, 2).RoundNearest() == -3,
            "roundNearest must send exact halves away from zero");
        Check(new DclRational(-1, 4).Floor() == -1 &&
              new DclRational(-1, 4).Ceiling() == 0,
            "floor and ceiling must not inherit truncation-toward-zero behavior for negatives");
        Check(DclRational.ParseExactDecimal("0.006") == new DclRational(3, 500) &&
              DclRational.ParseExactDecimal("-1.25") == new DclRational(-5, 4),
            "authored base-10 decimals must normalize to exact rationals");

        var equalContest = DclQuickContest.Resolve(10, 10, 10, 10);
        Check(equalContest.Outcome == DclQuickContestOutcome.TargetResisted &&
              equalContest.ActingMargin == equalContest.TargetMargin,
            "Quick Contest ties must belong to the target");
        var contestProbability = DclQuickContest.SuccessProbability(10, 10);
        Check(contestProbability.SuccessfulOutcomes == 16_413 &&
              contestProbability.TotalOutcomes == DclQuickContest.OutcomeCount,
            "Quick Contest forecast must exactly enumerate all 46,656 acting/target roll pairs");

        Check(!DclPercentageRoll.Succeeds(0, 0) && DclPercentageRoll.Succeeds(99, 100) &&
              DclPercentageRoll.Succeeds(29, 30) && !DclPercentageRoll.Succeeds(30, 30),
            "percentage rolls must use uniform 0..99 with the strict roll < clamped chance boundary");

        var probability = new DclExactProbability(21_924, 46_656);
        Check(probability.RoundWholePercent() == 47 && probability.FloorPermille() == 469,
            "forecast display percent and permille fields must use their distinct mandated rounding rules");

        var identity = new DclRollIdentity(7, 42, 1, 0x10, 4, 0x22, 2, DclRollSite.ActiveDefense, 0);
        Check(identity == identity with { },
            "roll identity must be a stable value independent from runtime pointers and callback instances");

        var randomSource = new SequenceRandomSource([1, 2, 3, 99, 6, 5, 4, 3]);
        var randomLedger = new DclExecutionRandomLedger(7, randomSource);
        int firstRoll = randomLedger.Roll3D6(identity);
        int repeatedRoll = randomLedger.Roll3D6(identity);
        Check(firstRoll == 6 && repeatedRoll == 6 && randomSource.DrawCount == 3 &&
              randomLedger.Get(identity).Components.SequenceEqual([1, 2, 3]),
            "confirmed execution re-entry must reuse one cached 3d6 result and its three independent component dice");
        var percentageIdentity = identity with { RollSite = DclRollSite.Percentage };
        var damageIdentity = identity with { RollSite = DclRollSite.DamageDie };
        var selectionIdentity = identity with { RollSite = DclRollSite.RandomSelection };
        Check(randomLedger.RollPercentage(percentageIdentity) == 99 &&
              randomLedger.RollD6Pool(damageIdentity, 3).SequenceEqual([6, 5, 4]) &&
              randomLedger.SelectIndex(selectionIdentity, 4) == 3 &&
              randomLedger.Count == 6 && randomSource.DrawCount == 8,
            "execution randomness must preserve exact 0..99, independent d6 draw-index, and uniform candidate-index domains");
        CheckThrows<InvalidOperationException>(
            () => randomLedger.SelectIndex(selectionIdentity, 5),
            "one RollIdentity cannot be silently reused under a different selection domain");
        CheckThrows<ArgumentException>(
            () => randomLedger.Roll3D6(identity with { BattleGeneration = 8 }),
            "a confirmed-execution draw cannot cross its battle generation");
        var targetlessSource = new SequenceRandomSource([4, 4, 4]);
        var targetlessLedger = new DclExecutionRandomLedger(7, targetlessSource);
        Check(targetlessLedger.Roll3D6(identity with
              {
                  TargetUnitSlot = -1,
                  TargetCharacterId = -1,
                  StrikeIndex = 0,
                  RollSite = DclRollSite.Explicit,
              }) == 12,
            "one shared per-Action caster draw must support an explicit targetless identity without borrowing a target");
    }

    private sealed class SequenceRandomSource : IDclUniformRandomSource
    {
        private readonly Queue<int> _values;

        public SequenceRandomSource(IEnumerable<int> values)
            => _values = new Queue<int>(values);

        public int DrawCount { get; private set; }

        public int Next(int inclusiveMinimum, int exclusiveMaximum)
        {
            if (_values.Count == 0)
                throw new InvalidOperationException("The deterministic random sequence is exhausted.");
            DrawCount++;
            return _values.Dequeue();
        }
    }

    private static void TestDclCharacteristics()
    {
        Check(DclCharacteristics.BraveToHt(0) == 4 &&
              DclCharacteristics.BraveToHt(25) == 7 &&
              DclCharacteristics.BraveToHt(50) == 10 &&
              DclCharacteristics.BraveToHt(75) == 13 &&
              DclCharacteristics.BraveToHt(100) == 16 &&
              DclCharacteristics.BraveToHt(112) == 18 &&
              DclCharacteristics.BraveToHt(120) == 19,
            "BraveToHT must preserve every canonical document-01 anchor");

        DclPrimaryCharacteristics primary = DclCharacteristics.ResolvePrimary(new DclAttributeInputs(
            RawPa: 4,
            RawSpeed: 7,
            RawMa: 8,
            CurrentBrave: 75,
            JobStAdjustment: -10,
            EquipmentStAdjustment: 2,
            StateStAdjustment: 1,
            JobDxAdjustment: 3,
            EquipmentDxAdjustment: 1,
            StateDxAdjustment: 0,
            JobIqAdjustment: 2,
            EquipmentIqAdjustment: 1,
            StateIqAdjustment: 1));
        Check(primary == new DclPrimaryCharacteristics(St: 1, Dx: 11, Iq: 12, Ht: 13),
            "ST, DX, and IQ must use additive current adjustments while HT remains Brave-derived");

        DclSecondaryCharacteristics secondary = DclCharacteristics.ResolveSecondary(
            new DclPrimaryCharacteristics(St: 10, Dx: 11, Iq: 12, Ht: 13),
            new DclSecondaryInputs(
                CharacterHpModifier: 1,
                JobHpModifier: 1,
                EquipmentStatusHpModifier: -3,
                CharacterMpModifier: 2,
                JobMpModifier: -1,
                EquipmentStatusMpModifier: -4,
                WillModifier: 3,
                JobBasicSpeedAdjustment: new DclRational(1, 4),
                BasicSpeedModifier: null,
                JobMoveAdjustment: 1,
                MoveModifier: -2,
                JobJumpAdjustment: -5,
                EquipmentStatusJumpModifier: 0));
        Check(secondary.BaseMaxHp == 12 && secondary.MaxHp == 9 &&
              secondary.BaseMaxMp == 14 && secondary.MaxMp == 10 && secondary.Will == 15 &&
              secondary.BasicLift == DclRational.FromInteger(20) &&
              secondary.BasicSpeed == new DclRational(25, 4) && secondary.BasicMove == 5 &&
              secondary.BaseJump == 1 && secondary.BaseDodge == 9,
            "secondary characteristics must retain exact Lift/Speed fractions and named rounding boundaries");

        var informationUnit = new DclUnitKey(31, 4, 44);
        var informationEquipmentItem = new DclItemMetadata(
            ItemId: 172,
            ProfileRevision: 1,
            DclItemSlot.Body,
            Weight: DclRational.FromInteger(40),
            BodyDr: 2,
            HeadDr: 0,
            StModifier: 1,
            DxModifier: 2,
            IqModifier: 0,
            HpModifier: -5,
            MpModifier: 3,
            BasicSpeedModifier: new DclRational(1, 2),
            MoveModifier: -1,
            JumpModifier: 1,
            DodgeModifier: -2,
            WillModifier: 2,
            MagicResistanceModifier: 1,
            Weapon: null,
            Shield: null,
            Focus: null,
            ElementProperties: [],
            StatusImmunities: [],
            SpecialProperties: []);
        var informationEquipment = new DclCanonicalEquipmentSnapshot(
            new DclNativeEquipmentSlots(0, 172, 0, 0, 0, 0, 0),
            [new DclCanonicalEquippedItem("body", informationEquipmentItem)],
            informationEquipmentItem.Weight,
            informationEquipmentItem.StModifier,
            informationEquipmentItem.DxModifier,
            informationEquipmentItem.IqModifier,
            informationEquipmentItem.HpModifier,
            informationEquipmentItem.MpModifier,
            informationEquipmentItem.BasicSpeedModifier,
            informationEquipmentItem.MoveModifier,
            informationEquipmentItem.JumpModifier,
            informationEquipmentItem.DodgeModifier,
            informationEquipmentItem.WillModifier,
            informationEquipmentItem.MagicResistanceModifier,
            informationEquipmentItem.BodyDr,
            informationEquipmentItem.HeadDr);
        var informationNonEquipmentAttributes = new DclCanonicalAttributeAdjustments(
            JobSt: 2,
            StateSt: -1,
            JobDx: 0,
            StateDx: -1,
            JobIq: 3);
        var informationNonEquipmentSecondary = new DclSecondaryInputs(
            CharacterHpModifier: 4,
            JobHpModifier: 6,
            CharacterMpModifier: 1,
            JobMpModifier: 2,
            WillModifier: 1,
            JobBasicSpeedAdjustment: null,
            JobMoveAdjustment: 1,
            JobJumpAdjustment: 0);
        var informationRaw = new byte[0x200];
        informationRaw[0x38] = 8;
        informationRaw[0x39] = 7;
        informationRaw[0x3A] = 9;
        informationRaw[0x4F] = 1;
        informationRaw[0x50] = 2;
        informationRaw[0x51] = 0;
        var informationNative = new UnitSnapshot(
            Ptr: (nint)0x4444,
            CharId: informationUnit.CharacterId,
            Level: 1,
            Hp: 4,
            MaxHp: 15,
            Team: 0,
            IsFoe: false,
            Pa: 99,
            Ma: 99,
            Speed: 99,
            Move: 4,
            Jump: 3,
            Brave: 75,
            Faith: 62,
            Raw: informationRaw,
            Mp: 11,
            MaxMp: 19);
        DclCanonicalNativeUnitProjection informationProjection =
            DclCanonicalNativeSnapshotAdapter.ProjectUnit(
                informationNative,
                informationUnit.BattleGeneration,
                informationUnit.UnitSlot,
                informationUnit,
                sourceTeam: 0,
                DclCanonicalNativeUnitProjectionInput.Compose(
                    informationNonEquipmentAttributes,
                    informationNonEquipmentSecondary,
                    informationEquipment,
                    tileHeight: 0,
                    new DclStateRegistry(informationUnit.BattleGeneration),
                    new DclDefenseResourceSnapshot(new Dictionary<string, int>(), BlockAvailable: true)));
        DclCanonicalUnitInformationProjection information =
            DclCanonicalUnitInformationProjector.Project(
                informationProjection,
                informationEquipment,
                informationNonEquipmentAttributes,
                informationNonEquipmentSecondary,
                rawPa: 8,
                rawSpeed: 9,
                rawMa: 7,
                currentBrave: 75);
        Check(information.St == new DclUnitAttributeBreakdown(8, 2, 1, -1, 10) &&
              information.Dx == new DclUnitAttributeBreakdown(9, 0, 2, -1, 10) &&
              information.Iq == new DclUnitAttributeBreakdown(7, 3, 0, 0, 10) &&
              information.Ht == 13 && information.CurrentBrave == 75 && information.CurrentFaith == 62 &&
              information.Hp == new DclUnitPoolBreakdown(4, 20, 15, 4, 6, -5) &&
              information.Mp == new DclUnitPoolBreakdown(11, 16, 19, 1, 2, 3) &&
              information.BasicLift == DclRational.FromInteger(20) &&
              information.Mobility.BasicSpeed == new DclRational(25, 4) &&
              information.Mobility.Encumbrance.Load == DclRational.FromInteger(40) &&
              information.Mobility.Encumbrance.Band == DclEncumbranceBand.Light &&
              information.Mobility.Encumbrance.EffectiveMove == 4 &&
              information.Mobility.Encumbrance.EffectiveJump == 3 &&
              information.Mobility.Encumbrance.EffectiveDodge == 6 &&
              information.Mobility.Critical is { IsCritical: true, FinalMove: 2, FinalDodge: 3 } &&
              information.Mobility.FinalMove == 2 &&
              information.Mobility.FinalJump == 3 &&
              information.Mobility.FinalDodge == 3,
            "selected-unit information must expose DCL 09 attribute, pool, encumbrance, and Critical breakdowns from the synchronized canonical snapshot");

        DclPoolReconciliation pools = DclCharacteristics.ReconcilePools(20, 8, newMaxHp: 15, newMaxMp: 12);
        Check(pools == new DclPoolReconciliation(15, 8),
            "maximum-pool reconciliation may clamp downward but must never heal or restore upward");

        var unit3 = new DclUnitKey(1, 3, 3);
        var unit4 = new DclUnitKey(1, 4, 4);
        var unit5 = new DclUnitKey(1, 5, 5);
        IReadOnlyList<DclInitiativeEntry> initiative = DclInitiative.Build(
        [
            new DclInitiativeCandidate(unit5, new DclRational(25, 4), Dx: 10),
            new DclInitiativeCandidate(unit3, DclRational.FromInteger(7), Dx: 8),
            new DclInitiativeCandidate(unit4, new DclRational(25, 4), Dx: 12),
        ]);
        Check(initiative.Select(entry => entry.Unit).SequenceEqual([unit3, unit4, unit5]) &&
              initiative.Select(entry => entry.InitialCt).SequenceEqual([75, 50, 25]),
            "initiative must sort by unrounded Basic Speed, DX, and stable slot before applying rank CT");

        var normalCt = new DclCtState(75);
        normalCt.Tick(DclCtRate.Normal);
        normalCt.Tick(DclCtRate.Normal);
        Check(!normalCt.IsTurnEligible && normalCt.CurrentCt == DclRational.FromInteger(95),
            "normal global CT gain must be exactly 10 and independent of Speed");
        normalCt.Tick(DclCtRate.Normal);
        Check(normalCt.IsTurnEligible && normalCt.CurrentCt == DclRational.FromInteger(105),
            "CT eligibility must begin at the exact 100 threshold without an upper clamp");
        normalCt.GrantTurnAndReset();
        Check(normalCt.CurrentCt == DclRational.FromInteger(0),
            "every granted turn must reset CT to zero");

        var slowCt = new DclCtState(25);
        for (int tick = 0; tick < 10; tick++) slowCt.Tick(DclCtRate.Slow);
        Check(slowCt.CurrentCt == DclRational.FromInteger(100),
            "Slow CT must retain exact quarter-point precision for its 7.5 gain");
        var hasteCt = new DclCtState(25);
        hasteCt.Tick(DclCtRate.Haste);
        Check(hasteCt.CurrentCt == DclRational.FromInteger(40),
            "Haste CT must apply the exact 1.5 multiplier to global gain");
        hasteCt.ApplyExplicitCtChange(DclRational.FromInteger(-1000));
        Check(hasteCt.CurrentCt == DclRational.FromInteger(0),
            "an explicit negative CT effect cannot create negative stored CT");

        var resources = new DclTurnResources();
        var attackTiming = new DclTimingProfile(ConsumesAction: true, ConsumesMovement: false, 0, 0, ConcentrationRequired: false);
        resources.Pay(attackTiming);
        Check(resources.MovementAvailable && !resources.ActionAvailable,
            "ordinary Attack consumes Action while preserving the Movement resource");
        CheckThrows<InvalidOperationException>(() => resources.Pay(attackTiming),
            "a turn cannot spend the same Action resource twice");
        var standUpResources = new DclTurnResources();
        standUpResources.Pay(new DclTimingProfile(ConsumesAction: true, ConsumesMovement: true, 0, 0, ConcentrationRequired: false));
        Check(!standUpResources.MovementAvailable && !standUpResources.ActionAvailable,
            "Stand Up-shaped timing must consume both turn resources atomically");
    }

    private static void TestDclUniversalActions()
    {
        var resources = new DclTurnResources();
        var heavy = new DclWeaponActionState(
            "main-hand",
            DclWeaponBalance.Balanced,
            DclWeaponReadinessProperty.UnreadyAfterAttack);
        DclUniversalActions.Attack(resources, heavy);
        Check(resources.MovementAvailable && !resources.ActionAvailable &&
              !heavy.Ready && !heavy.CanAttack && !heavy.CanParry,
            "Attack must spend only Action and an UnreadyAfterAttack weapon must immediately lose attack and Parry legality");
        resources.ResetForGrantedTurn();
        DclUniversalActions.Ready(resources, heavy);
        Check(resources.MovementAvailable && !resources.ActionAvailable && heavy.Ready && heavy.CanParry,
            "Ready must spend Action, preserve Movement, and restore both attack and Parry availability for the weapon");

        var unbalanced = new DclWeaponActionState(
            "off-hand",
            DclWeaponBalance.Unbalanced,
            DclWeaponReadinessProperty.AlwaysReady);
        resources.ResetForGrantedTurn();
        DclUniversalActions.Attack(resources, unbalanced);
        Check(unbalanced.Ready && !unbalanced.CanParry,
            "an Unbalanced weapon must remain Ready after attacking but lose Parry until its owner's next turn");
        unbalanced.BeginOwnerTurn();
        Check(unbalanced.CanParry,
            "the owner's next turn must clear only temporary Unbalanced Parry loss");

        var alwaysReadyResources = new DclTurnResources();
        CheckThrows<InvalidOperationException>(
            () => DclUniversalActions.Ready(alwaysReadyResources, unbalanced),
            "Ready must reject an already-ready/AlwaysReady weapon");
        Check(alwaysReadyResources.ActionAvailable && alwaysReadyResources.MovementAvailable,
            "an illegal Ready command must not partially spend turn resources");

        resources.ResetForGrantedTurn();
        var beforeReequip = new DclReequipDefenseSnapshot(
            new Dictionary<string, int> { ["main-hand"] = 2 },
            BlockAvailable: false,
            new Dictionary<string, bool> { ["main-hand"] = false },
            new Dictionary<string, bool> { ["off-hand"] = true });
        DclReequipDefenseSnapshot afterReequip = DclUniversalActions.Reequip(resources, beforeReequip);
        Check(resources.MovementAvailable && !resources.ActionAvailable &&
              afterReequip.ParryAttemptCounts["main-hand"] == 2 && !afterReequip.BlockAvailable &&
              !afterReequip.WeaponReady["main-hand"] && afterReequip.ParrySuppressedAfterAttack["off-hand"],
            "Reequip must preserve spent Block, repeated Parry, readiness, and temporary Parry loss while spending Action only");

        resources.ResetForGrantedTurn();
        DclUniversalActions.StandUp(resources, knockedDown: true);
        Check(!resources.MovementAvailable && !resources.ActionAvailable,
            "Stand Up must consume both resources and cannot leave a hidden movement or action remainder");
        resources.ResetForGrantedTurn();
        resources.RemoveMovement();
        resources.RemoveAction();
        Check(!resources.MovementAvailable && !resources.ActionAvailable,
            "Don't Move and Don't Act must be representable as independent resource removal");
    }

    private static void TestDclCharacterGrowth()
    {
        static DclGrowthRateVector Vector(
            string st, string dx, string iq, string brave, string hp, string mp)
            => DclGrowthRateVector.FromExactDecimals(new Dictionary<DclGrowthChannel, string>
            {
                [DclGrowthChannel.St] = st,
                [DclGrowthChannel.Dx] = dx,
                [DclGrowthChannel.Iq] = iq,
                [DclGrowthChannel.Brave] = brave,
                [DclGrowthChannel.HpModifier] = hp,
                [DclGrowthChannel.MpModifier] = mp,
            });

        DclRational budget = DclRational.FromInteger(4);
        DclGrowthRateVector physical = Vector("0.1", "0.05", "0.05", "0", "0.5", "0");
        DclGrowthRateVector magical = Vector("0", "0", "0.1", "0.4", "0", "0.5");
        Check(physical.PointEquivalentPerLevel() == budget && magical.PointEquivalentPerLevel() == budget,
            "synthetic job growth shapes must be allowed to differ only after proving the same exact point-equivalent budget");
        CheckThrows<ArgumentException>(
            () => Vector("0.0000001", "0", "0", "0", "0", "0"),
            "growth authoring must reject decimals requiring more than six places instead of rounding them");

        DclGrowthState initialState = DclCharacterGrowth.MigratePreDclSave(currentCharacterLevel: 1);
        var baseline = new DclPermanentGrowthValues(10, 10, 10, 50, 20, 5);
        DclGrowthAwardResult physicalTen = DclCharacterGrowth.AwardThroughLevel(
            initialState, baseline, newCharacterLevel: 11, physical, budget);
        Check(physicalTen.Changed && physicalTen.LevelsAwarded == 10 &&
              physicalTen.PermanentValues.St == 11 && physicalTen.PermanentValues.Dx == 10 &&
              physicalTen.PermanentValues.Iq == 10 && physicalTen.PermanentValues.HpModifier == 25 &&
              physicalTen.State.GrowthProgressMicro[DclGrowthChannel.Dx] == 500_000 &&
              physicalTen.State.GrowthProgressMicro[DclGrowthChannel.Iq] == 500_000,
            "level awards must floor integer gains per lifetime channel while retaining exact micro-unit fractions");

        DclGrowthAwardResult aThenB1 = DclCharacterGrowth.AwardThroughLevel(initialState, baseline, 2, physical, budget);
        DclGrowthAwardResult aThenB2 = DclCharacterGrowth.AwardThroughLevel(aThenB1.State, aThenB1.PermanentValues, 3, magical, budget);
        DclGrowthAwardResult bThenA1 = DclCharacterGrowth.AwardThroughLevel(initialState, baseline, 2, magical, budget);
        DclGrowthAwardResult bThenA2 = DclCharacterGrowth.AwardThroughLevel(bThenA1.State, bThenA1.PermanentValues, 3, physical, budget);
        Check(aThenB2.PermanentValues == bThenA2.PermanentValues &&
              Enum.GetValues<DclGrowthChannel>().All(channel =>
                  aThenB2.State.GrowthProgressMicro[channel] == bThenA2.State.GrowthProgressMicro[channel]),
            "the same multiset of job-level growth vectors must produce identical permanent values and latent progress regardless of order");

        DclGrowthAwardResult repeated = DclCharacterGrowth.AwardThroughLevel(
            aThenB2.State, aThenB2.PermanentValues, newCharacterLevel: 2, physical, budget);
        Check(!repeated.Changed && repeated.LevelsAwarded == 0 && repeated.PermanentValues == aThenB2.PermanentValues,
            "delevel and relevel at an already-awarded Character Level must never manufacture another growth award");
        DclGrowthState migrated = DclCharacterGrowth.MigratePreDclSave(currentCharacterLevel: 20);
        Check(migrated.HighestAwardedCharacterLevel == 20 &&
              migrated.GrowthProgressMicro.Values.All(value => value == 0),
            "pre-DCL migration must preserve the imported baseline, zero unknowable fractions, and begin only after the current level");
        DclGrowthAwardResult newerSchema = DclCharacterGrowth.AwardThroughLevel(
            migrated with { GrowthSchemaRevision = DclCharacterGrowth.CurrentSchemaRevision + 1 },
            baseline,
            21,
            physical,
            budget);
        Check(!newerSchema.Changed && newerSchema.Reason == "unknown-newer-schema-growth-disabled",
            "an unknown newer growth schema must visibly disable awards without resetting or guessing progress");

        string serializedGrowth = DclGrowthStateCodec.Serialize(physicalTen.State);
        DclGrowthPersistenceLoad loadedGrowth = DclGrowthStateCodec.Deserialize(serializedGrowth);
        Check(loadedGrowth is { GrowthEnabled: true, CompatibilityError: null, State: not null } &&
              loadedGrowth.SerializeForSave() == serializedGrowth &&
              loadedGrowth.State.HighestAwardedCharacterLevel == 11 &&
              Enum.GetValues<DclGrowthChannel>().All(channel =>
                  loadedGrowth.State.GrowthProgressMicro[channel] ==
                  physicalTen.State.GrowthProgressMicro[channel]),
            "the per-character growth record must serialize deterministically and restore every lifetime accumulator exactly");
        CheckThrows<DclGrowthPersistenceException>(
            () => DclGrowthStateCodec.Deserialize(serializedGrowth.Replace(
                "\"growthSchemaRevision\":1,",
                "\"growthSchemaRevision\":1,\"unknown\":true,",
                StringComparison.Ordinal)),
            "a current growth schema must reject unknown fields instead of silently dropping persistent data");
        CheckThrows<DclGrowthPersistenceException>(
            () => DclGrowthStateCodec.Deserialize(serializedGrowth.Replace(
                "\"st\":0,",
                "\"st\":0,\"st\":0,",
                StringComparison.Ordinal)),
            "a current growth schema must reject duplicate channel fields");
        string opaqueNewerGrowth = "{\"growthSchemaRevision\":2,\"futureProgress\":{\"opaque\":true}}";
        DclGrowthPersistenceLoad opaqueGrowth = DclGrowthStateCodec.Deserialize(opaqueNewerGrowth);
        Check(opaqueGrowth is
              {
                  State: null,
                  GrowthEnabled: false,
                  CompatibilityError: "unknown-newer-schema-growth-disabled",
              } && opaqueGrowth.SerializeForSave() == opaqueNewerGrowth,
            "an unknown newer growth record must disable awards and remain byte-for-byte reusable without data loss");
        CheckThrows<DclGrowthPersistenceException>(
            () => DclGrowthStateCodec.Deserialize(
                "{\"growthSchemaRevision\":0,\"highestAwardedCharacterLevel\":1,\"growthProgressMicro\":{}}"),
            "an older growth schema must require an explicit migration rather than being guessed");

        Check(DclCharacterGrowth.PermanentFaith(95, [10, -2]) == 100 &&
              DclCharacterGrowth.CurrentFaith(100, [-150, 10]) == 0,
            "permanent and temporary Faith changes must clamp their separate 0..100 roster/battle layers");
    }

    private static void TestDclPhysicalRules()
    {
        Check(DclSkillRules.JobRank(DclAptitudeTier.A, 8) == 6 &&
              DclSkillRules.JobRank(DclAptitudeTier.B, 8) == 5 &&
              DclSkillRules.JobRank(DclAptitudeTier.C, 8) == 4 &&
              DclSkillRules.JobRank(DclAptitudeTier.D, 8) == 3 &&
              DclSkillRules.JobRank(DclAptitudeTier.E, 8) == 2,
            "Job Level 8 aptitude tiers must yield the canonical 16/12/8/4/2-point ranks");
        Check(DclSkillRules.GurpsSkillScore(12, DclSkillDifficulty.Easy, 1) == 12 &&
              DclSkillRules.GurpsSkillScore(12, DclSkillDifficulty.Average, 4) == 14 &&
              DclSkillRules.GurpsSkillScore(12, DclSkillDifficulty.Hard, 7) == 16 &&
              DclSkillRules.GurpsSkillScore(12, DclSkillDifficulty.VeryHard, 2) == 10,
            "GurpsSkillScore must preserve difficulty and increasing four-point training bands");
        Check(DclSkillRules.GurpsSkillScore(12, DclSkillDifficulty.Average, 0, untrainedDefaultPenalty: -5) == 7,
            "Rank 0 must use an explicitly authored untrained/default penalty");
        CheckThrows<ArgumentException>(
            () => DclSkillRules.GurpsSkillScore(12, DclSkillDifficulty.Average, 0),
            "Rank 0 must never invent an implicit untrained default");
        DclSkillTrainingResult resolvedTraining = DclSkillRules.ResolveTraining(new DclSkillTrainingInput(
            ControllingAttribute: 12,
            DclSkillDifficulty.Average,
            DclAptitudeTier.B,
            JobLevel: 8,
            ExplicitSkillModifier: 2));
        Check(resolvedTraining is
              {
                  ControllingAttribute: 12,
                  Difficulty: DclSkillDifficulty.Average,
                  AptitudeTier: DclAptitudeTier.B,
                  JobLevel: 8,
                  Rank: 5,
                  BaseScore: 15,
                  ExplicitSkillModifier: 2,
                  FinalScore: 17,
              },
            "canonical skill training resolution must join explicit aptitude Tier, weapon Difficulty, Job Level, and post-training modifiers without reading draft job content");
        Check(DclSkillRules.NativeJobLevelFromTotalJp(-5) == 1 &&
              DclSkillRules.NativeJobLevelFromTotalJp(0) == 1 &&
              DclSkillRules.NativeJobLevelFromTotalJp(199) == 1 &&
              DclSkillRules.NativeJobLevelFromTotalJp(200) == 2 &&
              DclSkillRules.NativeJobLevelFromTotalJp(2999) == 7 &&
              DclSkillRules.NativeJobLevelFromTotalJp(3000) == 8 &&
              FormulaRuntimeContextBuilder.JobLevelFromTotalJp(1600) == 6,
            "native Job Level derivation must share the proven total-JP threshold table with canonical Skill training");
        var skillPolicy = new DclSkillTrainingPolicy(new Dictionary<DclSkillTrainingPolicyKey, DclAptitudeTier>
        {
            [new DclSkillTrainingPolicyKey(89, " Sword ")] = DclAptitudeTier.B,
        });
        Check(skillPolicy.Resolve(89, "sword") == DclAptitudeTier.B &&
              skillPolicy.Resolve(89, "SWORD") == DclAptitudeTier.B,
            "Skill aptitude policy must normalize explicit job/family keys without inferring draft job content");
        CheckThrows<KeyNotFoundException>(
            () => skillPolicy.Resolve(89, "bow"),
            "Skill aptitude policy must fail closed when the selected weapon family has no authored job/family row");
        CheckThrows<ArgumentOutOfRangeException>(
            () => DclSkillRules.ResolveTraining(new DclSkillTrainingInput(
                ControllingAttribute: 12,
                DclSkillDifficulty.Unknown,
                DclAptitudeTier.B,
                JobLevel: 8)),
            "skill training resolution must fail closed when weapon Difficulty is not authored");

        Check(DclActiveDefenseRules.Dodge(9, 2, 3, 1) == 7,
            "Dodge must apply explicit bonuses, encumbrance, and posture/state penalties once");
        Check(DclActiveDefenseRules.Parry(13, 1, 2, repeatedParryPenalty: 4, statePenalty: 1) == 7 &&
              DclActiveDefenseRules.Parry(-1, 0, 0, 0, 0) == 2,
            "Parry must floor half-skill even for negative situational scores and apply repeated penalties");
        Check(DclActiveDefenseRules.Block(12, 1, 2, statePenalty: 1) == 11,
            "Block must derive from Shield Skill and explicit shield quality/Defense Bonus");

        DclDefenseCandidate selected = DclActiveDefenseRules.SelectOne(
        [
            new DclDefenseCandidate(DclDefenseKind.Block, 12, Legal: true, "legal", "shield"),
            new DclDefenseCandidate(DclDefenseKind.Parry, 12, Legal: true, "legal", "main-hand"),
            new DclDefenseCandidate(DclDefenseKind.Dodge, 12, Legal: true, "legal"),
        ]);
        Check(selected.Kind == DclDefenseKind.Dodge,
            "equal active-defense scores must choose Dodge before Parry before Block");
        selected = DclActiveDefenseRules.SelectOne(
        [
            new DclDefenseCandidate(DclDefenseKind.Dodge, 10, Legal: true, "legal"),
            new DclDefenseCandidate(DclDefenseKind.Parry, 14, Legal: false, "missile", "main-hand"),
            new DclDefenseCandidate(DclDefenseKind.Block, 11, Legal: true, "legal", "shield"),
        ]);
        Check(selected.Kind == DclDefenseKind.Block,
            "an illegal high Parry must be removed before deterministic best-defense selection");

        DclRational unarmedLoad = DclActiveDefenseRules.IncomingParryLoad(null, null, attackerSt: 13);
        DclRational weaponLoad = DclActiveDefenseRules.IncomingParryLoad(null, new DclRational(12, 5), attackerSt: 13);
        DclRational overrideLoad = DclActiveDefenseRules.IncomingParryLoad(new DclRational(7, 2), new DclRational(12, 5), attackerSt: 13);
        Check(unarmedLoad == new DclRational(13, 10) && weaponLoad == new DclRational(12, 5) &&
              overrideLoad == new DclRational(7, 2),
            "ParryLoad must use skill override, else weapon Weight, else exact ST/10 without addition");
        DclRational oneHandLimit = DclActiveDefenseRules.ParryLimit(new DclRational(9, 2), twoHandedParry: false);
        DclRational twoHandLimit = DclActiveDefenseRules.ParryLimit(new DclRational(9, 2), twoHandedParry: true);
        Check(oneHandLimit == new DclRational(9, 2) && twoHandLimit == DclRational.FromInteger(9) &&
              DclActiveDefenseRules.ParryLoadIsLegal(new DclRational(9, 2), oneHandLimit) &&
              !DclActiveDefenseRules.ParryLoadIsLegal(new DclRational(19, 2), twoHandLimit),
            "Parry legality must retain exact load/BasicLift precision and allow equality");
    }

    private static void TestDclFacingAndTargeting()
    {
        var defender = new DclBattleTile(5, 5, 0);
        var north = new DclCardinalVector(0, -1);
        DclFacingClassification front = DclFacingAndTargeting.ClassifyArc(
            new DclBattleTile(6, 4, 0), defender, north);
        DclFacingClassification back = DclFacingAndTargeting.ClassifyArc(
            new DclBattleTile(4, 6, 0), defender, north);
        DclFacingClassification side = DclFacingAndTargeting.ClassifyArc(
            new DclBattleTile(6, 5, 0), defender, north);
        Check(front.Arc == DclAttackArc.Front && front.Forward == 1 && Math.Abs(front.Lateral) == 1 &&
              back.Arc == DclAttackArc.Back && back.Forward == -1 && Math.Abs(back.Lateral) == 1 &&
              side.Arc == DclAttackArc.Side && side.LateralSign != 0,
            "arc classification must put exact diagonals symmetrically into Front/Back and retain side sign for shield legality");
        CheckThrows<ArgumentException>(
            () => DclFacingAndTargeting.ClassifyArc(defender, defender, north),
            "same-tile Reach-C attacks must fail closed");

        var dodgeNine = new DclDefenseOption(DclDefenseKind.Dodge, 9, Depletes: false);
        var blockTen = new DclDefenseOption(DclDefenseKind.Block, 10, Depletes: true);
        DclDefenseOption sideBlind = DclFacingAndTargeting.ApplyDefenseLegality(
            dodgeNine, side, criticalAttack: false, invisibleImmediateOffense: false, defenderBlind: true);
        DclDefenseOption wrongShieldSide = DclFacingAndTargeting.ApplyDefenseLegality(
            blockTen, side, criticalAttack: false, invisibleImmediateOffense: false, defenderBlind: false,
            shieldProtectingLateralSign: -side.LateralSign);
        DclDefenseOption backDefense = DclFacingAndTargeting.ApplyDefenseLegality(
            dodgeNine, back, criticalAttack: false, invisibleImmediateOffense: false, defenderBlind: true);
        DclDefenseOption criticalDefense = DclFacingAndTargeting.ApplyDefenseLegality(
            dodgeNine, front, criticalAttack: true, invisibleImmediateOffense: false, defenderBlind: false);
        Check(sideBlind.Kind == DclDefenseKind.Dodge && sideBlind.Target == 3 &&
              wrongShieldSide.Kind == DclDefenseKind.None && backDefense.Kind == DclDefenseKind.None &&
              criticalDefense.Kind == DclDefenseKind.None,
            "defense legality must apply Side -2 and Blind -4 only after legality, require the shield side, and suppress rear/critical rolls");

        Check(DclFacingAndTargeting.ApplyBlindAttackPenalty(12, sourceBlind: true, visionRequired: true) == 6 &&
              DclFacingAndTargeting.ApplyBlindAttackPenalty(12, sourceBlind: true, visionRequired: false) == 12,
            "Blind must penalize VisionRequired delivery by six without inventing a Perception roll for tracked magic");
        Check(DclFacingAndTargeting.IsReachLegal(
                  new DclBattleTile(0, 0, 0), new DclBattleTile(2, 0, 0), 2, true, true) &&
              !DclFacingAndTargeting.IsReachLegal(
                  new DclBattleTile(0, 0, 0), new DclBattleTile(3, 0, 0), 2, true, true) &&
              !DclFacingAndTargeting.IsReachLegal(
                  new DclBattleTile(0, 0, 0), new DclBattleTile(1, 0, 0), 1, false, true),
            "Reach 1/2 must remain binary and subordinate to native path and height legality");
        Check(DclFacingAndTargeting.ApplicableDr(4, 2, DclPhysicalLocation.NormalCombined) == 6 &&
              DclFacingAndTargeting.ApplicableDr(4, 2, DclPhysicalLocation.Body) == 4 &&
              DclFacingAndTargeting.ApplicableDr(4, 2, DclPhysicalLocation.Head) == 2,
            "normal attacks must sum BodyDR and HeadDR while explicit locations select exactly one armor location");

        Check(!DclFacingAndTargeting.CanSelectInvisibleTarget(
                  targetInvisible: true, hostileSource: true, directlyUnitTargeted: true, sourceOnTargetSide: false) &&
              DclFacingAndTargeting.CanSelectInvisibleTarget(
                  targetInvisible: true, hostileSource: true, directlyUnitTargeted: false, sourceOnTargetSide: false) &&
              DclFacingAndTargeting.CanSelectInvisibleTarget(
                  targetInvisible: true, hostileSource: false, directlyUnitTargeted: true, sourceOnTargetSide: true),
            "Invisible must block hostile direct unit selection while allowing indiscriminate areas and friendly selection");
        DclInvisibleActionPolicy immediate = DclFacingAndTargeting.InvisibleFirstAction(true, offensive: true, castCt: 0);
        DclInvisibleActionPolicy delayed = DclFacingAndTargeting.InvisibleFirstAction(true, offensive: true, castCt: 5);
        Check(immediate.SuppressActiveDefenseForWholeDelivery && immediate.RemoveAtOuterActionCommit &&
              !immediate.RemoveAtDeclarationCompletion &&
              delayed.RemoveAtDeclarationCompletion && !delayed.SuppressActiveDefenseForWholeDelivery &&
              !delayed.RemoveAtOuterActionCommit,
            "immediate invisible offense must suppress active defense through the whole outer action, while delayed casting reveals at declaration");
    }

    private static void TestDclInjury()
    {
        Check(DclInjury.RollDamage(new DclDiceExpression(2, -1), [2, 3]) == 4,
            "damage rolls must consume exactly the normalized number of d6 and then apply Adds");
        CheckThrows<ArgumentException>(
            () => DclInjury.RollDamage(new DclDiceExpression(2, 0), [6]),
            "a damage random site cannot silently omit an authored die");

        DclInjuryResult crushingMinimum = DclInjury.Resolve(
            rawRolledDamage: -5,
            DclDamageType.Crushing,
            applicableDr: 0,
            armorDivisor: DclRational.FromInteger(1));
        DclInjuryResult impalingMinimum = DclInjury.Resolve(
            rawRolledDamage: -5,
            DclDamageType.Impaling,
            applicableDr: 0,
            armorDivisor: DclRational.FromInteger(1));
        Check(crushingMinimum.RolledDamage == 0 && crushingMinimum.Injury == 0 &&
              impalingMinimum.RolledDamage == 1 && impalingMinimum.Injury == 2,
            "minimum basic damage must be zero for crushing and one for cutting/impaling/piercing");

        DclInjuryResult fractionalDivisor = DclInjury.Resolve(
            rawRolledDamage: 3,
            DclDamageType.Piercing,
            applicableDr: 0,
            armorDivisor: new DclRational(1, 2));
        Check(fractionalDivisor.EffectiveDr == 2 && fractionalDivisor.PenetratingDamage == 1 && fractionalDivisor.Injury == 1,
            "a fractional divisor must treat zero ApplicableDR as one before exact division");
        DclInjuryResult halfDr = DclInjury.Resolve(
            rawRolledDamage: 8,
            DclDamageType.Cutting,
            applicableDr: 5,
            armorDivisor: DclRational.FromInteger(2));
        Check(halfDr.EffectiveDr == 2 && halfDr.PenetratingDamage == 6 && halfDr.Injury == 9,
            "DR must floor after division and precede the wound multiplier");
        DclInjuryResult blocked = DclInjury.Resolve(
            rawRolledDamage: 5,
            DclDamageType.Impaling,
            applicableDr: 5,
            armorDivisor: DclRational.FromInteger(1));
        Check(blocked.PenetratingDamage == 0 && blocked.Injury == 0,
            "fully protective DR must cause zero penetration and zero Injury without blunt-trauma leakage");
        DclInjuryResult tinyPiercing = DclInjury.Resolve(
            rawRolledDamage: 1,
            DclDamageType.SmallPiercing,
            applicableDr: 0,
            armorDivisor: DclRational.FromInteger(1));
        Check(tinyPiercing.PenetratingDamage == 1 && tinyPiercing.Injury == 1,
            "positive penetration must cause at least one Injury even with a sub-one wound multiplier");
        DclInjuryResult ignoredDr = DclInjury.Resolve(
            rawRolledDamage: 4,
            DclDamageType.Crushing,
            applicableDr: 999,
            armorDivisor: DclRational.FromInteger(1),
            ignoreDr: true);
        Check(ignoredDr.EffectiveDr == 0 && ignoredDr.Injury == 4,
            "IgnoreDR must be a distinct zero-DR policy rather than a huge synthetic divisor");

        DclMajorWoundResult halfHp = DclInjury.ResolveMajorWound(10, 10, injury: 5, effectiveHt: 10, htRoll: null);
        Check(!halfHp.RequiresHtRoll && halfHp.RemainingHp == 5,
            "Injury equal to half MaxHP is not a Major Wound");
        DclMajorWoundResult majorSuccess = DclInjury.ResolveMajorWound(10, 10, injury: 6, effectiveHt: 10, htRoll: 10);
        DclMajorWoundResult majorFailure = DclInjury.ResolveMajorWound(10, 10, injury: 6, effectiveHt: 10, htRoll: 11);
        Check(majorSuccess.RequiresHtRoll && majorSuccess.AvoidedCollapse &&
              majorFailure.RequiresHtRoll && !majorFailure.AvoidedCollapse,
            "a surviving injury above half MaxHP must make exactly one effective-HT success roll");
        DclMajorWoundResult ko = DclInjury.ResolveMajorWound(5, 10, injury: 5, effectiveHt: 10, htRoll: null);
        Check(ko.RemainingHp == 0 && !ko.RequiresHtRoll,
            "native KO at zero HP must short-circuit the Major-Wound HT roll");

        Check(DclInjury.CriticalKnockbackTiles(true, true, DclDamageType.Crushing, 8, 3, targetSt: 10) == 1 &&
              DclInjury.CriticalKnockbackTiles(false, true, DclDamageType.Crushing, 80, 30, targetSt: 10) == 0 &&
              DclInjury.CriticalKnockbackTiles(true, true, DclDamageType.Cutting, 8, 0, targetSt: 10) == 1 &&
              DclInjury.CriticalKnockbackTiles(true, true, DclDamageType.Cutting, 8, 1, targetSt: 10) == 0 &&
              DclInjury.CriticalKnockbackTiles(true, false, DclDamageType.Crushing, 80, 30, targetSt: 10) == 0,
            "universal knockback must be critical-only, type-gated, survival-gated, and capped at one tile");

        DclInjuryConsequenceResult collapse = DclInjury.ResolveConsequences(
            hpBeforeInjury: 10,
            DclInjury.Resolve(6, DclDamageType.Crushing, 0, DclRational.FromInteger(1)),
            DclDamageType.Crushing,
            criticalSuccess: false,
            new DclInjuryConsequenceInput(
                MaxHp: 10,
                TargetSt: 10,
                EffectiveHt: 10,
                UnexpiredShockInjury: 2,
                StillCharging: true,
                Will: 10,
                ConcentrationModifier: 0,
                ConcentrationStatePenaltyMagnitude: 0,
                MajorWoundHtRoll: 11,
                DirectConcentrationCancellation: false,
                AuthoredForcedDisplacement: 0,
                ConcentrationRoll: null));
        Check(collapse is
              {
                  MajorWound: { RemainingHp: 4, RequiresHtRoll: true, AvoidedCollapse: false },
                  UnexpiredShockInjury: 8,
                  ShockPenaltyMagnitude: 3,
                  ApplyStun: true,
                  ApplyKnockedDown: true,
                  Concentration: { Outcome: DclConcentrationOutcome.DirectCancellation, Rolled: false },
              },
            "one surviving failed Major Wound must accumulate raw Shock Injury, apply Stun/Knocked Down, and directly cancel Charging without another roll");

        DclInjuryConsequenceResult criticalDisruption = DclInjury.ResolveConsequences(
            hpBeforeInjury: 20,
            DclInjury.Resolve(8, DclDamageType.Crushing, 0, DclRational.FromInteger(1)),
            DclDamageType.Crushing,
            criticalSuccess: true,
            new DclInjuryConsequenceInput(
                MaxHp: 20,
                TargetSt: 10,
                EffectiveHt: 10,
                UnexpiredShockInjury: 0,
                StillCharging: true,
                Will: 10,
                ConcentrationModifier: 0,
                ConcentrationStatePenaltyMagnitude: 0,
                MajorWoundHtRoll: null,
                DirectConcentrationCancellation: false,
                AuthoredForcedDisplacement: 0,
                ConcentrationRoll: 8));
        Check(criticalDisruption is
              {
                  CriticalKnockbackTiles: 1,
                  TotalForcedDisplacement: 1,
                  ShockPenaltyMagnitude: 3,
                  Concentration: { Score: 7, Outcome: DclConcentrationOutcome.Interrupted, Rolled: true },
              },
            "a surviving critical crushing Injury must compose capped knockback and exactly one per-Strike concentration check");

        DclStateDefinition injuryShockDefinition = BuildDclStateDefinition(
            "shock", DclStateStackPolicy.Explicit, DclStateDurationClock.TargetTurn,
            removeOnTargetKo: true);
        DclStateDefinition injuryStunDefinition = BuildDclStateDefinition(
            "stun", DclStateStackPolicy.Refresh, DclStateDurationClock.ExplicitCommand,
            removeOnTargetKo: true);
        DclStateDefinition injuryKnockedDefinition = BuildDclStateDefinition(
            "knocked-down", DclStateStackPolicy.Refresh, DclStateDurationClock.ExplicitCommand,
            removeOnTargetKo: true);
        var injuryRegistry = new DclStateRegistry(15, initialGlobalCt: 100);
        var injuryTarget = new DclUnitKey(15, 2, 22);
        var injurySource = new DclUnitKey(15, 1, 11);
        var injuryCommitInput = new DclCanonicalInjuryStateCommitInput(
            injuryRegistry,
            injuryTarget,
            injurySource,
            MaxHp: 10,
            AppliedBeforeTurnSerial: 0,
            FirstEligibleTargetTurnSerial: 1,
            injuryShockDefinition,
            injuryStunDefinition,
            injuryKnockedDefinition);
        DclInjuryResult collapseInjury = DclInjury.Resolve(6, DclDamageType.Crushing, 0, DclRational.FromInteger(1));
        DclCanonicalInjuryStateCommitResult committedCollapse =
            DclCanonicalInjuryConsequenceCommitter.Commit(collapseInjury, collapse, injuryCommitInput);
        Check(committedCollapse is
              {
                  Shock: { Instance: { Payload: DclShockStatePayload { UnexpiredInjury: 6 } } },
                  Stun: { Instance: { Kind: "stun" } },
                  KnockedDown: { Instance: { Kind: "knocked-down" } },
                  CancelConcentrationPreparations: true,
              } && injuryRegistry.Instances.Count == 3,
            "a surviving failed Major Wound must atomically materialize its Shock accumulator, Stun, and Knocked Down state plan");
        DclInjuryResult followupInjury = DclInjury.Resolve(1, DclDamageType.Crushing, 0, DclRational.FromInteger(1));
        DclInjuryConsequenceResult followup = DclInjury.ResolveConsequences(
            hpBeforeInjury: 4,
            followupInjury,
            DclDamageType.Crushing,
            criticalSuccess: false,
            new DclInjuryConsequenceInput(10, 10, 10, 6, false, 10, 0, 0, null, false, 0, null));
        DclCanonicalInjuryStateCommitResult committedFollowup =
            DclCanonicalInjuryConsequenceCommitter.Commit(followupInjury, followup, injuryCommitInput);
        Check(committedFollowup.Shock is
              {
                  Outcome: DclStateApplicationOutcome.ExplicitMerged,
                  Instance: { Payload: DclShockStatePayload { UnexpiredInjury: 7 } },
              } && committedFollowup.Stun is null && committedFollowup.KnockedDown is null &&
              injuryRegistry.Instances.Count == 3,
            "later Injury in the same window must merge into Shock without duplicating or refreshing Major-Wound posture states");
        DclInjuryConsequenceResult lethalFollowup = DclInjury.ResolveConsequences(
            hpBeforeInjury: 1,
            followupInjury,
            DclDamageType.Crushing,
            criticalSuccess: false,
            new DclInjuryConsequenceInput(10, 10, 10, 7, false, 10, 0, 0, null, false, 0, null));
        DclCanonicalInjuryStateCommitResult committedKo =
            DclCanonicalInjuryConsequenceCommitter.Commit(followupInjury, lethalFollowup, injuryCommitInput);
        DclCanonicalNativeAuxiliaryEffects koCleanupProjection =
            DclCanonicalNativeAuxiliaryProjector.ProjectInjuryStates(committedKo) ??
            throw new InvalidOperationException("KO cleanup lost its exact state-removal projection");
        Check(committedKo.RemovedOnTargetKo?.Select(instance => instance.Kind).Order().SequenceEqual(
                  new[] { "knocked-down", "shock", "stun" }) == true &&
              koCleanupProjection.RemovedStates.Select(state => state.StateKind).Order().SequenceEqual(
                  new[] { "knocked-down", "shock", "stun" }) &&
              injuryRegistry.Instances.Count == 0,
            "target KO must remove and project every exact persistent state whose definition owns KO cleanup");
    }

    private static void TestDclEquipmentAndRanged()
    {
        DclRational basicLift = DclRational.FromInteger(20);
        DclEncumbranceResult none = DclEncumbrance.Resolve(basicLift, [DclRational.FromInteger(20)], 5, 3, 9);
        DclEncumbranceResult light = DclEncumbrance.Resolve(basicLift, [DclRational.FromInteger(40)], 5, 3, 9);
        DclEncumbranceResult medium = DclEncumbrance.Resolve(basicLift, [DclRational.FromInteger(60)], 5, 3, 9);
        DclEncumbranceResult heavy = DclEncumbrance.Resolve(basicLift, [DclRational.FromInteger(120)], 5, 3, 9);
        DclEncumbranceResult extra = DclEncumbrance.Resolve(basicLift, [DclRational.FromInteger(121)], 5, 3, 9);
        Check(none.Band == DclEncumbranceBand.None && none.EffectiveMove == 5 && none.EffectiveDodge == 9 &&
              light.Band == DclEncumbranceBand.Light && light.EffectiveMove == 4 && light.EffectiveDodge == 8 &&
              medium.Band == DclEncumbranceBand.Medium && medium.EffectiveMove == 3 && medium.EffectiveDodge == 7 &&
              heavy.Band == DclEncumbranceBand.Heavy && heavy.EffectiveMove == 2 && heavy.EffectiveJump == 1 &&
              extra.Band == DclEncumbranceBand.ExtraHeavy && extra.EffectiveMove == 1 && extra.EffectiveDodge == 5,
            "encumbrance boundaries must be inclusive at 1x/2x/3x/6x BasicLift with exact multipliers and floors");

        Check(DclRangedRules.DistancePenalty(1) == 0 && DclRangedRules.DistancePenalty(2) == 0 &&
              DclRangedRules.DistancePenalty(3) == -1 && DclRangedRules.DistancePenalty(5) == -2 &&
              DclRangedRules.DistancePenalty(7) == -3 && DclRangedRules.DistancePenalty(10) == -4 &&
              DclRangedRules.DistancePenalty(15) == -5 && DclRangedRules.DistancePenalty(20) == -6 &&
              DclRangedRules.DistancePenalty(30) == -7 && DclRangedRules.DistancePenalty(50) == -8,
            "horizontal FFT distance must map exactly to every canonical range band");
        Check(DclRangedRules.EffectiveSkill(15, aimBonus: 0, horizontalTiles: 6, locationPenaltyMagnitude: 0, shockStatePenaltyMagnitude: 0) == 12,
            "the canonical Bow Skill 15 at distance 6 example must resolve to Effective Skill 12");
        Check(DclRangedRules.AimBonus(3, 0) == 0 && DclRangedRules.AimBonus(3, 1) == 3 &&
              DclRangedRules.AimBonus(3, 2) == 4 && DclRangedRules.AimBonus(3, 8) == 5,
            "Aim must grant Acc, then Acc+1, then cap at Acc+2");
        Check(DclRangedRules.DefenseLegality(DclRangedWeaponKind.Bow) == new DclRangedDefenseLegality(true, true, false) &&
              DclRangedRules.DefenseLegality(DclRangedWeaponKind.Crossbow) == new DclRangedDefenseLegality(true, true, false) &&
              DclRangedRules.DefenseLegality(DclRangedWeaponKind.Gun) == new DclRangedDefenseLegality(true, false, false) &&
              DclRangedRules.DefenseLegality(DclRangedWeaponKind.ThrownWeapon) == new DclRangedDefenseLegality(true, true, false),
            "ranged delivery must preserve the explicit Bow/Crossbow/Gun/Thrown defense matrix");

        var aimTargetA = new DclUnitKey(3, 10, 40);
        var aimTargetB = new DclUnitKey(3, 11, 41);
        var aim = new DclAimState(aimTargetA);
        aim.GrantStep(aimTargetA);
        aim.GrantStep(aimTargetA);
        Check(aim.ConsecutiveSteps == 2 && aim.Bonus(3) == 4,
            "consecutive Aim steps must remain bound to one stable target identity");
        aim.GrantStep(aimTargetB);
        Check(aim.Target == aimTargetB && aim.ConsecutiveSteps == 1,
            "changing Aim target must reset accumulation to the first step");
        Check(aim.ResolveInjuryRetention(injury: 0, forcedMovement: false, will: 10, aimRetentionModifier: 0, statePenaltyMagnitude: 0, roll: null),
            "a landed hit reduced to zero Injury must preserve Aim without consuming RNG");
        Check(aim.ResolveInjuryRetention(injury: 1, forcedMovement: false, will: 10, aimRetentionModifier: 0, statePenaltyMagnitude: 0, roll: 10),
            "positive Injury must retain Aim on its one Will success roll");
        Check(!aim.ResolveInjuryRetention(injury: 1, forcedMovement: false, will: 10, aimRetentionModifier: 0, statePenaltyMagnitude: 0, roll: 11) && !aim.Active,
            "a failed Injury retention roll must clear the complete Aim state immediately");
        aim.GrantStep(aimTargetB);
        Check(!aim.ResolveInjuryRetention(injury: 1, forcedMovement: true, will: 10, aimRetentionModifier: 0, statePenaltyMagnitude: 0, roll: null) && !aim.Active,
            "forced movement must cancel Aim directly without a second retention roll");

        var aimOwner = new DclUnitKey(3, 9, 39);
        var secondAimOwner = new DclUnitKey(3, 8, 38);
        var aimRegistry = new DclStateRegistry(3);
        DclStateDefinition aimDefinition = BuildDclStateDefinition(
            "aim", DclStateStackPolicy.Replace, DclStateDurationClock.UsesOrTriggers);
        DclStateApplicationResult ApplyAim(DclUnitKey owner, DclUnitKey tracked, int steps)
            => aimRegistry.Apply(new DclStateApplication(
                aimDefinition,
                owner,
                Source: null,
                AppliedAtGlobalCt: aimRegistry.CurrentGlobalCt,
                AppliedBeforeTurnSerial: 0,
                FirstEligibleTargetTurnSerial: null,
                FirstEligibleSourceTurnSerial: null,
                DurationUnits: 1,
                Strength: null,
                WinningMargin: null,
                StackDiscriminator: "",
                ContributionIdentity: null,
                new DclAimStatePayload(aimDefinition.PayloadSchema, tracked, steps),
                aimDefinition.PresentationProfile));
        DclStateApplicationResult persistentAim = ApplyAim(aimOwner, aimTargetB, steps: 2);
        DclCanonicalAimLifecycleResult retainedAim = DclCanonicalAimLifecycle.ResolveInjuryRetention(
            aimRegistry, aimOwner, injury: 1, forcedMovement: false, will: 10,
            aimRetentionModifier: 0, statePenaltyMagnitude: 0, roll: 10);
        DclCanonicalAimLifecycleResult lostAim = DclCanonicalAimLifecycle.ResolveInjuryRetention(
            aimRegistry, aimOwner, injury: 1, forcedMovement: false, will: 10,
            aimRetentionModifier: 0, statePenaltyMagnitude: 0, roll: 11);
        Check(retainedAim is { HadAim: true, Retained: true } &&
              aimRegistry.CaptureTarget(aimOwner).Revision == 2 &&
              lostAim is { HadAim: true, Retained: false, Reason: "retention-roll-failed" } &&
              lostAim.InstanceId == persistentAim.Instance.InstanceId &&
              !aimRegistry.TryGet(persistentAim.Instance.InstanceId, out _),
            "the registry Aim lifecycle must retain on one successful Injury roll and remove the exact instance on failure without duplicating state");
        ApplyAim(aimOwner, aimTargetB, steps: 1);
        DclCanonicalAimLifecycleResult forcedAim = DclCanonicalAimLifecycle.ResolveInjuryRetention(
            aimRegistry, aimOwner, injury: 1, forcedMovement: true, will: 10,
            aimRetentionModifier: 0, statePenaltyMagnitude: 0, roll: null);
        Check(forcedAim is { HadAim: true, Retained: false, Reason: "forced-movement-cancelled" },
            "forced movement must remove persistent Aim directly without consuming retention RNG");
        ApplyAim(aimOwner, aimTargetB, steps: 1);
        ApplyAim(secondAimOwner, aimTargetB, steps: 1);
        Check(DclCanonicalAimLifecycle.CancelTrackedTargetLoss(aimRegistry, aimTargetB).Count == 2 &&
              !aimRegistry.CaptureTarget(aimOwner).Instances.Any(instance => instance.Kind == "aim") &&
              !aimRegistry.CaptureTarget(secondAimOwner).Instances.Any(instance => instance.Kind == "aim"),
            "loss of a stable tracked target must remove every Aim instance that points to that UnitKey");
    }

    private static void TestDclAuthoringContract()
    {
        var valid = new DclActionProfile(
            "spell.fire",
            1,
            new DclSourceProfile(DclActionSource.Spell, Verbal: true),
            new DclSkillProfile(1, 0, null, ZodiacSensitive: false),
            new DclResourceProfile(10, DclRational.FromInteger(1), DclOvercastPolicy.Allowed),
            new DclTimingProfile(ConsumesAction: true, ConsumesMovement: false, 4, 0, ConcentrationRequired: true),
            new DclTargetProfile(
                DclTargetMode.Unit,
                DclAllegiancePolicy.EnemiesOnly,
                DclEligibleTargetStates.Alive | DclEligibleTargetStates.Undead,
                1,
                5,
                3,
                VisionRequired: false,
                DclPhysicalRoute.None,
                Area: null),
            new DclDeliveryProfile(
                DclDelivery.ExternalProjectile,
                Dodgeable: true,
                Parryable: false,
                Blockable: false,
                UsesDefenseBonus: false,
                DclResistanceCharacteristic.None,
                DclArmorPolicy.Manifestation,
                ArmorDivisor: null,
                DclLocationPolicy.NormalCombined,
                Reflectable: true,
                ShellSensitive: true),
            new DclDamageMagnitude(
                DclDamageBasis.Fixed,
                "2d6",
                0,
                0,
                DclDamageType.Crushing,
                "fire",
                DclRational.FromInteger(1),
                DclFaithPolicy.Both),
            [new DclEffectProfile(
                DclEffectKind.Damage,
                DclEffectRole.Carrier,
                DclEligibleTargetStates.Alive | DclEligibleTargetStates.Undead,
                DclUndeadInteraction.Normal)],
            new DclTransactionProfile(
                1,
                DclCastingRollCardinality.PerAction,
                DclTargetGateCardinality.PerStrike,
                DclMagnitudeRollCardinality.PerTarget,
                DclWithinActionApplication.Deferred),
            new DclCriticalProfile(DclCriticalSuccessEffect.DeliveryDefault, DclCriticalFailureEffect.MissOnly),
            new DclPresentationProfile("fire", "spell-charge", "Fire", ["SpellScore", "DR"], []),
            new DclAiProfile(DclLegalUsePolicy.Standard, ["damage", "fire"], DclExpectedValuePolicy.Exact, DclFriendlyFirePolicy.Forbidden));

        Check(DclAuthoringContract.Validate(valid).IsValid,
            "a complete normalized action profile should pass fail-closed validation");

        var invalid = valid with
        {
            ResourceProfile = valid.ResourceProfile with { BaseMpCost = 0, OvercastPolicy = DclOvercastPolicy.Allowed },
            DeliveryProfile = valid.DeliveryProfile with
            {
                Delivery = DclDelivery.InternalDirect,
                Parryable = true,
                ResistanceCharacteristic = DclResistanceCharacteristic.None,
                ArmorPolicy = DclArmorPolicy.ArmorDividing,
                ArmorDivisor = null,
            },
            MagnitudeProfile = ((DclDamageMagnitude)valid.MagnitudeProfile!) with { FixedExpression = null },
            Effects = [new DclEffectProfile(
                DclEffectKind.StatusApplication,
                DclEffectRole.Rider,
                DclEligibleTargetStates.Alive,
                DclUndeadInteraction.Normal)],
            TransactionProfile = valid.TransactionProfile with { StrikeCount = 0 },
        };
        DclAuthoringValidation invalidAction = DclAuthoringContract.Validate(invalid);
        Check(!invalidAction.IsValid &&
              invalidAction.Findings.Any(f => f.Path == "ResourceProfile.OvercastPolicy") &&
              invalidAction.Findings.Any(f => f.Path == "DeliveryProfile") &&
              invalidAction.Findings.Any(f => f.Path == "DeliveryProfile.ResistanceCharacteristic") &&
              invalidAction.Findings.Any(f => f.Path == "DeliveryProfile.ArmorDivisor") &&
              invalidAction.Findings.Any(f => f.Path == "MagnitudeProfile.FixedExpression") &&
              invalidAction.Findings.Any(f => f.Path == "Effects[0].ReferencedStateKind") &&
              invalidAction.Findings.Any(f => f.Path == "TransactionProfile.StrikeCount"),
            "action normalization must reject incomplete unions and illegal delivery combinations together");

        DclAuthoringValidation badExpression = DclAuthoringContract.Validate(valid with
        {
            MagnitudeProfile = ((DclDamageMagnitude)valid.MagnitudeProfile!) with { FixedExpression = "IQ+d6" },
        });
        DclAuthoringValidation orphanRider = DclAuthoringContract.Validate(valid with
        {
            Effects = [valid.Effects[0] with { Role = DclEffectRole.Rider }],
        });
        DclAuthoringValidation mismatchedMagnitude = DclAuthoringContract.Validate(valid with
        {
            Effects = [valid.Effects[0] with { Kind = DclEffectKind.Healing }],
        });
        Check(!badExpression.IsValid && badExpression.Findings.Any(f => f.Path == "MagnitudeProfile.FixedExpression") &&
              !orphanRider.IsValid && orphanRider.Findings.Any(f => f.Path == "Effects[0].Role") &&
              !mismatchedMagnitude.IsValid && mismatchedMagnitude.Findings.Any(f => f.Path == "MagnitudeProfile"),
            "cross-profile validation must reject free-form dice, riders without carriers, and magnitude/effect union drift");

        var validState = new DclStateDefinition(
            "taunt",
            NativeStatusBit: null,
            SourceRequired: true,
            DclStateResistanceGate.QuickContest,
            "mental",
            DclStateStackPolicy.Refresh,
            "taunt",
            StackCap: null,
            ContributionKey: null,
            ContributionReapplicationPolicy: null,
            new DclStateDurationProfile(
                DclStateDurationClock.TargetTurn,
                "clamp(1, 2 + floor(margin / 3), 5)"),
            TickProfile: null,
            EffectStrengthFormula: "sourceScore",
            RemoveOnTargetKo: true,
            RemoveOnSourceKo: true,
            RemoveOnSourceLoss: true,
            ["mental", "dispel"],
            "source-unit-key",
            "force hostile targeting toward source",
            "state.taunt",
            "state.taunt.ai");
        Check(DclAuthoringContract.Validate(validState).IsValid,
            "a complete source-bound custom state should pass fail-closed validation");
        DclStateDurationRule marginDurationRule = DclStateDurationRules.Parse(validState.Duration);
        Check(marginDurationRule is
              {
                  Kind: DclStateDurationRuleKind.WinningMargin,
                  MinimumDuration: 1,
                  BaseDuration: 2,
                  DurationBand: 3,
                  MaximumDuration: 5,
              } && DclStateDurationRules.Resolve(
                  validState.Duration,
                  winningMargin: 4,
                  materializedUnits: null) == 3,
            "state authoring must normalize the complete clamped winning-margin formula into one executable duration rule");
        var fixedDuration = new DclStateDurationProfile(DclStateDurationClock.GlobalCt, "6");
        Check(DclStateDurationRules.Resolve(fixedDuration, winningMargin: null, materializedUnits: 6) == 6,
            "fixed state duration must normalize to its exact authored positive unit count");
        CheckThrows<ArgumentException>(
            () => DclStateDurationRules.Resolve(fixedDuration, winningMargin: null, materializedUnits: 7),
            "fixed state duration must reject application units that disagree with the normalized rule");
        (IReadOnlyDictionary<int, DclRational> marginDurationProbability,
            DclRational? expectedMarginDuration) = DclCanonicalStatusEvaluation.EvaluateDuration(
                validState,
                materializedDurationUnits: null,
                new Dictionary<int, DclRational>
                {
                    [1] = new DclRational(1, 4),
                    [4] = new DclRational(3, 4),
                },
                new Dictionary<DclMagicDeliveryOutcome, DclRational>
                {
                    [DclMagicDeliveryOutcome.Delivered] = DclRational.FromInteger(1),
                });
        Check(marginDurationProbability.Count == 2 &&
              marginDurationProbability[2] == new DclRational(1, 4) &&
              marginDurationProbability[3] == new DclRational(3, 4) &&
              expectedMarginDuration == new DclRational(11, 4),
            "status forecast must transform exact winning-margin mass through the normalized clamped duration rule");
        DclAuthoringValidation opaqueDuration = DclAuthoringContract.Validate(validState with
        {
            Duration = new DclStateDurationProfile(
                DclStateDurationClock.TargetTurn,
                "2 + floor(margin / 3)"),
        });
        Check(!opaqueDuration.IsValid && opaqueDuration.Findings.Any(f => f.Path == "Duration.Formula"),
            "state authoring must reject an unclamped or otherwise opaque duration expression");

        DclAuthoringValidation invalidNativeBit = DclAuthoringContract.Validate(validState with
        {
            NativeStatusBit = new DclNativeStatusBit(DclStatusPacket.Width, 0x03),
        });
        Check(!invalidNativeBit.IsValid &&
              invalidNativeBit.Findings.Any(f => f.Path == "NativeStatusBit.ByteIndex") &&
              invalidNativeBit.Findings.Any(f => f.Path == "NativeStatusBit.Mask"),
            "native state overlays must address exactly one bit inside the fixed five-byte vocabulary");

        var invalidState = validState with
        {
            StackPolicy = DclStateStackPolicy.StackToCap,
            StackCap = null,
            ContributionKey = null,
            ContributionReapplicationPolicy = null,
            Duration = new DclStateDurationProfile(DclStateDurationClock.GlobalCt, null),
            TickProfile = new DclStateTickProfile(
                0,
                "",
                -1,
                DclStateTickSource.Unknown,
                ImmediatePayload: false),
        };
        DclAuthoringValidation invalidStateResult = DclAuthoringContract.Validate(invalidState);
        Check(!invalidStateResult.IsValid &&
              invalidStateResult.Findings.Any(f => f.Path == "StackCap") &&
              invalidStateResult.Findings.Any(f => f.Path == "ContributionKey") &&
              invalidStateResult.Findings.Any(f => f.Path == "ContributionReapplicationPolicy") &&
              invalidStateResult.Findings.Any(f => f.Path == "Duration.Formula") &&
              invalidStateResult.Findings.Any(f => f.Path == "TickProfile.Interval") &&
              invalidStateResult.Findings.Any(f => f.Path == "TickProfile.EffectActionId"),
            "state normalization must reject incomplete stacking, duration, and tick definitions");

        var registry = new DclAuthoringRegistry();
        Check(registry.TryRegister(valid).IsValid && registry.TryRegister(validState).IsValid,
            "validated action and state definitions should enter the authoring registry");
        Check(!registry.TryRegister(valid with { ProfileRevision = 2 }).IsValid,
            "one registry must never expose different revisions of the same action identity");
        Check(!registry.TryRegister(validState).IsValid,
            "state kind registration must be unique within one normalized registry");

        DclActionProfile stateApplication = valid with
        {
            ActionId = "spell.taunt",
            MagnitudeProfile = null,
            Effects = [new DclEffectProfile(
                DclEffectKind.StatusApplication,
                DclEffectRole.Carrier,
                DclEligibleTargetStates.Alive,
                DclUndeadInteraction.Normal,
                ReferencedStateKind: validState.Kind)],
            DeliveryProfile = valid.DeliveryProfile with
            {
                Delivery = DclDelivery.InternalDirect,
                Dodgeable = false,
                ResistanceCharacteristic = DclResistanceCharacteristic.Will,
                ArmorPolicy = DclArmorPolicy.None,
                LocationPolicy = DclLocationPolicy.EffectOwned,
                Reflectable = false,
                ShellSensitive = false,
            },
            TransactionProfile = valid.TransactionProfile with
            {
                TargetGateCardinality = DclTargetGateCardinality.PerTarget,
            },
            PresentationProfile = valid.PresentationProfile with
            {
                ResultText = "Taunt",
                StatePresentationIds = [validState.PresentationProfile],
            },
        };
        var presentationRegistry = new DclAuthoringRegistry();
        Check(presentationRegistry.TryRegister(stateApplication).IsValid &&
              presentationRegistry.TryRegister(validState).IsValid &&
              presentationRegistry.ValidateReferences().IsValid,
            "an action that materializes a persistent state must bind that state's presentation profile");
        var missingPresentationRegistry = new DclAuthoringRegistry();
        Check(missingPresentationRegistry.TryRegister(stateApplication with
              {
                  PresentationProfile = stateApplication.PresentationProfile with
                  {
                      StatePresentationIds = [],
                  },
              }).IsValid &&
              missingPresentationRegistry.TryRegister(validState).IsValid &&
              missingPresentationRegistry.ValidateReferences().Findings.Any(f =>
                  f.Path == "Actions[spell.taunt].PresentationProfile.StatePresentationIds"),
            "state-materializing actions must fail bundle validation when the applied state presentation id is omitted");

        var duplicateNativeRegistry = new DclAuthoringRegistry();
        Check(duplicateNativeRegistry.TryRegister(validState with
              {
                  Kind = "native-a",
                  StackKey = "native-a",
                  NativeStatusBit = new DclNativeStatusBit(2, 0x04),
              }).IsValid &&
              duplicateNativeRegistry.TryRegister(validState with
              {
                  Kind = "native-b",
                  StackKey = "native-b",
                  NativeStatusBit = new DclNativeStatusBit(2, 0x04),
              }).IsValid &&
              !duplicateNativeRegistry.ValidateReferences().IsValid,
            "one normalized bundle must reject two semantic owners for the same native status bit");
    }

    private static void TestDclStateRegistry()
    {
        var target = new DclUnitKey(12, 4, 0x20);
        var sourceA = new DclUnitKey(12, 1, 0x10);
        var sourceB = new DclUnitKey(12, 2, 0x11);
        var registry = new DclStateRegistry(12, initialGlobalCt: 100);

        DclStateApplication Application(
            DclStateDefinition definition,
            DclUnitKey? source = null,
            int? duration = null,
            long? firstTargetTurn = null,
            long? firstSourceTurn = null,
            int? strength = null,
            int? margin = null,
            string discriminator = "",
            string? contribution = null,
            string payloadValue = "payload")
            => new(
                definition,
                target,
                source,
                registry.CurrentGlobalCt,
                AppliedBeforeTurnSerial: 5,
                firstTargetTurn,
                firstSourceTurn,
                duration,
                strength,
                margin,
                discriminator,
                contribution,
                new DclPropertyStatePayload(definition.PayloadSchema,
                    new Dictionary<string, string> { ["value"] = payloadValue }),
                definition.PresentationProfile);

        DclStateDefinition taunt = BuildDclStateDefinition(
            "taunt",
            DclStateStackPolicy.Refresh,
            DclStateDurationClock.TargetTurn,
            sourceRequired: true,
            removeOnTargetKo: true,
            removeOnSourceKo: true,
            removeOnSourceLoss: true);
        DclStateApplicationResult firstTaunt = registry.Apply(Application(
            taunt, sourceA, duration: 1, firstTargetTurn: 6, payloadValue: "source-a"));
        DclStateApplicationResult refreshedTaunt = registry.Apply(Application(
            taunt, sourceB, duration: 1, firstTargetTurn: 7, payloadValue: "source-b"));
        Check(firstTaunt.Outcome == DclStateApplicationOutcome.Added &&
              refreshedTaunt.Outcome == DclStateApplicationOutcome.Refreshed &&
              refreshedTaunt.Instance.InstanceId == firstTaunt.Instance.InstanceId &&
              refreshedTaunt.Instance.Source == sourceA &&
              ((DclPropertyStatePayload)refreshedTaunt.Instance.Payload).Values["value"] == "source-a" &&
              refreshedTaunt.Instance.ExpiresAfterTargetTurnSerial == 7,
            "Refresh must keep the existing source/payload/Strength while resetting duration from the new application");
        Check(registry.CompleteTargetTurn(target, 6).Count == 0 &&
              registry.CompleteTargetTurn(target, 7).SequenceEqual([firstTaunt.Instance.InstanceId]),
            "target-turn duration must expire only after the declared future turn that began active");

        DclStateDefinition haste = BuildDclStateDefinition(
            "haste", DclStateStackPolicy.Replace, DclStateDurationClock.GlobalCt, stackKey: "haste-slow");
        DclStateDefinition slow = BuildDclStateDefinition(
            "slow", DclStateStackPolicy.Replace, DclStateDurationClock.GlobalCt, stackKey: "haste-slow");
        DclStateApplicationResult hasteResult = registry.Apply(Application(haste, sourceA, duration: 20));
        DclStateApplicationResult slowResult = registry.Apply(Application(slow, sourceB, duration: 30));
        Check(slowResult.Outcome == DclStateApplicationOutcome.Replaced &&
              slowResult.RemovedInstanceIds.SequenceEqual([hasteResult.Instance.InstanceId]) &&
              slowResult.RemovedInstances.Single() == hasteResult.Instance &&
              registry.Instances.Count(instance => instance.Definition.StackKey == "haste-slow") == 1 &&
              slowResult.Instance.Kind == "slow",
            "Replace must atomically remove an opposed state sharing the same target-local StackKey");
        DclCanonicalNativeAuxiliaryEffects replacedProjection =
            DclCanonicalNativeAuxiliaryProjector.ProjectStateApplications([slowResult]) ??
            throw new InvalidOperationException("replacement projection lost its state mutations");
        Check(replacedProjection.AddedStates.Single() is { StateKind: "slow" } &&
              replacedProjection.RemovedStates.Single() is { StateKind: "haste" },
            "state replacement must retain the exact old and new semantic kinds after registry commit");

        DclStateDefinition fear = BuildDclStateDefinition(
            "fear", DclStateStackPolicy.StrongestWins, DclStateDurationClock.TargetTurn,
            sourceRequired: true, stackKey: "fear");
        DclStateApplicationResult fearFive = registry.Apply(Application(
            fear, sourceA, duration: 2, firstTargetTurn: 8, strength: 5, margin: 5, payloadValue: "source-a"));
        DclStateApplicationResult fearThree = registry.Apply(Application(
            fear, sourceB, duration: 9, firstTargetTurn: 8, strength: 3, margin: 3, payloadValue: "source-b"));
        DclStateApplicationResult fearEqual = registry.Apply(Application(
            fear, sourceB, duration: 4, firstTargetTurn: 8, strength: 5, margin: 5, payloadValue: "source-b"));
        DclStateApplicationResult fearSeven = registry.Apply(Application(
            fear, sourceB, duration: 2, firstTargetTurn: 8, strength: 7, margin: 7, payloadValue: "source-b"));
        Check(fearThree.Outcome == DclStateApplicationOutcome.WeakerRejected &&
              fearEqual.Outcome == DclStateApplicationOutcome.EqualExtended &&
              fearEqual.Instance.InstanceId == fearFive.Instance.InstanceId &&
              fearEqual.Instance.Source == sourceA && fearEqual.Instance.ExpiresAfterTargetTurnSerial == 11 &&
              fearSeven.Outcome == DclStateApplicationOutcome.StrongerReplaced && fearSeven.Instance.Source == sourceB,
            "StrongestWins must reject weaker states, preserve the older owner on ties, extend ties, and replace completely when stronger");

        DclStateDefinition exposure = BuildDclStateDefinition(
            "exposure",
            DclStateStackPolicy.StackToCap,
            DclStateDurationClock.GlobalCt,
            sourceRequired: true,
            stackKey: "exposure",
            stackCap: 3,
            contributionReapplication: DclStateStackPolicy.Refresh);
        DclStateApplicationResult exposureA = registry.Apply(Application(
            exposure, sourceA, duration: 10, strength: 2, discriminator: "fire", contribution: "source-a", payloadValue: "two"));
        registry.Apply(Application(
            exposure, sourceB, duration: 10, strength: 2, discriminator: "fire", contribution: "source-b", payloadValue: "two-b"));
        DclStateApplicationResult exposureRefresh = registry.Apply(Application(
            exposure, sourceB, duration: 20, strength: 99, discriminator: "fire", contribution: "source-a", payloadValue: "ninety-nine"));
        Check(registry.AggregateStrength(target, "exposure", "fire") == 3 &&
              exposureRefresh.Outcome == DclStateApplicationOutcome.ContributionRefreshed &&
              exposureRefresh.Instance.InstanceId == exposureA.Instance.InstanceId &&
              exposureRefresh.Instance.Strength == 2 && exposureRefresh.Instance.Source == sourceA &&
              exposureRefresh.Instance.ExpiresAtGlobalCt == 120,
            "StackToCap must keep distinct contributions, clamp their sum, and apply its declared same-contribution Refresh semantics");

        DclStateDefinition ward = BuildDclStateDefinition(
            "ward", DclStateStackPolicy.Independent, DclStateDurationClock.UsesOrTriggers,
            sourceRequired: true, stackKey: "ward");
        DclStateApplicationResult wardResult = registry.Apply(Application(ward, sourceA, duration: 2));
        Check(registry.ConsumeUse(wardResult.Instance.InstanceId) &&
              registry.TryGet(wardResult.Instance.InstanceId, out var oneUseWard) && oneUseWard.RemainingUses == 1 &&
              registry.ConsumeUse(wardResult.Instance.InstanceId) &&
              !registry.TryGet(wardResult.Instance.InstanceId, out _),
            "UsesOrTriggers state must decrement atomically and disappear when its final use commits");

        DclStateDefinition poison = BuildDclStateDefinition(
            "poison", DclStateStackPolicy.Independent, DclStateDurationClock.GlobalCt,
            stackKey: "poison", tickInterval: 3, removeOnTargetKo: true);
        DclStateApplicationResult poisonOne = registry.Apply(Application(poison, sourceA, duration: 6, discriminator: "one"));
        DclStateApplicationResult poisonTwo = registry.Apply(Application(poison, sourceB, duration: 6, discriminator: "two"));
        var schedule = new List<DclStateScheduleEvent>();
        var scheduleCommits = new List<DclStateScheduleCommit>();
        while (registry.BeginNextGlobalScheduleStepThrough(106) is { } pendingSchedule)
        {
            Check(registry.CurrentGlobalCt == pendingSchedule.Event.GlobalCt,
                "each scheduled tick/expiry must execute at its exact global timestamp");
            schedule.Add(pendingSchedule.Event);
            if (pendingSchedule.Event.Kind == DclStateScheduleEventKind.Tick)
            {
                Check(registry.TryGet(pendingSchedule.Instance.InstanceId, out DclStateInstance pendingTick) &&
                      pendingTick.NextTickGlobalCt == pendingSchedule.Event.GlobalCt,
                    "a periodic state must not advance NextTickGlobalCT before its outer tick action settles");
            }
            scheduleCommits.Add(registry.CommitGlobalScheduleStep(pendingSchedule));
        }
        Check(schedule.Select(item => (item.GlobalCt, item.Kind, item.InstanceId)).SequenceEqual(
        [
            (103L, DclStateScheduleEventKind.Tick, poisonOne.Instance.InstanceId),
            (103L, DclStateScheduleEventKind.Tick, poisonTwo.Instance.InstanceId),
            (106L, DclStateScheduleEventKind.Tick, poisonOne.Instance.InstanceId),
            (106L, DclStateScheduleEventKind.Tick, poisonTwo.Instance.InstanceId),
            (106L, DclStateScheduleEventKind.Expire, poisonOne.Instance.InstanceId),
            (106L, DclStateScheduleEventKind.Expire, poisonTwo.Instance.InstanceId),
        ]) && !registry.TryGet(poisonOne.Instance.InstanceId, out _) && !registry.TryGet(poisonTwo.Instance.InstanceId, out _),
            "global scheduler must run due ticks by stable InstanceId, tick at expiry, then remove expiries");
        Check(scheduleCommits.Count == 6 &&
              scheduleCommits.Take(4).All(commit => !commit.Expired) &&
              scheduleCommits.Skip(4).All(commit => commit.Expired) &&
              scheduleCommits.Skip(4).Select(commit => commit.Instance.Kind).SequenceEqual(["poison", "poison"]),
            "global scheduler must retain each exact tick/expiry instance after the ordered commit");

        DclStateDefinition curable = BuildDclStateDefinition(
            "curable", DclStateStackPolicy.Independent, DclStateDurationClock.Permanent,
            stackKey: "curable", cureFamilies: ["esuna"]);
        DclStateApplicationResult curableResult = registry.Apply(Application(curable, sourceA));
        DclStateRegistry evaluation = registry.CloneForEvaluation();
        evaluation.Apply(Application(curable, sourceB) with { AppliedAtGlobalCt = evaluation.CurrentGlobalCt });
        Check(evaluation.Instances.Count == registry.Instances.Count + 1 && registry.TryGet(curableResult.Instance.InstanceId, out _),
            "forecast/AI state evaluation must mutate an isolated registry clone rather than committed battle state");
        Check(registry.Cure(target, ["esuna"]).Contains(curableResult.Instance.InstanceId),
            "cure families must remove only matching target-local instances");

        DclStateDefinition sourceBound = BuildDclStateDefinition(
            "source-bound", DclStateStackPolicy.Independent, DclStateDurationClock.Permanent,
            sourceRequired: true, stackKey: "source-bound", removeOnSourceKo: true, removeOnSourceLoss: true);
        DclStateApplicationResult sourceBoundResult = registry.Apply(Application(sourceBound, sourceA));
        Check(registry.OnSourceKo(sourceA).Contains(sourceBoundResult.Instance.InstanceId),
            "source KO must clear states whose definition owns RemoveOnSourceKo");
        DclStateApplicationResult staleTarget = registry.Apply(Application(curable, sourceA));
        var reusedTarget = target with { CharacterId = target.CharacterId + 1 };
        Check(registry.OnUnitIdentityObserved(reusedTarget).Contains(staleTarget.Instance.InstanceId),
            "unit-slot identity reuse must clear state tied to the stale UnitKey immediately");

        DclStateDefinition checkpointAim = BuildDclStateDefinition(
            "checkpoint-aim",
            DclStateStackPolicy.Refresh,
            DclStateDurationClock.UsesOrTriggers);
        DclStateApplicationResult checkpointAimResult = registry.Apply(new DclStateApplication(
            checkpointAim,
            target,
            Source: null,
            AppliedAtGlobalCt: registry.CurrentGlobalCt,
            AppliedBeforeTurnSerial: 9,
            FirstEligibleTargetTurnSerial: null,
            FirstEligibleSourceTurnSerial: null,
            DurationUnits: 2,
            Strength: null,
            WinningMargin: null,
            StackDiscriminator: "",
            ContributionIdentity: null,
            new DclAimStatePayload(checkpointAim.PayloadSchema, sourceA, ConsecutiveSteps: 2),
            checkpointAim.PresentationProfile));
        Dictionary<string, DclStateDefinition> checkpointDefinitions = registry.Instances
            .Select(instance => instance.Definition)
            .DistinctBy(definition => definition.Kind)
            .ToDictionary(definition => definition.Kind, StringComparer.Ordinal);
        string checkpointJson = DclStateRegistryCheckpointCodec.Serialize(registry);
        Check(checkpointJson == DclStateRegistryCheckpointCodec.Serialize(registry),
            "an unchanged state registry must serialize to byte-identical deterministic checkpoint JSON");
        DclStateRegistry restored = DclStateRegistryCheckpointCodec.Restore(
            checkpointJson,
            battleGeneration: 22,
            checkpointDefinitions);
        DclStateInstance restoredAim = restored.Instances.Single(instance =>
            instance.InstanceId == checkpointAimResult.Instance.InstanceId);
        Check(restored.CurrentGlobalCt == registry.CurrentGlobalCt &&
              restored.NextInstanceId == registry.NextInstanceId &&
              restored.Instances.Select(instance => instance.InstanceId).SequenceEqual(
                  registry.Instances.Select(instance => instance.InstanceId)) &&
              restored.Instances.All(instance => instance.Target.BattleGeneration == 22 &&
                  (instance.Source is null || instance.Source.Value.BattleGeneration == 22)) &&
              restoredAim.Payload is DclAimStatePayload
              {
                  Target: { BattleGeneration: 22, UnitSlot: 1, CharacterId: 0x10 },
                  ConsecutiveSteps: 2,
              } &&
              restored.CaptureTarget(new DclUnitKey(22, target.UnitSlot, target.CharacterId)).Revision ==
                  registry.CaptureTarget(target).Revision,
            "state checkpoint restore must preserve exact instances, clocks, revisions, payloads, and rebase every UnitKey to the new battle generation");
        var incompatibleDefinitions = new Dictionary<string, DclStateDefinition>(checkpointDefinitions, StringComparer.Ordinal)
        {
            [checkpointAim.Kind] = checkpointAim with { MechanicalRules = "changed-after-save" },
        };
        CheckThrows<InvalidOperationException>(
            () => DclStateRegistryCheckpointCodec.Restore(
                checkpointJson,
                battleGeneration: 22,
                incompatibleDefinitions),
            "state checkpoint restore must fail closed when loaded authoring no longer matches the saved definition fingerprint");
    }

    private static void TestDclAuthoringJsonLoader()
    {
        DclActionProfile action = BuildDclMagicTargetingTestProfile();
        DclStateDefinition state = BuildDclStateDefinition(
            "loader-test", DclStateStackPolicy.Refresh, DclStateDurationClock.GlobalCt,
            cureFamilies: ["dispel"]);
        var bundle = new DclAuthoringBundle(
            DclAuthoringJsonLoader.CurrentSchemaRevision,
            [action],
            [state],
            []);
        string json = DclAuthoringJsonLoader.Serialize(bundle);
        DclAuthoringRegistry registry = DclAuthoringJsonLoader.Load(json);
        Check(registry.Actions.Count == 1 && registry.States.Count == 1 &&
              registry.Actions[action.ActionId].MagnitudeProfile is DclDamageMagnitude loadedDamage &&
              loadedDamage.ElementBoostMultiplier == DclRational.FromInteger(1) &&
              registry.States[state.Kind].Duration.Clock == DclStateDurationClock.GlobalCt,
            "strict JSON loading must preserve the normalized magnitude union, exact rationals, enums, action revision, and state lifecycle");

        string schemaRevisionProperty = $"\"schemaRevision\": {DclAuthoringJsonLoader.CurrentSchemaRevision},";
        string unknownField = json.Replace(
            schemaRevisionProperty,
            $"{schemaRevisionProperty}\n  \"unexpected\": true,",
            StringComparison.Ordinal);
        CheckThrows<DclAuthoringLoadException>(
            () => DclAuthoringJsonLoader.Load(unknownField),
            "unknown JSON fields must fail closed rather than being silently ignored");
        CheckThrows<DclAuthoringLoadException>(
            () => DclAuthoringJsonLoader.Load(DclAuthoringJsonLoader.Serialize(bundle with
            {
                SchemaRevision = DclAuthoringJsonLoader.CurrentSchemaRevision + 1,
            })),
            "unknown authoring schema revisions must fail before any profile reaches the runtime registry");
        CheckThrows<DclAuthoringLoadException>(
            () => DclAuthoringJsonLoader.Load(DclAuthoringJsonLoader.Serialize(bundle with { Actions = [action, action] })),
            "duplicate ActionIds must fail the atomic bundle load even when their revisions match");
        string unknownEnum = json.Replace("\"source\": \"spell\"", "\"source\": \"notARealSource\"", StringComparison.Ordinal);
        CheckThrows<DclAuthoringLoadException>(
            () => DclAuthoringJsonLoader.Load(unknownEnum),
            "unknown behavior enum values must fail strict deserialization rather than becoming a permissive default");
        DclActionProfile areaProfile = action with
        {
            TargetProfile = action.TargetProfile with
            {
                Area = new DclAreaProfile(
                    DclAreaCenterMode.TrackedUnit,
                    DclAreaShape.Diamond,
                    Size: 1,
                    DclAreaDeliveryGate.Dodge),
            },
            DeliveryProfile = action.DeliveryProfile with { Delivery = DclDelivery.Area },
        };
        string areaJson = DclAuthoringJsonLoader.Serialize(bundle with { Actions = [areaProfile] });
        CheckThrows<DclAuthoringLoadException>(
            () => DclAuthoringJsonLoader.Load(areaJson.Replace(
                "\"centerMode\": \"trackedUnit\"",
                "\"centerMode\": \"explicit\"",
                StringComparison.Ordinal)),
            "the new DCL schema must reject the retired Explicit area center instead of admitting an unresolvable profile");
        CheckThrows<DclAuthoringLoadException>(
            () => DclAuthoringJsonLoader.Load(areaJson.Replace(
                "\"deliveryGate\": \"dodge\"",
                "\"deliveryGate\": \"explicit\"",
                StringComparison.Ordinal)),
            "the new DCL schema must reject the retired Explicit area delivery gate instead of deferring undefined semantics");
        DclActionProfile missingStateReference = action with
        {
            MagnitudeProfile = null,
            Effects = [new DclEffectProfile(
                DclEffectKind.StatusApplication,
                DclEffectRole.Carrier,
                DclEligibleTargetStates.Alive,
                DclUndeadInteraction.Normal,
                ReferencedStateKind: "missing-state")],
        };
        CheckThrows<DclAuthoringLoadException>(
            () => DclAuthoringJsonLoader.Load(DclAuthoringJsonLoader.Serialize(bundle with { Actions = [missingStateReference] })),
            "status effects must resolve their referenced state definition inside the same atomic authoring bundle");
    }

    private static DclStateDefinition BuildDclStateDefinition(
        string kind,
        DclStateStackPolicy stackPolicy,
        DclStateDurationClock durationClock,
        bool sourceRequired = false,
        string? stackKey = null,
        int? stackCap = null,
        DclStateStackPolicy? contributionReapplication = null,
        int? tickInterval = null,
        bool removeOnTargetKo = false,
        bool removeOnSourceKo = false,
        bool removeOnSourceLoss = false,
        IReadOnlyList<string>? cureFamilies = null)
        => new(
            kind,
            NativeStatusBit: null,
            sourceRequired,
            DclStateResistanceGate.None,
            "none",
            stackPolicy,
            stackKey ?? kind,
            stackCap,
            stackPolicy == DclStateStackPolicy.StackToCap ? "authored-contribution" : null,
            contributionReapplication,
            new DclStateDurationProfile(
                durationClock,
                durationClock is DclStateDurationClock.Permanent or DclStateDurationClock.ExplicitCommand
                    ? null
                    : "resolved-at-application"),
            tickInterval is { } interval
                ? new DclStateTickProfile(
                    interval,
                    "periodic.poison.test",
                    0,
                    DclStateTickSource.Target,
                    ImmediatePayload: false)
                : null,
            EffectStrengthFormula: stackPolicy is DclStateStackPolicy.StrongestWins or DclStateStackPolicy.StackToCap
                ? "resolved-strength"
                : null,
            removeOnTargetKo,
            removeOnSourceKo,
            removeOnSourceLoss,
            cureFamilies ?? [],
            $"payload.{kind}",
            $"mechanics.{kind}",
            $"presentation.{kind}",
            $"ai.{kind}");

    private static DclStatePresentationProfile BuildDclSentinelStatePresentationProfile(
        DclStateDefinition definition)
        => new(
            definition.PresentationProfile,
            definition.Kind,
            definition.MechanicalRules,
            UnitIconAssetRef: definition.Kind == "shock"
                ? "NativeStatusIcon(Doom)"
                : DclStatePresentation.UnitIconFor(definition.Kind),
            TimelineIconAssetRef: DclStatePresentation.TimelineIconFor(definition.Kind),
            PositionAssetRef: definition.Kind switch
            {
                "stun" => "NativePosition(Critical)",
                "knocked-down" or "canonical-knocked-down-test" => "NativePosition(KO)",
                "aim" or "canonical-overwatch-test" => "NativePosition(Charging)",
                "canonical-protection-test" or "canonical-bulwark-test" => "NativePosition(Defending)",
                _ => null,
            },
            PaletteAssetRef: definition.Kind switch
            {
                "stun" => "DclPalette(PaleYellow:#E9D96E)",
                _ => null,
            },
            EntryFeedbackRef: "DclFeedback(StateApplied)",
            DetailTerms: ["mechanics", "expiry", "stacking"],
            ShowsSource: definition.SourceRequired,
            ShowsMagnitude: definition.EffectStrengthFormula is not null,
            ShowsExpiry: definition.Duration.Clock != DclStateDurationClock.Permanent,
            ShowsStacking: true,
            definition.CureFamilies);

    private static void TestDclCanonicalStateSnapshot()
    {
        var owner = new DclUnitKey(18, 4, 44);
        var tracked = new DclUnitKey(18, 5, 55);
        var registry = new DclStateRegistry(18, initialGlobalCt: 200);

        DclStateApplication Application(
            DclStateDefinition definition,
            DclStatePayload payload,
            int? duration,
            string discriminator = "")
            => new(
                definition,
                owner,
                Source: null,
                AppliedAtGlobalCt: registry.CurrentGlobalCt,
                AppliedBeforeTurnSerial: 0,
                FirstEligibleTargetTurnSerial: definition.Duration.Clock == DclStateDurationClock.TargetTurn ? 1 : null,
                FirstEligibleSourceTurnSerial: null,
                duration,
                Strength: null,
                WinningMargin: null,
                discriminator,
                ContributionIdentity: null,
                payload,
                definition.PresentationProfile);

        DclStateDefinition shockDefinition = BuildDclStateDefinition(
            "shock", DclStateStackPolicy.Explicit, DclStateDurationClock.TargetTurn);
        registry.ApplyShock(
            Application(
                shockDefinition,
                new DclShockStatePayload(shockDefinition.PayloadSchema, UnexpiredInjury: 8),
                duration: 1,
                discriminator: "injury-window"),
            maxHp: 20);

        DclStateDefinition aimDefinition = BuildDclStateDefinition(
            "aim", DclStateStackPolicy.Replace, DclStateDurationClock.UsesOrTriggers);
        var aim = new DclAimState(tracked);
        aim.GrantStep(tracked);
        aim.GrantStep(tracked);
        DclStateApplicationResult aimResult = registry.Apply(Application(
            aimDefinition,
            aim.ToPayload(aimDefinition.PayloadSchema),
            duration: 1));

        DclStateDefinition exposureDefinition = BuildDclStateDefinition(
            "elemental-exposure", DclStateStackPolicy.Independent, DclStateDurationClock.Permanent);
        registry.Apply(Application(
            exposureDefinition,
            new DclElementalExposureStatePayload(exposureDefinition.PayloadSchema, "Fire", 1),
            duration: null,
            discriminator: "one"));
        registry.Apply(Application(
            exposureDefinition,
            new DclElementalExposureStatePayload(exposureDefinition.PayloadSchema, "fire", -1),
            duration: null,
            discriminator: "two"));

        var raw = new byte[0x200];
        raw[0x57] = 0x01;
        raw[0x5D] = 0x02;
        raw[0x61] = 0x18;
        raw[0x63] = 0x80;
        raw[0x64] = 0x10;
        raw[0x65] = 0x02;
        raw[0x1EF] = 0x20;
        var native = new UnitSnapshot(
            Ptr: (nint)0x1804,
            CharId: owner.CharacterId,
            Level: 1,
            Hp: 20,
            MaxHp: 20,
            Team: 0,
            IsFoe: false,
            Pa: 10,
            Ma: 10,
            Speed: 10,
            Move: 4,
            Jump: 3,
            Brave: 50,
            Faith: 50,
            Raw: raw);
        DclCanonicalStateSnapshot snapshot = DclCanonicalStateSnapshot.Capture(native, owner, registry);
        Check(snapshot.Revision == 4 && snapshot.Instances.Count == 4 &&
              snapshot.HasNativeSource(new DclNativeStatusBit(0, 0x01)) &&
              snapshot.HasNativeImmunity(new DclNativeStatusBit(1, 0x02)) &&
              snapshot.HasNativeEffective(new DclNativeStatusBit(0, 0x10)) &&
              !snapshot.HasNativeEffective(new DclNativeStatusBit(0, 0x20)) &&
              snapshot.HasNativeMaster(new DclNativeStatusBit(0, 0x20)),
            "one immutable state snapshot must preserve the four proven native arrays and the exact target-local DCL revision without merging master and effective status semantics");
        Check(snapshot.Shock(20) == new DclCanonicalShockSnapshot(8, 3, -3) &&
              snapshot.TryGetAim(out DclAimStatePayload? capturedAim) &&
              capturedAim == new DclAimStatePayload(aimDefinition.PayloadSchema, tracked, 2) &&
              capturedAim.Materialize().Bonus(accuracy: 3) == 4 &&
              snapshot.ElementalExposureStep("FIRE") == 0,
            "typed state projection must expose exact Shock, persistent Aim, and signed elemental-exposure mechanics without parsing descriptive text");

        Check(registry.ConsumeUse(aimResult.Instance.InstanceId),
            "the persisted Aim trigger must be consumable by its registry lifecycle");
        DclCanonicalStateSnapshot afterAim = DclCanonicalStateSnapshot.Capture(native, owner, registry);
        Check(snapshot.Revision == 4 && snapshot.HasKind("aim") &&
              afterAim.Revision == 5 && !afterAim.TryGetAim(out _),
            "state mutation must advance a target-local monotonic revision while already-captured forecast snapshots remain immutable");
        CheckThrows<ArgumentOutOfRangeException>(
            () => snapshot.HasNativeEffective(new DclNativeStatusBit(5, 0x01)),
            "native-state queries must reject identities outside the fixed five-byte vocabulary");

        var mechanicsRegistry = new DclStateRegistry(18, initialGlobalCt: 200);
        DclStateApplication MechanicsApplication(
            DclStateDefinition definition,
            DclStatePayload payload,
            int? duration,
            int? strength = null,
            DclUnitKey? source = null,
            string discriminator = "") => new(
                definition,
                owner,
                source,
                AppliedAtGlobalCt: 200,
                AppliedBeforeTurnSerial: 0,
                FirstEligibleTargetTurnSerial:
                    definition.Duration.Clock == DclStateDurationClock.TargetTurn ? 1 : null,
                FirstEligibleSourceTurnSerial: null,
                duration,
                strength,
                WinningMargin: null,
                discriminator,
                ContributionIdentity: null,
                payload,
                definition.PresentationProfile);
        DclStateDefinition tauntDefinition = BuildDclStateDefinition(
            "taunt", DclStateStackPolicy.Replace, DclStateDurationClock.TargetTurn, sourceRequired: true);
        DclStateDefinition guardDefinition = BuildDclStateDefinition(
            "guard-broken", DclStateStackPolicy.StrongestWins, DclStateDurationClock.TargetTurn);
        DclStateDefinition boundDefinition = BuildDclStateDefinition(
            "weapon-bound", DclStateStackPolicy.StrongestWins, DclStateDurationClock.TargetTurn);
        DclStateDefinition bulwarkDefinition = BuildDclStateDefinition(
            "bulwark", DclStateStackPolicy.Refresh, DclStateDurationClock.ExplicitCommand);
        mechanicsRegistry.Apply(MechanicsApplication(
            tauntDefinition,
            new DclTauntStatePayload(tauntDefinition.PayloadSchema, tracked),
            duration: 1,
            source: tracked));
        mechanicsRegistry.Apply(MechanicsApplication(
            guardDefinition,
            new DclGuardBrokenStatePayload(guardDefinition.PayloadSchema, SuppressBlock: true, ParryPenalty: 3),
            duration: 1,
            strength: 1_000_003));
        mechanicsRegistry.Apply(MechanicsApplication(
            boundDefinition,
            new DclWeaponBoundStatePayload(
                boundDefinition.PayloadSchema,
                "main-hand",
                SuppressAttack: true,
                SuppressParry: false,
                SuppressWeaponReactions: true,
                WeaponSkillPenalty: -2),
            duration: 1,
            strength: 2,
            discriminator: "main-hand"));
        mechanicsRegistry.Apply(MechanicsApplication(
            bulwarkDefinition,
            new DclBulwarkStatePayload(
                bulwarkDefinition.PayloadSchema,
                new DclBulwarkPayload(2, 3, 4, "native-passability")),
            duration: null));
        DclCanonicalStateSnapshot mechanicsSnapshot =
            DclCanonicalStateSnapshot.Capture(native, owner, mechanicsRegistry);
        DclCanonicalTauntActionLegality tauntMovement = mechanicsSnapshot.EvaluateTauntAction(
            consumesAction: false,
            isUniversalNormalAttack: false,
            selectedTarget: null,
            provocateurActive: true,
            normalAttackTargetLegal: false);
        DclCanonicalTauntActionLegality tauntWrongAction = mechanicsSnapshot.EvaluateTauntAction(
            consumesAction: true,
            isUniversalNormalAttack: false,
            tracked,
            provocateurActive: true,
            normalAttackTargetLegal: true);
        DclCanonicalTauntActionLegality tauntAttack = mechanicsSnapshot.EvaluateTauntAction(
            consumesAction: true,
            isUniversalNormalAttack: true,
            tracked,
            provocateurActive: true,
            normalAttackTargetLegal: true);
        DclCanonicalTauntActionLegality staleTaunt = mechanicsSnapshot.EvaluateTauntAction(
            consumesAction: true,
            isUniversalNormalAttack: false,
            selectedTarget: null,
            provocateurActive: false,
            normalAttackTargetLegal: false);
        DclCanonicalDefenseStateMechanics defenseMechanics = mechanicsSnapshot.DefenseMechanics("main-hand");
        Check(tauntMovement is { Restricted: true, Legal: true, StateShouldEnd: false } &&
              tauntWrongAction is { Restricted: true, Legal: false, StateShouldEnd: false } &&
              tauntAttack is { Restricted: true, Legal: true, Provocateur: var tauntSource } &&
              tauntSource == tracked &&
              staleTaunt is { Legal: true, StateShouldEnd: true } &&
              defenseMechanics is
              {
                  BlockSuppressed: true,
                  ParrySuppressed: false,
                  WeaponAttackSuppressed: true,
                  WeaponReactionsSuppressed: true,
                  ParryPenaltyMagnitude: 3,
                  WeaponSkillModifier: -2,
                  BlockModifier: 2,
                  DrModifier: 3,
                  DisplacementResistance: 4,
                  PassabilityPolicy: "native-passability",
              },
            "typed state mechanics must expose exact Taunt command legality and Guard Broken, Weapon Bound, and Bulwark modifiers to one shared forecast/AI/execution surface");

        DclItemMetadata focusItem = BuildDclSentinelWeaponMetadata() with
        {
            Focus = new DclFocusMetadata(
                SpellSkillModifier: 2,
                FocusDamageModifier: 1,
                FocusHealingModifier: 3,
                ElementBoostMultiplier: new DclRational(3, 2),
                ConcentrationModifier: 1,
                CastCtModifier: -2,
                MpCostMultiplier: new DclRational(1, 2),
                CompatibleTraditions: ["black-magic"]),
        };
        DclItemMetadata targetArmor = focusItem with
        {
            ItemId = 172,
            Slot = DclItemSlot.Body,
            Weight = DclRational.FromInteger(5),
            BodyDr = 3,
            Weapon = null,
            Focus = null,
            ElementProperties = [new DclElementItemProperty(
                "fire", Absorb: false, Nullify: false, AffinityStep: -1, SourceBoostMultiplier: null)],
        };
        DclCanonicalEquipmentSnapshot casterEquipment = EquipmentSnapshot(
            [new DclCanonicalEquippedItem("right-weapon", focusItem)],
            bodyDr: 0);
        DclCanonicalEquipmentSnapshot targetEquipment = EquipmentSnapshot(
            [new DclCanonicalEquippedItem("body", targetArmor)],
            bodyDr: 3,
            magicResistance: 2);
        DclCanonicalNativeUnitProjectionInput composedProjectionInput =
            DclCanonicalNativeUnitProjectionInput.Compose(
                new DclCanonicalAttributeAdjustments(JobSt: 2, StateDx: -1),
                new DclSecondaryInputs(
                    EquipmentStatusHpModifier: 2,
                    EquipmentStatusMpModifier: 1,
                    WillModifier: -1,
                    BasicSpeedModifier: new DclRational(1, 4),
                    MoveModifier: -1,
                    EquipmentStatusJumpModifier: 1),
                targetEquipment with
                {
                    StModifier = 1,
                    DxModifier = 2,
                    IqModifier = 3,
                    HpModifier = 4,
                    MpModifier = 5,
                    BasicSpeedModifier = new DclRational(1, 2),
                    MoveModifier = 2,
                    JumpModifier = 3,
                    WillModifier = 4,
                },
                tileHeight: 0,
                registry,
                new DclDefenseResourceSnapshot(new Dictionary<string, int>(), BlockAvailable: false));
        Check(composedProjectionInput.AttributeAdjustments is
              { JobSt: 2, EquipmentSt: 1, EquipmentDx: 2, StateDx: -1, EquipmentIq: 3 } &&
              composedProjectionInput.SecondaryInputs is
              {
                  EquipmentStatusHpModifier: 6,
                  EquipmentStatusMpModifier: 6,
                  WillModifier: 3,
                  BasicSpeedModifier: { } speedModifier,
                  MoveModifier: 1,
                  EquipmentStatusJumpModifier: 4,
              } && speedModifier == new DclRational(3, 4),
            "native characteristic input composition must place equipment in its named channels exactly once while retaining explicit non-equipment state/job inputs");

        var casterRaw = new byte[0x200];
        var casterNative = native with { CharId = tracked.CharacterId, Raw = casterRaw, Faith = 60 };
        DclCanonicalStateSnapshot casterState = DclCanonicalStateSnapshot.Capture(
            casterNative,
            tracked,
            new DclStateRegistry(18));
        var casterCandidate = new DclTargetCandidate(
            tracked,
            new DclBattleTile(1, 1, 0),
            Height: 0,
            DclAllegianceRelation.Self,
            DclEligibleTargetStates.Alive,
            CurrentHp: 20,
            casterState.Revision,
            new DclDefenseResourceSnapshot(new Dictionary<string, int>(), BlockAvailable: false));
        var targetCandidate = new DclTargetCandidate(
            owner,
            new DclBattleTile(2, 1, 0),
            Height: 0,
            DclAllegianceRelation.Enemy,
            DclEligibleTargetStates.Alive,
            CurrentHp: 20,
            snapshot.Revision,
            new DclDefenseResourceSnapshot(new Dictionary<string, int>(), BlockAvailable: false));
        var primary = new DclPrimaryCharacteristics(10, 10, 10, 10);
        var secondary = new DclSecondaryCharacteristics(
            20, 20, 10, 10, 10, DclRational.FromInteger(20), DclRational.FromInteger(5), 5, 3, 8);
        var progression = new DclCanonicalProgressionSnapshot(JobId: 89, JobIndex: 15, SpendableJp: 0, TotalJp: 0, JobLevel: 1);
        var casterProjection = new DclCanonicalNativeUnitProjection(
            tracked, primary, secondary, progression, casterCandidate, casterState, CurrentMp: 10, CurrentFaith: 60);
        var targetProjection = new DclCanonicalNativeUnitProjection(
            owner, primary, secondary, progression, targetCandidate, snapshot, CurrentMp: 10, CurrentFaith: 50);
        DclActionProfile magicProfile = BuildDclMagicTargetingTestProfile();
        DclCanonicalMagicSnapshotMechanics magicMechanics = DclCanonicalMagicSnapshotProjector.Resolve(
            magicProfile,
            "BLACK-MAGIC",
            casterProjection,
            casterEquipment,
            targetProjection,
            targetProjection,
            targetEquipment);
        Check(magicMechanics is
              {
                  SpellScoreModifier: 2,
                  MagnitudeIntegerModifier: 1,
                  Affinity: { Kind: DclElementAffinityKind.Numeric, Step: 0, SourceBoost: { } },
                  TargetHasShell: true,
                  DeclaredTargetHasReflect: true,
                  FireEffect: true,
                  OilContributed: true,
                  ApplicableDr: 3,
                  ConcentrationModifier: 1,
              } && magicMechanics.Affinity.SourceBoost == new DclRational(3, 2) &&
              magicMechanics.FaithMagnitude == new DclRational(53, 50) &&
              magicMechanics.CastCtModifiers.SequenceEqual([-2]) &&
              magicMechanics.MpCostMultipliers.SequenceEqual([new DclRational(1, 2)]),
            "the synchronized magic projection must compose focus, Shock, Faith, DR, equipment affinity, Exposure, Oil, Shell, and Reflect from the same canonical snapshots");

        DclCanonicalInjuryTargetContext injuryMechanics =
            DclCanonicalCombatSnapshotProjector.ResolveInjuryTarget(
                targetProjection,
                effectiveHtModifier: -1,
                concentrationModifier: magicMechanics.ConcentrationModifier,
                concentrationStatePenaltyMagnitude: 2);
        DclCanonicalRangedSnapshotMechanics rangedMechanics =
            DclCanonicalCombatSnapshotProjector.ResolveRangedStrike(
                targetProjection,
                focusItem.Weapon! with
                {
                    MaximumRange = 10,
                    Accuracy = 3,
                    Trajectory = DclPhysicalRoute.NativeArc,
                    RangedKind = DclRangedWeaponKind.Bow,
                },
                tracked,
                baseWeaponSkill: 15,
                horizontalTiles: 6,
                locationPenaltyMagnitude: 1,
                nativeRangeLegal: true,
                nativeTrajectoryLegal: true,
                movedBeforeShot: false);
        DclStateDefinition resistedDefinition = BuildDclStateDefinition(
            "snapshot-resistance",
            DclStateStackPolicy.Refresh,
            DclStateDurationClock.TargetTurn) with
        {
            NativeStatusBit = new DclNativeStatusBit(1, 0x02),
            ResistanceGate = DclStateResistanceGate.QuickContest,
            ImmunityFamily = "poison",
        };
        DclCanonicalStatusSnapshotMechanics statusMechanics =
            DclCanonicalCombatSnapshotProjector.ResolveStatusTarget(
                resistedDefinition,
                DclResistanceCharacteristic.SpiritualResistance,
                targetProjection,
                targetEquipment,
                jobMagicResistance: 1,
                explicitStateResistanceModifier: -1);
        Check(injuryMechanics is
              {
                  MaxHp: 20,
                  TargetSt: 10,
                  EffectiveHt: 9,
                  UnexpiredShockInjury: 8,
                  Charging: true,
                  Will: 10,
                  ConcentrationModifier: 1,
                  ConcentrationStatePenaltyMagnitude: 2,
              } && rangedMechanics is
              {
                  EffectiveAttackSkill: 12,
                  Context: { ShockStatePenaltyMagnitude: 3, Aim: { Active: true } },
                  AimWillDischargeOrCancel: true,
              } && DclCanonicalCombatSnapshotProjector.ResolveApplicableDr(
                  targetEquipment,
                  DclLocationPolicy.NormalCombined) == 3 &&
              DclCanonicalCombatSnapshotProjector.ResolveApplicableDr(
                  targetEquipment,
                  DclLocationPolicy.NormalCombined,
                  targetState: mechanicsSnapshot) == 6 &&
              statusMechanics == new DclCanonicalStatusSnapshotMechanics(Immune: true, ResistanceScore: 12),
            "physical Injury, ranged Aim/Shock, location/Bulwark DR, and status resistance/immunity must derive from the same unit/state/equipment revision as magic");

        static DclCanonicalEquipmentSnapshot EquipmentSnapshot(
            IReadOnlyList<DclCanonicalEquippedItem> equipped,
            int bodyDr,
            int magicResistance = 0)
            => new(
                new DclNativeEquipmentSlots(255, 255, 255, 255, 255, 255, 255),
                equipped,
                equipped.Aggregate(DclRational.FromInteger(0), (total, slot) => total + slot.Item.Weight),
                0, 0, 0, 0, 0, DclRational.FromInteger(0), 0, 0, 0, 0, magicResistance, bodyDr, 0);
    }

    private static void TestDclStatePresentation()
    {
        string knockedPosition = DclStatePresentation.ResolvePosition(new DclPositionPresentationInput(
            Ko: false,
            Transformation: false,
            KnockedDown: true,
            Stun: true,
            Confusion: true,
            Critical: true,
            Charging: true,
            Casting: true,
            Performing: true,
            Defending: true));
        string koPosition = DclStatePresentation.ResolvePosition(new DclPositionPresentationInput(
            Ko: true,
            Transformation: true,
            KnockedDown: true,
            Stun: true,
            Confusion: false,
            Critical: true,
            Charging: true,
            Casting: false,
            Performing: false,
            Defending: false));
        Check(knockedPosition == "NativePosition(KO)" && koPosition == "NativePosition(KO)",
            "position resolution must preserve KO > transformation > Knocked Down > Stun/Confusion > Critical > action-state precedence");

        DclResolvedPresentation presentation = DclStatePresentation.Resolve(
            new DclPositionPresentationInput(false, false, false, true, false, true, true, false, false, false),
            new DclPalettePresentationInput(
                Ko: false,
                Invisible: true,
                Stun: false,
                Berserk: false,
                Taunt: true,
                Fear: true,
                Vampire: true,
                Undead: true,
                Poison: true,
                Oil: true,
                ElementalExposure: "Fire"));
        Check(presentation.PositionAssetRef == "NativePosition(Critical)" &&
              presentation.PaletteAssetRef == "DclPalette(IntenseRed:#D82020)" &&
              presentation.ApplyInvisibilityTransparency,
            "palette priority must be presentation-only and Invisibility transparency must apply after the winning palette");
        string? koPalette = DclStatePresentation.ResolvePalette(new DclPalettePresentationInput(
            Ko: true, Invisible: true, Stun: true, Berserk: true, Taunt: true, Fear: true,
            Vampire: true, Undead: true, Poison: true, Oil: true, ElementalExposure: "Ice"));
        Check(koPalette is null,
            "KO must suppress temporary DCL palettes without deleting the underlying states");
        Check(DclStatePresentation.IconFor("stun") == "NativeStatusIcon(Disable)" &&
              DclStatePresentation.IconFor("shock", 3) == "NativeStatusIcon(Doom3)" &&
              DclStatePresentation.IconFor("elemental-exposure") == "NativeStatusIcon(Oil)",
            "custom state icons must remain symbolic references to existing native assets rather than repurposed status bits");
        Check(DclStatePresentation.UnitIconFor("stun") == "NativeStatusIcon(Disable)" &&
              DclStatePresentation.UnitIconFor("shock", 2) == "NativeStatusIcon(Doom2)" &&
              DclStatePresentation.UnitIconFor("quicklock") is null &&
              DclStatePresentation.UnitIconFor("ready") is null &&
              DclStatePresentation.UnitIconFor("block-spent") is null &&
              DclStatePresentation.UnitIconFor("repeated-parry") is null &&
              DclStatePresentation.TimelineIconFor("quicklock") == "NativeStatusIcon(Haste)" &&
              DclStatePresentation.TimelineIconFor("stun") is null,
            "presentation channels must keep technical turn/equipment resources out of the above-unit status icon layer while still exposing QuickLock on the CT timeline");

        DclStateDefinition shock = BuildDclStateDefinition(
            "shock", DclStateStackPolicy.Refresh, DclStateDurationClock.GlobalCt, cureFamilies: ["recovery"]);
        var source = new DclUnitKey(13, 1, 11);
        var target = new DclUnitKey(13, 2, 22);
        var instance = new DclStateInstance(
            InstanceId: 1,
            shock,
            target,
            source,
            AppliedAtGlobalCt: 100,
            AppliedBeforeTurnSerial: 0,
            ExpiresAtGlobalCt: 150,
            ExpiresAfterTargetTurnSerial: null,
            ExpiresAfterSourceTurnSerial: null,
            RemainingUses: null,
            NextTickGlobalCt: null,
            Strength: 2,
            WinningMargin: null,
            StackDiscriminator: "",
            ContributionIdentity: null,
            new DclPropertyStatePayload("payload.shock", new Dictionary<string, string>()),
            "presentation.shock");
        DclSelectedStateDetail detail = DclStatePresentation.Detail(instance, "Shock", currentGlobalCt: 120);
        Check(detail.DisplayName == "Shock" && detail.MechanicalEffect == "mechanics.shock" &&
              detail.Source == source && detail.Magnitude == 2 && detail.Remaining == "30 CT" &&
              detail.Stacking == DclStateStackPolicy.Refresh && detail.CureFamilies.SequenceEqual(["recovery"]) &&
              detail.IconAssetRef == "NativeStatusIcon(Doom2)",
            "selected-state detail must expose mechanics, source, magnitude, exact expiry, stacking, cure, and icon ownership together");

        DclStateDefinition quickLock = BuildDclStateDefinition(
            "quicklock", DclStateStackPolicy.Refresh, DclStateDurationClock.ExplicitCommand);
        DclStateDefinition ready = BuildDclStateDefinition(
            "ready", DclStateStackPolicy.Refresh, DclStateDurationClock.ExplicitCommand);
        DclStatePresentationChannels channels = DclStatePresentation.ResolveChannels(
            [
                new DclStateInstance(
                    InstanceId: 3,
                    quickLock,
                    target,
                    Source: null,
                    AppliedAtGlobalCt: 100,
                    AppliedBeforeTurnSerial: 0,
                    ExpiresAtGlobalCt: null,
                    ExpiresAfterTargetTurnSerial: null,
                    ExpiresAfterSourceTurnSerial: null,
                    RemainingUses: null,
                    NextTickGlobalCt: null,
                    Strength: null,
                    WinningMargin: null,
                    StackDiscriminator: "",
                    ContributionIdentity: null,
                    new DclPropertyStatePayload("payload.quicklock", new Dictionary<string, string>()),
                    "presentation.quicklock"),
                instance,
                new DclStateInstance(
                    InstanceId: 2,
                    ready,
                    target,
                    Source: null,
                    AppliedAtGlobalCt: 100,
                    AppliedBeforeTurnSerial: 0,
                    ExpiresAtGlobalCt: null,
                    ExpiresAfterTargetTurnSerial: null,
                    ExpiresAfterSourceTurnSerial: null,
                    RemainingUses: null,
                    NextTickGlobalCt: null,
                    Strength: null,
                    WinningMargin: null,
                    StackDiscriminator: "",
                    ContributionIdentity: null,
                    new DclPropertyStatePayload("payload.ready", new Dictionary<string, string>()),
                    "presentation.ready"),
            ],
            new Dictionary<string, string>
            {
                ["shock"] = "Shock",
                ["quicklock"] = "Quick Lock",
                ["ready"] = "Ready",
            },
            currentGlobalCt: 120);
        Check(channels.UnitIcons.Single().IconAssetRef == "NativeStatusIcon(Doom2)" &&
              channels.TimelineIcons.Single().IconAssetRef == "NativeStatusIcon(Haste)" &&
              channels.SelectedDetails.Select(row => row.DisplayName).SequenceEqual(["Shock", "Ready", "Quick Lock"]) &&
              channels.DetailOnlyStateKinds.SequenceEqual(["ready"]),
            "state presentation channel snapshots must keep above-unit icons, CT timeline icons, and selected-unit detail separate in stable instance order");
        CheckThrows<ArgumentException>(
            () => DclStatePresentation.ResolveChannels([instance], new Dictionary<string, string>(), currentGlobalCt: 120),
            "selected-state channel resolution must fail closed when a visible state lacks a display name");

        var presentationRegistry = new DclStatePresentationProfileRegistry();
        DclStatePresentationProfile shockPresentation = new(
            "presentation.shock",
            "Shock",
            "Accumulated injury shock penalty.",
            UnitIconAssetRef: "NativeStatusIcon(Doom2)",
            TimelineIconAssetRef: null,
            PositionAssetRef: null,
            PaletteAssetRef: null,
            EntryFeedbackRef: "NativeFeedback(Hit)",
            DetailTerms: ["source", "magnitude", "expiry", "stacking", "cure"],
            ShowsSource: true,
            ShowsMagnitude: true,
            ShowsExpiry: true,
            ShowsStacking: true,
            CureFamilies: ["recovery"]);
        DclStatePresentationProfile quickLockPresentation = new(
            "presentation.quicklock",
            "Quick Lock",
            "Prevents another Quick grant until the granted turn resolves.",
            UnitIconAssetRef: null,
            TimelineIconAssetRef: "NativeStatusIcon(Haste)",
            PositionAssetRef: null,
            PaletteAssetRef: null,
            EntryFeedbackRef: null,
            DetailTerms: ["expiry"],
            ShowsSource: false,
            ShowsMagnitude: false,
            ShowsExpiry: true,
            ShowsStacking: false,
            CureFamilies: []);
        DclStateDefinition stun = BuildDclStateDefinition(
            "stun", DclStateStackPolicy.Refresh, DclStateDurationClock.ExplicitCommand);
        DclStatePresentationProfile stunPresentation = new(
            "presentation.stun",
            "Stun",
            "Cannot act and suffers active-defense penalties.",
            UnitIconAssetRef: "NativeStatusIcon(Disable)",
            TimelineIconAssetRef: null,
            PositionAssetRef: "NativePosition(Critical)",
            PaletteAssetRef: "DclPalette(PaleYellow:#E9D96E)",
