            DetailTerms: ["expiry", "stacking", "cure"],
            ShowsSource: false,
            ShowsMagnitude: false,
            ShowsExpiry: true,
            ShowsStacking: true,
            CureFamilies: ["recovery"]);
        DclStateDefinition taunt = BuildDclStateDefinition(
            "taunt", DclStateStackPolicy.Refresh, DclStateDurationClock.TargetTurn);
        DclStatePresentationProfile tauntPresentation = new(
            "presentation.taunt",
            "Taunt",
            "Forces hostile targeting toward the source.",
