            ShowsSource: true,
            ShowsMagnitude: false,
            ShowsExpiry: true,
            ShowsStacking: true,
            CureFamilies: ["mental"]);
        Check(presentationRegistry.TryRegister(shockPresentation).IsValid &&
              presentationRegistry.TryRegister(quickLockPresentation).IsValid &&
              presentationRegistry.TryRegister(stunPresentation).IsValid &&
              presentationRegistry.TryRegister(tauntPresentation).IsValid &&
              presentationRegistry.BuildDisplayNamesByStateKind(new Dictionary<string, DclStateDefinition>
              {
                  ["shock"] = shock,
                  ["quicklock"] = quickLock,
              }).OrderBy(pair => pair.Key, StringComparer.Ordinal)
                  .Select(pair => pair.Value)
                  .SequenceEqual(["Quick Lock", "Shock"]),
            "state presentation profiles must load symbolic assets and provide display names for state channel resolution");
        DclStatePresentationChannels catalogChannels = DclStatePresentation.ResolveChannels(
            [instance],
