            currentGlobalCt: 120);
        Check(catalogChannels.SelectedDetails.Single().DisplayName == "Shock" &&
              catalogChannels.UnitIcons.Single().IconAssetRef == "NativeStatusIcon(Doom2)",
            "state channel resolution must consume display names through the loaded presentation catalog while retaining dynamic instance-owned icon data");
        CheckThrows<ArgumentException>(
            () => DclStatePresentation.ResolveChannels(
                [
                    instance with { PresentationId = "presentation.wrong" },
                ],
                presentationRegistry,
                currentGlobalCt: 120),
            "state channel resolution must reject an instance whose presentation id diverges from its definition");
        var stunInstance = new DclStateInstance(
            InstanceId: 4,
            stun,
            target,
            Source: null,
            AppliedAtGlobalCt: 100,
            AppliedBeforeTurnSerial: 0,
            ExpiresAtGlobalCt: null,
            ExpiresAfterTargetTurnSerial: null,
