                "entry feedback trigger point not yet proven"),
        };
        DclPresentationNativeSurfaceAuditResult presentationNativeAudit =
            DclPresentationNativeSurfaceAudit.Audit(
                unitPresentation,
                [tauntInstance, stunInstance],
                presentationRegistry,
                liveGatedPresentationBindings);
        Check(presentationNativeAudit.IsValid &&
              !presentationNativeAudit.AllNativeBindingsProven &&
              presentationNativeAudit.Requirements.Select(requirement => requirement.Surface).SequenceEqual([
                  DclPresentationNativeSurface.UnitBodyPosition,
                  DclPresentationNativeSurface.UnitBodyPalette,
                  DclPresentationNativeSurface.UnitTransparency,
                  DclPresentationNativeSurface.AboveUnitStatusIcon,
                  DclPresentationNativeSurface.SelectedStateDetail,
                  DclPresentationNativeSurface.CommandDisablement,
                  DclPresentationNativeSurface.EntryFeedback,
              ]),
            "presentation-native audit must accept explicit live-gated bindings while refusing to treat the pure snapshot as native-complete");
        var missingPaletteBinding = liveGatedPresentationBindings
            .Where(pair => pair.Key != DclPresentationNativeSurface.UnitBodyPalette)
            .ToDictionary(pair => pair.Key, pair => pair.Value);
        DclPresentationNativeSurfaceAuditResult missingPresentationNativeAudit =
            DclPresentationNativeSurfaceAudit.Audit(
