        Check(!missingPresentationNativeAudit.IsValid &&
              missingPresentationNativeAudit.Findings.Any(finding =>
                  finding.Surface == DclPresentationNativeSurface.UnitBodyPalette),
            "presentation-native audit must fail closed when a required native surface has no explicit binding status");
        var unprovenPresentationBindings = new Dictionary<DclPresentationNativeSurface, DclPresentationNativeSurfaceBinding>(
            liveGatedPresentationBindings)
        {
            [DclPresentationNativeSurface.UnitBodyPosition] = new(
                DclPresentationNativeSurface.UnitBodyPosition,
