        DclPresentationNativeSurfaceAuditResult blankProofPresentationAudit =
            DclPresentationNativeSurfaceAudit.Audit(
                unitPresentation,
                [tauntInstance, stunInstance],
                presentationRegistry,
                unprovenPresentationBindings);
        Check(!blankProofPresentationAudit.IsValid &&
              blankProofPresentationAudit.Findings.Any(finding =>
                  finding.Surface == DclPresentationNativeSurface.UnitBodyPosition),
            "presentation-native audit must require a stable proof id before any UI binding is marked proven");
        DclStateDefinition blockSpent = BuildDclStateDefinition(
            "block-spent", DclStateStackPolicy.Refresh, DclStateDurationClock.SourceTurn);
        DclStatePresentationProfile readyPresentation = new(
            "presentation.ready",
