            PositionAssetRef: null,
            PaletteAssetRef: null,
            EntryFeedbackRef: null,
            DetailTerms: ["expiry", "stacking"],
            ShowsSource: false,
            ShowsMagnitude: false,
            ShowsExpiry: true,
            ShowsStacking: true,
            CureFamilies: []);
        DclStatePresentationProfile blockSpentPresentation = new(
            "presentation.block-spent",
            "Block Spent",
            "Block has been spent until the defender's next turn.",
            UnitIconAssetRef: null,
            TimelineIconAssetRef: null,
            PositionAssetRef: null,
            PaletteAssetRef: null,
            EntryFeedbackRef: null,
            DetailTerms: ["expiry", "stacking"],
            ShowsSource: false,
            ShowsMagnitude: false,
            ShowsExpiry: true,
            ShowsStacking: true,
            CureFamilies: []);
        Check(presentationRegistry.TryRegister(readyPresentation).IsValid &&
              presentationRegistry.TryRegister(blockSpentPresentation).IsValid,
            "technical ready/defense presentation profiles must remain selected-detail facts without unit-icon fallbacks");
        var readyInstance = new DclStateInstance(
            InstanceId: 6,
            ready,
            target,
            Source: null,
            AppliedAtGlobalCt: 100,
            AppliedBeforeTurnSerial: 0,
            ExpiresAtGlobalCt: null,
            ExpiresAfterTargetTurnSerial: null,
            ExpiresAfterSourceTurnSerial: null,
            RemainingUses: null,
            NextTickGlobalCt: null,
            Strength: null,
            WinningMargin: null,
            StackDiscriminator: "main-hand",
            ContributionIdentity: null,
            new DclPropertyStatePayload("payload.ready", new Dictionary<string, string>()),
            "presentation.ready");
        var blockSpentInstance = new DclStateInstance(
            InstanceId: 7,
            blockSpent,
            target,
            Source: null,
            AppliedAtGlobalCt: 100,
            AppliedBeforeTurnSerial: 0,
            ExpiresAtGlobalCt: null,
            ExpiresAfterTargetTurnSerial: null,
            ExpiresAfterSourceTurnSerial: 3,
            RemainingUses: null,
            NextTickGlobalCt: null,
            Strength: null,
            WinningMargin: null,
            StackDiscriminator: "shield",
            ContributionIdentity: null,
            new DclPropertyStatePayload("payload.block-spent", new Dictionary<string, string>()),
            "presentation.block-spent");
        DclUnitPresentationSnapshot equipmentDefensePresentation = DclStatePresentation.ResolveUnitPresentation(
            [readyInstance, blockSpentInstance],
            presentationRegistry,
            new DclNativePresentationInput(
                Ko: false,
                Transformation: false,
                Confusion: false,
                Critical: false,
                Charging: false,
                Casting: false,
                Performing: false,
                Defending: false,
                Invisible: false,
                Berserk: false,
                Vampire: false,
                Undead: false,
                Poison: false,
                Oil: false,
                ElementalExposure: null),
            currentGlobalCt: 120,
            new Dictionary<long, int> { [7] = 1 });
        var equipmentDefenseBindings = new Dictionary<DclPresentationNativeSurface, DclPresentationNativeSurfaceBinding>
        {
            [DclPresentationNativeSurface.SelectedStateDetail] = new(
                DclPresentationNativeSurface.SelectedStateDetail,
                DclPresentationNativeSurfaceStatus.NativeBindingLiveGated,
                ProofId: null,
                "selected-unit technical-state detail binding not yet proven"),
            [DclPresentationNativeSurface.EquipmentDetail] = new(
                DclPresentationNativeSurface.EquipmentDetail,
                DclPresentationNativeSurfaceStatus.NativeBindingLiveGated,
                ProofId: null,
                "selected-equipment readiness binding not yet proven"),
            [DclPresentationNativeSurface.DefensePanel] = new(
                DclPresentationNativeSurface.DefensePanel,
                DclPresentationNativeSurfaceStatus.NativeBindingLiveGated,
                ProofId: null,
                "defense-resource panel binding not yet proven"),
        };
        DclPresentationNativeSurfaceAuditResult equipmentDefenseAudit =
            DclPresentationNativeSurfaceAudit.Audit(
                equipmentDefensePresentation,
                [readyInstance, blockSpentInstance],
                presentationRegistry,
                equipmentDefenseBindings);
        Check(equipmentDefensePresentation.Channels.UnitIcons.Count == 0 &&
              equipmentDefensePresentation.Channels.DetailOnlyStateKinds.SequenceEqual(["ready", "block-spent"]) &&
              equipmentDefenseAudit.IsValid &&
              equipmentDefenseAudit.Requirements.Select(requirement => requirement.Surface).SequenceEqual([
                  DclPresentationNativeSurface.SelectedStateDetail,
                  DclPresentationNativeSurface.EquipmentDetail,
                  DclPresentationNativeSurface.DefensePanel,
              ]),
            "Ready/Block resource states must stay out of above-unit icons while requiring equipment and defense-panel native bindings");
        DclStatePresentationValidation invalidPresentation =
            DclStatePresentationProfileContract.Validate(shockPresentation with
            {
                UnitIconAssetRef = "TextureAtlas[12,4]",
                DetailTerms = [],
            });
        Check(!invalidPresentation.IsValid &&
              invalidPresentation.Findings.Any(f => f.Path == "UnitIconAssetRef") &&
              invalidPresentation.Findings.Any(f => f.Path == "DetailTerms"),
            "state presentation profiles must reject texture-coordinate assets and missing selected-unit detail");
        Check(!presentationRegistry.ValidateStateReferences(new Dictionary<string, DclStateDefinition>
              {
                  ["ready"] = ready,
              }).IsValid,
            "state presentation catalogs must fail closed when a state references an unloaded presentation profile");
    }

    private static void TestDclPostureAndStatusRules()
    {
        Check(!DclCriticalState.IsCritical(currentHp: 4, maxHp: 12) &&
              DclCriticalState.IsCritical(currentHp: 3, maxHp: 12) &&
              !DclCriticalState.IsCritical(currentHp: 0, maxHp: 12),
            "Critical must be strictly below one-third HP and native KO must replace it at zero");
        DclCriticalAdjustments critical = DclCriticalState.Apply(3, 12, moveBeforeCritical: 5, dodgeBeforeCritical: -3);
        Check(critical.IsCritical && critical.FinalMove == 3 && critical.FinalDodge == -1,
            "Critical must ceil half final Move/Dodge, including negative Dodge, and preserve Move minimum one");

        Check(DclStunRules.Canonical == new DclStunRules(true, false, -4, -4, -4),
            "Stun must preserve Movement, remove Action, and penalize all three active defenses by four");
        Check(!DclStunRecovery.Resolve(turnBeganStunned: false, recoveryScore: 10, roll: null).Rolled &&
              DclStunRecovery.Resolve(turnBeganStunned: true, recoveryScore: 10, roll: 10).RemoveStun &&
              !DclStunRecovery.Resolve(turnBeganStunned: true, recoveryScore: 10, roll: 11).RemoveStun,
            "Stun recovery must occur only after a turn that began Stunned and use the named characteristic once");
        CheckThrows<ArgumentException>(
            () => DclStunRecovery.Resolve(turnBeganStunned: false, recoveryScore: 10, roll: 10),
            "Stun applied during the current turn must not consume recovery RNG");

        Check(DclKnockedDownAdjustments.Canonical == new DclKnockedDownAdjustments(-3, -2, false, -4, 1, 2, -2),
            "Knocked Down must expose the complete canonical posture modifier package");

        var shock = new DclShockStatePayload("payload.shock", 0).AddInjury(7);
        Check(shock.PenaltyMagnitude(80) == 0,
            "Shock must retain sub-threshold Injury even when no numeric penalty is visible");
        shock = shock.AddInjury(1);
        Check(shock.PenaltyMagnitude(80) == 1 && shock.SkillModifier(80) == -1,
            "accumulated Injury must cross the exact ShockUnit boundary");
        shock = shock.AddInjury(16);
        Check(shock.PenaltyMagnitude(80) == 3 && shock.SkillModifier(80) == -3,
            "Shock penalty must accumulate raw Injury and cap at three");

        DclStateDefinition shockDefinition = BuildDclStateDefinition(
            "shock",
            DclStateStackPolicy.Explicit,
            DclStateDurationClock.TargetTurn,
            cureFamilies: ["recovery"]);
        var shockRegistry = new DclStateRegistry(14, initialGlobalCt: 100);
        var shockTarget = new DclUnitKey(14, 2, 22);
        DclStateApplication ShockApplication(int injury) => new(
            shockDefinition,
            shockTarget,
            Source: null,
            AppliedAtGlobalCt: 100,
            AppliedBeforeTurnSerial: 0,
            FirstEligibleTargetTurnSerial: 1,
            FirstEligibleSourceTurnSerial: null,
            DurationUnits: 1,
            Strength: null,
            WinningMargin: null,
            StackDiscriminator: "injury-window",
            ContributionIdentity: null,
            new DclShockStatePayload(shockDefinition.PayloadSchema, injury),
            shockDefinition.PresentationProfile);
        DclStateApplicationResult firstShock = shockRegistry.ApplyShock(ShockApplication(3), maxHp: 20);
        DclStateApplicationResult mergedShock = shockRegistry.ApplyShock(ShockApplication(4), maxHp: 20);
        Check(firstShock.Outcome == DclStateApplicationOutcome.Added &&
              mergedShock is
              {
                  Outcome: DclStateApplicationOutcome.ExplicitMerged,
                  Instance:
                  {
                      InstanceId: var mergedShockId,
                      Strength: 3,
                      ExpiresAfterTargetTurnSerial: 1,
                      Payload: DclShockStatePayload { UnexpiredInjury: 7 },
                  },
              } && mergedShockId == firstShock.Instance.InstanceId && shockRegistry.Instances.Count == 1,
            "the named Shock handler must merge raw Injury into one unchanged next-turn window instead of refreshing or stacking rounded penalties");

        Check(DclStatusRules.BraveTemperamentModifier(90) == 2 &&
              DclStatusRules.BraveTemperamentModifier(40) == -1 &&
              DclStatusRules.TauntResistance(10, 90) == 8 &&
              DclStatusRules.FearResistance(10, 90) == 12,
            "Brave temperament must use exact nearest rounding and opposite Taunt/Fear modifiers");
        Check(DclStatusRules.DurationFromWinningMargin(2, 3, 1, 5, winningMargin: 1) == 2 &&
              DclStatusRules.DurationFromWinningMargin(2, 3, 1, 5, winningMargin: 6) == 4 &&
              DclStatusRules.DurationFromWinningMargin(2, 3, 1, 5, winningMargin: 99) == 5,
            "margin duration must floor by the positive band and clamp to authored bounds");
        Check(DclStatusRules.EffectStrength(0, -50) == 1 && DclStatusRules.EffectStrength(12, 3) == 15,
            "persistent EffectStrength must have a minimum of one after its named basis and modifier");

        DclQuickContestResult statusTie = DclStatusRules.ResolveHostileStatus(12, 10, 10, 8);
        Check(statusTie.Outcome == DclQuickContestOutcome.TargetResisted &&
              statusTie.ActingMargin == statusTie.TargetMargin,
            "hostile status Quick Contest ties must remain with the target");
        DclQuickContestResult dispelTie = DclStatusRules.ResolveDispel(12, 10, storedEffectStrength: 10, effectResistanceRoll: 8);
        Check(dispelTie.Outcome == DclQuickContestOutcome.TargetResisted,
            "Dispel ties must preserve the stored effect instance");

        var guardBlock = new DclGuardBrokenStatePayload("payload.guard", SuppressBlock: true, ParryPenalty: 1);
        var guardParry = new DclGuardBrokenStatePayload("payload.guard", SuppressBlock: false, ParryPenalty: 999);
        Check(guardBlock.StrengthKey > guardParry.StrengthKey,
            "Guard Broken StrongestWins must compare Block suppression before absolute Parry penalty");
    }

    private static void TestDclPreparedStates()
    {
        Check(!DclBulwarkRules.Cancels(false, false, false, false) &&
              DclBulwarkRules.Cancels(true, false, false, false) &&
              DclBulwarkRules.Cancels(false, true, false, false),
            "Bulwark must persist only until voluntary movement, Knocked Down, stance-cancelling Stun, or KO");

        var overwatch = new DclOverwatchState(new DclOverwatchPayload(
            "main-hand", "tiles:4,5;4,6", "enemy-finishes-movement", RemainingTriggers: 2,
            ExpiresAfterSourceTurnSerial: 8));
        DclPreparedTriggerResult midMovement = overwatch.TryTrigger(new DclOverwatchTriggerContext(
            MovementEvent: true,
            MovementSettled: false,
            WeaponStillValid: true,
            SourceStillValid: true,
            TargetStillValid: true,
            RangeLegal: true,
            TrajectoryLegal: true,
            TriggerConditionSatisfied: true));
        Check(!midMovement.Triggered && midMovement.StateRemains && midMovement.RemainingUses == 2 &&
              midMovement.Reason == "movement-not-settled-no-tile-by-tile-trigger",
            "prepared movement reactions must never fire or pause tile by tile before native movement settles");
        DclPreparedTriggerResult firstShot = overwatch.TryTrigger(new DclOverwatchTriggerContext(
            true, true, true, true, true, true, true, true));
        DclPreparedTriggerResult secondShot = overwatch.TryTrigger(new DclOverwatchTriggerContext(
            true, true, true, true, true, true, true, true));
        Check(firstShot.Triggered && firstShot.StateRemains && firstShot.RemainingUses == 1 &&
              secondShot.Triggered && !secondShot.StateRemains && secondShot.RemainingUses == 0,
            "Overwatch must revalidate and spend exactly one remaining trigger per settled prepared delivery");
        var invalidOverwatch = new DclOverwatchState(new DclOverwatchPayload(
            "main-hand", "front-arc", "enemy-action", 1, 8));
        DclPreparedTriggerResult invalidShot = invalidOverwatch.TryTrigger(new DclOverwatchTriggerContext(
            MovementEvent: false, MovementSettled: true, WeaponStillValid: false, SourceStillValid: true,
            TargetStillValid: true, RangeLegal: true, TrajectoryLegal: true, TriggerConditionSatisfied: true));
        Check(!invalidShot.Triggered && !invalidShot.StateRemains,
            "weapon/source/target/range/trajectory failure at trigger time must cancel Overwatch without firing");

        var protectedUnit = new DclUnitKey(15, 3, 33);
        var protection = new DclProtectionState(new DclProtectionPayload(
            protectedUnit,
            new HashSet<DclDelivery> { DclDelivery.PhysicalAttack },
            "adjacent",
            RemainingIntercepts: 1,
            ExpiresAfterSourceTurnSerial: 9));
        DclPreparedTriggerResult redirect = protection.TryIntercept(new DclProtectionTriggerContext(
            SourceValid: true,
            ProtectedUnitValid: true,
            RangeOrAdjacencyLegal: true,
            Delivery: DclDelivery.PhysicalAttack,
            SourceCanReceiveHit: true));
        Check(redirect.Triggered && !redirect.StateRemains && redirect.RemainingUses == 0,
            "Cover/Bodyguard must validate both units, range, delivery class, receiver legality, and one intercept atomically");
        var invalidProtection = new DclProtectionState(new DclProtectionPayload(
            protectedUnit,
            new HashSet<DclDelivery> { DclDelivery.PhysicalAttack },
            "adjacent",
            1,
            9));
        DclPreparedTriggerResult noRedirect = invalidProtection.TryIntercept(new DclProtectionTriggerContext(
            true, true, true, DclDelivery.InternalDirect, true));
        Check(!noRedirect.Triggered && !noRedirect.StateRemains && noRedirect.Reason == "protection-invalid-ended-without-redirect",
            "invalid protection must end without redirecting an ineligible delivery");

        var quickTarget = new DclUnitKey(15, 5, 55);
        var quick = new DclQuickLockController();
        var clock = new DclCtState(initialCt: 70);
        Check(quick.TryApplyQuick(quickTarget, clock, DclRational.FromInteger(30)) &&
              clock.IsTurnEligible && quick.IsLocked(quickTarget) &&
              !quick.TryApplyQuick(quickTarget, clock, DclRational.FromInteger(30)),
            "Quick must grant enough authored CT, create QuickLock, and refuse a loop while that granted turn is pending");
        clock.GrantTurnAndReset();
        Check(quick.OnGrantedTurnResolved(quickTarget) && !quick.IsLocked(quickTarget) &&
              clock.CurrentCt == DclRational.FromInteger(0),
            "QuickLock must clear only after the granted turn resolves and ordinary turn reset still returns CT to zero");
        var insufficientClock = new DclCtState(initialCt: 20);
        CheckThrows<ArgumentException>(
            () => quick.TryApplyQuick(quickTarget, insufficientClock, DclRational.FromInteger(79)),
            "Quick magnitude must fail before mutation when it cannot grant the target's next turn");
        Check(insufficientClock.CurrentCt == DclRational.FromInteger(20) && !quick.IsLocked(quickTarget),
            "an invalid Quick application must not partially alter CT or create QuickLock");
    }

    private static void TestDclMagicResourcesAndCasting()
    {
        Check(DclMagicResources.FinalMpCost(10, [new DclRational(1, 2), new DclRational(5, 4)]) == 7,
            "MP cost must multiply exact factors and apply one final ceiling with minimum one");
        Check(DclMagicResources.FinalMpCost(0, [DclRational.FromInteger(1)]) == 0,
            "an explicitly zero-cost action must remain zero and bypass the minimum-cost rule");
        CheckThrows<ArgumentOutOfRangeException>(
            () => DclMagicResources.FinalMpCost(0, [DclRational.FromInteger(0)]),
            "zero-cost actions must still reject invalid nonpositive authored multipliers");

        DclCostCommitment commitment = DclMagicResources.DeclareCost(
            currentMp: 6,
            currentHp: 20,
            finalMpCost: 10,
            DclOvercastPolicy.Allowed,
            overcastConfirmed: true);
        Check(commitment.Legal && commitment.DeclarationMpCoverage == 6 && commitment.ApprovedHpCap == 4 &&
              commitment.ProjectedMp == 0 && commitment.ProjectedHp == 16,
            "declaration must store the exact MP coverage and explicitly confirmed ApprovedHPCap");
        DclOvercastForecastProjection overcastForecast =
            DclMagicResources.ProjectOvercastForecast(commitment);
        Check(overcastForecast.FinalMpCost == 10 &&
              overcastForecast.MpPaidAtDeclaration == 6 &&
              overcastForecast.HpPaidAtDeclaration == 4 &&
              overcastForecast.ApprovedHpCap == 4 &&
              overcastForecast.ProjectedMp == 0 &&
              overcastForecast.ProjectedHp == 16 &&
              overcastForecast.RequiresConfirmation &&
              overcastForecast.Legal &&
              !overcastForecast.WouldKoCaster &&
              overcastForecast.WarningText == "",
            "overcast forecast must expose the exact MP+HP split, ApprovedHPCap, projected pools, confirmation, and no false KO warning");
        DclCostCommitment unconfirmed = DclMagicResources.DeclareCost(
            6, 20, 10, DclOvercastPolicy.Allowed, overcastConfirmed: false);
        Check(!unconfirmed.Legal && unconfirmed.ProjectedMp == 0 && unconfirmed.ProjectedHp == 16 &&
              !DclMagicResources.DeclareCost(6, 20, 10, DclOvercastPolicy.Forbidden, overcastConfirmed: true).Legal,
            "the full MP+HP split must remain forecastable before confirmation, while legality requires permission and confirmation");
        Check(DclMagicResources.CanPayFullCost(currentMp: 8, currentHp: 20, commitment) &&
              !DclMagicResources.CanPayFullCost(currentMp: 0, currentHp: 20, commitment),
            "restored MP may reduce HP payment, while drained MP may not raise it above ApprovedHPCap");

        DclResourcePayment success = DclMagicResources.Settle(8, 20, commitment, DclCastingOutcome.Success);
        DclResourcePayment ordinaryFailure = DclMagicResources.Settle(0, 20, commitment, DclCastingOutcome.OrdinaryFailure);
        DclResourcePayment criticalFailure = DclMagicResources.Settle(8, 20, commitment, DclCastingOutcome.CriticalFailure);
        DclResourcePayment resourceFailure = DclMagicResources.Settle(0, 20, commitment, DclCastingOutcome.ResourceFailure);
        Check(success.Legal && success.MpPaid == 8 && success.HpPaid == 2 && success.RemainingHp == 18 &&
              ordinaryFailure.Legal && ordinaryFailure.CostDue == 1 && ordinaryFailure.HpPaid == 1 &&
              criticalFailure.CostDue == 10 && criticalFailure.MpPaid == 8 && criticalFailure.HpPaid == 2 &&
              resourceFailure.CostDue == 0 && resourceFailure.MpPaid == 0 && resourceFailure.HpPaid == 0,
            "settlement must use full/single-point/zero cost by the one BaseSpellScore outcome classification");
        DclCostCommitment lethalCommitment = DclMagicResources.DeclareCost(0, 4, 4, DclOvercastPolicy.Allowed, true);
        DclResourcePayment lethalPayment = DclMagicResources.Settle(0, 4, lethalCommitment, DclCastingOutcome.Success);
        DclOvercastForecastProjection lethalOvercastForecast =
            DclMagicResources.ProjectOvercastForecast(lethalCommitment);
        Check(lethalPayment.Legal && lethalPayment.HpPaid == 4 && lethalPayment.RemainingHp == 0 && lethalPayment.PayerKo &&
              lethalOvercastForecast.WouldKoCaster &&
              lethalOvercastForecast.WarningText.Contains("0 HP", StringComparison.Ordinal),
            "overcasting has no nonlethal floor and must forecast a textual KO warning when the approved HP payment reaches zero");

        DclCastTiming delayed = DclCastingTiming.Declare(5, [-2, 1], currentGlobalCt: 100);
        DclCastTiming immediate = DclCastingTiming.Declare(2, [-9], currentGlobalCt: 100);
        Check(delayed.CastCt == 4 && delayed.ResolvesAtGlobalCt == 104 && !delayed.IsImmediate &&
              immediate.CastCt == 0 && immediate.ResolvesAtGlobalCt == 100 && immediate.IsImmediate,
            "CastCT must combine integer modifiers once, clamp at zero, and advance on the global clock");

        Check(DclConcentration.Score(will: 12, concentrationModifier: 2, statePenaltyMagnitude: 1) == 10,
            "ConcentrationScore must apply fixed -3 exactly once plus named modifiers");
        DclConcentrationResult noIncident = DclConcentration.ResolveStrikeIncident(
            true, false, injury: 0, forcedDisplacement: 0, will: 12, concentrationModifier: 0, statePenaltyMagnitude: 0, roll: null);
        DclConcentrationResult preserved = DclConcentration.ResolveStrikeIncident(
            true, false, injury: 3, forcedDisplacement: 1, will: 12, concentrationModifier: 0, statePenaltyMagnitude: 0, roll: 9);
        DclConcentrationResult interrupted = DclConcentration.ResolveStrikeIncident(
            true, false, injury: 3, forcedDisplacement: 0, will: 12, concentrationModifier: 0, statePenaltyMagnitude: 0, roll: 10);
        DclConcentrationResult direct = DclConcentration.ResolveStrikeIncident(
            true, true, injury: 99, forcedDisplacement: 9, will: 12, concentrationModifier: 0, statePenaltyMagnitude: 0, roll: null);
        Check(noIncident.Outcome == DclConcentrationOutcome.NoIncident && !noIncident.Rolled &&
              preserved.Outcome == DclConcentrationOutcome.Preserved && preserved.Rolled &&
              interrupted.Outcome == DclConcentrationOutcome.Interrupted && interrupted.Rolled &&
              direct.Outcome == DclConcentrationOutcome.DirectCancellation && !direct.Rolled,
            "each Strike must create at most one concentration roll, while impossible continuation cancels directly");
    }

    private static void TestDclMagicResolution()
    {
        int tradition = DclSpellResolution.TraditionSkill(12, DclSkillDifficulty.Hard, rank: 4, explicitTraditionModifier: 1);
        int baseScore = DclSpellResolution.BaseSpellScore(
            tradition,
            spellModifier: -1,
            equipmentSkillModifiers: [2, -1],
            shockPenaltyMagnitude: 1,
            casterStatePenaltyMagnitude: 0);
        Check(tradition == 14 && baseScore == 13,
            "TraditionSkill must use IQ/difficulty/Rank while BaseSpellScore applies technique, equipment, and Shock once");
        Check(DclSpellResolution.TargetSpellScore(13, true, DclZodiacCompatibility.Best, 1) == 14 &&
              DclSpellResolution.TargetSpellScore(13, false, DclZodiacCompatibility.Worst, 1) == 12,
            "Zodiac modifies only target-relative SpellScore and only when explicitly sensitive");

        DclSpellGateResult cannotRescue = DclSpellResolution.ClassifySharedRoll(sharedRoll: 10, baseSpellScore: 8, targetSpellScore: 12);
        Check(!cannotRescue.BaseSucceeded && !cannotRescue.TargetSucceeded,
            "a favorable target modifier must never rescue a shared draw that failed BaseSpellScore");
        DclSpellGateResult targetCritical = DclSpellResolution.ClassifySharedRoll(sharedRoll: 5, baseSpellScore: 14, targetSpellScore: 15);
        Check(targetCritical.BaseOutcome == DclCastingOutcome.Success && targetCritical.TargetCritical,
            "the same shared draw may be ordinary against BaseSpellScore and critical against one target score");

        var dodgeNine = new DclDefenseOption(DclDefenseKind.Dodge, 9, Depletes: false);
        DclMagicDeliveryResult criticalExternal = DclSpellResolution.ResolveExternal(5, 14, 15, dodgeNine, defenseRoll: null);
        DclMagicDeliveryResult defendedExternal = DclSpellResolution.ResolveExternal(10, 12, 12, dodgeNine, defenseRoll: 9);
        DclMagicDeliveryResult landedExternal = DclSpellResolution.ResolveExternal(10, 12, 12, dodgeNine, defenseRoll: 10);
        Check(criticalExternal.Outcome == DclMagicDeliveryOutcome.CriticalDelivered &&
              defendedExternal.Outcome == DclMagicDeliveryOutcome.Defended &&
              landedExternal.Outcome == DclMagicDeliveryOutcome.Delivered,
            "External Projectile must use one shared casting draw, critical defense bypass, then one legal active defense");

        DclMagicDeliveryResult internalTie = DclSpellResolution.ResolveInternal(
            sharedRoll: 10,
            baseSpellScore: 12,
            targetSpellScore: 12,
            resistanceScore: 10,
            resistanceRoll: 8);
        Check(internalTie.Outcome == DclMagicDeliveryOutcome.Resisted && internalTie.WinningMargin == 0,
            "Internal Direct must use the shared caster roll in a target-owned Quick Contest whose ties resist");

        DclExactProbability externalProbability = DclSpellResolution.ExternalSuccessProbability(12, 12, dodgeNine);
        DclExactProbability beneficialProbability = DclSpellResolution.BeneficialSuccessProbability(12, 12);
        DclExactProbability internalProbability = DclSpellResolution.InternalSuccessProbability(10, 10, 10);
        Check(externalProbability.SuccessfulOutcomes == 21_924 && externalProbability.TotalOutcomes == 46_656 &&
              beneficialProbability.SuccessfulOutcomes == 160 && beneficialProbability.TotalOutcomes == 216 &&
              internalProbability.SuccessfulOutcomes == 16_413 && internalProbability.TotalOutcomes == 46_656,
            "magic forecast must exactly enumerate shared casting, defense, and resistance spaces without Magic Evade subtraction");

        Check(DclMagicMagnitude.ClampFaith(120, permanentChanges: -10, temporaryChanges: 50) == 100 &&
              DclMagicMagnitude.FaithFactor(0) == new DclRational(7, 10) &&
              DclMagicMagnitude.FaithFactor(50) == DclRational.FromInteger(1) &&
              DclMagicMagnitude.FaithFactor(100) == new DclRational(13, 10) &&
              DclMagicMagnitude.FaithMagnitude(DclFaithPolicy.Both, 70, 70) == new DclRational(784, 625),
            "Faith must clamp by complete expression and use the exact continuous 0.006 factor once per declared side");

        DclElementAffinity numericAffinity = DclMagicMagnitude.ResolveAffinity(
            absorb: false,
            nullify: false,
            numericSteps: [-1, 1, 1],
            sourceBoosts: [new DclRational(5, 4), new DclRational(3, 2)]);
        DclElementAffinity absorbAffinity = DclMagicMagnitude.ResolveAffinity(
            absorb: true,
            nullify: true,
            numericSteps: [99],
            sourceBoosts: [DclRational.FromInteger(1)]);
        Check(numericAffinity.Kind == DclElementAffinityKind.Numeric && numericAffinity.Step == 1 &&
              numericAffinity.TargetMultiplier == new DclRational(3, 2) &&
              numericAffinity.SourceBoost == new DclRational(3, 2) &&
              absorbAffinity.Kind == DclElementAffinityKind.Absorb,
            "affinity steps must clamp after summing, source boosts choose the strongest, and Absorb precedes Null");

        DclDiceExpression magicDice = DclMagicMagnitude.BuildDiceExpression(
            iq: 10,
            DclDamageBasis.Swing,
            fixedExpression: null,
            integerModifier: 4,
            wholeDiceModifier: 1);
        DclCriticalHealingExpression criticalHeal = DclMagicMagnitude.CriticalHealingExpression(new DclDiceExpression(3, 2));
        Check(magicDice == new DclDiceExpression(3, 0) &&
              criticalHeal == new DclCriticalHealingExpression(2, 8),
            "magic magnitude must normalize integer adds before whole dice, while critical healing replaces exactly one die with +6");

        DclMagicalEffectResult magicalInjury = DclMagicalEffect.ResolveInjuryOrAbsorb(
            baseInjury: 5,
            numericAffinity,
            faithMagnitude: DclRational.FromInteger(1),
            shellSensitive: true,
            targetHasShell: true,
            targetCurrentHp: 20,
            targetMaxHp: 30,
            fireEffect: true,
            oilContributed: true);
        Check(magicalInjury.Route == DclMagicalEffectRoute.Injury &&
              magicalInjury.CombinedMultiplier == new DclRational(63, 40) && magicalInjury.FinalInjury == 7 &&
              magicalInjury.ConsumeOil,
            "element, strongest boost, Faith, and Shell must remain exact until one final magical Injury floor");
        DclMagicalEffectResult absorbed = DclMagicalEffect.ResolveInjuryOrAbsorb(
            5,
            absorbAffinity,
            DclRational.FromInteger(1),
            shellSensitive: false,
            targetHasShell: false,
            targetCurrentHp: 28,
            targetMaxHp: 30,
            fireEffect: true,
            oilContributed: true);
        Check(absorbed.Route == DclMagicalEffectRoute.AbsorbedHealing && absorbed.FinalInjury == 0 &&
              absorbed.UncappedHealing == 5 && absorbed.AppliedHealing == 2 && !absorbed.ConsumeOil,
            "Absorb must convert post-DR energy to capped healing without Injury, Shock, or Oil consumption");
        DclHealingResult healing = DclMagicalEffect.ResolveHealing(
            rawHealing: 10,
            faithMultiplier: new DclRational(28, 25),
            currentHp: 15,
            maxHp: 20);
        Check(healing.FinalHealing == 11 && healing.AppliedHealing == 5,
            "direct healing must floor once after Faith and lose excess above missing HP");

        var caster = new DclUnitKey(4, 1, 10);
        var originalTarget = new DclUnitKey(4, 2, 11);
        DclReflectRoute reflected = DclReflectRouting.Resolve(
            DclTargetMode.Unit, reflectable: true, targetHasReflect: true, reflectionAlreadyConsumed: false, caster, originalTarget);
        DclReflectRoute noLoop = DclReflectRouting.Resolve(
            DclTargetMode.Unit, reflectable: true, targetHasReflect: true, reflectionAlreadyConsumed: true, caster, originalTarget);
        DclReflectRoute fixedTile = DclReflectRouting.Resolve(
            DclTargetMode.FixedTile, reflectable: true, targetHasReflect: true, reflectionAlreadyConsumed: false, caster, originalTarget);
        Check(reflected.Reflected && reflected.FinalTarget == caster && reflected.ReflectionConsumed &&
              !noLoop.Reflected && noLoop.FinalTarget == originalTarget &&
              !fixedTile.Reflected,
            "Reflect must reroute only an eligible unit target to the original caster and consume the one-reflection guard");
    }

    private static void TestDclMagicTargeting()
    {
        DclActionProfile profile = BuildDclMagicTargetingTestProfile();
        var caster = new DclUnitKey(9, 2, 20);
        var target = new DclTargetCandidate(
            new DclUnitKey(9, 7, 70),
            new DclBattleTile(4, 0, 0),
            Height: 2,
            DclAllegianceRelation.Enemy,
            DclEligibleTargetStates.Alive,
            CurrentHp: 30,
            CombatStateRevision: 4,
            new DclDefenseResourceSnapshot(new Dictionary<string, int>(), BlockAvailable: true));
        var request = new DclCastDeclarationRequest(
            profile,
            caster,
            new DclBattleTile(0, 0, 0),
            CasterHeight: 0,
            target,
            FixedTile: null,
            FixedTileHeight: null,
            Learned: true,
            SourceUsable: true,
            SourceSilenced: false,
            PrerequisitesMet: true,
            CurrentMp: 6,
            CurrentHp: 20,
            OvercastConfirmed: true,
            CurrentGlobalCt: 100,
            CastCtModifiers: [-1]);
        DclCastDeclarationAttempt legal = DclMagicTargeting.Declare(request, actionInstanceId: 41);
        Check(legal.Legal && legal.Declaration is { TrackedTarget: not null } &&
              legal.Declaration.TrackedTarget == target.Unit && legal.Declaration.FinalMpCost == 10 &&
              legal.Declaration.ApprovedHpCap == 4 && legal.Declaration.CastCt == 3 &&
              legal.Declaration.DeclaredAtGlobalCt == 100 && legal.Declaration.ResolvesAtGlobalCt == 103 &&
              legal.Declaration.DeclarationTile == request.CasterTile,
            "cast declaration must freeze identity, declaration tile, FinalMPCost, ApprovedHPCap, and CastCT after one legality pass");
        DclCastDeclarationAttempt focusedDeclaration = DclMagicTargeting.Declare(
            request with
            {
                CastCtModifiers = [-1, -2],
                MpCostMultipliers = [new DclRational(1, 2)],
            },
            actionInstanceId: 45);
        Check(focusedDeclaration.Legal && focusedDeclaration.Declaration is
              {
                  FinalMpCost: 5,
                  ApprovedHpCap: 0,
                  CastCt: 1,
                  ResolvesAtGlobalCt: 101,
              },
            "applicable focus MPCostMultiplier and CastCTModifier must freeze into the same declaration used by forecast and execution");

        DclCastDeclarationAttempt unconfirmed = DclMagicTargeting.Declare(
            request with { OvercastConfirmed = false }, actionInstanceId: 42);
        DclCastDeclarationAttempt silenced = DclMagicTargeting.Declare(
            request with { SourceSilenced = true }, actionInstanceId: 43);
        DclCastDeclarationAttempt outside = DclMagicTargeting.Declare(
            request with { UnitTarget = target with { Tile = new DclBattleTile(8, 0, 0) } }, actionInstanceId: 44);
        Check(!unconfirmed.Legal && unconfirmed.CostCommitment.ProjectedHp == 16 &&
              unconfirmed.Failures.Contains("overcast-not-confirmed") &&
              !silenced.Legal && silenced.Failures.Contains("silence-blocks-verbal-action") &&
              !outside.Legal && outside.Failures.Contains("outside-authored-range"),
            "declaration must expose exact forecast while rejecting missing confirmation, verbal Silence, and binary range illegality");

        var movedTarget = target with { Tile = new DclBattleTile(9, 9, 0) };
        var movedCaster = new DclTargetCandidate(
            caster,
            new DclBattleTile(3, 3, 0),
            Height: 1,
            DclAllegianceRelation.Self,
            DclEligibleTargetStates.Alive,
            20,
            5,
            new DclDefenseResourceSnapshot(new Dictionary<string, int>(), BlockAvailable: true));
        var currentUnits = new Dictionary<DclUnitKey, DclTargetCandidate>
        {
            [caster] = movedCaster,
            [target.Unit] = movedTarget,
        };
        DclResolvedCastCenter tracked = DclMagicTargeting.ResolveCenter(
            legal.Declaration!, DclAreaCenterMode.TrackedUnit, currentUnits);
        DclResolvedCastCenter casterCentered = DclMagicTargeting.ResolveCenter(
            legal.Declaration!, DclAreaCenterMode.Caster, currentUnits);
        Check(tracked.Available && tracked.Tile == movedTarget.Tile &&
              casterCentered.Available && casterCentered.Tile == movedCaster.Tile,
            "tracked-unit and caster-centered magic must resolve from current tiles without repeating declaration range or LoS checks");

        var ally = movedCaster with
        {
            Unit = new DclUnitKey(9, 5, 50),
            Relation = DclAllegianceRelation.Ally,
            CurrentHp = 12,
        };
        var enemyKo = target with
        {
            Unit = new DclUnitKey(9, 4, 40),
            States = DclEligibleTargetStates.Ko,
            CurrentHp = 0,
        };
        DclTargetBatch area = DclMagicTargeting.SnapshotAreaTargets(
            9,
            [target, ally, enemyKo],
            DclAllegiancePolicy.EnemiesOnly,
            DclEligibleTargetStates.Alive);
        Check(area.Count == 1 && area.Targets[0].Target == target.Unit,
            "the area snapshot must filter allegiance and current state before any target-local delivery result");
        DclTargetBatch stable = DclMagicTargeting.SnapshotAreaTargets(
            9,
            [target, enemyKo],
            DclAllegiancePolicy.EnemiesOnly,
            DclEligibleTargetStates.Alive | DclEligibleTargetStates.Ko);
        Check(stable.Targets.Select(snapshot => snapshot.Target.UnitSlot).SequenceEqual([4, 7]),
            "area membership must enter the transaction in stable battle-slot order independent of enumeration order");
    }

