    private static void TestDclTouchResolution(AbilityCatalog nativeCatalog)
    {
        DclActionProfile baseProfile = BuildDclMagicTargetingTestProfile();
        DclActionProfile touchProfile = baseProfile with
        {
            ActionId = "spell.touch.test",
            TargetProfile = baseProfile.TargetProfile with { PhysicalRoute = DclPhysicalRoute.NativeDirect },
            DeliveryProfile = baseProfile.DeliveryProfile with
            {
                Delivery = DclDelivery.Touch,
                Dodgeable = true,
                Parryable = true,
                Blockable = false,
                UsesDefenseBonus = false,
                Reflectable = false,
            },
            TransactionProfile = baseProfile.TransactionProfile with
            {
                CastingRollCardinality = DclCastingRollCardinality.None,
                TargetGateCardinality = DclTargetGateCardinality.PerStrike,
            },
        };
        Check(DclAuthoringContract.Validate(touchProfile).IsValid &&
              !DclAuthoringContract.Validate(touchProfile with
              {
                  DeliveryProfile = touchProfile.DeliveryProfile with
                  {
                      Blockable = true,
                      UsesDefenseBonus = true,
                  },
              }).IsValid,
            "Touch authoring must permit only explicitly enabled Dodge/Parry and reject Block");
        Check(DclAuthoringContract.Validate(baseProfile with
              {
                  DeliveryProfile = baseProfile.DeliveryProfile with { Parryable = true },
              }).Findings.Any(finding => finding.Path == "DeliveryProfile.Parryable"),
            "ExternalProjectile authoring must reject ordinary Parry before runtime loading");
        Check(DclAuthoringContract.Validate(touchProfile with
              {
                  DeliveryProfile = touchProfile.DeliveryProfile with
                  {
                      ResistanceCharacteristic = DclResistanceCharacteristic.Ht,
                  },
              }).Findings.Any(finding => finding.Path == "DeliveryProfile.ResistanceCharacteristic"),
            "Touch authoring must reject a second resistance gate after its attack/active-defense gate");
        DclActionProfile invalidBeneficialDefense = baseProfile with
        {
            DeliveryProfile = baseProfile.DeliveryProfile with { Delivery = DclDelivery.Beneficial },
            TransactionProfile = baseProfile.TransactionProfile with
            {
                TargetGateCardinality = DclTargetGateCardinality.PerTarget,
            },
        };
        Check(DclAuthoringContract.Validate(invalidBeneficialDefense).Findings.Any(
                  finding => finding.Path == "DeliveryProfile") &&
              DclAuthoringContract.Validate(invalidBeneficialDefense with
              {
                  DeliveryProfile = invalidBeneficialDefense.DeliveryProfile with { Dodgeable = false },
                  TransactionProfile = invalidBeneficialDefense.TransactionProfile with
                  {
                      TargetGateCardinality = DclTargetGateCardinality.PerStrike,
                  },
              }).Findings.Any(finding => finding.Path == "TransactionProfile.TargetGateCardinality"),
            "Beneficial authoring must reject hostile active defense and any per-Strike target gate");

        var resources = new DclDefenseResourceSnapshot(
            new Dictionary<string, int> { ["right-hand"] = 1 },
            BlockAvailable: true,
            Revision: 7);
        DclDefenseCandidate[] candidates =
        [
            new(DclDefenseKind.Dodge, Score: 8, Legal: true, "touch-dodge"),
            new(DclDefenseKind.Parry, Score: 14, Legal: true, "touch-parry", "right-hand"),
        ];
        DclTouchEvaluationResult evaluation = DclTouchResolution.Evaluate(
            touchProfile.DeliveryProfile,
            spellScore: 12,
            candidates,
            resources);
        DclExactProbability expectedHit = DclPhysicalContest.HitProbability(
            attackSkill: 12,
            new DclDefenseOption(DclDefenseKind.Parry, Target: 10, Depletes: true));
        DclTouchForecastProjection touchForecast = DclTouchResolution.ProjectPlayer(evaluation);
        DclTouchAiProjection touchAi = DclTouchResolution.ProjectAi(evaluation);
        Check(evaluation.SelectedDefense is { Kind: DclDefenseKind.Parry, Score: 10 } &&
              evaluation.OutcomeProbability.Values.Aggregate(DclRational.FromInteger(0), (sum, value) => sum + value) ==
                  DclRational.FromInteger(1) &&
              evaluation.HitProbability == expectedHit.Fraction &&
              evaluation.DefenseAttemptProbability > DclRational.FromInteger(0) &&
              evaluation.ParrySpendProbability == evaluation.DefenseAttemptProbability &&
              touchForecast.ParrySpendPercent == touchForecast.DefenseAttemptPercent &&
              touchAi.HitProbability == evaluation.HitProbability &&
              touchAi.SelectedDefense == DclDefenseKind.Parry,
            "Touch evaluation must share exact critical-bypass, active-defense, and cumulative-Parry probability");

        DclTouchResolutionResult first = DclTouchResolution.Resolve(
            touchProfile.DeliveryProfile,
            spellScore: 12,
            attackRoll: 10,
            candidates,
            resources,
            defenseRoll: 18);
        Check(first.Contest is { Outcome: DclPhysicalOutcome.Hit, DefenseKind: DclDefenseKind.Parry } &&
              first.FinalDefenseResources.ParryAttemptCounts["right-hand"] == 2 &&
              first.FinalDefenseResources.Revision == resources.Revision,
            "a reachable failed Touch Parry must spend its exact weapon resource once");
        DclTouchResolutionResult second = DclTouchResolution.Resolve(
            touchProfile.DeliveryProfile,
            spellScore: 12,
            attackRoll: 10,
            candidates,
            first.FinalDefenseResources,
            defenseRoll: 18);
        Check(second.SelectedDefense.Kind == DclDefenseKind.Dodge &&
              second.FinalDefenseResources.ParryAttemptCounts["right-hand"] == 2,
            "Touch must reapply cumulative Parry penalty and reselect reusable Dodge for the later Strike/action");
        CheckThrows<ArgumentException>(
            () => DclTouchResolution.Resolve(
                touchProfile.DeliveryProfile,
                spellScore: 12,
                attackRoll: 4,
                candidates,
                resources,
                defenseRoll: 10),
            "critical Touch delivery must bypass active defense without consuming defense RNG");
        DclTouchResolutionResult critical = DclTouchResolution.Resolve(
            touchProfile.DeliveryProfile,
            spellScore: 12,
            attackRoll: 4,
            candidates,
            resources,
            defenseRoll: null);
        Check(critical.Contest.Outcome == DclPhysicalOutcome.CriticalHit &&
              critical.FinalDefenseResources.ParryAttemptCounts["right-hand"] == 1,
            "critical Touch delivery must preserve every finite Parry resource");

        var authoring = new DclAuthoringRegistry();
        Check(authoring.TryRegister(touchProfile).IsValid,
            "the normalized Touch action must register before canonical composition");
        foreach (DclStateDefinition definition in new[]
        {
            BuildDclStateDefinition("shock", DclStateStackPolicy.Explicit, DclStateDurationClock.TargetTurn, removeOnTargetKo: true),
            BuildDclStateDefinition("stun", DclStateStackPolicy.Refresh, DclStateDurationClock.ExplicitCommand, removeOnTargetKo: true),
            BuildDclStateDefinition("knocked-down", DclStateStackPolicy.Refresh, DclStateDurationClock.ExplicitCommand, removeOnTargetKo: true),
        })
            Check(authoring.TryRegister(definition).IsValid,
                $"Touch injury composition requires universal state '{definition.Kind}'");
        var bindings = new DclAbilityBindingRegistry();
        var binding = new DclAbilityBinding(
            AbilityId: 16,
            NativeFormula: 0x08,
            touchProfile.ActionId,
            touchProfile.ProfileRevision,
            DclNativeCarrierKind.SingleResult,
            DclCarrierRewritePolicy.ReplaceCompleteResult,
            RequiresDataNeutralization: true,
            ForecastBoundary: "forecast-state-0x19",
            AiBoundary: "compute-point-post-0x281F12",
            ExecutionBoundary: "outer-sweep-state-0x2A",
            ApplyBoundary: "native-pre-clamp-and-apply",
            PresentationBoundary: "native-result-selector");
        Check(bindings.TryRegister(binding, nativeCatalog, authoring).IsValid,
            "Touch must retain one verified replaceable SingleResult carrier");
        var runtime = new DclCanonicalRuntimeCatalog(
            authoring,
            new DclItemMetadataRegistry(),
            bindings,
            BuildNativeReactionBindings(authoring, bindings, nativeCatalog));
        var source = new DclUnitKey(44, 1, 41);
        var target = new DclUnitKey(44, 2, 42);
        var random = new SequenceRandomSource([3, 3, 4, 6, 6, 6, 3, 4]);
        var battle = new DclCanonicalBattleRuntime(runtime, battleGeneration: 44, initialGlobalCt: 0, random);
        battle.ObserveUnit(source);
        battle.ObserveUnit(target);
        DclDefenseResourceSnapshot battleDefense = battle.CaptureDefenseResources(target, ["right-hand"]);
        var targetCandidate = new DclTargetCandidate(
            target,
            new DclBattleTile(2, 1, 0),
            Height: 0,
            DclAllegianceRelation.Enemy,
            DclEligibleTargetStates.Alive,
            CurrentHp: 30,
            CombatStateRevision: battle.States.CaptureTarget(target).Revision,
            battleDefense);
        var declaration = new DclCastDeclarationRequest(
            touchProfile,
            source,
            new DclBattleTile(1, 1, 0),
            CasterHeight: 0,
            targetCandidate,
            FixedTile: null,
            FixedTileHeight: null,
            Learned: true,
            SourceUsable: true,
            SourceSilenced: false,
            PrerequisitesMet: true,
            CurrentMp: 20,
            CurrentHp: 20,
            OvercastConfirmed: false,
            CurrentGlobalCt: 0,
            CastCtModifiers: []);
        DclDefenseCandidate[] battleCandidates =
        [
            new(DclDefenseKind.Dodge, Score: 8, Legal: true, "touch-dodge"),
            new(DclDefenseKind.Parry, Score: 14, Legal: true, "touch-parry", "right-hand"),
        ];
        var canonicalTouchEvaluationInput = new DclCanonicalMagicEvaluationInput(
                    AbilityId: 16,
                    declaration,
                    targetCandidate,
                    BaseSpellScore: 12,
                    TargetSpellScore: 12,
                    new DclDefenseOption(DclDefenseKind.None, 0, Depletes: false),
                    MagnitudeAttribute: 12,
                    new DclElementAffinity(DclElementAffinityKind.Numeric, 0, DclRational.FromInteger(1), DclRational.FromInteger(1)),
                    FaithMagnitude: DclRational.FromInteger(1),
                    TargetHasShell: false,
                    TargetMaxHp: 30,
                    FireEffect: false,
                    OilContributed: false,
                    CurrentMpAtResolution: 20,
                    CurrentHpAtResolution: 20,
                    ApplicableDr: 0,
                    TouchDefenseCandidates: battleCandidates,
                    TouchRouteVerdict: new DclTouchNativeRouteVerdict(DclPhysicalRoute.NativeDirect, true, true),
                    InjuryTargetContext: new DclCanonicalInjuryTargetContext(
                        MaxHp: 30,
                        TargetSt: 100,
                        EffectiveHt: 10,
                        UnexpiredShockInjury: 0,
                        Charging: false,
                        Will: 10,
                        ConcentrationModifier: 0,
                        ConcentrationStatePenaltyMagnitude: 0));
        DclCanonicalMagicEvaluationResult canonicalTouchEvaluation =
            DclCanonicalMagicEvaluationExecutor.Evaluate(runtime, canonicalTouchEvaluationInput);
        DclCanonicalMagicForecastProjection canonicalTouchForecast =
            DclCanonicalMagicForecastProjection.From(canonicalTouchEvaluation);
        DclCanonicalMagicAiProjection canonicalTouchAi =
            DclCanonicalMagicAiProjection.From(canonicalTouchEvaluation);
        Check(canonicalTouchEvaluation.Legal &&
              canonicalTouchEvaluation.DeliveryProbability > DclRational.FromInteger(0) &&
              canonicalTouchEvaluation.ParrySpendProbability == canonicalTouchEvaluation.DefenseAttemptProbability &&
              canonicalTouchEvaluation.BlockSpendProbability == DclRational.FromInteger(0) &&
              canonicalTouchEvaluation.TargetHpDebit.ExpectedValue > DclRational.FromInteger(0) &&
              canonicalTouchForecast.ParrySpendPercent == canonicalTouchForecast.DefenseAttemptPercent &&
              canonicalTouchAi.ParrySpendProbability == canonicalTouchEvaluation.ParrySpendProbability,
            "canonical Touch forecast and AI must compose the exact gate, magnitude, payment, and finite-Parry probability without execution RNG");
        Check(random.DrawCount == 0 && battle.ExecutionRandom.Count == 0,
            "Touch forecast/AI evaluation must not advance the execution RNG ledger");
        DclCanonicalMagicEvaluationResult blockedTouchEvaluation =
            DclCanonicalMagicEvaluationExecutor.Evaluate(
                runtime,
                canonicalTouchEvaluationInput with
                {
                    TouchRouteVerdict = new DclTouchNativeRouteVerdict(DclPhysicalRoute.NativeDirect, true, false),
                });
        Check(!blockedTouchEvaluation.Legal &&
              blockedTouchEvaluation.Failures.SequenceEqual(["native-touch-trajectory-illegal"]) &&
              random.DrawCount == 0 && battle.ExecutionRandom.Count == 0,
            "Touch forecast and AI must suppress a native-illegal trajectory without execution RNG");
        var touchExecutionRequest = new DclCanonicalMagicExecutionRequest(
                    AbilityId: 16,
                    declaration,
                    battle.NextActionInstanceId(),
                    targetCandidate,
                    BaseSpellScore: 12,
                    TargetSpellScore: 12,
                    new DclDefenseOption(DclDefenseKind.None, 0, Depletes: false),
                    MagnitudeAttribute: 12,
                    new DclElementAffinity(DclElementAffinityKind.Numeric, 0, DclRational.FromInteger(1), DclRational.FromInteger(1)),
                    FaithMagnitude: DclRational.FromInteger(1),
                    TargetHasShell: false,
                    TargetMaxHp: 30,
                    FireEffect: false,
                    OilContributed: false,
                    CurrentMpAtResolution: 20,
                    CurrentHpAtResolution: 20,
                    ApplicableDr: 0,
                    InjuryTargetContext: new DclCanonicalInjuryTargetContext(30, 10, 10, 0, false, 10, 0, 0),
                    TouchDefenseCandidates: battleCandidates,
                    TouchRouteVerdict: new DclTouchNativeRouteVerdict(DclPhysicalRoute.NativeDirect, true, false));
        CheckThrows<ArgumentException>(
            () => DclCanonicalMagicExecutionCoordinator.ResolveAndPublish(battle, touchExecutionRequest),
            "confirmed Touch must reject a native-illegal trajectory before Attack RNG");
        Check(random.DrawCount == 0 && battle.ExecutionRandom.Count == 0,
            "native-illegal confirmed Touch must not consume attack/defense/magnitude RNG or publish an action");
        DclCanonicalPublishedMagicExecution published =
            DclCanonicalMagicExecutionCoordinator.ResolveAndPublish(
                battle,
                touchExecutionRequest with
                {
                    ActionInstanceId = battle.NextActionInstanceId(),
                    TouchRouteVerdict = new DclTouchNativeRouteVerdict(DclPhysicalRoute.NativeDirect, true, true),
                });
        DclDefenseResourceSnapshot spentDefense = battle.CaptureDefenseResources(target, ["right-hand"]);
        string touchVerticalDetail =
            $"contest={published.Result.TouchContest} delivery={published.Result.Delivery} " +
            $"effect={published.Result.Effect} shock={published.Result.InjuryStates?.Shock?.Instance.Kind ?? "none"} " +
            $"mp={published.Result.Payment.MpPaid} reactions={published.Result.Reactions?.Accepted.Count.ToString() ?? "none"} " +
            $"parry={spentDefense.ParryAttemptCounts.GetValueOrDefault("right-hand", -1)} rev={spentDefense.Revision}/{battleDefense.Revision} " +
            $"txnParry={published.Result.Transaction?.DefenseResourcesFor(target).CaptureSnapshot().ParryAttemptCounts.GetValueOrDefault("right-hand", -1)} " +
            $"draws={random.DrawCount} ledger={battle.ExecutionRandom.Count}";
        Check(published.Result.TouchContest is
              {
                  Outcome: DclPhysicalOutcome.Hit,
                  DefenseKind: DclDefenseKind.Parry,
              } &&
              published.Result.Delivery is { Outcome: DclMagicDeliveryOutcome.Delivered } &&
              published.Result.Effect is { Route: DclMagicalEffectRoute.Injury, FinalInjury: 7 } &&
              published.Result.InjuryStates?.Shock?.Instance.Kind == "shock" &&
              published.Result.Payment.MpPaid == 10 &&
              published.Result.Reactions is { Accepted.Count: 0 } &&
              spentDefense.ParryAttemptCounts["right-hand"] == 1 &&
              spentDefense.Revision == battleDefense.Revision + 1 &&
              published.Result.Transaction?.DefenseResourcesFor(target).CaptureSnapshot().ParryAttemptCounts["right-hand"] == 1 &&
              random.DrawCount == 8 && battle.ExecutionRandom.Count == 4,
            "confirmed Touch must compose attack, failed-Parry spend, magnitude, Injury state, payment, transaction, and one Reaction window under one ActionInstance: " + touchVerticalDetail);
        DclCanonicalNativeStrikeProjection nativeTouch = published.Application.ApplyNextStrike(target, 0);
        Check(nativeTouch.Delivered && nativeTouch.PhysicalOutcome == DclPhysicalOutcome.Hit &&
              nativeTouch.Channels.HpDebit == 7 &&
              nativeTouch.AuxiliaryEffects?.AddedStates.Any(state => state.StateKind == "shock") == true,
            "Touch must publish its numeric and universal Injury carriers through the verified SingleResult plan");
        _ = published.Application.CommitResourcePayment();
        published.Application.AcknowledgeReactionWindow();
        published.Application.Settle();
        Check(published.Application.Stage == DclCanonicalNativeActionStage.Settled,
            "Touch native application must settle only after target, payment, and Reaction acknowledgement");
        int touchDrawsBeforeStaleRetry = random.DrawCount;
        int touchLedgerBeforeStaleRetry = battle.ExecutionRandom.Count;
        CheckThrows<ArgumentException>(
            () => DclCanonicalMagicExecutionCoordinator.ResolveAndPublish(
                battle,
                new DclCanonicalMagicExecutionRequest(
                    AbilityId: 16,
                    declaration,
                    battle.NextActionInstanceId(),
                    targetCandidate,
                    BaseSpellScore: 12,
                    TargetSpellScore: 12,
                    new DclDefenseOption(DclDefenseKind.None, 0, Depletes: false),
                    MagnitudeAttribute: 12,
                    new DclElementAffinity(DclElementAffinityKind.Numeric, 0, DclRational.FromInteger(1), DclRational.FromInteger(1)),
                    FaithMagnitude: DclRational.FromInteger(1),
                    TargetHasShell: false,
                    TargetMaxHp: 30,
                    FireEffect: false,
                    OilContributed: false,
                    CurrentMpAtResolution: 20,
                    CurrentHpAtResolution: 20,
                    ApplicableDr: 0,
                    InjuryTargetContext: new DclCanonicalInjuryTargetContext(30, 10, 10, 0, false, 10, 0, 0),
                    TouchDefenseCandidates: battleCandidates,
                    TouchRouteVerdict: new DclTouchNativeRouteVerdict(DclPhysicalRoute.NativeDirect, true, true))),
            "Touch must reject a stale cumulative-Parry snapshot before a second action consumes RNG");
        Check(random.DrawCount == touchDrawsBeforeStaleRetry &&
              battle.ExecutionRandom.Count == touchLedgerBeforeStaleRetry,
            "a stale Touch retry must leave attack/defense/magnitude RNG and native publication untouched");

        var resourceRandom = new SequenceRandomSource([6]);
        var resourceBattle = new DclCanonicalBattleRuntime(runtime, battleGeneration: 44, initialGlobalCt: 0, resourceRandom);
        resourceBattle.ObserveUnit(source);
        resourceBattle.ObserveUnit(target);
        DclDefenseResourceSnapshot resourceDefense = resourceBattle.CaptureDefenseResources(target, ["right-hand"]);
        DclTargetCandidate resourceTarget = targetCandidate with { DefenseResources = resourceDefense };
        DclCanonicalPublishedMagicExecution resourceFailedTouch =
            DclCanonicalMagicExecutionCoordinator.ResolveAndPublish(
                resourceBattle,
                new DclCanonicalMagicExecutionRequest(
                    AbilityId: 16,
                    declaration,
                    resourceBattle.NextActionInstanceId(),
                    resourceTarget,
                    BaseSpellScore: 12,
                    TargetSpellScore: 12,
                    new DclDefenseOption(DclDefenseKind.None, 0, Depletes: false),
                    MagnitudeAttribute: 12,
                    new DclElementAffinity(DclElementAffinityKind.Numeric, 0, DclRational.FromInteger(1), DclRational.FromInteger(1)),
                    FaithMagnitude: DclRational.FromInteger(1),
                    TargetHasShell: false,
                    TargetMaxHp: 30,
                    FireEffect: false,
                    OilContributed: false,
                    CurrentMpAtResolution: 0,
                    CurrentHpAtResolution: 20,
                    ApplicableDr: 0,
                    InjuryTargetContext: new DclCanonicalInjuryTargetContext(30, 10, 10, 0, false, 10, 0, 0),
                    TouchDefenseCandidates: battleCandidates,
                    TouchRouteVerdict: new DclTouchNativeRouteVerdict(DclPhysicalRoute.NativeDirect, true, true)));
        Check(resourceFailedTouch.Result.Outcome == DclCastingOutcome.ResourceFailure &&
              resourceFailedTouch.Result.TouchContest is null &&
              resourceFailedTouch.Result.Delivery is null &&
              resourceFailedTouch.Result.Transaction is { Stage: DclActionTransactionStage.ResourceFailed } &&
              resourceRandom.DrawCount == 0 && resourceBattle.ExecutionRandom.Count == 0 &&
              resourceBattle.CaptureDefenseResources(target, ["right-hand"]).ParryAttemptCounts["right-hand"] == 0,
            "Touch ResourceFailure must occur before attack, active defense, magnitude, Parry spend, and Reaction creation");
    }

    private static void VerifyDclResourceChangeForecastProjection(
        DclActionProfile profile,
        DclCanonicalResourcePoolSnapshot target,
        DclCanonicalResourcePoolSnapshot source,
        DclCanonicalResourceChangeEvaluation evaluation)
    {
        DclCanonicalResourceChangeForecastProjection forecast =
            DclCanonicalResourceChange.ProjectForecast(profile, target, source, evaluation);
        Check(forecast.Resource == DclResourceKind.Hp &&
              forecast.Route == DclResourceChangeRoute.DrainTargetToSource &&
              forecast.IsDrain &&
              forecast.TargetUndeadInteraction == DclUndeadInteraction.Normal &&
              forecast.SourceUndeadInteraction == DclUndeadInteraction.Normal &&
              forecast.MinimumRolledMagnitude == 1 &&
              forecast.MaximumRolledMagnitude == 6 &&
              forecast.TargetCurrent == 5 &&
              forecast.TargetMaximum == 10 &&
              forecast.SourceCurrent == 8 &&
              forecast.SourceMaximum == 10 &&
              forecast.NoDeliveryProbability == DclRational.FromInteger(0) &&
              forecast.TargetKoProbability == new DclRational(1, 3) &&
              forecast.SourceKoProbability == DclRational.FromInteger(0) &&
              forecast.RejectionProbability == DclRational.FromInteger(0) &&
              forecast.ExpectedTargetDebit == new DclRational(10, 3) &&
              forecast.ExpectedSourceCredit == new DclRational(11, 6) &&
              forecast.ExpectedTargetExcessLostToCap == new DclRational(1, 6) &&
              forecast.ExpectedSourceExcessLostToCap == new DclRational(3, 2),
            "ResourceChange player forecast must name HP Drain, rolled range, both pool caps, Undead routes, KO odds, expected target loss/source gain, and excess lost to each cap");
    }

    private static void TestDclCanonicalResourceChange(AbilityCatalog nativeCatalog)
    {
        Check(!Mod.ShouldInstallDclCanonicalAdmissionHook(new RuntimeSettings()) &&
              Mod.ShouldInstallDclCanonicalAdmissionHook(new RuntimeSettings
              {
                  DclCanonicalRuntimeEnabled = true,
                  DclCanonicalAdmissionEnabled = true,
              }),
            "canonical outer-action admission installs only under its explicit runtime gate");
        Check(!Mod.ShouldInstallDclCanonicalPostApplyHook(new RuntimeSettings()) &&
              Mod.ShouldInstallDclCanonicalPostApplyHook(new RuntimeSettings
              {
                  DclCanonicalRuntimeEnabled = true,
                  DclCanonicalPostApplyEnabled = true,
              }),
            "canonical post-apply installs only under its explicit runtime gate");
        Check(!Mod.ShouldInstallDclCanonicalReactionCompletionHook(new RuntimeSettings
              {
                  DclCanonicalRuntimeEnabled = true,
                  DclCanonicalPostApplyEnabled = true,
              }) &&
              Mod.ShouldInstallDclCanonicalReactionCompletionHook(new RuntimeSettings
              {
                  DclCanonicalRuntimeEnabled = true,
                  DclCanonicalPostApplyEnabled = true,
                  DclCanonicalReactionCompletionEnabled = true,
              }),
            "canonical Reaction completion installs only with the runtime, post-apply owner, and explicit completion gate");
        Check(!Mod.ShouldInstallDclCanonicalReactionEffectCompletionHook(new RuntimeSettings
              {
                  DclCanonicalRuntimeEnabled = true,
                  DclCanonicalPostApplyEnabled = true,
                  DclCanonicalReactionCompletionEnabled = true,
              }) &&
              Mod.ShouldInstallDclCanonicalReactionEffectCompletionHook(new RuntimeSettings
              {
                  DclCanonicalRuntimeEnabled = true,
                  DclCanonicalPostApplyEnabled = true,
                  DclCanonicalReactionCompletionEnabled = true,
                  DclCanonicalReactionEffectCompletionEnabled = true,
              }),
            "canonical Reaction effect completion installs only under its separate static-boundary gate");
        DclActionProfile baseProfile = BuildDclMagicTargetingTestProfile();
        DclActionProfile drain = baseProfile with
        {
            ActionId = "spell.resource-drain.test",
            ResourceProfile = new DclResourceProfile(
                BaseMpCost: 0,
                DclRational.FromInteger(1),
                DclOvercastPolicy.Forbidden),
            MagnitudeProfile = new DclFixedResourceMagnitude(DclResourceKind.Hp, "1d6"),
            Effects =
            [
                new DclEffectProfile(
                    DclEffectKind.ResourceChange,
                    DclEffectRole.Carrier,
                    DclEligibleTargetStates.Alive | DclEligibleTargetStates.Undead,
                    DclUndeadInteraction.Normal),
            ],
            ResourceChangeProfile = new DclResourceChangeProfile(
                DclResourceChangeRoute.DrainTargetToSource,
                DclUndeadInteraction.Normal),
        };
        Check(DclAuthoringContract.Validate(drain).IsValid,
            "an explicit HP drain route should pass normalized ResourceChange validation");
        Check(!DclAuthoringContract.Validate(drain with { ResourceChangeProfile = null }).IsValid,
            "ResourceChange authoring must fail closed without its route/source-Undead table");

        var target = new DclCanonicalResourcePoolSnapshot(5, 10, 3, 10, IsUndead: false);
        var cappedSource = new DclCanonicalResourcePoolSnapshot(8, 10, 4, 10, IsUndead: false);
        DclCanonicalResourceChangeResult resolved = DclCanonicalResourceChange.Resolve(
            drain,
            target,
            cappedSource,
            [6]);
        Check(resolved.TargetChannels.HpDebit == 5 && resolved.SourceChannels.HpCredit == 2 &&
              resolved.AppliedTargetMagnitude == 5 && resolved.AppliedSourceMagnitude == 2 &&
              resolved.TargetKo && !resolved.SourceKo && !resolved.RejectedByUndeadPolicy,
            "HP drain must cap target debit and source credit independently, transfer only applied target loss, and keep pool debit outside Injury");

        DclCanonicalResourceChangeEvaluation exact = DclCanonicalResourceChange.Evaluate(
            drain,
            target,
            cappedSource);
        Check(exact.Outcomes.Values.Aggregate(DclRational.FromInteger(0), (sum, value) => sum + value) ==
              DclRational.FromInteger(1) &&
              exact.ExpectedTargetHpDebit == new DclRational(10, 3) &&
              exact.ExpectedSourceHpCredit == new DclRational(11, 6) &&
              exact.TargetKoProbability == new DclRational(1, 3),
            "ResourceChange forecast/AI must retain the exact correlated magnitude space, caps, and target-KO probability");
        VerifyDclResourceChangeForecastProjection(drain, target, cappedSource, exact);

        var authoring = new DclAuthoringRegistry();
        Check(authoring.TryRegister(drain).IsValid,
            "the direct ResourceChange evaluation sentinel must register in canonical authoring");
        var bindings = new DclAbilityBindingRegistry();
        var binding = new DclAbilityBinding(
            AbilityId: 16,
            NativeFormula: 0x08,
            drain.ActionId,
            drain.ProfileRevision,
            DclNativeCarrierKind.SingleResult,
            DclCarrierRewritePolicy.ReplaceCompleteResult,
            RequiresDataNeutralization: true,
            "forecast-state-0x19",
            "compute-point-post-0x281F12",
            "outer-sweep-state-0x2A",
            "native-pre-clamp-and-apply",
            "native-result-selector");
        Check(bindings.TryRegister(binding, nativeCatalog, authoring).IsValid,
            "the direct ResourceChange sentinel must retain a verified numeric native carrier");
        var runtime = new DclCanonicalRuntimeCatalog(
            authoring,
            new DclItemMetadataRegistry(),
            bindings,
            BuildNativeReactionBindings(authoring, bindings, nativeCatalog));
        var sourceKey = new DclUnitKey(30, 1, 31);
        var targetKey = new DclUnitKey(30, 2, 32);
        var targetCandidate = new DclTargetCandidate(
            targetKey,
            new DclBattleTile(2, 1, 0),
            Height: 0,
            DclAllegianceRelation.Enemy,
            DclEligibleTargetStates.Alive,
            CurrentHp: target.CurrentHp,
            CombatStateRevision: 0,
            new DclDefenseResourceSnapshot(new Dictionary<string, int>(), BlockAvailable: true));
        var declarationRequest = new DclCastDeclarationRequest(
            drain,
            sourceKey,
            new DclBattleTile(1, 1, 0),
            CasterHeight: 0,
            targetCandidate,
            FixedTile: null,
            FixedTileHeight: null,
            Learned: true,
            SourceUsable: true,
            SourceSilenced: false,
            PrerequisitesMet: true,
            CurrentMp: cappedSource.CurrentMp,
            CurrentHp: cappedSource.CurrentHp,
            OvercastConfirmed: false,
            CurrentGlobalCt: 0,
            CastCtModifiers: []);
        DclCanonicalMagicEvaluationResult actionEvaluation = DclCanonicalMagicEvaluationExecutor.Evaluate(
            runtime,
            new DclCanonicalMagicEvaluationInput(
                AbilityId: 16,
                declarationRequest,
                targetCandidate,
                BaseSpellScore: 12,
                TargetSpellScore: 12,
                new DclDefenseOption(DclDefenseKind.None, 0, Depletes: false),
                MagnitudeAttribute: 0,
                new DclElementAffinity(
                    DclElementAffinityKind.Numeric,
                    Step: 0,
                    DclRational.FromInteger(1),
                    DclRational.FromInteger(1)),
                DclRational.FromInteger(1),
                TargetHasShell: false,
                TargetMaxHp: target.MaxHp,
                FireEffect: false,
                OilContributed: false,
                CurrentMpAtResolution: cappedSource.CurrentMp,
                CurrentHpAtResolution: cappedSource.CurrentHp,
                ResourceTargetPools: target,
                ResourceSourcePools: cappedSource));
        Check(actionEvaluation.ResourceChange is { } actionResource &&
              actionResource.ExpectedTargetHpDebit == exact.ExpectedTargetHpDebit * actionEvaluation.DeliveryProbability &&
              actionResource.ExpectedSourceHpCredit == exact.ExpectedSourceHpCredit * actionEvaluation.DeliveryProbability &&
              actionResource.TargetKoProbability == exact.TargetKoProbability * actionEvaluation.DeliveryProbability &&
              actionEvaluation.TargetHpDebit.ExpectedValue == actionResource.ExpectedTargetHpDebit &&
              DclCanonicalMagicAiProjection.From(actionEvaluation).ResourceChange == actionResource &&
              DclCanonicalMagicForecastProjection.From(actionEvaluation).ResourceChange == actionResource,
            "the direct magic evaluator must correlate no-delivery with exact drain magnitude and expose one lossless result to player forecast and AI");
        DclCanonicalMagicExecutionResult actionExecution = DclCanonicalMagicExecutor.Resolve(
            runtime,
            new DclCanonicalMagicExecutionInput(
                AbilityId: 16,
                declarationRequest,
                ActionInstanceId: 1,
                targetCandidate,
                BaseSpellScore: 12,
                TargetSpellScore: 12,
                SharedCasterRoll: 10,
                new DclDefenseOption(DclDefenseKind.None, 0, Depletes: false),
                DefenseRoll: null,
                MagnitudeAttribute: 0,
                MagnitudeDice: [6],
                new DclElementAffinity(
                    DclElementAffinityKind.Numeric,
                    Step: 0,
                    DclRational.FromInteger(1),
                    DclRational.FromInteger(1)),
                DclRational.FromInteger(1),
                TargetHasShell: false,
                TargetMaxHp: target.MaxHp,
                FireEffect: false,
                OilContributed: false,
                CurrentMpAtResolution: cappedSource.CurrentMp,
                CurrentHpAtResolution: cappedSource.CurrentHp,
                ResourceTargetPools: target,
                ResourceSourcePools: cappedSource));
        Check(actionExecution.Delivery is { Delivered: true } &&
              actionExecution.ResourceChange is { TargetKo: true } executedResource &&
              executedResource.TargetChannels.HpDebit == 5 && executedResource.SourceChannels.HpCredit == 2 &&
              actionExecution.TargetKoAfterStrike &&
              actionExecution.Transaction is
              { Stage: DclActionTransactionStage.Settled, ReactionWindowOpened: true } &&
              actionExecution.InjuryConsequences is null,
            "confirmed direct ResourceChange must consume its supplied magnitude once, commit the typed Carrier, expose both pool owners, and avoid the Injury pipeline");
        var coordinatedRandom = new SequenceRandomSource([3, 3, 4, 6]);
        var battle = new DclCanonicalBattleRuntime(runtime, battleGeneration: 30, initialGlobalCt: 0, coordinatedRandom);
        battle.ObserveUnit(sourceKey);
        battle.ObserveUnit(targetKey);
        DclCanonicalPublishedMagicExecution coordinated =
            DclCanonicalMagicExecutionCoordinator.ResolveAndPublish(
                battle,
                new DclCanonicalMagicExecutionRequest(
                    AbilityId: 16,
                    declarationRequest,
                    ActionInstanceId: battle.NextActionInstanceId(),
                    targetCandidate,
                    BaseSpellScore: 12,
                    TargetSpellScore: 12,
                    new DclDefenseOption(DclDefenseKind.None, 0, Depletes: false),
                    MagnitudeAttribute: 0,
                    new DclElementAffinity(
                        DclElementAffinityKind.Numeric,
                        Step: 0,
                        DclRational.FromInteger(1),
                        DclRational.FromInteger(1)),
                    DclRational.FromInteger(1),
                    TargetHasShell: false,
                    TargetMaxHp: target.MaxHp,
                    FireEffect: false,
                    OilContributed: false,
