              immuneAreaStatusTarget.ExpectedLandedStrikes == DclRational.FromInteger(0) &&
              immuneAreaStatusTarget.RiderApplicationProbability[0] == DclRational.FromInteger(0),
            "pure Area status immunity must suppress delivery before target resistance probability and RNG");

        var areaStatusRandom = new SequenceRandomSource([3, 3, 4, 6, 6, 6, 1, 1, 1]);
        var areaStatusBattle = new DclCanonicalBattleRuntime(
            areaStatusRuntime,
            battleGeneration: 32,
            initialGlobalCt: 100,
            areaStatusRandom);
        areaStatusBattle.ObserveUnit(areaStatusSource);
        areaStatusBattle.ObserveUnit(areaStatusTargetA);
        areaStatusBattle.ObserveUnit(areaStatusTargetB);
        var areaStatusMaterialization = new DclCanonicalStateMaterialization(
            BindSource: true,
            AppliedBeforeTurnSerial: 1,
            FirstEligibleTargetTurnSerial: null,
            FirstEligibleSourceTurnSerial: null,
            DurationUnits: 20,
            Strength: null,
            StackDiscriminator: "",
            ContributionIdentity: null,
            new DclPropertyStatePayload(
                areaStatusDefinition.PayloadSchema,
                new Dictionary<string, string>()));
        DclCanonicalAreaTargetExecutionRequest AreaStatusExecutionTarget(DclTargetCandidate target) => new(
            target,
            TargetSpellScore: 12,
            Dodge: null,
            ResistanceScore: 10,
            MagnitudeAttribute: 0,
            new DclElementAffinity(
                DclElementAffinityKind.Numeric,
                Step: 0,
                DclRational.FromInteger(1),
                DclRational.FromInteger(1)),
            FaithMagnitude: DclRational.FromInteger(1),
            TargetHasShell: false,
            TargetMaxHp: 20,
            FireEffect: false,
            OilContributed: false,
            StatusRiders:
            [
                new DclCanonicalStatusRiderExecutionRequest(
                    EffectIndex: 0,
                    ResistanceScore: 10,
                    Immune: false,
                    areaStatusBattle.States,
                    areaStatusMaterialization),
            ]);
        DclCanonicalPublishedAreaMagicExecution areaStatusExecution =
            DclCanonicalAreaMagicExecutionCoordinator.ResolveAndPublish(
                areaStatusBattle,
                new DclCanonicalAreaMagicExecutionRequest(
                    AbilityId: 16,
                    areaStatusDeclaration,
                    areaStatusBattle.NextActionInstanceId(),
                    areaStatusUnits,
                    [areaStatusCandidateA, areaStatusCandidateB],
                    BaseSpellScore: 12,
                    [AreaStatusExecutionTarget(areaStatusCandidateA), AreaStatusExecutionTarget(areaStatusCandidateB)],
                    CurrentMpAtResolution: 10,
                    CurrentHpAtResolution: 20,
                    ReactionCandidates: []));
        DclCanonicalAreaMagicStrikeResult[] areaStatusStrikes = areaStatusExecution.Result.Strikes.ToArray();
        Check(areaStatusStrikes.Length == 2 &&
              areaStatusStrikes[0].StatusRiders?.Single().Gate is
                  { Attempted: true, Applied: true, Reason: "area-status-carrier-applied" } &&
              areaStatusStrikes[1].StatusRiders?.Single().Gate is
                  { Attempted: true, Applied: false, Reason: "area-status-carrier-resisted-tie-or-better" } &&
              areaStatusBattle.States.Instances.Single().Kind == areaStatusDefinition.Kind &&
              areaStatusExecution.Application.Plan.Strikes.All(strike => strike.Channels.IsEmpty) &&
              areaStatusExecution.Application.Plan.Strikes[0].AuxiliaryEffects?.AddedStates.Single().StateKind ==
                  areaStatusDefinition.Kind &&
              (areaStatusExecution.Application.Plan.Strikes[1].AuxiliaryEffects?.AddedStates.Count ?? 0) == 0 &&
              areaStatusExecution.Application.Plan.ReactionWindowOpened &&
              areaStatusRandom.DrawCount == 9 && areaStatusBattle.ExecutionRandom.Count == 3,
            "confirmed pure Area status must consume one shared cast and one resistance per target, apply only the winning Carrier, and publish empty numeric channels");
    }

    private static void TestDclCanonicalForcedMovement(AbilityCatalog nativeCatalog)
    {
        DclActionProfile baseProfile = BuildDclMagicTargetingTestProfile();
        DclActionProfile push = baseProfile with
        {
            ActionId = "skill.forced-movement.test",
            ResourceProfile = new DclResourceProfile(0, DclRational.FromInteger(1), DclOvercastPolicy.Forbidden),
            MagnitudeProfile = null,
            Effects =
            [
                new DclEffectProfile(
                    DclEffectKind.ForcedMovement,
                    DclEffectRole.Carrier,
                    DclEligibleTargetStates.Alive,
                    DclUndeadInteraction.Normal),
            ],
            ForcedMovementProfile = new DclForcedMovementProfile(
                DistanceTiles: 2,
                DclForcedMovementDirection.AwayFromSource),
            DeliveryProfile = baseProfile.DeliveryProfile with
            {
                Blockable = true,
                UsesDefenseBonus = true,
            },
        };
        Check(DclAuthoringContract.Validate(push).IsValid,
            "one explicit forced-movement profile should normalize without a fabricated numeric magnitude");
        Check(!DclAuthoringContract.Validate(push with
            {
                TransactionProfile = push.TransactionProfile with
                {
                    StrikeCount = 2,
                    WithinActionApplication = DclWithinActionApplication.Immediate,
                },
            }).IsValid,
            "multi-Strike Immediate forced movement must fail closed without between-Strike map reprojection");
        DclActionProfile explicitVector = push with
        {
            ForcedMovementProfile = new DclForcedMovementProfile(
                1,
                DclForcedMovementDirection.ExplicitVector,
                DeltaX: 1,
                DeltaY: -1),
        };
        Check(DclAuthoringContract.Validate(explicitVector).IsValid &&
              !DclAuthoringContract.Validate(explicitVector with
              {
                  ForcedMovementProfile = explicitVector.ForcedMovementProfile! with { DeltaX = 2 },
              }).IsValid,
            "explicit forced movement must carry one normalized nonzero tile vector");

        var target = new DclUnitKey(31, 2, 32);
        var origin = new DclBattleTile(2, 2, 0);
        var destination = new DclBattleTile(4, 2, 0);
        var verdict = new DclCanonicalNativeMovementVerdict(
            target,
            origin,
            destination,
            RequestedTiles: 2,
            MovedTiles: 2,
            DclForcedMovementDirection.AwayFromSource,
            Fell: false,
            NativePathResolved: true);
        DclCanonicalForcedMovementResult movement = DclCanonicalForcedMovement.Resolve(
            push,
            target,
            origin,
            targetKo: false,
            verdict);
        Check(movement is
              {
                  MovedTiles: 2,
                  CancelAim: true,
                  CreatesConcentrationIncident: true,
                  SuppressedByTargetKo: false,
              },
            "forced movement must consume the one shared native map verdict and expose target-local Aim/concentration consequences only after settling");
        DclCanonicalForcedMovementResult blocked = DclCanonicalForcedMovement.Resolve(
            push,
            target,
            origin,
            targetKo: false,
            verdict with { Destination = origin, MovedTiles = 0 });
        Check(blocked.MovedTiles == 0 && !blocked.CancelAim && !blocked.CreatesConcentrationIncident &&
              DclCanonicalNativeAuxiliaryProjector.ProjectForcedMovement(blocked) is null,
            "a native-blocked displacement must remain a zero-move result without lifecycle or native carrier effects");
        DclCanonicalForcedMovementResult koSuppressed = DclCanonicalForcedMovement.Resolve(
            push,
            target,
            origin,
            targetKo: true,
            nativeVerdict: null);
        Check(koSuppressed.SuppressedByTargetKo && koSuppressed.MovedTiles == 0,
            "target KO must short-circuit forced movement before requesting map resolution");
        CheckThrows<ArgumentException>(
            () => DclCanonicalForcedMovement.Resolve(
                push,
                target,
                origin,
                targetKo: false,
                verdict with { RequestedTiles = 1 }),
            "forecast/execution must reject a map verdict built for a different authored distance");

        var authoring = new DclAuthoringRegistry();
        Check(authoring.TryRegister(push).IsValid,
            "forced-movement native projection sentinel must register");
        DclStateDefinition movementAimDefinition = BuildDclStateDefinition(
            "aim", DclStateStackPolicy.Replace, DclStateDurationClock.UsesOrTriggers);
        Check(authoring.TryRegister(movementAimDefinition).IsValid,
            "ForcedMovement Aim cancellation requires the authoritative typed Aim definition");
        var bindings = new DclAbilityBindingRegistry();
        var binding = new DclAbilityBinding(
            16,
            0x08,
            push.ActionId,
            push.ProfileRevision,
            DclNativeCarrierKind.SingleResult,
            DclCarrierRewritePolicy.ReplaceCompleteResult,
            RequiresDataNeutralization: true,
            "forecast-state-0x19",
            "compute-point-post-0x281F12",
            "outer-sweep-state-0x2A",
            "native-pre-clamp-and-apply",
            "native-result-selector");
        Check(bindings.TryRegister(binding, nativeCatalog, authoring).IsValid,
            "forced-movement sentinel must retain a verified single-result native carrier");
        var runtime = new DclCanonicalRuntimeCatalog(
            authoring,
            new DclItemMetadataRegistry(),
            bindings,
            BuildNativeReactionBindings(authoring, bindings, nativeCatalog));
        DclCanonicalNativeAuxiliaryEffects auxiliary =
            DclCanonicalNativeAuxiliaryProjector.ProjectForcedMovement(movement)!;
        var strike = new DclCanonicalNativeStrikeProjection(
            target,
            StrikeIndex: 0,
            DclMagicDeliveryOutcome.Delivered,
            PhysicalOutcome: null,
            Delivered: true,
            new DclCanonicalNativeNumericChannels(0, 0, 0, 0),
            MagicalRoute: null,
            InjuryConsequences: null,
            TargetKoAfterStrike: false,
            KoShortCircuited: false,
            auxiliary);
        DclCanonicalNativeAuxiliaryApplyPlan applyPlan =
            DclCanonicalNativeAuxiliaryApplyPlanner.Build(runtime, strike);
        DclBattleTile nativeTile = origin;
        DclCanonicalNativeForcedMovementWriter.Apply(
            applyPlan,
            () => nativeTile,
            resolved => nativeTile = resolved.Destination);
        Check(applyPlan.RequiresNativeAuxiliaryCarrier && nativeTile == destination,
            "the forced-movement writer must validate the pre-move tile and exact post-native destination without stepping tile-by-tile");

        var source = new DclUnitKey(31, 1, 31);
        var targetCandidate = new DclTargetCandidate(
            target,
            origin,
            Height: 0,
            DclAllegianceRelation.Enemy,
            DclEligibleTargetStates.Alive,
            CurrentHp: 10,
            CombatStateRevision: 0,
            new DclDefenseResourceSnapshot(new Dictionary<string, int>(), BlockAvailable: true));
        var declaration = new DclCastDeclarationRequest(
            push,
            source,
            new DclBattleTile(1, 2, 0),
            CasterHeight: 0,
            targetCandidate,
            FixedTile: null,
            FixedTileHeight: null,
            Learned: true,
            SourceUsable: true,
            SourceSilenced: false,
            PrerequisitesMet: true,
            CurrentMp: 5,
            CurrentHp: 10,
            OvercastConfirmed: false,
            CurrentGlobalCt: 0,
            CastCtModifiers: []);
        DclCanonicalForcedMovementEvaluationResult evaluation =
            DclCanonicalForcedMovementEvaluation.Evaluate(
                runtime,
                new DclCanonicalForcedMovementEvaluationInput(
                    AbilityId: 16,
                    declaration,
                    targetCandidate,
                    BaseSpellScore: 12,
                    TargetSpellScore: 12,
                    new DclDefenseOption(DclDefenseKind.None, 0, Depletes: false),
                    ResistanceScore: null,
                    Immune: false,
                    CurrentMpAtResolution: 5,
                    CurrentHpAtResolution: 10,
                    verdict,
                    new DclCanonicalConcentrationTargetContext(
                        Charging: true,
                        Will: 10,
                        ConcentrationModifier: 0,
                        StatePenaltyMagnitude: 0)));
        DclCanonicalForcedMovementForecast playerMovement =
            DclCanonicalForcedMovementEvaluation.ProjectPlayer(evaluation);
        DclCanonicalForcedMovementAiProjection aiMovement =
            DclCanonicalForcedMovementEvaluation.ProjectAi(evaluation);
        Check(evaluation.Legal && evaluation.DeliveredMovement == movement &&
              evaluation.ExpectedMovedTiles ==
                  evaluation.DeliveryProbability * DclRational.FromInteger(2) &&
              playerMovement.RequestedTiles == 2 &&
              playerMovement.Direction == DclForcedMovementDirection.AwayFromSource &&
              playerMovement.Origin == origin &&
              playerMovement.Destination == destination &&
              playerMovement.MovedTilesOnDelivery == 2 &&
              playerMovement.ExpectedMovedTiles == evaluation.ExpectedMovedTiles &&
              !playerMovement.FellOnDelivery &&
              aiMovement.ExpectedMovedTiles == evaluation.ExpectedMovedTiles &&
              evaluation.ConcentrationInterruptionProbability ==
                  evaluation.DeliveryProbability * new DclRational(
                      216 - DclSuccessRoll.SuccessOutcomeCount(7), 216),
            "forced-movement forecast and AI must share the exact delivery space, direction, native origin/destination, expected moved tiles, concentration risk, and one immutable native map verdict");

        var blockDefense = new DclDefenseOption(DclDefenseKind.Block, Target: 8, Depletes: true);
        DclCanonicalForcedMovementEvaluationResult blockEvaluation =
            DclCanonicalForcedMovementEvaluation.Evaluate(
                runtime,
                new DclCanonicalForcedMovementEvaluationInput(
                    AbilityId: 16,
                    declaration,
                    targetCandidate,
                    BaseSpellScore: 12,
                    TargetSpellScore: 12,
                    blockDefense,
                    ResistanceScore: null,
                    Immune: false,
                    CurrentMpAtResolution: 5,
                    CurrentHpAtResolution: 10,
                    verdict));
        DclCanonicalForcedMovementForecast blockForecast =
            DclCanonicalForcedMovementEvaluation.ProjectPlayer(blockEvaluation);
        DclCanonicalForcedMovementAiProjection blockAi =
            DclCanonicalForcedMovementEvaluation.ProjectAi(blockEvaluation);
        Check(blockEvaluation.DefenseAttemptProbability > DclRational.FromInteger(0) &&
              blockEvaluation.BlockSpendProbability == blockEvaluation.DefenseAttemptProbability &&
              blockForecast.BlockSpendPercent == blockForecast.DefenseAttemptPercent &&
              blockAi.BlockSpendProbability == blockEvaluation.BlockSpendProbability,
            "ForcedMovement forecast and AI must expose the exact correlated chance of attempting and spending finite Block");

        var executionRandom = new SequenceRandomSource([3, 3, 4, 6, 6, 6]);
        var battle = new DclCanonicalBattleRuntime(runtime, battleGeneration: 31, initialGlobalCt: 0, executionRandom);
        battle.ObserveUnit(source);
        battle.ObserveUnit(target);
        CheckThrows<ArgumentException>(
            () => DclCanonicalForcedMovementExecutionCoordinator.ResolveAndPublish(
                battle,
                new DclCanonicalForcedMovementExecutionRequest(
                    AbilityId: 16,
                    declaration,
                    battle.NextActionInstanceId(),
                    targetCandidate with { CombatStateRevision = 7 },
                    BaseSpellScore: 12,
                    TargetSpellScore: 12,
                    new DclDefenseOption(DclDefenseKind.None, 0, Depletes: false),
                    CurrentMpAtResolution: 5,
                    CurrentHpAtResolution: 10,
                    verdict)),
            "confirmed ForcedMovement must reject a stale target state before casting or map resolution");
        Check(executionRandom.DrawCount == 0 && battle.ExecutionRandom.Count == 0,
            "stale ForcedMovement must leave the execution random ledger untouched");
        DclStateApplicationResult movementTargetAim = battle.States.Apply(new DclStateApplication(
            movementAimDefinition,
            target,
            Source: null,
            AppliedAtGlobalCt: battle.CurrentGlobalCt,
            AppliedBeforeTurnSerial: 0,
            FirstEligibleTargetTurnSerial: null,
            FirstEligibleSourceTurnSerial: null,
            DurationUnits: 1,
            Strength: null,
            WinningMargin: null,
            StackDiscriminator: "",
            ContributionIdentity: null,
            new DclAimStatePayload(movementAimDefinition.PayloadSchema, source, 1),
            movementAimDefinition.PresentationProfile));
        DclTargetCandidate currentMovementTarget = targetCandidate with
        {
            CombatStateRevision = battle.States.CaptureTarget(target).Revision,
        };
        var chargingTargetDeclarationRequest = declaration with
        {
            Caster = target,
            CasterTile = origin,
            UnitTarget = new DclTargetCandidate(
                source,
                new DclBattleTile(1, 2, 0),
                Height: 0,
                DclAllegianceRelation.Enemy,
                DclEligibleTargetStates.Alive,
                CurrentHp: 10,
                CombatStateRevision: battle.States.CaptureTarget(source).Revision,
                new DclDefenseResourceSnapshot(new Dictionary<string, int>(), BlockAvailable: true)),
        };
        DclCastDeclarationAttempt chargingTargetAttempt = DclMagicTargeting.Declare(
            chargingTargetDeclarationRequest,
            battle.NextActionInstanceId());
        Check(chargingTargetAttempt is { Legal: true, Declaration: not null },
            "ForcedMovement concentration sentinel requires one legal pending cast on the target");
        var movementTimeline = new DclCanonicalTimelineScheduler(
            battle,
            [new DclCanonicalTimelineUnit(target, initiativeRank: 0, new DclCtState(0), DclCtRate.Normal)]);
        movementTimeline.ScheduleChargedAction(16, chargingTargetAttempt.Declaration!);
        var movementConcentrationContext = new DclCanonicalConcentrationTargetContext(
            Charging: true,
            Will: 10,
            ConcentrationModifier: 0,
            StatePenaltyMagnitude: 0);
        DclCanonicalPublishedForcedMovementExecution published =
            DclCanonicalForcedMovementExecutionCoordinator.ResolveAndPublish(
                battle,
                new DclCanonicalForcedMovementExecutionRequest(
                    AbilityId: 16,
                    declaration,
                    battle.NextActionInstanceId(),
                    currentMovementTarget,
                    BaseSpellScore: 12,
                    TargetSpellScore: 12,
                    new DclDefenseOption(DclDefenseKind.None, 0, Depletes: false),
                    CurrentMpAtResolution: 5,
                    CurrentHpAtResolution: 10,
                    verdict,
                    ConcentrationContext: movementConcentrationContext));
        Check(published.Result.Movement == movement &&
              published.Result.AimCancellation is
                  { HadAim: true, Retained: false, InstanceId: var removedMovementAimId } &&
              removedMovementAimId == movementTargetAim.Instance.InstanceId &&
              !battle.States.TryGet(movementTargetAim.Instance.InstanceId, out _) &&
              published.Result.Reactions is { Accepted.Count: 0 } &&
              ReferenceEquals(published.Result.Reactions, published.Application.Plan.Reactions) &&
              published.Application.Plan.Strikes.Single().AuxiliaryEffects?.ForcedMovement == movement &&
              published.Application.Plan.Strikes.Single().AuxiliaryEffects?.RemovedStates.Single().InstanceId ==
                  movementTargetAim.Instance.InstanceId &&
              published.Result.Concentration is
                  { Outcome: DclConcentrationOutcome.Interrupted, Score: 7, Rolled: true } &&
              published.Result.ChargingCancellation is
                  { Reason: DclChargingCancellationReason.ConcentrationFailure } &&
              !movementTimeline.TryGetChargedAction(target, out _) &&
              executionRandom.DrawCount == 6 && battle.ExecutionRandom.Count == 2,
            "confirmed ForcedMovement must atomically cancel target Aim and failed concentration before the terminal Reaction window");

        byte[] composedMovementSourceRaw = new byte[0x200];
        composedMovementSourceRaw[0x38] = 10;
        composedMovementSourceRaw[0x39] = 10;
        composedMovementSourceRaw[0x3A] = 10;
        composedMovementSourceRaw[0x4F] = 1;
        composedMovementSourceRaw[0x50] = 2;
        byte[] composedMovementTargetRaw = (byte[])composedMovementSourceRaw.Clone();
        composedMovementTargetRaw[0x4F] = 2;
        var composedMovementSourceNative = new UnitSnapshot(
            Ptr: (nint)0x7100,
            CharId: source.CharacterId,
            Level: 1,
            Hp: 10,
            MaxHp: 10,
            Team: 0,
            IsFoe: false,
            Pa: 99,
            Ma: 99,
            Speed: 99,
            Move: 4,
            Jump: 3,
            Brave: 50,
            Faith: 50,
            Raw: composedMovementSourceRaw,
            Mp: 5,
            MaxMp: 10);
        UnitSnapshot composedMovementTargetNative = composedMovementSourceNative with
        {
            Ptr = (nint)0x7200,
            CharId = target.CharacterId,
            Team = 1,
            IsFoe = true,
            Raw = composedMovementTargetRaw,
        };
        var composedMovementRandom = new SequenceRandomSource([3, 3, 4]);
        var composedMovementBattle = new DclCanonicalBattleRuntime(
            runtime,
            battleGeneration: 31,
            initialGlobalCt: 0,
            composedMovementRandom);
        composedMovementBattle.ObserveUnit(source);
        composedMovementBattle.ObserveUnit(target);
        DclCanonicalNativeSnapshotBatch composedMovementBatch = DclCanonicalNativeSnapshotBatchProjector.Project(
            composedMovementBattle,
            source,
            [
                new DclCanonicalNativeUnitSnapshotRequest(
                    source.UnitSlot,
                    composedMovementSourceNative,
                    new DclCanonicalAttributeAdjustments(),
                    new DclSecondaryInputs(),
                    TileHeight: 0),
                new DclCanonicalNativeUnitSnapshotRequest(
                    target.UnitSlot,
                    composedMovementTargetNative,
                    new DclCanonicalAttributeAdjustments(),
                    new DclSecondaryInputs(),
                    TileHeight: 0),
            ]);
        DclCanonicalNativeOuterSweepAdmission composedMovementAdmission =
            composedMovementBattle.NativeAdmissions.Admit(
                composedMovementBattle,
                new DclCanonicalNativeOuterSweepRequest(
                    SweepSerial: 1,
                    source,
                    ActionType: 0x0B,
                    AbilityId: 16,
                    BattleState: DclCalcProvenance.ConfirmedExecutionBattleState,
                    NativeRepeatCount: 1,
                    NativeRepeatIndex: 0,
                    Targets: [target],
                    SelectedUnit: target,
                    SelectedTile: new DclBattleTile(2, 2, 0)));
        DclBattleTile composedMovementOrigin = composedMovementBatch.Units[target].Unit.Target.Tile;
        var composedMovementVerdict = new DclCanonicalNativeMovementVerdict(
            target,
            composedMovementOrigin,
            composedMovementOrigin with { X = composedMovementOrigin.X + 2 },
            RequestedTiles: 2,
            MovedTiles: 2,
            DclForcedMovementDirection.AwayFromSource,
            Fell: false,
            NativePathResolved: true);
        string forcedMovementPolicyTemplateJson = DclCanonicalNativePolicyTicketTemplateJsonLoader.Serialize(
            new DclCanonicalNativePolicyTicketTemplateBundle(
                DclCanonicalNativePolicyTicketTemplateJsonLoader.CurrentSchemaRevision,
                [
                    new DclCanonicalNativePolicyTicketTemplate(
                        binding.AbilityId,
                        new DclCanonicalNativeUnitPolicyTemplate(SourceTileHeight: 0, TargetTileHeight: 0),
                        new DclCanonicalNativeFamilyPolicyTicketTemplate(
                            DclCanonicalActionFamily.ForcedMovement,
                            ForcedMovement: new DclCanonicalNativeForcedMovementActionPolicyTemplate(
                                new DclCanonicalNativeSingleTargetMagicPolicySource(
                                    "forced-movement",
                                    12,
                                    DclZodiacCompatibility.Neutral,
                                    0,
                                    Learned: true,
                                    SourceUsable: true,
                                    PrerequisitesMet: true,
                                    OvercastConfirmed: false),
                                new DclDefenseOption(DclDefenseKind.None, 0, Depletes: false),
                                composedMovementVerdict))),
                ]));
        DclCanonicalNativePolicyTicketTemplateRegistry forcedMovementPolicyTemplateRegistry =
            DclCanonicalNativePolicyTicketTemplateJsonLoader.Load(forcedMovementPolicyTemplateJson);
        var forcedMovementTemplateBattle = new DclCanonicalBattleRuntime(
            runtime,
            battleGeneration: 31,
            initialGlobalCt: 0,
            new SequenceRandomSource([]));
        forcedMovementTemplateBattle.ObserveUnit(source);
        forcedMovementTemplateBattle.ObserveUnit(target);
        DclCanonicalNativeAdmittedAction forcedMovementTemplateAction =
            new DclCanonicalNativeOuterActionCapture().Capture(
                forcedMovementTemplateBattle,
                new DclCanonicalNativeOuterSweepRequest(
                    SweepSerial: 1,
                    source,
                    ActionType: 0x0B,
                    AbilityId: binding.AbilityId,
                    BattleState: DclCalcProvenance.ConfirmedExecutionBattleState,
                    NativeRepeatCount: 1,
                    NativeRepeatIndex: 0,
                    Targets: [target],
                    SelectedUnit: target,
                    SelectedTile: new DclBattleTile(2, 2, 0)),
                new Dictionary<DclUnitKey, UnitSnapshot>
                {
                    [source] = composedMovementSourceNative,
                    [target] = composedMovementTargetNative,
                })!;
        forcedMovementTemplateBattle.NativeAdmittedActions.Publish(
            forcedMovementTemplateBattle,
            forcedMovementTemplateAction);
        DclCanonicalNativePolicyTicketTemplateBuildResult forcedMovementTemplateTicket =
            forcedMovementPolicyTemplateRegistry.TryBuildTicket(
                forcedMovementTemplateBattle,
                forcedMovementTemplateAction);
        DclCanonicalNativePolicyTicketPublishResult forcedMovementTemplatePublish =
            forcedMovementTemplateBattle.NativePolicySources.TryPublishForRetainedAdmission(
                forcedMovementTemplateBattle,
                forcedMovementTemplateTicket.Ticket!);
        Check(forcedMovementTemplateTicket.Status == DclCanonicalNativePolicyTicketTemplateBuildStatus.Built &&
              forcedMovementTemplateTicket.Ticket?.FamilyPolicySource is DclCanonicalNativeForcedMovementActionPolicySource
              {
                  NativeMovementVerdict: var templateMovementVerdict,
              } &&
              templateMovementVerdict == composedMovementVerdict &&
              forcedMovementTemplatePublish.Status == DclCanonicalNativePolicyTicketPublishStatus.Published &&
              forcedMovementTemplateBattle.NativePolicySources.Count == 1 &&
              forcedMovementTemplateBattle.NativeActions.Count == 0,
            "native policy ticket templates must materialize and validate ForcedMovement policy from an explicit final native verdict without executing the retained carrier");
        string invalidForcedMovementPolicyTemplateJson = DclCanonicalNativePolicyTicketTemplateJsonLoader.Serialize(
            new DclCanonicalNativePolicyTicketTemplateBundle(
                DclCanonicalNativePolicyTicketTemplateJsonLoader.CurrentSchemaRevision,
                [
                    new DclCanonicalNativePolicyTicketTemplate(
                        binding.AbilityId,
                        new DclCanonicalNativeUnitPolicyTemplate(SourceTileHeight: 0, TargetTileHeight: 0),
                        new DclCanonicalNativeFamilyPolicyTicketTemplate(
                            DclCanonicalActionFamily.ForcedMovement,
                            ForcedMovement: new DclCanonicalNativeForcedMovementActionPolicyTemplate(
                                new DclCanonicalNativeSingleTargetMagicPolicySource(
                                    "forced-movement",
                                    12,
                                    DclZodiacCompatibility.Neutral,
                                    0,
                                    Learned: true,
                                    SourceUsable: true,
                                    PrerequisitesMet: true,
                                    OvercastConfirmed: false),
                                new DclDefenseOption(DclDefenseKind.None, 0, Depletes: false),
                                composedMovementVerdict with
                                {
                                    MovedTiles = 3,
                                }))),
                ]));
        CheckThrows<DclAuthoringLoadException>(
            () => DclCanonicalNativePolicyTicketTemplateJsonLoader.Load(invalidForcedMovementPolicyTemplateJson),
            "native policy ticket template loader must reject ForcedMovement verdicts that move farther than requested before publication");
        var forcedMovementTemplateRuntime = new DclCanonicalRuntimeCatalog(
            runtime.Authoring,
            runtime.Items,
            runtime.Abilities,
            runtime.ReactionBindings,
            forcedMovementPolicyTemplateRegistry);
        var forcedMovementTemplateHandshakeRandom = new SequenceRandomSource([3, 3, 4]);
        var forcedMovementTemplateHandshakeBattle = new DclCanonicalBattleRuntime(
            forcedMovementTemplateRuntime,
            battleGeneration: 31,
            initialGlobalCt: 0,
            forcedMovementTemplateHandshakeRandom);
        forcedMovementTemplateHandshakeBattle.ObserveUnit(source);
        forcedMovementTemplateHandshakeBattle.ObserveUnit(target);
        DclCanonicalNativeAdmittedAction forcedMovementTemplateHandshakeAction =
            new DclCanonicalNativeOuterActionCapture().Capture(
                forcedMovementTemplateHandshakeBattle,
                new DclCanonicalNativeOuterSweepRequest(
                    SweepSerial: 1,
                    source,
                    ActionType: 0x0B,
                    AbilityId: binding.AbilityId,
                    BattleState: DclCalcProvenance.ConfirmedExecutionBattleState,
                    NativeRepeatCount: 1,
                    NativeRepeatIndex: 0,
                    Targets: [target],
                    SelectedUnit: target,
                    SelectedTile: new DclBattleTile(2, 2, 0)),
                new Dictionary<DclUnitKey, UnitSnapshot>
                {
                    [source] = composedMovementSourceNative,
                    [target] = composedMovementTargetNative,
                })!;
        DclCanonicalNativeAdmissionTemplateExecutionResult forcedMovementTemplateHandshake =
            DclCanonicalNativeRetainedActionBridge.TryPublishAdmissionBuildTemplateAndResolve(
                forcedMovementTemplateHandshakeBattle,
                forcedMovementTemplateHandshakeAction);
        Check(forcedMovementTemplateHandshake.Admission.Intake.Status == DclCanonicalNativeAdmittedActionPublishStatus.Published &&
              forcedMovementTemplateHandshake.Admission.Bridge.Status == DclCanonicalNativePolicyTicketBridgeStatus.MissingPolicyTicket &&
              forcedMovementTemplateHandshake.Template?.Status == DclCanonicalNativePolicyTicketTemplateBuildStatus.Built &&
              forcedMovementTemplateHandshake.Ticket?.Intake.Status == DclCanonicalNativePolicyTicketPublishStatus.Published &&
              forcedMovementTemplateHandshake.FinalBridge.Status == DclCanonicalNativePolicyTicketBridgeStatus.Published &&
              forcedMovementTemplateHandshake.FinalBridge.Execution?.Dispatch.Family == DclCanonicalActionFamily.ForcedMovement &&
              forcedMovementTemplateHandshake.FinalBridge.Execution.Dispatch.Application?.Plan.ActionInstanceId ==
                  forcedMovementTemplateHandshakeAction.ActionInstanceId &&
              forcedMovementTemplateHandshakeBattle.NativeAdmittedActions.Count == 0 &&
              forcedMovementTemplateHandshakeBattle.NativePolicySources.Count == 0 &&
              forcedMovementTemplateHandshakeBattle.NativeActions.Count == 1 &&
              forcedMovementTemplateHandshakeRandom.DrawCount == 3,
            "native admission template handshake must build and settle a non-Direct ForcedMovement policy ticket through the same retained bridge");
        DclCanonicalForcedMovementExecutionRequest composedMovement =
            DclCanonicalNativeForcedMovementExecutionComposer.Compose(
                composedMovementBattle,
                composedMovementAdmission,
                composedMovementBatch,
                DclCanonicalNativeAuxiliaryMagicPolicyProvider.BuildForcedMovement(
                    composedMovementAdmission,
                    new DclCanonicalNativeForcedMovementActionPolicySource(
                        new DclCanonicalNativeSingleTargetMagicPolicySource(
                            "forced-movement",
                            12,
                            DclZodiacCompatibility.Neutral,
                            0,
                            Learned: true,
                            SourceUsable: true,
                            PrerequisitesMet: true,
                            OvercastConfirmed: false),
                        new DclDefenseOption(DclDefenseKind.None, 0, Depletes: false),
                        composedMovementVerdict,
                        ReactionCandidates: [])));
        DclCanonicalConfirmedExecutionDispatchResult composedMovementDispatch =
            DclCanonicalConfirmedExecutionDispatcher.ResolveAndPublish(
                composedMovementBattle,
                16,
                composedMovement);
        Check(composedMovementDispatch is
              {
                  Family: DclCanonicalActionFamily.ForcedMovement,
                  Resolution: DclCanonicalForcedMovementExecutionResult
                  {
                      Movement: { MovedTiles: 2, CancelAim: true },
                  },
                  Application: not null,
              } && composedMovementDispatch.Application.Plan.ActionInstanceId == composedMovementAdmission.ActionInstanceId &&
              composedMovementDispatch.Application.Plan.Strikes.Single().AuxiliaryEffects?.ForcedMovement ==
                  ((DclCanonicalForcedMovementExecutionResult)composedMovementDispatch.Resolution).Movement &&
              composedMovementRandom.DrawCount == 3,
            "admitted ForcedMovement must preserve the synchronized origin and final native verdict through one canonical publication without per-tile resolution");
        DclCanonicalNativeStrikeProjection appliedMovement = published.Application.ApplyNextStrike(target, 0);
        DclCanonicalNativeAuxiliaryApplyPlan publishedMovementPlan =
            DclCanonicalNativeAuxiliaryApplyPlanner.Build(runtime, appliedMovement);
        DclBattleTile publishedTile = origin;
        DclCanonicalNativeForcedMovementWriter.Apply(
            publishedMovementPlan,
            () => publishedTile,
            resolved => publishedTile = resolved.Destination);
        _ = published.Application.CommitResourcePayment();
        published.Application.AcknowledgeReactionWindow();
        published.Application.Settle();
        Check(publishedTile == destination &&
              published.Application.Stage == DclCanonicalNativeActionStage.Settled,
            "confirmed ForcedMovement must finish its whole native displacement before payment and the single post-action Reaction window");

        var blockRandom = new SequenceRandomSource([3, 3, 4, 6, 6, 6]);
        var blockBattle = new DclCanonicalBattleRuntime(runtime, battleGeneration: 31, initialGlobalCt: 0, blockRandom);
        blockBattle.ObserveUnit(source);
        blockBattle.ObserveUnit(target);
        DclCanonicalPublishedForcedMovementExecution blockPublished =
            DclCanonicalForcedMovementExecutionCoordinator.ResolveAndPublish(
                blockBattle,
                new DclCanonicalForcedMovementExecutionRequest(
                    AbilityId: 16,
                    declaration,
                    blockBattle.NextActionInstanceId(),
                    targetCandidate,
                    BaseSpellScore: 12,
                    TargetSpellScore: 12,
                    blockDefense,
                    CurrentMpAtResolution: 5,
                    CurrentHpAtResolution: 10,
                    verdict));
        Check(blockPublished.Result.Delivery is { Delivered: true, DefenseKind: DclDefenseKind.Block } &&
              blockPublished.Result.FinalDefenseResources is { BlockAvailable: false } &&
              !blockPublished.Result.Transaction.DefenseResourcesFor(target).CaptureSnapshot().BlockAvailable &&
              !blockBattle.CaptureDefenseResources(target).BlockAvailable &&
              blockRandom.DrawCount == 6 && blockBattle.ExecutionRandom.Count == 2,
            "a reachable failed Block against ForcedMovement must still spend the battle-owned finite Block exactly once");
        _ = blockPublished.Application.ApplyNextStrike(target, 0);
        _ = blockPublished.Application.CommitResourcePayment();
        blockPublished.Application.AcknowledgeReactionWindow();
        blockPublished.Application.Settle();
        int drawsBeforeRejectedRetry = blockRandom.DrawCount;
        int ledgerBeforeRejectedRetry = blockBattle.ExecutionRandom.Count;
        CheckThrows<ArgumentException>(
            () => DclCanonicalForcedMovementExecutionCoordinator.ResolveAndPublish(
                blockBattle,
                new DclCanonicalForcedMovementExecutionRequest(
                    AbilityId: 16,
                    declaration,
                    blockBattle.NextActionInstanceId(),
                    targetCandidate,
                    BaseSpellScore: 12,
                    TargetSpellScore: 12,
                    blockDefense,
                    CurrentMpAtResolution: 5,
                    CurrentHpAtResolution: 10,
                    verdict)),
            "a second ForcedMovement Block selection must reject its stale finite-resource snapshot before RNG");
        Check(blockRandom.DrawCount == drawsBeforeRejectedRetry &&
              blockBattle.ExecutionRandom.Count == ledgerBeforeRejectedRetry,
            "a rejected spent-Block ForcedMovement retry must not consume casting/defense RNG or publish native work");
        CheckThrows<ArgumentException>(
            () => DclCanonicalForcedMovementEvaluation.Evaluate(
                runtime,
                new DclCanonicalForcedMovementEvaluationInput(
                    AbilityId: 16,
                    declaration,
                    targetCandidate with { DefenseResources = blockBattle.CaptureDefenseResources(target) },
                    BaseSpellScore: 12,
                    TargetSpellScore: 12,
                    blockDefense,
                    ResistanceScore: null,
                    Immune: false,
                    CurrentMpAtResolution: 5,
                    CurrentHpAtResolution: 10,
                    verdict)),
            "ForcedMovement evaluation must reject Block after the battle-owned resource is spent");

        DclActionProfile areaPush = push with
        {
            ActionId = "skill.forced-movement.area.test",
            TargetProfile = push.TargetProfile with
            {
                AllegiancePolicy = DclAllegiancePolicy.Everyone,
                Area = new DclAreaProfile(
                    DclAreaCenterMode.TrackedUnit,
                    DclAreaShape.Diamond,
                    Size: 1,
                    DclAreaDeliveryGate.QuickContest),
            },
            DeliveryProfile = push.DeliveryProfile with
            {
                Delivery = DclDelivery.Area,
                Dodgeable = false,
                Parryable = false,
                Blockable = false,
                UsesDefenseBonus = false,
                ResistanceCharacteristic = DclResistanceCharacteristic.Will,
                ArmorPolicy = DclArmorPolicy.None,
            },
            TransactionProfile = push.TransactionProfile with
            {
                CastingRollCardinality = DclCastingRollCardinality.PerAction,
                TargetGateCardinality = DclTargetGateCardinality.PerTarget,
                StrikeCount = 1,
            },
        };
        Check(DclAuthoringContract.Validate(areaPush).IsValid,
            "the normalized contract must admit one pure Area ForcedMovement Carrier");
        var areaPushAuthoring = new DclAuthoringRegistry();
        Check(areaPushAuthoring.TryRegister(areaPush).IsValid,
            "the pure Area ForcedMovement sentinel must register");
        DclStateDefinition areaMovementAimDefinition = BuildDclStateDefinition(
            "aim", DclStateStackPolicy.Replace, DclStateDurationClock.UsesOrTriggers);
        Check(areaPushAuthoring.TryRegister(areaMovementAimDefinition).IsValid,
            "Area ForcedMovement Aim cancellation requires the authoritative typed Aim definition");
        var areaPushBindings = new DclAbilityBindingRegistry();
        Check(areaPushBindings.TryRegister(
                binding with { ActionId = areaPush.ActionId },
                nativeCatalog,
                areaPushAuthoring).IsValid,
            "pure Area ForcedMovement must retain one complete canonical family and native carrier");
        var areaPushRuntime = new DclCanonicalRuntimeCatalog(
            areaPushAuthoring,
            new DclItemMetadataRegistry(),
            areaPushBindings,
            BuildNativeReactionBindings(areaPushAuthoring, areaPushBindings, nativeCatalog));
        var areaPushSource = new DclUnitKey(33, 1, 61);
        var areaPushTargetA = new DclUnitKey(33, 2, 62);
        var areaPushTargetB = new DclUnitKey(33, 3, 63);
        DclTargetCandidate AreaPushTarget(DclUnitKey unit, int x) => new(
            unit,
            new DclBattleTile(x, 2, 0),
            Height: 0,
            DclAllegianceRelation.Enemy,
            DclEligibleTargetStates.Alive,
            CurrentHp: 10,
            CombatStateRevision: 0,
            new DclDefenseResourceSnapshot(new Dictionary<string, int>(), BlockAvailable: true));
        DclTargetCandidate areaPushCandidateA = AreaPushTarget(areaPushTargetA, 2);
        DclTargetCandidate areaPushCandidateB = AreaPushTarget(areaPushTargetB, 3);
        var areaPushUnits = new Dictionary<DclUnitKey, DclTargetCandidate>
        {
            [areaPushTargetA] = areaPushCandidateA,
            [areaPushTargetB] = areaPushCandidateB,
        };
        DclCanonicalNativeMovementVerdict AreaPushVerdict(DclTargetCandidate target, int moved) => new(
            target.Unit,
            target.Tile,
            target.Tile with { X = target.Tile.X + moved },
            RequestedTiles: 2,
            MovedTiles: moved,
            DclForcedMovementDirection.AwayFromSource,
            Fell: false,
            NativePathResolved: true);
        var areaPushDeclaration = new DclCastDeclarationRequest(
            areaPush,
            areaPushSource,
            new DclBattleTile(1, 2, 0),
            CasterHeight: 0,
            areaPushCandidateA,
            FixedTile: null,
            FixedTileHeight: null,
            Learned: true,
            SourceUsable: true,
            SourceSilenced: false,
            PrerequisitesMet: true,
            CurrentMp: 5,
            CurrentHp: 10,
            OvercastConfirmed: false,
            CurrentGlobalCt: 0,
            CastCtModifiers: []);
        DclCanonicalAreaTargetEvaluationInput AreaPushEvaluationTarget(
            DclTargetCandidate target,
            bool immune) => new(
                target,
                TargetSpellScore: 12,
                TargetGateScore: 10,
                MagnitudeAttribute: 0,
                new DclElementAffinity(
                    DclElementAffinityKind.Numeric,
                    Step: 0,
                    DclRational.FromInteger(1),
                    DclRational.FromInteger(1)),
                FaithMagnitude: DclRational.FromInteger(1),
                TargetHasShell: false,
                TargetMaxHp: 10,
                FireEffect: false,
                OilContributed: false,
                ForcedMovementVerdict: AreaPushVerdict(target, target.Unit == areaPushTargetA ? 2 : 1),
                ForcedMovementImmune: immune,
                ForcedMovementConcentrationContext: target.Unit == areaPushTargetA
                    ? new DclCanonicalConcentrationTargetContext(
                        Charging: true,
                        Will: 10,
                        ConcentrationModifier: 0,
                        StatePenaltyMagnitude: 0)
                    : null);
        DclCanonicalAreaMagicEvaluationResult areaPushEvaluation =
            DclCanonicalAreaMagicEvaluationExecutor.Evaluate(
                areaPushRuntime,
                new DclCanonicalAreaMagicEvaluationInput(
                    AbilityId: 16,
                    areaPushDeclaration,
                    areaPushUnits,
                    [areaPushCandidateA, areaPushCandidateB],
                    BaseSpellScore: 12,
                    [
                        AreaPushEvaluationTarget(areaPushCandidateA, immune: false),
                        AreaPushEvaluationTarget(areaPushCandidateB, immune: true),
                    ],
                    CurrentMpAtResolution: 5,
                    CurrentHpAtResolution: 10));
        DclCanonicalAreaTargetEvaluationResult areaPushEvaluationA =
            areaPushEvaluation.Targets.Single(targetResult => targetResult.Target == areaPushTargetA);
        DclCanonicalAreaTargetEvaluationResult areaPushEvaluationB =
            areaPushEvaluation.Targets.Single(targetResult => targetResult.Target == areaPushTargetB);
        Check(areaPushEvaluation.Legal &&
              areaPushEvaluationA.DeliveredMovement is { MovedTiles: 2, CancelAim: true } &&
              areaPushEvaluationA.ExpectedMovedTiles ==
                  areaPushEvaluationA.AnyCarrierDeliveryProbability * DclRational.FromInteger(2) &&
              areaPushEvaluationB.AnyCarrierDeliveryProbability == DclRational.FromInteger(0) &&
              areaPushEvaluationB.ExpectedMovedTiles == DclRational.FromInteger(0) &&
              areaPushEvaluationA.ConcentrationInterruptionProbability ==
                  areaPushEvaluationA.AnyCarrierDeliveryProbability * new DclRational(
                      216 - DclSuccessRoll.SuccessOutcomeCount(7), 216) &&
              DclCanonicalAreaMagicAiProjection.From(areaPushEvaluation).ExpectedMovedTiles ==
                  areaPushEvaluationA.ExpectedMovedTiles,
            "Area ForcedMovement forecast/AI must retain each immutable final-map verdict, shared casting correlation, and immunity-before-RNG");

        var areaPushRandom = new SequenceRandomSource([3, 3, 4, 6, 6, 6, 6, 6, 6]);
        var areaPushBattle = new DclCanonicalBattleRuntime(
            areaPushRuntime,
            battleGeneration: 33,
            initialGlobalCt: 0,
            areaPushRandom);
        areaPushBattle.ObserveUnit(areaPushSource);
        areaPushBattle.ObserveUnit(areaPushTargetA);
        areaPushBattle.ObserveUnit(areaPushTargetB);
        DclStateApplicationResult areaMovementAim = areaPushBattle.States.Apply(new DclStateApplication(
            areaMovementAimDefinition,
            areaPushTargetA,
            Source: null,
            AppliedAtGlobalCt: areaPushBattle.CurrentGlobalCt,
            AppliedBeforeTurnSerial: 0,
            FirstEligibleTargetTurnSerial: null,
            FirstEligibleSourceTurnSerial: null,
            DurationUnits: 1,
            Strength: null,
            WinningMargin: null,
            StackDiscriminator: "",
            ContributionIdentity: null,
            new DclAimStatePayload(areaMovementAimDefinition.PayloadSchema, areaPushSource, 1),
            areaMovementAimDefinition.PresentationProfile));
        DclTargetCandidate currentAreaPushCandidateA = areaPushCandidateA with
        {
            CombatStateRevision = areaPushBattle.States.CaptureTarget(areaPushTargetA).Revision,
        };
        DclTargetCandidate currentAreaPushCandidateB = areaPushCandidateB with
        {
            CombatStateRevision = areaPushBattle.States.CaptureTarget(areaPushTargetB).Revision,
        };
        var currentAreaPushUnits = new Dictionary<DclUnitKey, DclTargetCandidate>
        {
            [areaPushTargetA] = currentAreaPushCandidateA,
            [areaPushTargetB] = currentAreaPushCandidateB,
        };
        DclCastDeclarationRequest currentAreaPushDeclaration = areaPushDeclaration with
        {
            UnitTarget = currentAreaPushCandidateA,
        };
        DclCanonicalAreaTargetExecutionRequest AreaPushExecutionTarget(
            DclTargetCandidate target,
            bool immune) => new(
                target,
                TargetSpellScore: 12,
                Dodge: null,
                ResistanceScore: 10,
                MagnitudeAttribute: 0,
                new DclElementAffinity(
                    DclElementAffinityKind.Numeric,
                    Step: 0,
                    DclRational.FromInteger(1),
                    DclRational.FromInteger(1)),
                FaithMagnitude: DclRational.FromInteger(1),
                TargetHasShell: false,
                TargetMaxHp: 10,
                FireEffect: false,
                OilContributed: false,
                ForcedMovementVerdict: AreaPushVerdict(target, target.Unit == areaPushTargetA ? 2 : 1),
                ForcedMovementImmune: immune,
                ForcedMovementConcentrationContext: target.Unit == areaPushTargetA
                    ? new DclCanonicalConcentrationTargetContext(
                        Charging: true,
                        Will: 10,
                        ConcentrationModifier: 0,
                        StatePenaltyMagnitude: 0)
                    : null);
        DclCastDeclarationAttempt areaChargingAttempt = DclMagicTargeting.Declare(
            currentAreaPushDeclaration with
            {
                Caster = areaPushTargetA,
                CasterTile = currentAreaPushCandidateA.Tile,
                UnitTarget = currentAreaPushCandidateB,
            },
            areaPushBattle.NextActionInstanceId());
        Check(areaChargingAttempt is { Legal: true, Declaration: not null },
            "Area ForcedMovement concentration sentinel requires one legal pending target cast");
        var areaMovementTimeline = new DclCanonicalTimelineScheduler(
            areaPushBattle,
            [new DclCanonicalTimelineUnit(
                areaPushTargetA,
                initiativeRank: 0,
                new DclCtState(0),
                DclCtRate.Normal)]);
        areaMovementTimeline.ScheduleChargedAction(16, areaChargingAttempt.Declaration!);
        DclCanonicalPublishedAreaMagicExecution areaPushExecution =
            DclCanonicalAreaMagicExecutionCoordinator.ResolveAndPublish(
                areaPushBattle,
                new DclCanonicalAreaMagicExecutionRequest(
                    AbilityId: 16,
                    currentAreaPushDeclaration,
                    areaPushBattle.NextActionInstanceId(),
                    currentAreaPushUnits,
                    [currentAreaPushCandidateA, currentAreaPushCandidateB],
                    BaseSpellScore: 12,
                    [
                        AreaPushExecutionTarget(currentAreaPushCandidateA, immune: false),
                        AreaPushExecutionTarget(currentAreaPushCandidateB, immune: true),
                    ],
                    CurrentMpAtResolution: 5,
                    CurrentHpAtResolution: 10,
                    ReactionCandidates: []));
        DclCanonicalAreaMagicStrikeResult[] areaPushStrikes = areaPushExecution.Result.Strikes.ToArray();
        Check(areaPushStrikes.Length == 2 &&
              areaPushStrikes[0].ForcedMovement is { MovedTiles: 2, CancelAim: true } &&
              areaPushStrikes[0].AimRetention is
                  { HadAim: true, Retained: false, InstanceId: var removedAreaMovementAimId } &&
              removedAreaMovementAimId == areaMovementAim.Instance.InstanceId &&
              !areaPushBattle.States.TryGet(areaMovementAim.Instance.InstanceId, out _) &&
              areaPushStrikes[0].Concentration is
                  { Outcome: DclConcentrationOutcome.Interrupted, Score: 7, Rolled: true } &&
              areaPushStrikes[0].ChargingCancellation is
                  { Reason: DclChargingCancellationReason.ConcentrationFailure } &&
              !areaMovementTimeline.TryGetChargedAction(areaPushTargetA, out _) &&
              areaPushStrikes[1] is
                  { DeliveryOutcome: DclMagicDeliveryOutcome.Resisted, ForcedMovement: null } &&
              areaPushExecution.Application.Plan.Strikes[0].AuxiliaryEffects?.ForcedMovement ==
                  areaPushStrikes[0].ForcedMovement &&
              areaPushExecution.Application.Plan.Strikes[0].AuxiliaryEffects?.RemovedStates.Single().InstanceId ==
                  areaMovementAim.Instance.InstanceId &&
              areaPushExecution.Application.Plan.Strikes[1].AuxiliaryEffects is null &&
              areaPushExecution.Application.Plan.Strikes.All(nativeStrike => nativeStrike.Channels.IsEmpty) &&
              areaPushExecution.Application.Plan.ReactionWindowOpened &&
              areaPushRandom.DrawCount == 9 && areaPushBattle.ExecutionRandom.Count == 3,
            "confirmed Area ForcedMovement must use one shared cast, interrupt target concentration once, skip immune target RNG, and open one terminal Reaction window");
        foreach (DclCanonicalNativeStrikeProjection nativeStrike in areaPushExecution.Application.Plan.Strikes)
            _ = areaPushExecution.Application.ApplyNextStrike(nativeStrike.Target, nativeStrike.StrikeIndex);
        _ = areaPushExecution.Application.CommitResourcePayment();
        areaPushExecution.Application.AcknowledgeReactionWindow();
        areaPushExecution.Application.Settle();
    }

    private static void TestDclMagicActionGates()
    {
        var target = new DclUnitKey(10, 6, 60);
        DclMagicTargetGateResult baseFailure = DclMagicActionGates.ResolveAreaTarget(
            target, 15, 10, 10, DclAreaDeliveryGate.None, 2,
            dodge: null, dodgeRolls: null, resistanceScore: null, resistanceRoll: null);
        DclMagicTargetGateResult targetFailure = DclMagicActionGates.ResolveAreaTarget(
            target, 11, 12, 10, DclAreaDeliveryGate.None, 2,
            dodge: null, dodgeRolls: null, resistanceScore: null, resistanceRoll: null);
        Check(!baseFailure.AnyStrikeLanded && !baseFailure.SharedCastingGate.BaseSucceeded &&
              !targetFailure.AnyStrikeLanded && targetFailure.SharedCastingGate.BaseSucceeded &&
              !targetFailure.SharedCastingGate.TargetSucceeded &&
              baseFailure.TargetGateRollCount == 0 && targetFailure.TargetGateRollCount == 0,
            "one shared casting draw must end all target delivery without consuming avoidance RNG when Base or TargetSpellScore fails");

        DclMagicTargetGateResult unavoidable = DclMagicActionGates.ResolveAreaTarget(
            target, 10, 12, 12, DclAreaDeliveryGate.None, 3,
            dodge: null, dodgeRolls: null, resistanceScore: null, resistanceRoll: null);
        Check(unavoidable.Strikes.Count == 3 && unavoidable.Strikes.All(strike => strike.Landed) &&
              unavoidable.TargetGateRollCount == 0,
            "AreaDeliveryGate None must share the successful casting classification and add no target avoidance roll");

        var dodge = new DclDefenseOption(DclDefenseKind.Dodge, 9, Depletes: false);
        DclMagicTargetGateResult dodged = DclMagicActionGates.ResolveAreaTarget(
            target, 10, 12, 12, DclAreaDeliveryGate.Dodge, 3,
            dodge, dodgeRolls: [10, 8, 18], resistanceScore: null, resistanceRoll: null);
        Check(dodged.Strikes.Count(strike => strike.Landed) == 2 &&
              dodged.Strikes[1].Outcome == DclMagicDeliveryOutcome.Defended &&
              dodged.TargetGateRollCount == 3 && dodged.Strikes.All(strike => strike.TargetGateRolled),
            "Dodge area delivery must grant exactly one current Dodge roll for every Strike against the target");

        DclMagicTargetGateResult critical = DclMagicActionGates.ResolveAreaTarget(
            target, 5, 14, 15, DclAreaDeliveryGate.Dodge, 3,
            dodge, dodgeRolls: [], resistanceScore: null, resistanceRoll: null);
        Check(critical.Strikes.All(strike => strike.Landed && !strike.TargetGateRolled) &&
              critical.TargetGateRollCount == 0,
            "a target-relative critical casting success must bypass every External Projectile Dodge without drawing defense RNG");

        DclMagicTargetGateResult contested = DclMagicActionGates.ResolveAreaTarget(
            target, 10, 12, 12, DclAreaDeliveryGate.QuickContest, 3,
            dodge: null, dodgeRolls: null, resistanceScore: 9, resistanceRoll: 8);
        DclMagicTargetGateResult tied = DclMagicActionGates.ResolveAreaTarget(
            target, 10, 12, 12, DclAreaDeliveryGate.QuickContest, 3,
            dodge: null, dodgeRolls: null, resistanceScore: 10, resistanceRoll: 8);
        Check(contested.Strikes.All(strike => strike.Landed) && contested.TargetGateRollCount == 1 &&
              contested.Strikes.Count(strike => strike.TargetGateRolled) == 1 &&
              tied.Strikes.All(strike => !strike.Landed),
            "Internal area delivery must make one Quick Contest per target, share it across all hits, and award ties to resistance");

        DclSpellGateResult carrier = DclSpellResolution.ClassifySharedRoll(10, 12, 12);
        DclMagicRiderResult resistedRider = DclMagicActionGates.ResolveStatusRider(
            carrier, carrierLanded: true, resistanceScore: 10, resistanceRoll: 8, immune: false);
        DclMagicRiderResult appliedRider = DclMagicActionGates.ResolveStatusRider(
            carrier, carrierLanded: true, resistanceScore: 10, resistanceRoll: 9, immune: false);
        DclMagicRiderResult immuneRider = DclMagicActionGates.ResolveStatusRider(
            carrier, carrierLanded: true, resistanceScore: 10, resistanceRoll: null, immune: true);
        DclMagicRiderResult unresistedRider = DclMagicActionGates.ResolveStatusRider(
            carrier, carrierLanded: true, resistanceScore: 0, resistanceRoll: null, immune: false,
            resistanceGate: DclStateResistanceGate.None);
        DclMagicRiderResult successRollResisted = DclMagicActionGates.ResolveStatusRider(
            carrier, carrierLanded: true, resistanceScore: 10, resistanceRoll: 8, immune: false,
            resistanceGate: DclStateResistanceGate.SuccessRoll);
        DclMagicRiderResult failedSuccessRoll = DclMagicActionGates.ResolveStatusRider(
            carrier, carrierLanded: true, resistanceScore: 10, resistanceRoll: 12, immune: false,
            resistanceGate: DclStateResistanceGate.SuccessRoll);
        Check(resistedRider.Attempted && !resistedRider.Applied &&
              appliedRider.Attempted && appliedRider.Applied &&
              !immuneRider.Attempted && !immuneRider.Applied &&
              !unresistedRider.Attempted && unresistedRider.Applied &&
              successRollResisted is { Attempted: true, Applied: false, CasterMargin: 0 } &&
              failedSuccessRoll is { Attempted: true, Applied: true, CasterMargin: 0 },
            "a landed status rider must reuse its Carrier, honor None/SuccessRoll/QuickContest gates, and short-circuit visible immunity before RNG");
        CheckThrows<InvalidOperationException>(
            () => DclMagicActionGates.ResolveStatusRider(
                carrier, carrierLanded: true, resistanceScore: 10, resistanceRoll: null, immune: false,
                resistanceGate: DclStateResistanceGate.Explicit),
            "an Explicit Rider gate must fail closed without its named mechanism owner");
    }

    private static void TestDclReviveAndUndead()
    {
        static DclUndeadInteractionTable InteractionTable()
        {
            var rules = Enum.GetValues<DclUndeadEffectFamily>().ToDictionary(
                family => family,
                _ => new DclUndeadFamilyRule(
                    DclUndeadInteraction.Normal,
                    DclUndeadInteraction.EffectOwned,
                    DclUndeadInteraction.Normal));
            rules[DclUndeadEffectFamily.DirectHealing] = new DclUndeadFamilyRule(
                DclUndeadInteraction.Normal,
                DclUndeadInteraction.Harm,
                DclUndeadInteraction.Normal);
            rules[DclUndeadEffectFamily.HpDrain] = new DclUndeadFamilyRule(
                DclUndeadInteraction.Normal,
                DclUndeadInteraction.Reverse,
                DclUndeadInteraction.Reverse);
            rules[DclUndeadEffectFamily.RaiseOrArise] = new DclUndeadFamilyRule(
                DclUndeadInteraction.Normal,
                DclUndeadInteraction.Reject,
                DclUndeadInteraction.Normal);
            rules[DclUndeadEffectFamily.Reraise] = new DclUndeadFamilyRule(
                DclUndeadInteraction.Normal,
                DclUndeadInteraction.Reject,
                DclUndeadInteraction.Normal);
            return new DclUndeadInteractionTable(rules);
        }

        CheckThrows<ArgumentException>(
            () => new DclUndeadInteractionTable(new Dictionary<DclUndeadEffectFamily, DclUndeadFamilyRule>()),
            "the Undead policy must explicitly cover every required effect family instead of inferring one global healing inversion");
        DclUndeadInteractionTable table = InteractionTable();
        Check(table.TargetInteraction(DclUndeadEffectFamily.DirectHealing, targetUndead: true) == DclUndeadInteraction.Harm &&
              table.CasterInteraction(DclUndeadEffectFamily.HpDrain, casterUndead: true) == DclUndeadInteraction.Reverse &&
              table.TargetInteraction(DclUndeadEffectFamily.MpDrain, targetUndead: false) == DclUndeadInteraction.Normal,
            "target and caster Undead axes must remain explicit per effect family");

        var revive = new DclReviveProfile(
            DclEligibleTargetStates.Ko | DclEligibleTargetStates.Undead,
            DclReviveMode.Immediate,
            DclReviveFaithAxis.RestoredHp,
            PaysForBothFaithAxes: false,
            DclUndeadEffectFamily.RaiseOrArise);
        DclReviveResult restored = DclReviveRules.Resolve(
            revive,
            table,
            DclEligibleTargetStates.Ko,
            targetUndead: false,
            deliverySucceeded: true,
            rawRestoredHp: 10,
            faithMultiplier: new DclRational(3, 2),
            currentHp: 0,
            maxHp: 50);
        Check(restored.Route == DclReviveRoute.ImmediateHpCredit && restored.RawRestoredHp == 10 &&
              restored.FinalRestoredHp == 15 && restored.AppliedHpCredit == 15 && restored.ClearKoAfterPositiveCredit,
            "immediate revive must apply its declared HP expression and Faith axis, then clear KO only after positive native HP credit");
        DclReviveResult successFaithOnly = DclReviveRules.Resolve(
            revive with { FaithAxis = DclReviveFaithAxis.Success },
            table,
            DclEligibleTargetStates.Ko,
            targetUndead: false,
            deliverySucceeded: true,
            rawRestoredHp: 10,
            faithMultiplier: new DclRational(3, 2),
            currentHp: 0,
            maxHp: 50);
        Check(successFaithOnly.FinalRestoredHp == 10,
            "Faith assigned to revive success must not also multiply restored HP");

        DclReviveResult rejectedUndead = DclReviveRules.Resolve(
            revive,
            table,
            DclEligibleTargetStates.Ko | DclEligibleTargetStates.Undead,
            targetUndead: true,
            deliverySucceeded: true,
            rawRestoredHp: 10,
            faithMultiplier: DclRational.FromInteger(1),
            currentHp: 0,
            maxHp: 50);
        DclReviveResult ineligible = DclReviveRules.Resolve(
            revive,
            table,
            DclEligibleTargetStates.Alive,
            targetUndead: false,
            deliverySucceeded: true,
            rawRestoredHp: 10,
            faithMultiplier: DclRational.FromInteger(1),
            currentHp: 20,
            maxHp: 50);
        Check(rejectedUndead.Route == DclReviveRoute.RejectedByUndeadRule &&
              ineligible.Route == DclReviveRoute.NotEligible,
            "revive must obey explicit Undead and target-state policy before producing HP credit");

        var reraise = new DclReviveProfile(
            DclEligibleTargetStates.Alive,
            DclReviveMode.StoredReraise,
            DclReviveFaithAxis.Success,
            PaysForBothFaithAxes: false,
            DclUndeadEffectFamily.Reraise);
        DclReviveResult stored = DclReviveRules.Resolve(
            reraise,
            table,
            DclEligibleTargetStates.Alive,
            targetUndead: false,
            deliverySucceeded: true,
            rawRestoredHp: 99,
            faithMultiplier: DclRational.FromInteger(2),
            currentHp: 30,
            maxHp: 50);
        Check(stored.Route == DclReviveRoute.StoredReraise && stored.StoreReraise &&
              stored.AppliedHpCredit == 0 && !stored.ClearKoAfterPositiveCredit,
            "Reraise must store a trigger rather than silently performing immediate healing");
        CheckThrows<ArgumentException>(
            () => DclReviveRules.Validate(revive with
            {
                FaithAxis = DclReviveFaithAxis.BothExplicit,
                PaysForBothFaithAxes = false,
            }),
            "revive must reject double Faith benefit unless the profile explicitly pays for both axes");
    }

    private static void TestDclMagicCorrelatedForecast()
    {
        var targetA = new DclUnitKey(14, 2, 20);
        var targetB = new DclUnitKey(14, 3, 30);
        DclMagicCorrelatedForecastResult identical = DclMagicCorrelatedForecast.Enumerate(
            baseSpellScore: 12,
            [
                new DclMagicForecastTarget(targetA, 12, DclAreaDeliveryGate.None, TargetGateScore: null),
                new DclMagicForecastTarget(targetB, 12, DclAreaDeliveryGate.None, TargetGateScore: null),
            ]);
        DclRational total = identical.DeliveredTargetCountProbability.Values.Aggregate(
            DclRational.FromInteger(0), (sum, probability) => sum + probability);
        Check(total == DclRational.FromInteger(1) &&
              identical.DeliveredTargetCountProbability[1] == DclRational.FromInteger(0) &&
              identical.PerTargetDeliveryProbability[targetA] == new DclRational(160, 216) &&
              identical.PerTargetDeliveryProbability[targetB] == new DclRational(160, 216),
            "identical unavoidable targets must remain perfectly correlated through the one shared casting draw, never modeled as independent rerolls");

        DclMagicCorrelatedForecastResult differentScores = DclMagicCorrelatedForecast.Enumerate(
            12,
            [
                new DclMagicForecastTarget(targetA, 12, DclAreaDeliveryGate.None, null),
                new DclMagicForecastTarget(targetB, 10, DclAreaDeliveryGate.None, null),
            ]);
        Check(differentScores.PerTargetDeliveryProbability[targetA] > differentScores.PerTargetDeliveryProbability[targetB] &&
              differentScores.DeliveredTargetCountProbability[1] > DclRational.FromInteger(0),
            "one shared draw may deliver to the favorable target alone when target-relative SpellScores differ");

        DclMagicCorrelatedForecastResult dodge = DclMagicCorrelatedForecast.Enumerate(
            12,
            [
                new DclMagicForecastTarget(targetA, 12, DclAreaDeliveryGate.Dodge, 9),
                new DclMagicForecastTarget(targetB, 12, DclAreaDeliveryGate.Dodge, 9),
            ]);
        Check(dodge.DeliveredTargetCountProbability[1] > DclRational.FromInteger(0) &&
              dodge.PerTargetDeliveryProbability[targetA] == dodge.PerTargetDeliveryProbability[targetB] &&
              dodge.AnyTargetDelivered > dodge.PerTargetDeliveryProbability[targetA],
            "target Dodge rolls must be independent conditional branches under the correlated shared casting draw");

        DclMagicCorrelatedForecastResult singleStrikeRider = DclMagicCorrelatedForecast.Enumerate(
            12,
            [
                new DclMagicForecastTarget(
                    targetA,
                    12,
                    DclAreaDeliveryGate.Dodge,
                    TargetGateScore: 9,
                    StrikeCount: 1,
                    StatusRiders: [new DclMagicStatusRiderForecast(1, 10, Immune: false)]),
            ]);
        DclMagicCorrelatedForecastResult multiStrikeRiders = DclMagicCorrelatedForecast.Enumerate(
            12,
            [
                new DclMagicForecastTarget(
                    targetA,
                    12,
                    DclAreaDeliveryGate.Dodge,
                    TargetGateScore: 9,
                    StrikeCount: 3,
                    StatusRiders:
                    [
                        new DclMagicStatusRiderForecast(1, 10, Immune: false),
                        new DclMagicStatusRiderForecast(2, 10, Immune: true),
                    ]),
            ]);
        Check(multiStrikeRiders.PerTargetDeliveryProbability[targetA] >
                  singleStrikeRider.PerTargetDeliveryProbability[targetA] &&
              multiStrikeRiders.PerTargetExpectedLandedStrikes[targetA] ==
                  singleStrikeRider.PerTargetDeliveryProbability[targetA] * DclRational.FromInteger(3) &&
              multiStrikeRiders.PerTargetRiderApplicationProbability[targetA][1] >
                  singleStrikeRider.PerTargetRiderApplicationProbability[targetA][1] &&
              multiStrikeRiders.PerTargetRiderApplicationProbability[targetA][1] <=
                  multiStrikeRiders.PerTargetDeliveryProbability[targetA] &&
              multiStrikeRiders.PerTargetRiderApplicationProbability[targetA][2] ==
                  DclRational.FromInteger(0),
            "correlated Area forecast must model per-Strike Dodge, any-landed Rider reachability, one shared-roll resistance contest, and immunity without execution sampling");
        DclMagicCorrelatedForecastResult authoredGateRiders = DclMagicCorrelatedForecast.Enumerate(
            12,
            [
                new DclMagicForecastTarget(
                    targetA,
                    12,
                    DclAreaDeliveryGate.None,
                    TargetGateScore: null,
                    StrikeCount: 1,
                    StatusRiders:
                    [
                        new DclMagicStatusRiderForecast(
                            1, 10, Immune: false, DclStateResistanceGate.None),
                        new DclMagicStatusRiderForecast(
                            2, 10, Immune: false, DclStateResistanceGate.SuccessRoll),
                    ]),
            ]);
        DclRational authoredGateDelivery = authoredGateRiders.PerTargetDeliveryProbability[targetA];
        Check(authoredGateRiders.PerTargetRiderApplicationProbability[targetA][1] == authoredGateDelivery &&
              authoredGateRiders.PerTargetRiderApplicationProbability[targetA][2] ==
                  authoredGateDelivery * new DclRational(
                      216 - DclSuccessRoll.SuccessOutcomeCount(10),
                      216),
            "Area Rider forecast must derive None and SuccessRoll application mass from the authored state gate rather than assuming a Quick Contest");
        CheckThrows<ArgumentException>(
            () => DclMagicCorrelatedForecast.Enumerate(
                12,
                [
                    new DclMagicForecastTarget(
                        targetA,
                        12,
                        DclAreaDeliveryGate.None,
                        TargetGateScore: null,
                        StrikeCount: 2,
                        StatusRiders:
                        [
                            new DclMagicStatusRiderForecast(1, 10, Immune: false),
                            new DclMagicStatusRiderForecast(1, 11, Immune: false),
                        ]),
                ]),
            "Area forecast must reject duplicate Rider effect identities before probability enumeration");

        DclMagicCorrelatedForecastResult contest = DclMagicCorrelatedForecast.Enumerate(
            12,
            [new DclMagicForecastTarget(targetA, 12, DclAreaDeliveryGate.QuickContest, 10)]);
        Check(contest.PerTargetDeliveryProbability[targetA] == DclSpellResolution.InternalSuccessProbability(12, 12, 10).Fraction,
            "correlated area forecast must reduce to the exact single-target Internal Direct probability for one Quick Contest target");
    }

    private static void TestDclActionTransaction()
    {
        var sequence = new DclActionInstanceSequence(7);
        Check(sequence.Next() == 1 && sequence.Next() == 2,
            "ActionInstance ids must be stable and monotonic inside one battle generation");
        sequence.Reset(8);
        Check(sequence.BattleGeneration == 8 && sequence.Next() == 1,
            "a new battle generation must reset its independent ActionInstance sequence");

        DclActionProfile profile = BuildDclTransactionTestProfile(DclWithinActionApplication.Deferred);
        var source = new DclUnitKey(8, 1, 0x10);
        var targetA = new DclUnitKey(8, 4, 0x20);
        var targetB = new DclUnitKey(8, 5, 0x21);
        var declaration = new DclActionDeclaration(
            sequence.Next(),
            source,
            profile.ActionId,
            profile.ProfileRevision,
            DclTargetMode.Unit,
            targetA,
            FixedTile: null,
            new DclBattleTile(3, 4, 0),
            PassedRangeCheck: true,
            PassedVerticalCheck: true,
            FinalMpCost: 0,
            ApprovedHpCap: 0,
            CastCt: 0,
            DeclaredAtGlobalCt: 0,
            ResolvesAtGlobalCt: 0);
        var targetBatch = new DclTargetBatch(8,
        [
            new DclTargetResolutionSnapshot(
                targetA,
                40,
                100,
                new DclDefenseResourceSnapshot(new Dictionary<string, int> { ["main-hand"] = 0 }, BlockAvailable: true)),
            new DclTargetResolutionSnapshot(
                targetB,
                60,
                101,
                new DclDefenseResourceSnapshot(new Dictionary<string, int>(), BlockAvailable: false)),
        ]);
        CheckThrows<ArgumentException>(
            () => new DclTargetBatch(8,
            [
                targetBatch.Targets[0],
                targetBatch.Targets[0],
            ]),
            "a TargetBatch must reject duplicate stable UnitKeys");

        DclEffectProfile damageEffect = profile.Effects[0];
        DclEffectProfile stateEffect = profile.Effects[1];
        DclPlannedEffect[] DeferredStrikeEffects() =>
        [
            new DclPlannedEffect(0, damageEffect, ImmediateWithinAction: true),
            new DclPlannedEffect(1, stateEffect, ImmediateWithinAction: false),
        ];
        var unrelatedEffect = new DclEffectProfile(
            DclEffectKind.Reequip,
            DclEffectRole.Independent,
            DclEligibleTargetStates.Alive,
            DclUndeadInteraction.Normal);
        var transaction = new DclActionTransaction(declaration, profile);
        transaction.SnapshotTargetBatch(targetBatch);
        transaction.BeginPlanning();
        CheckThrows<ArgumentException>(
            () => transaction.PlanStrike(targetB, 1, [new DclPlannedEffect(0, unrelatedEffect, ImmediateWithinAction: true)]),
            "a transaction must reject effects that do not belong to its normalized profile");
        transaction.PlanStrike(targetB, 1, DeferredStrikeEffects());
        transaction.PlanStrike(targetA, 0, DeferredStrikeEffects());
        transaction.PlanStrike(targetB, 0, DeferredStrikeEffects());
        transaction.PlanStrike(targetA, 1, DeferredStrikeEffects());
        transaction.SealPlan();

        DclMutableDefenseResources defense = transaction.DefenseResourcesFor(targetA);
        Check(defense.CurrentParryPenalty("main-hand") == 0 && defense.SpendParryAttempt("main-hand") == 1 &&
              defense.CurrentParryPenalty("main-hand") == -4 && defense.SpendParryAttempt("main-hand") == 2 &&
              defense.CurrentParryPenalty("main-hand") == -8,
            "each attempted Parry must add the cumulative -4 penalty for that weapon or limb");
        Check(defense.TrySpendBlock() && !defense.TrySpendBlock(),
            "Block must be available once in the snapshotted defense interval");

        transaction.BeginCommit();
        DclStrikeCommitDecision first = transaction.BeginNextStrike()!.Value;
        Check(first.ExecuteMechanics && first.Strike.Target == targetA && first.Strike.StrikeIndex == 0,
            "commit must use stable TargetBatch order and Strike order, not planning enumeration order");
        DclRollIdentity rollIdentity = transaction.RollIdentityFor(first.Strike, DclRollSite.Attack, 0);
        Check(rollIdentity.ActionInstanceId == declaration.ActionInstanceId &&
              rollIdentity.TargetUnitSlot == targetA.UnitSlot && rollIdentity.StrikeIndex == 0,
            "every Strike random site must retain outer ActionInstance, target, and Strike identity");
        transaction.CompleteActiveStrike(targetIsKoAfterStrike: true);
        Check(transaction.VisibleEffects.Count == 1 && transaction.VisibleEffects[0].Effect.Kind == DclEffectKind.Damage,
            "native damage is immediate while a Deferred state remains invisible to later Strikes");

        DclStrikeCommitDecision second = transaction.BeginNextStrike()!.Value;
        Check(second.Skipped && second.Strike.Target == targetA && second.Strike.StrikeIndex == 1,
            "KO during a combo must skip every later mechanical roll and effect for that target");
        DclStrikeCommitDecision third = transaction.BeginNextStrike()!.Value;
        Check(third.ExecuteMechanics && third.Strike.Target == targetB && third.Strike.StrikeIndex == 0,
            "one target's KO short-circuit must not cancel other members of the TargetBatch");
        transaction.CompleteActiveStrike(targetIsKoAfterStrike: false);
        DclStrikeCommitDecision fourth = transaction.BeginNextStrike()!.Value;
        Check(fourth.ExecuteMechanics && fourth.Strike.Target == targetB && fourth.Strike.StrikeIndex == 1,
            "the other target's combo must continue through its remaining Strikes");
        transaction.CompleteActiveStrike(targetIsKoAfterStrike: false);
        Check(transaction.BeginNextStrike() is null, "the commit sequence must end after every target and Strike");
        transaction.CompleteCommit();
        Check(transaction.VisibleEffects.Count == 6 &&
              transaction.VisibleEffects.Count(effect => effect.Effect.Kind == DclEffectKind.StatusApplication) == 3 &&
              transaction.Stage == DclActionTransactionStage.ReactionWindowReady,
            "Deferred effects become visible at outer commit and a KO-skipped Strike contributes no rider");
        transaction.OpenReactionWindow();
        Check(transaction.ReactionWindowOpened && transaction.Stage == DclActionTransactionStage.ReactionWindowOpen,
            "the Reaction window must open once after all targets and Strikes finish");
        transaction.Settle();
        Check(transaction.Stage == DclActionTransactionStage.Settled,
            "cleanup and presentation settle only after the Reaction window");
        CheckThrows<InvalidOperationException>(transaction.OpenReactionWindow,
            "a settled ActionInstance must never manufacture another Reaction window");

        DclCanonicalTransactionResult canonical = DclCanonicalTransactionExecutor.Commit(
            declaration with { ActionInstanceId = sequence.Next() },
            profile,
            [targetBatch.Targets[1], targetBatch.Targets[0]],
            [
                new DclCanonicalResolvedStrike(targetB, 1, [0, 1], TargetKoAfterStrike: false),
                new DclCanonicalResolvedStrike(targetA, 1, [0, 1], TargetKoAfterStrike: false),
                new DclCanonicalResolvedStrike(targetB, 0, [0, 1], TargetKoAfterStrike: false),
                new DclCanonicalResolvedStrike(targetA, 0, [0, 1], TargetKoAfterStrike: true),
            ]);
        Check(canonical.Transaction is { Stage: DclActionTransactionStage.Settled, ReactionWindowOpened: true } &&
              canonical.ExecutedStrikes.SequenceEqual([(targetA, 0), (targetB, 0), (targetB, 1)]) &&
              canonical.KoShortCircuitedStrikes.SequenceEqual([(targetA, 1)]) &&
              canonical.Transaction.VisibleEffects.Count == 6,
            "the canonical batch executor must normalize target/Strike order, preserve KO short-circuiting, commit staged effects, and open one Reaction window");

        var failed = new DclActionTransaction(declaration with { ActionInstanceId = sequence.Next() }, profile);
        failed.FailResourceCommitment();
        Check(failed.Stage == DclActionTransactionStage.ResourceFailed && !failed.ReactionWindowOpened,
            "ResourceFailure must occur before target snapshot and cannot open a Reaction window");
        CheckThrows<InvalidOperationException>(failed.OpenReactionWindow,
            "ResourceFailure must reject Reaction-window entry");

        DclActionProfile immediateProfile = BuildDclTransactionTestProfile(DclWithinActionApplication.Immediate);
        var immediate = new DclActionTransaction(
            declaration with
            {
                ActionInstanceId = sequence.Next(),
                ActionId = immediateProfile.ActionId,
                ProfileRevision = immediateProfile.ProfileRevision,
            },
            immediateProfile);
        immediate.SnapshotTargetBatch(new DclTargetBatch(8, [targetBatch.Targets[1]]));
        immediate.BeginPlanning();
        DclPlannedEffect[] ImmediateStrikeEffects() =>
        [
            new DclPlannedEffect(0, immediateProfile.Effects[0], ImmediateWithinAction: true),
            new DclPlannedEffect(1, immediateProfile.Effects[1], ImmediateWithinAction: true),
        ];
        immediate.PlanStrike(targetB, 0, ImmediateStrikeEffects());
        immediate.PlanStrike(targetB, 1, ImmediateStrikeEffects());
        immediate.SealPlan();
        immediate.BeginCommit();
        Check(immediate.BeginNextStrike()!.Value.ExecuteMechanics,
            "an Immediate setup action still begins with ordinary Strike mechanics");
        immediate.CompleteActiveStrike(targetIsKoAfterStrike: false);
        Check(immediate.VisibleEffects.Count == 2 &&
              immediate.VisibleEffects.Any(effect => effect.Effect.Kind == DclEffectKind.StatusApplication),
            "an explicitly Immediate state must become visible with native damage before the next Strike");
    }

