            new DclSourceProfile(DclActionSource.Physical, Verbal: false),
            new DclSkillProfile(1, 0, null, ZodiacSensitive: false),
            new DclResourceProfile(0, DclRational.FromInteger(1), DclOvercastPolicy.Forbidden),
            new DclTimingProfile(ConsumesAction: true, ConsumesMovement: false, 0, 0, ConcentrationRequired: false),
            new DclTargetProfile(
                DclTargetMode.Unit,
                DclAllegiancePolicy.EnemiesOnly,
                DclEligibleTargetStates.Alive,
                1,
                1,
                1,
                VisionRequired: true,
                DclPhysicalRoute.NativeDirect,
                Area: null),
            new DclDeliveryProfile(
                DclDelivery.PhysicalAttack,
                Dodgeable: true,
                Parryable: true,
                Blockable: true,
                UsesDefenseBonus: true,
                ResistanceCharacteristic: null,
                DclArmorPolicy.Manifestation,
                ArmorDivisor: null,
                DclLocationPolicy.NormalCombined,
                Reflectable: false,
                ShellSensitive: false),
            new DclDamageMagnitude(
                DclDamageBasis.Swing,
                FixedExpression: null,
                0,
                0,
                DclDamageType.Crushing,
                Element: null,
                ElementBoostMultiplier: null,
                DclFaithPolicy.None),
            [
                new DclEffectProfile(
                    DclEffectKind.Damage,
                    DclEffectRole.Carrier,
                    DclEligibleTargetStates.Alive,
                    DclUndeadInteraction.Normal),
                new DclEffectProfile(
                    DclEffectKind.StatusApplication,
                    DclEffectRole.Rider,
                    DclEligibleTargetStates.Alive,
                    DclUndeadInteraction.Normal,
                    ReferencedStateKind: "test-state"),
